// ── Deleted-business tombstone — survives refresh, guards both demo and DB merges ──
function _getDeletedBizIds(){
  try{ return new Set(JSON.parse(localStorage.getItem('st_deleted_biz')||'[]')); }catch(e){ return new Set(); }
}
function _markBizDeleted(bizId){
  try{
    const ids = _getDeletedBizIds();
    ids.add(bizId);
    localStorage.setItem('st_deleted_biz', JSON.stringify([...ids]));
  }catch(e){}
}

function _loadAdminBiz(){
  const deleted = _getDeletedBizIds();

  // ── Super Admin with real Supabase data already loaded ────────
  // After _dbLoadAdminBiz() runs, D.adminBiz contains real businesses from the DB.
  // We must NOT re-inject hardcoded demo businesses on top of real data —
  // that is what caused deleted businesses to reappear after a refresh.
  // Only inject demo businesses when the SA has no real DB connection (offline/demo mode).
  const hasRealData = D.adminBiz.some(b => !_DEMO_DATA.adminBiz.find(d => d.id === b.id) && b.id !== 'BIZ-107');

  let base;
  if(hasRealData || SESSION.isSuperAdmin){
    // Real SA session: use only what came from Supabase — never merge in hardcoded demo rows
    base = D.adminBiz.slice();
  } else {
    // No real DB data: show demo businesses so the SA panel is not blank
    const existing = D.adminBiz.filter(b => !_DEMO_DATA.adminBiz.find(d => d.id === b.id));
    base = _DEMO_DATA.adminBiz.slice().concat(existing);
  }

  // Always ensure Test LLC (BIZ-107) is present as the platform test account
  // (only add it if not already in the list from DB)
  const testLLC = {id:'BIZ-107',name:'Test LLC',owner:'Alex Lasen',email:'alasen479@gmail.com',type:'General Retail',st:'Active',plan:'Professional',users:1,rev:0,created:'2026-03-23'};
  if(!base.find(b => b.id === 'BIZ-107')){
    base.push(testLLC);
  }

  // Apply deletion tombstones — filter out anything marked deleted this session
  // or in a prior session (stored in localStorage)
  D.adminBiz = base.filter(b => !deleted.has(b.id));
}


