// Get effective rights object for current session user
function _getRights(){
  // Super Admins have NO access to business data — only platform admin pages
  if(SESSION.isSuperAdmin) return {}; // empty = no module access
  const user = BIZ_USERS.find(u=>u.id===SESSION.userId);
  return (user && user.rights) ? user.rights : (DEFAULT_RIGHTS[SESSION.level] || {});
}

// Get tier for a module: 'edit'|'read'|'none'
function tier(module){
  // Super Admin: blocked from all business data modules
  if(SESSION.isSuperAdmin) return 'none';
  const r=_getRights();
  return r ? (r[module]||'none') : 'edit';
}

// Can the user access (read or edit) a module?
function canAccess(module){ const t=tier(module); return t==='edit'||t==='read'; }

// Can the user edit a module?
function canEdit(module){ return tier(module)==='edit'; }

// Legacy boolean helper (mapped to new modules)
function can(right){
  const map={
    edit_inventory:'inventory',edit_sales:'sales',edit_expenses:'expenses',
    edit_purchases:'purchases',edit_rentals:'rentals',edit_customers:'customers',
    edit_vendors:'vendors',bulk_import:'bulk_import',export_data:'export_data',
    view_reports:'reports',apply_discount:'discounts',view_cost_prices:'inventory_cost',
    manage_users:'manage_users',
  };
  const mod=map[right]||right;
  if(right.startsWith('view_')||right==='view_cost_prices') return canAccess(mod);
  return canEdit(mod);
}

function requireRight(right, label){
  if(!can(right)){
    toast('⛔ '+label+' — permission denied for your role','error');
    return false;
  }
  return true;
}

function requireAccess(module, label){
  if(!canAccess(module)){
    toast('⛔ '+label+' — not accessible for your role','error');
    return false;
  }
  return true;
}

