// Live rate cache — all relative to 1 USD base
const _rates = { XAF:615, NGN:1620, GHS:15.8, GBP:0.79, EUR:0.92 };

async function fetchRates(){
  try {
    const r = await fetch('https://api.frankfurter.app/latest?from=USD&to=XAF,NGN,GHS,GBP,EUR');
    const d = await r.json();
    if(d.rates){
      if(d.rates.XAF) _rates.XAF = d.rates.XAF;
      if(d.rates.NGN) _rates.NGN = d.rates.NGN;
      if(d.rates.GHS) _rates.GHS = d.rates.GHS;
      if(d.rates.GBP) _rates.GBP = d.rates.GBP;
      if(d.rates.EUR) _rates.EUR = d.rates.EUR;
    }
  } catch(e){
    // keep fallback values already set above
  }
  // If active currency rate updated, refresh CUR
  if(CUR.code === 'XAF') CUR.rate = _rates.XAF;
  if(CUR.code === 'NGN') CUR.rate = _rates.NGN;
  if(CUR.code === 'GHS') CUR.rate = _rates.GHS;
  if(CUR.code === 'GBP') CUR.rate = _rates.GBP;
  if(CUR.code === 'EUR') CUR.rate = _rates.EUR;
}
