function setCurrency(code, flag){
  // Update currency pill active state
  document.querySelectorAll('.cur-opt').forEach(el => {
    el.classList.toggle('on', el.dataset.cur === code);
  });
  const configs = {
    USD: { symbol:'$',   rate:1,          decimals:2, flag:'🇺🇸' },
    XAF: { symbol:'Frs', rate:_rates.XAF, decimals:0, flag:'🇨🇲' },
    NGN: { symbol:'₦',   rate:_rates.NGN, decimals:0, flag:'🇳🇬' },
    GHS: { symbol:'₵',   rate:_rates.GHS, decimals:2, flag:'🇬🇭' },
    GBP: { symbol:'£',   rate:_rates.GBP, decimals:2, flag:'🇬🇧' },
    EUR: { symbol:'€',   rate:_rates.EUR, decimals:2, flag:'🇪🇺' },
  };
  const cfg = configs[code] || configs.USD;
  const resolvedFlag = flag || cfg.flag;
  CUR = { code, symbol:cfg.symbol, flag:resolvedFlag, rate:cfg.rate, decimals:cfg.decimals };

  // Update topbar pill
  const flagEl = document.getElementById('cur-flag');
  const codeEl = document.getElementById('cur-code');
  if(flagEl) flagEl.textContent = resolvedFlag;
  if(codeEl) codeEl.textContent = code;
  document.getElementById('cur-panel')?.classList.remove('open');

  // Persist to localStorage so it survives refresh
  try{ localStorage.setItem('shoptrack_currency', JSON.stringify({code, flag:resolvedFlag})); }catch(e){}

  // Save to business profile in DB
  if(SESSION.bizId && !SESSION.isSuperAdmin){
    BIZ.currency = code;
    _dbSaveBizProfile(SESSION.bizId);
  }

  // Update ALL live form placeholders to match the new locale
  _applyLocaleToForms(code);

  // Sync the settings dropdown if it exists
  const curSel = document.getElementById('cur-settings-sel');
  if(curSel) curSel.value = code;

  addAudit('Currency changed', code+' ('+resolvedFlag+')');
  nav(curPage);
}

// ── Apply locale-aware placeholders to all open forms ────────────────────────
function _applyLocaleToForms(code){
  const loc = _getLocale();
  // Phone fields
  document.querySelectorAll('input[data-locale="phone"]').forEach(el => {
    el.placeholder = loc.phonePh;
  });
  // Country fields
  document.querySelectorAll('input[data-locale="country"]').forEach(el => {
    el.placeholder = loc.countryPh;
  });
  // City fields
  document.querySelectorAll('input[data-locale="city"]').forEach(el => {
    if(!el.value) el.placeholder = 'e.g. '+loc.city;
  });
  // Address fields
  document.querySelectorAll('input[data-locale="address"], textarea[data-locale="address"]').forEach(el => {
    el.placeholder = loc.addrPh;
  });
}

// ── Helper: get locale object respecting country (e.g. Belgium vs Germany for EUR) ─
function _getLocale(){
  const country = BIZ.country || '';
  if(CUR.code === 'EUR'){
    if(country === 'Belgium') return CUR_LOCALE.EUR_BE;
    if(country === 'Germany') return CUR_LOCALE.EUR_DE;
  }
  return CUR_LOCALE[CUR.code] || CUR_LOCALE.XAF;
}

// ── Helper: get locale-aware placeholder strings ─────────────────────────────
function _ph(type){
  const loc = _getLocale();
  return loc[type] || '';
}

// ── Restore currency from localStorage on boot ───────────────────────────────
function _restoreCurrency(){
  try{
    const saved = localStorage.getItem('shoptrack_currency');
    if(saved){
      const {code, flag} = JSON.parse(saved);
      if(code && code !== CUR.code){
        setCurrency(code, flag);
        return;
      }
    }
  }catch(e){}
  // Apply default locale placeholders even if no change
  _applyLocaleToForms(CUR.code);
}

function _applyTheme(theme){
  if(theme==='light'){
    document.body.classList.add('light');
  } else {
    document.body.classList.remove('light');
  }
  // Persist preference
  try{ localStorage.setItem('st_theme', theme); }catch(e){}
}
function toggleTheme(){
  const isLight = document.body.classList.contains('light');
  const next = isLight ? 'dark' : 'light';
  _applyTheme(next);
  BIZ.theme = next;
  if(SESSION.bizId && !SESSION.isSuperAdmin) _dbSaveBizProfile(SESSION.bizId);
  toast((next==='light'?'☀️ Light':'🌙 Dark')+' theme applied','success');
}
function toggleCurrencyPanel(){
  document.getElementById('cur-panel').classList.toggle('open');
  document.getElementById('np').classList.remove('open');
}

