// HELPERS
// ============================================================
const $ = id => document.getElementById(id);

// App UI formatting — currency-aware, proper separators
// Custom confirm dialog (replaces browser confirm() which is blocked in iframes)
// ── confirmDo — generic confirmation dialog ───────────────────
// Stores the callback in a closure variable — never serialises it with
// .toString() — so async functions and closures always work correctly.
// btnLabel defaults to 'Confirm'; pass a third argument to customise it
// (e.g. 'Convert', 'Delete', 'Charge', 'Suspend').
var _confirmDoCallback = null;
function confirmDo(msg, onYes, btnLabel, btnCls){
  _confirmDoCallback = onYes;
  const label = btnLabel || 'Confirm';
  const cls   = btnCls  || 'btn-p';
  const body  = `<p style="font-size:15px;color:var(--ink);margin:8px 0 4px">${msg}</p>`;
  const foot  = `<button class="btn btn-s btn-sm" onclick="closeModal()">Cancel</button>
  <button class="btn ${cls} btn-sm" onclick="closeModal();if(_confirmDoCallback){var _cb=_confirmDoCallback;_confirmDoCallback=null;_cb();}">${label}</button>`;
  modal('Confirm', body, foot);
}

// Returns local date as YYYY-MM-DD (avoids UTC offset issues with toISOString)
function localDateStr(offsetDays=0, base=null){
  const d=base?new Date(base):new Date(); d.setDate(d.getDate()+offsetDays);
  return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');
}

// ── Reliable number formatter (comma thousands separator) ────────────────
const _numFmt = n => {
  const num = Math.abs(Math.round(Number(n)));
  return (n < 0 ? '-' : '') + num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
};
// KPI display formatter — splits number from currency suffix for clean rendering
const fmtKpi = n => {
  const val = Number(n) * CUR.rate;
  switch(CUR.code){
    case 'XAF': return `<span>${_numFmt(Math.round(val))}</span><span class="kpi-cur">Frs</span>`;
    case 'NGN': return `<span>&#8358;${_numFmt(Math.round(val))}</span>`;
    case 'GBP': return `<span>&#163;${val.toLocaleString('en-GB',{minimumFractionDigits:0,maximumFractionDigits:0})}</span>`;
    case 'EUR': return `<span>&#8364;${val.toLocaleString('de-DE',{minimumFractionDigits:0,maximumFractionDigits:0})}</span>`;
    default:    return `<span>$${val.toLocaleString('en-US',{minimumFractionDigits:0,maximumFractionDigits:0})}</span>`;
  }
};

const fmt = n => {
  const val = Number(n) * CUR.rate;
  switch(CUR.code){
    case 'XAF': return _numFmt(Math.round(val)) + ' Frs';
    case 'NGN': return '\u20a6' + _numFmt(Math.round(val));
    case 'GBP': return '\u00a3' + val.toLocaleString('en-GB', {minimumFractionDigits:2,maximumFractionDigits:2});
    case 'EUR': return '\u20ac' + val.toLocaleString('de-DE', {minimumFractionDigits:2,maximumFractionDigits:2});
    default:    return '$' + val.toLocaleString('en-US', {minimumFractionDigits:2,maximumFractionDigits:2});
  }
};
// Format a value that is ALREADY in display currency (no rate multiply)
const fmtRaw = n => {
  const val = Number(n);
  switch(CUR.code){
    case 'XAF': return _numFmt(Math.round(val)) + ' Frs';
    case 'NGN': return '\u20a6' + _numFmt(Math.round(val));
    case 'GBP': return '\u00a3' + val.toLocaleString('en-GB',{minimumFractionDigits:2,maximumFractionDigits:2});
    case 'EUR': return '\u20ac' + val.toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2});
    default:   return '$' + val.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2});
  }
};


// Document formatting — same as fmt (consistent decimal handling)
const fmtDoc = n => fmt(n);
const cc = c => ({New:'c-new',Excellent:'c-exc',Good:'c-good',Fair:'c-fair',Worn:'c-worn',Damaged:'c-dmg','Under Repair':'c-rep'}[c]||'c-good');
const bx = (lbl,cls) => `<span class="bx ${cls}">${lbl}</span>`;
const badge = s => {
  const m = {Paid:'bx-g',Unpaid:'bx-r',Partial:'bx-y',Active:'bx-g',Inactive:'bx-r',Pending:'bx-y',
    Overdue:'bx-r','Checked Out':'bx-b',Reserved:'bx-p',Returned:'bx-g',Closed:'bx-n',Draft:'bx-n',
    'For Sale':'bx-b','For Rent':'bx-p',Both:'bx-c',VIP:'bx-p',Regular:'bx-b',New:'bx-g'};
  return bx(s, m[s]||'bx-n');
};
const mono = (n,col='') => `<span style="font-family:var(--mono);font-size:12px;color:${col?'var(--'+col+')':'var(--text)'}">${n}</span>`;

function toast(msg,type='info'){
  const t=document.createElement('div');
  const cols={info:'var(--a)',success:'var(--g)',error:'var(--r)',warn:'var(--y)'};
  const icos={info:'ℹ',success:'✓',error:'✕',warn:'⚠'};
  t.className='toast';
  t.style.cssText += ';z-index:99999!important;position:fixed';
  t.style.borderLeft=`3px solid ${cols[type]}`;
  t.innerHTML=`<span style="color:${cols[type]}">${icos[type]}</span><span>${msg}</span>`;
  document.body.appendChild(t);
  setTimeout(()=>{t.style.transition='opacity .3s';t.style.opacity='0';setTimeout(()=>t.remove(),300)},2800);
}

function _addInvCat(){
  var val=document.getElementById('ai-newcat-inp').value.trim();
  if(!val){toast('Enter a category name','error');return;}
  if(D.invCats.indexOf(val)===-1){
    D.invCats.push(val);
    if(SESSION.bizId&&!SESSION.isSuperAdmin) _dbSaveCategories(SESSION.bizId);
  }
  // Update hidden input and refresh searchable select
  var hidden=document.getElementById('ai-cat');
  if(hidden) hidden.value=val;
  if(document.getElementById('ai-cat-wrap')){
    _mkSearchSelect('ai-cat-wrap', D.invCats.map(function(c){return{val:c,label:c};}), val,
      function(v){ var h=document.getElementById('ai-cat'); if(h) h.value=v; }, 'Category…');
  }
  document.getElementById('ai-newcat-inp').value='';
  var row=document.getElementById('ai-newcat-row'); if(row) row.style.display='none';
  toast('✅ Category "'+val+'" added','success');
}

