function _csAddLine(){
  var row = document.createElement('div');
  row.className = 'cs-line-row';
  row.style.cssText = 'display:grid;grid-template-columns:1fr auto auto auto;gap:6px;margin-bottom:6px;align-items:center';
  var sellOpts = D.inv.filter(function(i){return (i.st==='For Sale'||i.st==='Both')&&((i.qty||0)-(i.rented||0))>0;})
    .map(function(i){return '<option value="inv:'+i.id+'" data-sp="'+Math.round((i.sp||0)*CUR.rate)+'" data-cost="'+Math.round((i.cost||0)*CUR.rate)+'" data-name="'+_esc(i.name+(i.sku?' ('+i.sku+')':''))+'">'+i.name+' ('+((i.qty||0)-(i.rented||0))+' avail) — '+fmt(i.sp)+'</option>';}).join('');
  var svcOpts = (D.services||[]).filter(function(s){return s.active!==false;})
    .map(function(s){var pt=s.priceType||'flat';var ptSfx={'per_hour':'/hr','per_min':'/min','per_day':'/day','per_week':'/wk','per_session':'/session'}[pt]||'';return '<option value="svc:'+s.id+'" data-sp="'+Math.round((s.price||0)*CUR.rate)+'" data-cost="0" data-name="'+_esc(s.name)+'">'+s.name+(s.cat?' · '+s.cat:'')+' — '+fmt(s.price)+ptSfx+'</option>';}).join('');
  row.innerHTML = '<select class="fs cs-inv-sel" onchange="_csLineChange(this);_csCheckMinSpWarn()">'
    +'<option value="">-- Select product or service --</option>'
    +(sellOpts?'<optgroup label="📦 Products">'+sellOpts+'</optgroup>':'')
    +(svcOpts?'<optgroup label="✂️ Services">'+svcOpts+'</optgroup>':'')
    +'<option value="__custom__">── Custom item ──</option></select>'
    +'<input class="fi cs-line-qty" type="number" value="1" min="1" style="width:56px;text-align:center" oninput="_csRecalcTotal()" placeholder="Qty"/>'
    +'<input class="fi cs-line-price" type="number" placeholder="Price" style="width:90px" oninput="_csRecalcTotal();_csCheckMinSpWarn()"/>'
    +'<button type="button" class="btn btn-d btn-xs" onclick="_csRemoveLine(this)" style="padding:6px 8px">✕</button>';
  var container = document.getElementById('cs-line-rows');
  if(container) container.appendChild(row);
}
function _csRemoveLine(btn){
  var row = btn.closest('.cs-line-row');
  var container = document.getElementById('cs-line-rows');
  if(container && container.querySelectorAll('.cs-line-row').length > 1) {
    row.remove(); _csRecalcTotal();
  } else {
    // Clear the last row instead of removing
    var sel = row.querySelector('.cs-inv-sel'); if(sel) sel.value='';
    var qty = row.querySelector('.cs-line-qty'); if(qty) qty.value='1';
    var price = row.querySelector('.cs-line-price'); if(price) price.value='';
    _csRecalcTotal();
  }
}
// Open New Service modal from inside the Create Sale modal,
// then on save re-open Create Sale with the new service pre-selected
function _csAddServiceInline(){
  // Store current sale state so we can restore it after service creation
  window._csSaleSnapshot = {
    custId: document.getElementById('cs-cust')?.value,
    dt:     document.getElementById('cs-dt')?.value,
    notes:  document.getElementById('cs-notes')?.value,
    items:  document.getElementById('cs-items')?.value,
  };
  closeModal();
  // Open new service modal; hook into save to re-open sale modal
  mNewService();
  // Patch _saveSvc to re-open sale after service is created
  var _origSaveSvc = window._saveSvc;
  window._saveSvc = async function(){
    await _origSaveSvc.call(this);
    window._saveSvc = _origSaveSvc; // restore
    // Re-open sale modal and pre-select the newly created service
    setTimeout(function(){
      mCreateSale();
      // Try to pre-select the newly added service in the first line row
      setTimeout(function(){
        var newSvc = D.services[D.services.length-1];
        if(!newSvc) return;
        var sel = document.querySelector('#cs-line-rows .cs-inv-sel');
        if(sel){
          // Find the option matching this service
          for(var i=0;i<sel.options.length;i++){
            if(sel.options[i].value==='svc:'+newSvc.id){ sel.selectedIndex=i; _csLineChange(sel); break; }
          }
        }
        // Restore notes/customer
        var snap = window._csSaleSnapshot||{};
        if(snap.custId){ var c=document.getElementById('cs-cust'); if(c) c.value=snap.custId; }
        if(snap.dt){ var d=document.getElementById('cs-dt'); if(d) d.value=snap.dt; }
        if(snap.notes){ var n=document.getElementById('cs-notes'); if(n) n.value=snap.notes; }
      }, 150);
    }, 200);
  };
}
function _csLineChange(sel){
  var val = sel.value;
  var row = sel.closest('.cs-line-row');
  var priceEl = row ? row.querySelector('.cs-line-price') : null;
  if(val && val.startsWith('svc:')){
    // Service item
    var svcId = val.replace('svc:','');
    var svc = D.services.find(function(x){return x.id===svcId;});
    if(svc && priceEl) priceEl.value = Math.round((svc.price||0)*CUR.rate)||'';
  } else if(val && val.startsWith('inv:')){
    // Inventory item
    var invId2 = val.replace('inv:','');
    var it = D.inv.find(function(x){return x.id===invId2;});
    if(it && priceEl) priceEl.value = Math.round((it.sp||0)*CUR.rate)||'';
  } else if(val && val !== '__custom__'){
    // Legacy plain invId (backwards compat)
    var it2 = D.inv.find(function(x){return x.id===val;});
    if(it2 && priceEl) priceEl.value = Math.round((it2.sp||0)*CUR.rate)||'';
  }
  // Update description field
  var allNames = Array.from(document.querySelectorAll('.cs-inv-sel')).map(function(s){
    var opt = s.options[s.selectedIndex];
    return opt && opt.dataset.name ? opt.dataset.name : (s.value==='__custom__'?'Custom item':'');
  }).filter(Boolean);
  var descEl = document.getElementById('cs-items');
  if(descEl && !descEl.dataset.manualEdit) descEl.value = allNames.join(' + ');
  _csRecalcTotal();
  _csCheckMinSpWarn();
}
function _csRecalcTotal(){
  // Sum all line rows
  var sp = 0;
  document.querySelectorAll('#cs-line-rows .cs-line-row').forEach(function(row){
    var qty = parseFloat(row.querySelector('.cs-line-qty')?.value)||1;
    var price = parseFloat(row.querySelector('.cs-line-price')?.value)||0;
    sp += qty * price;
  });
  // Also read legacy cs-amt if no line rows (backwards compat)
  if(!document.getElementById('cs-line-rows') || !document.querySelectorAll('#cs-line-rows .cs-line-row').length){
    sp = parseFloat(document.getElementById('cs-amt')?.value)||0;
  }
  // Update cs-amt display field
  var amtEl = document.getElementById('cs-amt'); if(amtEl) amtEl.value = sp||'';
  var fr  = parseFloat(document.getElementById('cs-freight')?.value)||0;
  var tx  = parseFloat(document.getElementById('cs-taxes')?.value)||0;
  var ot  = parseFloat(document.getElementById('cs-other')?.value)||0;
  var tot = Math.round((sp + fr + tx + ot)*100)/100;
  var el  = document.getElementById('cs-total');
  if(el) el.value = tot||'';
}
function _csCheckCostWarn(){
  var warnEl = document.getElementById('cs-cost-warn');
  if(!warnEl) return;
  var hasLinkedInv = Array.from(document.querySelectorAll('.cs-inv-sel')).some(function(s){
    return s.value && s.value !== '__custom__' && !s.value.startsWith('svc:');
  });
  var costVal = parseFloat((document.getElementById('cs-cost')||{}).value) || 0;
  warnEl.style.display = (!hasLinkedInv && costVal === 0) ? '' : 'none';
}

