function _poRemoveLine(btn){
  var row=btn.closest('.po-line-row');
  var c=document.getElementById('po-line-rows');
  if(c&&c.querySelectorAll('.po-line-row').length>1){row.remove();_poRecalcTotal();}
  else{var s=row.querySelector('.po-inv-sel');if(s)s.value='';var q=row.querySelector('.po-line-qty');if(q)q.value='1';var p=row.querySelector('.po-line-cost');if(p)p.value='';_poRecalcTotal();}
}
function _poLineChange(sel){
  var it=D.inv.find(function(x){return x.id===sel.value;});
  var row=sel.closest('.po-line-row');
  if(it&&row){var c=row.querySelector('.po-line-cost');if(c)c.value=Math.round((it.cost||0)*CUR.rate)||'';}
  var allNames=Array.from(document.querySelectorAll('.po-inv-sel')).map(function(s){
    var o=s.options[s.selectedIndex];return o&&o.dataset.name?o.dataset.name:(s.value==='__custom__'?'Custom':'');
  }).filter(Boolean);
  var d=document.getElementById('po-items');if(d)d.value=allNames.join(', ');
  _poRecalcTotal();
}
function _poRecalcTotal(){
  // Sum line rows
  var sub=0;
  document.querySelectorAll('#po-line-rows .po-line-row').forEach(function(row){
    var qty=parseFloat(row.querySelector('.po-line-qty')?.value)||1;
    var uc=parseFloat(row.querySelector('.po-line-cost')?.value)||0;
    sub+=qty*uc;
  });
  if(!document.getElementById('po-line-rows')||!document.querySelectorAll('#po-line-rows .po-line-row').length){
    var qty  = parseFloat(document.getElementById('po-qty')?.value)||1;
    var uc   = parseFloat(document.getElementById('po-unit-cost')?.value)||0;
    sub=qty*uc;
  }
  var fr   = parseFloat(document.getElementById('po-freight')?.value)||0;
  var du   = parseFloat(document.getElementById('po-duties')?.value)||0;
  var tx   = parseFloat(document.getElementById('po-taxes')?.value)||0;
  var ot   = parseFloat(document.getElementById('po-other')?.value)||0;
  var tot  = Math.round((sub + fr + du + tx + ot)*100)/100;
  var el   = document.getElementById('po-total');
  if(el) el.value = tot||'';
}

function _epRecalcTotal(){
  var sub  = parseFloat(document.getElementById('ep-sub')?.value)||0;
  var fr   = parseFloat(document.getElementById('ep-freight')?.value)||0;
  var du   = parseFloat(document.getElementById('ep-duties')?.value)||0;
  var tx   = parseFloat(document.getElementById('ep-taxes')?.value)||0;
  var ot   = parseFloat(document.getElementById('ep-other')?.value)||0;
  var tot  = Math.round((sub + fr + du + tx + ot)*100)/100;
  var el   = document.getElementById('ep-total-display');
  if(el) el.value = tot||'';
}

// ── Modal stack — nested modals return to parent ─────────────────────────
const _mStack=[];

function modal(title,body,foot='',size=''){
  const maxW=size==='xl'?'920px':size==='lg'?'740px':'600px';
  $('mc').innerHTML=`<div class="mo">
    <div class="mo-box" style="max-width:${maxW}">
      <div class="mo-hd"><h2>${title}</h2><button class="mo-x" onclick="closeModal()">✕</button></div>
      <div class="mo-body">${body}</div>
      ${foot?`<div class="mo-ft">${foot}</div>`:''}
    </div></div>`;
  // Auto-initialise any searchable select wrappers in this modal
  setTimeout(_initModalSearchSelects, 40);
}

function closeModal(){
  if(_mStack.length){
    const prev=_mStack.pop();
    $('mc').innerHTML=prev.html;
    if(prev.restore) prev.restore();
  } else {
    $('mc').innerHTML='';
  }
}

function _mPush(selectId){
  _mStack.push({html:$('mc').innerHTML, selectId:selectId||null, restore:null});
}

function _mPopAndSelect(selectId,newId,newLabel){
  if(!_mStack.length){$('mc').innerHTML='';return;}
  const prev=_mStack.pop();
  $('mc').innerHTML=prev.html;
  if(prev.restore) prev.restore();
  const sid=selectId||prev.selectId;
  if(sid){
    const sel=document.getElementById(sid);
    if(sel){
      if(!sel.querySelector('option[value="'+newId+'"]')){
        const opt=document.createElement('option');
        opt.value=newId;opt.textContent=newLabel;sel.appendChild(opt);
      }
      sel.value=newId;
      sel.dispatchEvent(new Event('change'));
    }
  }
}

