// Pages Super Admin may visit — everything else is off-limits (privacy wall)
const ADMIN_ONLY_PAGES = new Set(['admin-biz','admin-users','admin-analytics','admin-affiliates']);
let _navUserTriggered = false; // true only on explicit user clicks, not bootApp restores
const BIZ_ONLY_PAGES   = new Set(['dashboard','inventory','sales','rentals','purchases','customers','vendors','expenses','accounting','reports','catalog','ai-studio','auditlog','settings','appointments','services']);

// Pages that require a plan to have been chosen before entry
const PLAN_GATE_PAGES = new Set([
  'dashboard','inventory','sales','rentals','purchases','customers',
  'vendors','expenses','accounting','reports','catalog','ai-studio',
  'auditlog','appointments','services'
]);

// Returns true when the business has an active paid/trial plan set
function _hasPlan(){
  if(SESSION.isSuperAdmin) return true;
  // Demo businesses always pass
  if(SESSION.bizId==='BIZ-001'||SESSION.bizId==='BIZ-107') return true;
  // If BIZ data is still loading (name empty), don't gate — wait for DB
  if(!BIZ.name && SESSION.bizId) return true;
  const p = (BIZ.plan||'').toLowerCase().trim();
  // Empty plan = SA provisioned but hasn't set plan yet → allow access
  if(!p) return true;
  // Accept all known plan names including trial variants
  return p==='starter'||p==='pro'||p==='professional'||p==='enterprise'
      || p==='free trial'||p==='trial (30 days)'||p.includes('trial')
      || p==='active'; // legacy status-as-plan
}

// Public nav — called from UI elements (sidebar, buttons)
// Sets _navUserTriggered so error toasts show on explicit navigation
function navTo(p){ _navUserTriggered = true; nav(p); }

function nav(p){
  // ══ IDENTITY WALL — cannot be bypassed ══════════════════════
  // Rule 1: SA can NEVER access business data pages
  if(SESSION.isSuperAdmin && BIZ_ONLY_PAGES.has(p)){
    if(SESSION.bizId && SESSION.bizId !== 'BIZ-001'){
      // Self-healing: corrupted SA+bizId session — nuke and re-evaluate
      console.warn('[SECURITY] SA+bizId corruption — clearing session');
      try{ localStorage.removeItem('st_session'); sessionStorage.removeItem('st_session'); }catch(_e){}
      SESSION.isSuperAdmin = false;
  _updateMobileNav(); SESSION.bizId = null;
    } else {
      p = 'admin-biz'; // genuine SA → redirect to SA home silently
    }
  }
  // Rule 2: Business users can NEVER access SA platform pages — no toast during boot
  if(!SESSION.isSuperAdmin && ADMIN_ONLY_PAGES.has(p)){
    if(_navUserTriggered) toast('Platform Admin access required','error');
    p = 'dashboard';
  }
  // Rule 3: Plan gate
  if(!SESSION.isSuperAdmin && PLAN_GATE_PAGES.has(p) && !_hasPlan()){
    _showPlanSelectionModal(); return;
  }
  curPage=p;
  document.querySelectorAll('.sb-item').forEach(el=>el.classList.toggle('on',el.dataset.p===p));
  _navUserTriggered = false;
  $('np').classList.remove('open');
  $('page').innerHTML='';
  destroyCharts();
  const fn=window[pageMap[p]];
  if(typeof fn==='function'){$('page').innerHTML=fn();var _pg=document.getElementById('page');if(_pg)_pg.scrollTop=0;}
  afterRender(p);
  setTimeout(_autoSizeKpis, 50);
  // sync bottom nav bar
  const bnMap={dashboard:'bn-dashboard',inventory:'bn-inventory',sales:'bn-sales',rentals:'bn-rentals'};
  document.querySelectorAll('.bni').forEach(el=>el.classList.remove('on'));
  const mapped=bnMap[p];
  const bnEl=document.getElementById(mapped||'bn-more');
  if(bnEl)bnEl.classList.add('on');
  closeDrawer();
  if(!SESSION.isSuperAdmin&&SESSION.bizId) _track('Page View',{page:p});
}

// ── Mobile nav: show SA or BIZ items depending on who is logged in ───────────
function _updateMobileNav(){
  var isSA = !!(SESSION && SESSION.isSuperAdmin);
  // Toggle biz items
  document.querySelectorAll('.bni-biz').forEach(function(el){
    el.style.display = isSA ? 'none' : '';
  });
  // Toggle SA items
  document.querySelectorAll('.bni-sa').forEach(function(el){
    el.style.display = isSA ? '' : 'none';
  });
  // Update drawer biz items too
  document.querySelectorAll('.dr-biz-item').forEach(function(el){
    el.style.display = isSA ? 'none' : '';
  });
  // Show/hide SA drawer items
  document.querySelectorAll('.dr-sa-item').forEach(function(el){
    el.style.display = isSA ? '' : 'none';
  });
}

document.querySelectorAll('.sb-item').forEach(el=>el.addEventListener('click',()=>nav(el.dataset.p)));
document.addEventListener('click',e=>{
  const _np=$('np'); if(_np&&!e.target.closest('#np')&&!e.target.closest('.tb-btn'))_np.classList.remove('open');
  const _cp=$('cur-panel'); if(_cp&&!e.target.closest('#cur-panel')&&!e.target.closest('#cur-pill'))_cp.classList.remove('open');
});

let _charts=[];
function destroyCharts(){_charts.forEach(c=>{try{c.destroy()}catch(e){}});_charts=[];}
function mkChart(id,cfg){const el=$(id);if(!el)return;if(typeof Chart==='undefined'){el.parentElement.innerHTML='<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text2);font-size:12px">Chart unavailable offline</div>';return;}const c=new Chart(el,cfg);_charts.push(c);return c;}

// _co() must be called fresh each render — never cached at parse time,
// because the theme class is applied in bootApp() which runs after this file is parsed.
function _co(){ var _lt=document.body.classList.contains('light'),_tc=_lt?'#374151':'#c8cee8',_gc=_lt?'rgba(0,0,0,.06)':'rgba(255,255,255,.06)'; return {plugins:{legend:{labels:{color:_tc,font:{size:10.5},boxWidth:10,padding:12}}},scales:{x:{ticks:{color:_tc,font:{size:11}},grid:{color:_gc}},y:{ticks:{color:_tc,font:{size:11},callback:function(v){return fmtRaw(v);}},grid:{color:_gc}}}}; }
// co is a live getter — always reads the current theme at the moment charts are built
const co = new Proxy({}, { get(_,k){ return _co()[k]; } });

// ── Recurring expense reminder ─────────────────────────────────────────
// Checks once per session if any recurring expense hasn't been recorded this month
function _checkRecurringExpenses(){
  if(SESSION.isSuperAdmin||!D.exp||!D.exp.length) return;
  var _sesKey='st_rec_exp_check_'+localDateStr().slice(0,7); // monthly key
  try{ if(sessionStorage.getItem(_sesKey)) return; }catch(e){}
  var thisMonth=localDateStr().slice(0,7); // YYYY-MM
  var recurringTypes=D.exp.filter(function(e){ return e.type==='Recurring'; });
  if(!recurringTypes.length) return;
  // Group by category+payee to find unique recurring lines
  var _recMap={};
  recurringTypes.forEach(function(e){
    var key=(e.cat||'')+'|'+(e.payee||e.desc||'');
    if(!_recMap[key]) _recMap[key]={cat:e.cat,payee:e.payee||e.desc||'',amt:e.amt,lastDt:e.dt};
    else if(e.dt>_recMap[key].lastDt) _recMap[key]={cat:e.cat,payee:e.payee||e.desc||'',amt:e.amt,lastDt:e.dt};
  });
  // Find which ones haven't been recorded this month
  var _due=Object.values(_recMap).filter(function(r){
    return r.lastDt && r.lastDt.slice(0,7)<thisMonth;
  });
  if(!_due.length) return;
  try{ sessionStorage.setItem(_sesKey,'1'); }catch(e){}
  // Show banner in dashboard
  var banner=document.createElement('div');
  banner.id='rec-exp-banner';
  banner.style.cssText='background:rgba(245,158,11,.12);border:1px solid rgba(245,158,11,.3);border-radius:var(--r8);padding:12px 16px;margin-bottom:14px;display:flex;align-items:flex-start;gap:12px;cursor:pointer';
  var items=_due.slice(0,4).map(function(r){ return '<strong>'+_esc(r.cat)+(r.payee?' — '+_esc(r.payee):'')+' ('+fmt(r.amt)+')</strong>'; }).join(', ');
  var more=_due.length>4?' and '+ (_due.length-4)+' more':'';
  banner.innerHTML='<span style="font-size:22px;flex-shrink:0">🔁</span>'
    +'<div><div style="font-size:13px;font-weight:700;color:var(--y);margin-bottom:3px">Recurring expenses may be due this month</div>'
    +'<div style="font-size:12px;color:var(--text2)">'+items+more+'</div>'
    +'<div style="font-size:11px;color:var(--a);margin-top:6px;font-weight:600">Tap to record → Expenses</div></div>';
  banner.onclick=function(){ nav('expenses'); document.getElementById('rec-exp-banner')?.remove(); };
  var pg=document.getElementById('page');
  if(pg&&pg.firstChild) pg.insertBefore(banner,pg.firstChild);
}


// ── Upcoming birthdays widget ──────────────────────────────────────────
function _checkUpcomingBirthdays(){
  if(SESSION.isSuperAdmin) return;
  var today = localDateStr();
  var mm = today.slice(5,7);
  var dd = today.slice(8,10);
  // Check birthdays in next 7 days (same month for simplicity)
  var upcoming = (D.cust||[]).filter(function(c){
    if(!c.dob) return false;
    var bMM = c.dob.slice(5,7);
    var bDD = c.dob.slice(8,10);
    if(bMM !== mm) return false;
    var diff = parseInt(bDD,10) - parseInt(dd,10);
    return diff >= 0 && diff <= 7;
  }).sort(function(a,b){
    return parseInt(a.dob.slice(8,10),10) - parseInt(b.dob.slice(8,10),10);
  });
  if(!upcoming.length) return;
  // Remove existing widget if re-navigated
  var existing = document.getElementById('birthday-widget');
  if(existing) existing.remove();
  var widget = document.createElement('div');
  widget.id = 'birthday-widget';
  widget.style.cssText = 'background:rgba(168,85,247,.1);border:1px solid rgba(168,85,247,.3);border-radius:var(--r8);padding:12px 16px;margin-bottom:14px';
  var items = upcoming.map(function(cu){
    var bDD = parseInt(cu.dob.slice(8,10),10);
    var todDD = parseInt(dd,10);
    var daysLeft = bDD - todDD;
    var when = daysLeft===0?'Today 🎂':daysLeft===1?'Tomorrow':('In '+daysLeft+' days');
    var waBtn = (cu.phone||cu.whatsapp)
      ? '<button class="btn btn-g btn-xs" onclick="_sendBirthdayWA(\'' + cu.id + '\')" style="margin-left:8px">💬 WA</button>'
      : '';
    return '<div style="display:flex;align-items:center;justify-content:space-between;padding:4px 0;border-bottom:1px solid rgba(168,85,247,.15)">'
      +'<div><strong style="font-size:13px;color:var(--ink)">'+_esc(cu.name)+'</strong>'
      +'<span style="font-size:11px;color:var(--text2);margin-left:8px">'+when+'</span></div>'
      +'<div>'+waBtn+'</div></div>';
  }).join('');
  widget.innerHTML = '<div style="font-size:12px;font-weight:700;color:rgba(168,85,247,1);margin-bottom:8px">🎂 Upcoming Birthdays</div>'+items;
  var pg = document.getElementById('page');
  // Insert after recurring expense banner if present, else at top
  var recBanner = document.getElementById('rec-exp-banner');
  if(recBanner && recBanner.nextSibling) pg.insertBefore(widget, recBanner.nextSibling);
  else if(pg && pg.firstChild) pg.insertBefore(widget, pg.firstChild);
}

function _sendBirthdayWA(custId){
  var cu = D.cust.find(function(x){return x.id===custId;});
  if(!cu) return;
  var ph = (cu.whatsapp||cu.phone||'').replace(/\D/g,'');
  if(!ph){ toast('No phone number on file','error'); return; }
  var msg = 'Happy Birthday '+cu.name+'! 🎂\n\nWishing you a wonderful day from all of us at '+(BIZ.name||'ShopTrack')+'!';
  window.open('https://wa.me/'+ph+'?text='+encodeURIComponent(msg),'_blank');
}


// ── Bulk AR collection ─────────────────────────────────────────────────
function _arBulkCollect(){
  var debtors = D.cust.filter(function(cu){return cu.bal>0;}).sort(function(a,b){return b.bal-a.bal;});
  if(!debtors.length){ toast('No outstanding balances ✓','success'); return; }
  var today = localDateStr();
  var rows = debtors.map(function(cu){
    var unpaidSales = D.sales.filter(function(s){return (s.custId===cu.id||s.cust===cu.name)&&s.st!=='Paid';});
    return '<div style="display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:1px solid var(--border)">'
      +'<input type="checkbox" class="bc-chk" data-id="'+cu.id+'" data-bal="'+cu.bal+'" checked style="width:16px;height:16px;accent-color:var(--a);flex-shrink:0"/>'
      +'<div style="flex:1"><strong style="color:var(--ink)">'+_esc(cu.name)+'</strong>'
      +'<div style="font-size:11px;color:var(--text2)">'+unpaidSales.length+' invoice'+(unpaidSales.length!==1?'s':'')+' unpaid</div></div>'
      +'<div style="font-family:var(--mono);font-weight:700;color:var(--r)">'+fmt(cu.bal)+'</div>'
      +'<input type="number" class="fi bc-amt" data-id="'+cu.id+'" value="'+Math.round(cu.bal*CUR.rate)+'" step="any" style="width:90px;font-size:12px" placeholder="Amount"/>'
      +'</div>';
  }).join('');
  modal('💰 Collect Outstanding Balances',
    '<div style="font-size:12px;color:var(--text2);margin-bottom:12px">Check off customers you&#39;ve collected from. Amounts are pre-filled with full balance &#x2014; edit if partial.</div>'
    +'<div style="max-height:360px;overflow-y:auto">'+rows+'</div>'
    +'<div style="margin-top:12px;padding:10px;background:var(--bg3);border-radius:var(--r8)">'
    +'<div style="display:flex;justify-content:space-between"><span style="font-size:12px;color:var(--text2)">Selected total</span>'
    +'<strong id="bc-total-display" style="font-family:var(--mono);color:var(--g)">'+fmt(debtors.reduce(function(a,cu){return a+cu.bal;},0))+'</strong></div></div>',
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +'<button class="btn btn-p" onclick="_arBulkCollectSave(\'' + today + '\')" >✅ Record Payments</button>'
  );
  // Update total on check/amount change
  setTimeout(function(){
    function _bcUpdate(){
      var total=0;
      document.querySelectorAll('.bc-chk:checked').forEach(function(chk){
        var amtEl=document.querySelector('.bc-amt[data-id="'+chk.dataset.id+'"]');
        total+=(parseFloat(amtEl&&amtEl.value)||0)/CUR.rate;
      });
      var disp=document.getElementById('bc-total-display');
      if(disp) disp.textContent=fmt(total);
    }
    document.querySelectorAll('.bc-chk,.bc-amt').forEach(function(el){
      el.addEventListener('input',_bcUpdate); el.addEventListener('change',_bcUpdate);
    });
  },50);
}

function _arBulkCollectSave(dt){
  var today = dt||localDateStr();
  var collected = 0;
  document.querySelectorAll('.bc-chk:checked').forEach(function(chk){
    var custId = chk.dataset.id;
    var amtEl = document.querySelector('.bc-amt[data-id="'+custId+'"]');
    var amtFrs = parseFloat(amtEl&&amtEl.value)||0;
    if(amtFrs<=0) return;
    var amt = amtFrs/CUR.rate;
    var cu = D.cust.find(function(x){return x.id===custId;});
    if(!cu) return;
    // Apply payment to oldest unpaid sales first
    var unpaid = D.sales.filter(function(s){return (s.custId===cu.id||s.cust===cu.name)&&s.st!=='Paid';})
      .sort(function(a,b){return a.dt<b.dt?-1:1;});
    var remaining = amt;
    unpaid.forEach(function(s){
      if(remaining<=0) return;
      var due=(s.total||s.amt)-s.paid;
      var paying=Math.min(due,remaining);
      s.paid+=paying;
      s.st=s.paid>=(s.total||s.amt)?'Paid':s.paid>0?'Partial':'Unpaid';
      remaining-=paying;
      _dbSaveSale(s);
    });
    // Update customer balance
    cu.bal=Math.max(0,(cu.bal||0)-amt);
    cu.spent=(cu.spent||0)+amt;
    cu.spend=cu.spent;
    _dbSaveCust(cu);
    addAudit('Bulk payment collected',custId+' — '+fmt(amt));
    collected++;
  });
  closeModal();
  refreshLiveKpis();
  if(collected>0) toast('✅ '+collected+' payment'+(collected!==1?'s':'')+' recorded','success');
  else toast('No payments selected','info');
  if(typeof pgCust==='function'&&curPage==='customers') nav('customers');
}


function afterRender(p){
  if(p==='dashboard'){ initDash(); setTimeout(_checkRecurringExpenses, 1500); setTimeout(_checkUpcomingBirthdays, 1800); }
  if(p==='accounting') initAccounting();
  if(p==='reports') initReports();
  if(p==='admin-analytics') initAdminAnalytics();
  if(p==='admin-affiliates') _initAffiliatesPage();
  if(SESSION.isSuperAdmin) _updateAffBadge();
  if(p==='appointments') initAppointments();
  if(p==='sales')     setTimeout(_salesFilterInit,   20);
  if(p==='rentals')   setTimeout(_rentalsFilterInit,  20);
  if(p==='expenses')  setTimeout(_expFilterInit,      20);
  if(p==='purchases') setTimeout(_poFilterInit,       20);
  if(p==='customers') setTimeout(function(){ filterCustTable(); }, 20);
  if(p==='vendors')   setTimeout(function(){ filterVendTable(); }, 20);
  if(p==='ai-studio') setTimeout(_aiLoadHistory, 60);
  // Always apply locale to any forms on the new page
  setTimeout(()=>_applyLocaleToForms(CUR.code), 30);
  // Show currency preview in financial settings
  if(p==='settings') setTimeout(()=>_updateCurPreview(CUR.code), 60);
}


