function _buildTopProducts(range){
  var periodSales = range ? D.sales.filter(function(s){return inRange(s.dt,range);}) : D.sales;
  var revenueMap = {}; // invId → {rev, count, inv}

  periodSales.forEach(function(s){
    var rev = s.total||s.amt||0;
    // Strategy 1: use stored invId if valid
    if(s.invId && s.invId!=='__custom__' && s.invId!=='__deleted__' && s.invId!=='__none__'){
      if(!revenueMap[s.invId]) revenueMap[s.invId]={rev:0,count:0,invId:s.invId,inv:D.inv.find(function(x){return x.id===s.invId;})};
      revenueMap[s.invId].rev += rev;
      revenueMap[s.invId].count += 1;
    } else {
      // Strategy 2: match inventory items by name in the items string
      // For multi-item sales, split by comma and match each part
      var itemStr = (s.items||'').toLowerCase();
      var matched = false;
      D.inv.forEach(function(inv){
        var invWord = inv.name.split(' ')[0].toLowerCase();
        if(invWord.length > 2 && itemStr.indexOf(invWord) >= 0){
          if(!revenueMap[inv.id]) revenueMap[inv.id]={rev:0,count:0,invId:inv.id,inv:inv};
          // Distribute revenue evenly if multiple items
          var itemCount = (s.items||'').split(',').length || 1;
          revenueMap[inv.id].rev += rev / itemCount;
          revenueMap[inv.id].count += 1;
          matched = true;
        }
      });
      // Strategy 3: no match — show as generic sale in "Other Products"
      if(!matched && rev > 0){
        var k = '__other__';
        if(!revenueMap[k]) revenueMap[k]={rev:0,count:0,invId:'__other__',inv:null,label:s.items||'Direct Sales'};
        revenueMap[k].rev += rev;
        revenueMap[k].count += 1;
      }
    }
  });

  var ranked = Object.values(revenueMap)
    .filter(function(r){ return r.rev > 0; })
    .sort(function(a,b){ return b.rev - a.rev; })
    .slice(0,5);

  if(!ranked.length){
    return '<div style="text-align:center;padding:16px;color:var(--text3);font-size:13px">No sales in this period</div>';
  }

  var maxRev = ranked[0].rev || 1;
  var rankColors = ['var(--y)','var(--text2)','var(--o)','var(--text3)','var(--text3)'];
  return ranked.map(function(r, i){
    var rankNum = i + 1;
    var pct = Math.round(r.rev / maxRev * 100);
    var it = r.inv;
    var name = it ? it.name : (r.label||'Direct Sales');
    var cat  = it ? it.cat  : 'Sales';
    var photo = it && (it.photoDataUrls&&it.photoDataUrls.length)
      ? '<img loading="lazy" src="'+it.photoDataUrls[0]+'" style="width:100%;height:100%;object-fit:cover"/>'
      : (it ? itemPhoto(it.img||'gown-aline', it.imgC&&it.imgC[0], it.imgC&&it.imgC[1], it.imgC&&it.imgC[2])
            : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:20px">🛒</div>');
    var clickable = r.invId && r.invId!=='__other__';
    return '<div style="display:flex;align-items:center;gap:12px;padding:9px 0;border-bottom:1px solid var(--border);'+(clickable?'cursor:pointer':'')+'" '
      +(clickable ? 'data-inv-id="'+r.invId+'" onclick="_showProductSales(this.dataset.invId)" title="View all sales"' : '')
      +'>'
      +'<div style="width:20px;text-align:center;font-size:11px;font-weight:800;color:'+rankColors[i]+';flex-shrink:0">#'+rankNum+'</div>'
      +'<div style="width:40px;height:40px;background:var(--bg4);border-radius:8px;overflow:hidden;flex-shrink:0;border:1px solid var(--border)">'+photo+'</div>'
      +'<div style="flex:1;min-width:0">'
        +'<div style="font-size:13px;font-weight:600;color:var(--ink);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+_esc(name)+'</div>'
        +'<div style="font-size:10px;color:var(--text2);margin-top:1px">'+_esc(cat)+' &middot; '+r.count+' sale'+(r.count!==1?'s':'')+'</div>'
        +'<div style="height:3px;background:var(--border);border-radius:2px;margin-top:5px;overflow:hidden">'
          +'<div style="height:100%;width:'+pct+'%;background:var(--g);border-radius:2px;transition:width .4s ease"></div>'
        +'</div>'
      +'</div>'
      +'<div style="text-align:right;flex-shrink:0">'
        +'<div style="font-family:var(--mono);font-size:13px;font-weight:700;color:var(--g)">'+fmt(r.rev)+'</div>'
        +'<div style="font-size:10px;color:var(--text3);margin-top:1px">revenue</div>'
      +'</div>'
      +'</div>';
  }).join('');
}

function _showProductSales(invId){
  var inv = D.inv.find(function(x){return x.id===invId;});
  if(!inv){ toast('Product not found','error'); return; }
  var range = PERIOD_RANGES[_dashPeriod];
  var sales = D.sales.filter(function(s){
    return s.invId===invId && (!range||inRange(s.dt,range));
  }).sort(function(a,b){ return b.dt>a.dt?1:-1; });

  var photoHtml = (inv.photoDataUrls&&inv.photoDataUrls.length)
    ? '<img loading="lazy" src="'+inv.photoDataUrls[0]+'" style="height:52px;width:52px;object-fit:cover;border-radius:8px"/>'
    : '<div style="height:52px;width:52px;border-radius:8px;overflow:hidden;flex-shrink:0">'+itemPhoto(inv.img||'gown-aline',inv.imgC?.[0],inv.imgC?.[1],inv.imgC?.[2])+'</div>';

  var totalRev = sales.reduce(function(a,s){return a+(s.total||s.amt||0);},0);
  var rows = sales.length ? sales.map(function(s){
    return '<tr style="cursor:pointer" data-sid="'+s.id+'" onclick="mInvoice(this.dataset.sid)" title="View invoice">'
      +'<td>'+mono(s.id,'a')+'</td>'
      +'<td><strong>'+_esc(s.cust)+'</strong></td>'
      +'<td style="font-family:var(--mono);font-size:12px">'+s.dt+'</td>'
      +'<td style="font-family:var(--mono);font-size:12px;font-weight:600;color:var(--g)">'+fmt(s.total||s.amt)+'</td>'
      +'<td>'+badge(s.st)+'</td>'
      +'</tr>';
  }).join('') : '<tr><td colspan="5" style="text-align:center;color:var(--text3);padding:14px">No sales in this period</td></tr>';

  modal(_esc(inv.name)+' — Sales',
    '<div style="display:flex;align-items:center;gap:14px;margin-bottom:16px;padding-bottom:14px;border-bottom:1px solid var(--border)">'
      +photoHtml
      +'<div>'
        +'<div style="font-size:11px;color:var(--text2)">'+_esc(inv.cat)+' &middot; '+_esc(inv.sku)+'</div>'
        +'<div style="font-size:22px;font-weight:800;color:var(--g);font-family:var(--mono)">'+fmt(totalRev)+'</div>'
        +'<div style="font-size:11px;color:var(--text2)">'+sales.length+' sale'+(sales.length!==1?'s':'')+' &middot; '+PERIOD_RANGES[_dashPeriod].label+'</div>'
      +'</div>'
    +'</div>'
    +'<div class="tbl-wrap"><table><thead><tr><th>Sale ID</th><th>Customer</th><th>Date</th><th>Revenue</th><th>Status</th></tr></thead>'
    +'<tbody>'+rows+'</tbody></table></div>',
    '<button class="btn btn-s" onclick="closeModal()">Close</button>'
    +'<button class="btn btn-p btn-sm" id="go-inv-btn-sp">View Item</button>');
  setTimeout(function(){ var b=document.getElementById('go-inv-btn-sp'); if(b) b.onclick=function(){closeModal();nav('inventory');}; },30);
}

