// Subscription plan prices in XAF (mirrors BILLING_PLANS in campay-billing.js)
// Stripe publishable key (USD payments for USA businesses)
const STRIPE_PK = 'pk_live_51TIU2aDJ710ezCR6Y4mNk05q3LXt9UaEUAWLK9Y6QKiQnL06YK3n6N6BMQH7yGk2yXDRAW8cfjGVyiSMb7oPTo5Y00N8MV6QB0';

// Plan prices in USD (cents) for Stripe checkout
const SUB_PLAN_USD = {
  Free:              { monthly: 0,    yearly: 0     },
  Premium:           { monthly: 8900, yearly: 89000 },
  'Trial (30 Days)': { monthly: 0,    yearly: 0     },
};

const SUB_PLAN_XAF = {
  'Free':          { monthly: 0,     yearly: 0      },
  'Premium':       { monthly: 8900,  yearly: 89000  },
  
  
  'Demo Test':    { monthly: 10,    yearly: 10     }, // CamPay demo only — max 25 XAF
  'Trial (30 Days)': { monthly: 0,  yearly: 0      },
};

function _subDaysLeft(){
  if(!BIZ.subExpires) return null;
  const now  = new Date(); now.setHours(0,0,0,0);
  const then = new Date(BIZ.subExpires+'T00:00:00');
  return Math.round((then - now) / 86400000);
}

function _subAmtXAF(){
  const p = SUB_PLAN_XAF[BIZ.plan||'Free'] || SUB_PLAN_XAF['Free'];
  return (BIZ.billingCycle||'monthly') === 'yearly' ? p.yearly : p.monthly;
}

// Returns HTML for the dashboard banner — empty string when nothing to show
function _subExpiryBanner(){
  if(SESSION.isSuperAdmin) return '';
  const d = _subDaysLeft();
  if(d === null) return '';
  // Only show banner when ≤5 days remain OR already expired
  if(d > 5) return '';

  const amt    = _subAmtXAF();
  const plan   = BIZ.plan || 'Free';
  const expiry = BIZ.subExpires || '';
  const isFree = amt === 0;

  let bg, border, icon, msg;
  if(d < 0){
    bg = 'rgba(239,68,68,.08)'; border = 'var(--r)'; icon = '🚨';
    msg = '<strong>Your ShopTrack subscription has expired.</strong> Renew now to keep full access.';
  } else if(d === 0){
    bg = 'rgba(239,68,68,.08)'; border = 'var(--r)'; icon = '🚨';
    msg = '<strong>Your subscription expires today.</strong> Renew now to avoid interruption.';
  } else if(d <= 2){
    bg = 'rgba(245,200,66,.08)'; border = 'var(--y)'; icon = '⚠️';
    msg = '<strong>Your subscription expires in '+d+' day'+(d>1?'s':'')+' ('+expiry+').</strong> Renew now to stay uninterrupted.';
  } else {
    bg = 'rgba(14,165,233,.08)'; border = 'var(--b)'; icon = '📅';
    msg = 'Your <strong>'+plan+' plan</strong> expires in <strong>'+d+' days</strong> on '+expiry+'.';
  }

  if(isFree){
    // Trial — no Pay Now, just a notice
    return '<div style="display:flex;align-items:center;gap:12px;padding:12px 16px;background:'+bg+';border:1px solid '+border+';border-radius:var(--r8);margin-bottom:14px">'
      +'<span style="font-size:20px">'+icon+'</span>'
      +'<div style="flex:1;font-size:13px;color:var(--ink)">'+msg+'</div>'
      +'<button class="btn btn-p btn-sm" onclick="mChangePlan()">⬆ Upgrade Plan</button>'
      +'<button class="btn btn-s btn-sm" onclick="nav(\'settings\')">View Plans</button>'
      +'</div>';
  }

  return '<div style="display:flex;align-items:center;gap:12px;padding:12px 16px;background:'+bg+';border:1px solid '+border+';border-left:4px solid '+border+';border-radius:var(--r8);margin-bottom:14px">'
    +'<span style="font-size:20px">'+icon+'</span>'
    +'<div style="flex:1;min-width:0">'
      +'<div style="font-size:13px;color:var(--ink)">'+msg+'</div>'
      +(CUR.code==='USD'
        ? '<div style="font-size:11px;color:var(--text2);margin-top:2px">Amount due: <strong style="font-family:var(--mono);color:var(--ink)">$'+(((SUB_PLAN_USD[BIZ.plan||'Free']||SUB_PLAN_USD.Free)[(BIZ.billingCycle==='yearly'?'yearly':'monthly')])/100).toFixed(2)+' USD</strong> · Secure card payment via Stripe</div>'
        : '<div style="font-size:11px;color:var(--text2);margin-top:2px">Amount due: <strong style="font-family:var(--mono);color:var(--ink)">'+amt.toLocaleString()+' XAF</strong> · Payment via Mobile Money (MTN or Orange)</div>'
      )
    +'</div>'
    +'<button class="btn btn-p btn-sm" style="flex-shrink:0;white-space:nowrap" onclick="mSubPayNow()">💳 Pay Now</button>'
    +'</div>';
}

