function _pgSelectPlan(planId){
  var colors = {Free:'45,212,160', Premium:'91,127,255'};
  var borders = {Free:'#2dd4a0', Premium:'#5b7fff'};
  document.querySelectorAll('[id^="pgc-"]').forEach(function(c){
    c.style.border='2px solid var(--border2)';
    c.style.background='var(--bg3)';
  });
  var card = document.getElementById('pgc-'+planId);
  if(card){
    card.style.border='2px solid '+(borders[planId]||'var(--a)');
    card.style.background='rgba('+(colors[planId]||'99,102,241')+',.09)';
  }
  var sel = document.getElementById('pg-selected-plan');
  if(sel) sel.value=planId;
  var btn = document.getElementById('pg-confirm-btn');
  if(btn) btn.disabled=false;
}

async function _pgConfirmPlan(){
  var planId = (document.getElementById('pg-selected-plan')||{}).value||'';
  if(!planId){ toast('Please select a plan first','error'); return; }
  var btn = document.getElementById('pg-confirm-btn');
  if(btn){ btn.textContent='Saving\u2026'; btn.disabled=true; }
  try{
    if(_sb && SESSION.bizId && SESSION.bizId!=='BIZ-001' && SESSION.bizId!=='BIZ-107'){
      const {error} = await _sb.from('businesses').update({plan:planId}).eq('id',SESSION.bizId);
      if(error) throw new Error(error.message);
    }
    BIZ.plan = planId;
    addAudit('Plan selected',planId+' chosen during onboarding');
    closeModal();
    toast('\u2705 '+planId+' plan activated \u2014 your 30-day free trial has started!','success');
    nav('dashboard');
  } catch(e){
    toast('Could not save plan \u2014 '+e.message,'error');
    if(btn){ btn.textContent='\u25b6 Start Free Trial'; btn.disabled=false; }
  }
}

// Returns true if business uses USD (routes to Stripe instead of CamPay)
function _isUSD(){ return CUR.code==='USD'; }

// Stripe payment flow for USD businesses
async function mSubPayNowStripe(){
  var isTrial3=(BIZ.plan||''  ).toLowerCase().includes('trial')||(BIZ.plan||'')=='Free Trial';
  var plan=isTrial3?'Free':(BIZ.plan||'Free');
  var planKey=plan==='Pro'?'Professional':plan;
  var cycle=BIZ.billingCycle==='yearly'?'yearly':'monthly';
  var expiry=BIZ.subExpires||BIZ.trialEnd||'';
  var base=expiry&&expiry>=localDateStr()?expiry:localDateStr();
  var d2=new Date(base+'T00:00:00');
  if(cycle==='yearly')d2.setFullYear(d2.getFullYear()+1); else d2.setMonth(d2.getMonth()+1);
  var newExpiry=d2.toISOString().slice(0,10);
  var prices=SUB_PLAN_USD[planKey]||SUB_PLAN_USD.Free;
  var amtCents=prices[cycle];
  var amtUSD=(amtCents/100).toFixed(2);

  // Show confirmation modal before redirecting to Stripe
  modal('\uD83D\uDCB3 Pay with Card',
    '<div style="background:var(--bg3);border-radius:var(--r8);padding:14px;margin-bottom:16px;display:flex;flex-direction:column;gap:9px;font-size:13px">'
    +'<div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Plan</span>'+bx(planKey,'bx-b')+'</div>'
    +'<div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Billing</span><span>'+( cycle==='yearly'?'Annual':'Monthly')+'</span></div>'
    +'<div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Renews until</span><strong style="font-family:var(--mono);color:var(--g)">'+newExpiry+'</strong></div>'
    +'<div style="border-top:1px solid var(--border);padding-top:9px;display:flex;justify-content:space-between;align-items:center">'
    +'<span style="color:var(--text2)">Amount</span>'
    +'<strong style="font-size:20px;font-family:var(--mono);color:var(--g)">$'+amtUSD+' USD</strong></div></div>'
    +'<div class="alrt alrt-b">\uD83D\uDD12 Secure card payment via Stripe. You will be redirected to a Stripe checkout page. After payment, your account activates automatically.</div>',
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +'<button class="btn btn-p" id="stripe-pay-btn" onclick="_doStripeCheckout(\''+(planKey)+'\',\''+(cycle)+'\',\''+(newExpiry)+'\')">\uD83D\uDD12 Pay $'+amtUSD+' USD \u2192 Stripe</button>'
  );
}

async function _doStripeCheckout(plan,cycle,newExpiry){
  var btn=document.getElementById('stripe-pay-btn');
  if(btn){btn.disabled=true;btn.textContent='Preparing checkout\u2026';}
  try{
    var resp=await fetch('/.netlify/functions/stripe-checkout',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({
        bizId:SESSION.bizId,plan,billingCycle:cycle,newExpiry,
        email:BIZ.email||SESSION.email||'',
        bizName:BIZ.name||''
      })
    });
    var data=await resp.json();
    if(data.url){
      window.location.href=data.url;
    } else {
      toast('Stripe checkout failed: '+(data.error||'unknown error'),'error');
      if(btn){btn.disabled=false;btn.textContent='\uD83D\uDD12 Pay via Stripe';}
    }
  }catch(e){
    toast('Checkout error: '+e.message,'error');
    if(btn){btn.disabled=false;btn.textContent='\uD83D\uDD12 Pay via Stripe';}
  }
}

function mSubPayNow(){
  // USD businesses use Stripe card payment
  if(_isUSD()){ mSubPayNowStripe(); return; }
  const d      = _subDaysLeft();
  const isTrial2 = (BIZ.plan||'').toLowerCase().includes('trial')||(BIZ.plan||'')==='Free Trial';
  const plan   = isTrial2 ? 'Free' : (BIZ.plan || 'Free');
  const amt    = isTrial2 ? 4900 : _subAmtXAF();
  const expiry = BIZ.subExpires || BIZ.trialEnd || '';
  const phone  = BIZ.subPhone || BIZ.whatsapp || BIZ.phone || '';

  // Calculate new expiry: extend from current expiry date (not from today)
  // e.g. paying on March 20 when expiry is March 31 → new expiry = April 30
  function calcNewExpiry(currentExpiry){
    const base = currentExpiry && currentExpiry >= localDateStr() ? currentExpiry : localDateStr();
    const d2   = new Date(base+'T00:00:00');
    if((BIZ.billingCycle||'monthly') === 'yearly'){
      d2.setFullYear(d2.getFullYear() + 1);
    } else {
      d2.setMonth(d2.getMonth() + 1);
    }
    return d2.toISOString().slice(0, 10);
  }
  const newExpiry = calcNewExpiry(expiry);

  modal('💳 Renew ShopTrack Subscription',`
  <div style="background:var(--bg3);border-radius:var(--r8);padding:14px;margin-bottom:16px;display:flex;flex-direction:column;gap:9px;font-size:13px">
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Plan</span>${bx(plan,'bx-b')}</div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Current expiry</span><span style="font-family:var(--mono)">${expiry||'—'}</span></div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">New expiry after payment</span><strong style="font-family:var(--mono);color:var(--g)">${newExpiry}</strong></div>
    <div style="border-top:1px solid var(--border);padding-top:9px;display:flex;justify-content:space-between;align-items:center">
      <span style="color:var(--text2)">Amount due</span>
      <strong style="font-size:20px;font-family:var(--mono);color:var(--g)">${amt.toLocaleString()} XAF</strong>
    </div>
  </div>
  <div class="fg">
    <label class="fl">Your MTN or Orange WhatsApp Number *</label>
    <input class="fi" id="spn-phone" type="tel" value="${_esc(phone)}"
      placeholder="e.g. 671234567 or 237671234567"
      oninput="_subDetectCarrier(this.value)"/>
    <div id="spn-carrier" style="font-size:11px;color:var(--text2);margin-top:4px">MTN or Orange numbers accepted</div>
  </div>
  <div class="alrt alrt-b" style="margin-top:10px">
    📱 You will receive a Mobile Money payment prompt on your phone. Enter your PIN to approve.
    Your subscription will be extended to <strong>${newExpiry}</strong> immediately after confirmation.
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" id="spn-pay-btn" onclick="_doSubPayNow('${_esc(expiry)}','${newExpiry}',${amt})">
     📱 Request Payment — ${amt.toLocaleString()} XAF
   </button>`);
}

