function _subDetectCarrier(raw){
  const el = document.getElementById('spn-carrier');
  if(!el) return;
  const digits = String(raw).replace(/\D/g,'');
  const local  = digits.startsWith('237') ? digits.slice(3) : digits;
  const p3     = parseInt(local.slice(0,3), 10);
  if((p3>=670&&p3<=679)||(p3>=650&&p3<=654)||(p3>=680&&p3<=689)){
    el.style.color='var(--b)'; el.textContent='✓ MTN Mobile Money detected';
  } else if((p3>=655&&p3<=657)||(p3>=695&&p3<=699)||(p3>=620&&p3<=629)){
    el.style.color='var(--o)'; el.textContent='✓ Orange Money detected';
  } else if(local.length >= 9){
    el.style.color='var(--r)'; el.textContent='⚠ Not recognised as MTN or Orange';
  } else {
    el.style.color='var(--text2)'; el.textContent='MTN or Orange numbers accepted';
  }
}

async function _doSubPayNow(currentExpiry, newExpiry, amtXAF){
  const phone = (document.getElementById('spn-phone')?.value||'').trim();
  const btn   = document.getElementById('spn-pay-btn');
  if(!phone){ toast('Please enter your phone number','error'); return; }

  if(btn){ btn.disabled=true; btn.textContent='⏳ Sending request…'; }

  try {
    // Call the SA billing proxy using query params to bypass Netlify WAF
    // Pure GET — WAF blocks POST bodies with payment keywords
    const qp = new URLSearchParams({ a: 'charge_one', b: SESSION.bizId, p: phone, e: newExpiry });
    const resp = await fetch('/.netlify/functions/sub-engine?' + qp.toString()); // GET
    let data;
    try { data = await resp.json(); } catch(e) {
      if(btn){ btn.disabled=false; btn.textContent='📱 Request Payment — '+amtXAF.toLocaleString()+' XAF'; }
      toast('❌ Server error — check Netlify function logs','error'); return;
    }

    if(!resp.ok || (data.errors && data.errors.length)){
      const errMsg = (data.errors&&data.errors[0]?.error) || data.error || 'Request failed';
      if(btn){ btn.disabled=false; btn.textContent='📱 Request Payment — '+amtXAF.toLocaleString()+' XAF'; }
      toast('❌ '+errMsg,'error');
      return;
    }

    if(data.charged && data.charged.length){
      const campayRef = data.charged[0].campayRef;
      const mb = document.querySelector('.modal-body');
      if(mb) mb.innerHTML = `
        <div style="text-align:center;padding:24px 16px">
          <div style="font-size:48px;margin-bottom:16px">📱</div>
          <div style="font-size:17px;font-weight:700;color:var(--ink);margin-bottom:8px">Waiting for your approval</div>
          <div style="font-size:13px;color:var(--text);margin-bottom:16px">
            Check your phone — a Mobile Money prompt has been sent to <strong>${_esc(phone)}</strong>.<br>
            Enter your PIN to complete the payment.
          </div>
          <div style="font-size:12px;color:var(--text2);background:var(--bg3);border-radius:var(--r8);padding:10px;margin-bottom:14px">
            Reference: <span style="font-family:var(--mono);color:var(--a)">${_esc(campayRef||'—')}</span>
          </div>
          <div id="spn-status" style="font-size:13px;color:var(--text2)">⏳ Confirming payment…</div>
        </div>`;

      // Poll Supabase directly for sub_expires update — avoids another WAF-blocked call
      let polls = 0;
      const iv = setInterval(async function(){
        polls++;
        if(polls > 24){ clearInterval(iv); document.getElementById('spn-status').innerHTML='<span style="color:var(--y)">⏳ Still waiting — your subscription will update automatically once approved.</span>'; return; }
        try {
          if(!_sb) return;
          const {data:brow} = await _sb.from('businesses').select('sub_expires,sub_charge_status').eq('id',SESSION.bizId).single();
          if(brow && brow.sub_expires === newExpiry){
            clearInterval(iv);
            _subPaymentConfirmed(newExpiry, amtXAF);
          }
        } catch(e){ /* keep polling */ }
      }, 5000);

      // Also listen for webhook confirmation via a Supabase realtime-style poll
      // Check BIZ sub_expires update every 5s as a fallback
      let dbPolls = 0;
      const dbIv = setInterval(async function(){
        dbPolls++;
        if(dbPolls > 24){ clearInterval(dbIv); return; }
        try {
          if(!_sb) return;
          const {data:brow} = await _sb.from('businesses').select('sub_expires,sub_charge_status').eq('id',SESSION.bizId).single();
          if(brow && brow.sub_expires === newExpiry){
            clearInterval(dbIv);
            clearInterval(iv);
            _subPaymentConfirmed(newExpiry, amtXAF);
          }
        } catch(e){ /* keep polling */ }
      }, 5000);
    }

  } catch(err){
    if(btn){ btn.disabled=false; btn.textContent='📱 Request Payment — '+amtXAF.toLocaleString()+' XAF'; }
    toast('Error: '+err.message,'error');
  }
}

function _subPaymentConfirmed(newExpiry, amtXAF){
  _track('Trial Converted',{plan:BIZ.plan||'Starter',amount_xaf:amtXAF});
  // Update BIZ in memory so banner disappears immediately
  BIZ.subExpires = newExpiry;
  // Update status message
  const statusEl = document.getElementById('spn-status');
  if(statusEl) statusEl.innerHTML = '<span style="color:var(--g);font-weight:700;font-size:15px">✅ Payment confirmed! Subscription extended to '+newExpiry+'</span>';
  // Close and refresh after short delay
  setTimeout(function(){
    closeModal();
    addAudit('Subscription self-payment confirmed', SESSION.bizId+' — '+amtXAF.toLocaleString()+' XAF — expires '+newExpiry);
    toast('✅ Subscription renewed! Your plan is active until '+newExpiry,'success');
    nav('dashboard'); // refresh dashboard to remove banner
  }, 2000);
}

