function initDash(){
  // Starter revenue upsell: check if monthly revenue > 5M XAF
  if(!SESSION.isSuperAdmin && _getPlanTier()==='starter'){
    var _upsellKey='st_rev_upsell_'+(new Date().getMonth())+SESSION.bizId;
    try{
      if(!localStorage.getItem(_upsellKey)){
        var _mRange=PERIOD_RANGES['month'];
        var _mRev=D.sales.filter(function(s){return inRange(s.dt,_mRange);})
          .reduce(function(a,s){return a+(s.total||s.amt||0);},0)*CUR.rate;
        if(_mRev>5000000){
          localStorage.setItem(_upsellKey,'1');
          setTimeout(function(){_showUpsell('revenue');},2000);
        }
      }
    }catch(e){}
  }
  // Initialize with current month — use setTimeout so DOM is ready
  setTimeout(function(){
    var monthBtn = document.querySelector('#dash-period-tabs .dtab.on');
    if(!monthBtn) monthBtn = document.querySelector('#dash-period-tabs .dtab');
    if(monthBtn) setDashPeriod(monthBtn, _dashPeriod || 'month');
  }, 0);
  // Donut chart — use CSS-aware label color
  var _isLight = document.body.classList.contains('light');
  var _chartTextColor = _isLight ? '#374151' : '#c8cee8';
  mkChart('donutChart',{type:'doughnut',data:{labels:['Net Profit','COGS','Overhead'],datasets:[{data:[D.kpis.np*CUR.rate,D.kpis.cogs*CUR.rate,D.kpis.oh*CUR.rate].map(Math.round),backgroundColor:['#2dd4a0','#ff5f7a','#f5c842'],borderWidth:0,hoverOffset:5}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:_chartTextColor,font:{size:11},boxWidth:10,padding:10}}},cutout:'66%'}});
}

