// ── Inventory filter state (persists across nav) ─────────────
let _invFilterQ='', _invFilterCat='', _invFilterSt='', _invFilterCond='';

function pgInv(){const _ui=_L();
  return `
<div class="ph">
  <div class="bc">ShopTrack / <span>${_ui.nav_inventory}</span></div>
  <div class="ph-row">
    <h1>${_ui.nav_inventory}</h1>
    <div class="btn-row">
      <button class="btn btn-s btn-sm" onclick="mBulkImport('inventory')">&#x2B06; Import</button>
      <button class="btn btn-s btn-sm" onclick="exportInventoryCSV()">⬇ CSV</button><button class="btn btn-g btn-sm" onclick="exportInventoryPDF()">⬇ PDF</button>
      <button class="btn btn-g btn-sm" onclick="mDuplicateCategory('inv')">⧉ Duplicate Category</button>
      <button class="btn btn-p btn-sm" onclick="mAddItem()">${_ui.btn_add_item}</button>
    </div>
  </div>
  <p>${_ui.ph_inventory}</p>
</div>
<div class="kpi-grid" style="grid-template-columns:repeat(auto-fill,minmax(155px,1fr))">
  <div class="kpi b"><div class="kpi-lbl">Total Items</div><div class="kpi-val b">${D.inv.length}</div><div class="kpi-sub">SKUs</div></div>
  <div class="kpi g"><div class="kpi-lbl">Available</div><div class="kpi-val g">${D.inv.filter(i=>(i.qty||0)-(i.rented||0)>0).length}</div><div class="kpi-sub">In stock</div></div>
  <div class="kpi c"><div class="kpi-lbl">Rented Out</div><div class="kpi-val c">${D.inv.reduce((a,i)=>a+(i.rented||0),0)}</div><div class="kpi-sub">Active rentals</div></div>
  <div class="kpi p" style="cursor:pointer" title="Click to see table with stock values"><div class="kpi-lbl">Stock Value (cost)</div><div class="kpi-val p">${fmtKpi(D.inv.reduce((a,i)=>a+(i.cost||0)*(i.qty||0),0))}</div><div class="kpi-sub">At cost price</div></div>
  <div class="kpi g" style="cursor:pointer" title="Total retail value of all stock"><div class="kpi-lbl">Retail Value</div><div class="kpi-val g">${fmtKpi(D.inv.reduce((a,i)=>a+(i.sp||0)*(i.qty||0),0))}</div><div class="kpi-sub">At selling price</div></div>
  <div class="kpi y" style="cursor:pointer" onclick="_filterInvLowStock()"><div class="kpi-lbl">Low Stock</div><div class="kpi-val y">${D.inv.filter(i=>{const avail=(i.qty||0)-(i.rented||0);const min=i.minStock||i.minQty||0;return min>0&&avail<=min&&avail>0;}).length}</div><div class="kpi-sub">Click to filter</div></div>
</div>
<div class="stabs">
  <button class="stab on" onclick="switchInvView(this,'grid')">Grid</button>
  <button class="stab" onclick="switchInvView(this,'table')">Table</button>
  <button class="stab" onclick="switchInvView(this,'movements')">Movements</button>
</div>
<div class="fbar">
  <input class="fi-s" id="inv-search" placeholder="${_ui.flt_search_inv}" style="width:200px" value="${_esc(_invFilterQ)}" oninput="_filterInv()"/>
  <select class="sel" id="inv-cat-filter" onchange="_filterInv()"><option value="">${_ui.flt_all_cat}</option>${(D.invCats.length?D.invCats:[...new Set(D.inv.map(i=>i.cat).filter(Boolean))].sort()).map(c=>`<option value="${c}"${_invFilterCat===c?' selected':''}>${c}</option>`).join('')}</select>
  <select class="sel" id="inv-st-filter" onchange="_filterInv()"><option value="">${_ui.flt_all_status}</option>${['For Sale','For Rent','Both'].map(s=>`<option${_invFilterSt===s?' selected':''}>${s}</option>`).join('')}</select>
  <select class="sel" id="inv-cond-filter" onchange="_filterInv()"><option value="">All Conditions</option>${['New','Excellent','Good','Fair','Worn','Damaged'].map(s=>`<option${_invFilterCond===s?' selected':''}>${s}</option>`).join('')}</select>
  ${(_invFilterQ||_invFilterCat||_invFilterSt||_invFilterCond)?`<button class="btn btn-s btn-xs" onclick="_invClearFilters()" style="flex-shrink:0">✕ Clear</button>`:''}
</div>
<div id="inv-view" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(190px,1fr));gap:12px" onclick="_invGridClick(event)">
  ${_buildInvGridFiltered(_getFilteredInv())}
</div>
${D.inv.length===0?'<div style="background:var(--bg2);border:1px dashed var(--border2);border-radius:var(--r8);padding:28px 24px;text-align:center;margin-top:8px"><div style="font-size:28px;margin-bottom:10px">\uD83D\uDCE6</div><div style="font-size:15px;font-weight:700;color:var(--ink);margin-bottom:6px">You haven\u2019t added any products yet</div><div style="font-size:13px;color:var(--text2);margin-bottom:16px">Most businesses set up in 8 minutes \u2014 start with your 5 best sellers.</div><button class="btn btn-p" onclick="mAddItem()">+ Add your first product</button></div>':''}`;}

function _getFilteredInv(){
  const q=_invFilterQ.toLowerCase();
  return D.inv.filter(function(i){
    if(q && !i.name.toLowerCase().includes(q) && !(i.sku||'').toLowerCase().includes(q) && !(i.cat||'').toLowerCase().includes(q)) return false;
    if(_invFilterCat && i.cat!==_invFilterCat) return false;
    if(_invFilterSt && i.st!==_invFilterSt) return false;
    if(_invFilterCond && i.cond!==_invFilterCond) return false;
    return true;
  });
}

function _invClearFilters(){
  _invFilterQ=''; _invFilterCat=''; _invFilterSt=''; _invFilterCond='';
  nav('inventory');
}


function _invGridClick(e){
  var editEl = e.target.closest('[data-edit-id]');
  if(editEl){ e.stopPropagation(); mEditItem(editEl.dataset.editId); return; }
  var dupEl = e.target.closest('[data-dup-id]');
  if(dupEl){ e.stopPropagation(); mDuplicateItem(dupEl.dataset.dupId); return; }
  var delEl = e.target.closest('[data-del-id]');
  if(delEl){ e.stopPropagation(); _mItemDelete(delEl.dataset.delId); return; }
  var card = e.target.closest('[data-inv-id]');
  if(card) mItem(card.dataset.invId);
}



function _filterInv(){
  _invFilterQ   = (document.getElementById('inv-search')?.value||'').trim();
  _invFilterCat = document.getElementById('inv-cat-filter')?.value||'';
  _invFilterSt  = document.getElementById('inv-st-filter')?.value||'';
  _invFilterCond= document.getElementById('inv-cond-filter')?.value||'';
  const filtered = _getFilteredInv();
  const v = document.getElementById('inv-view');
  if(!v) return;
  // Show/hide clear button
  const hasFilt = _invFilterQ||_invFilterCat||_invFilterSt||_invFilterCond;
  const clearBtn = document.querySelector('.fbar .btn-xs');
  if(clearBtn) clearBtn.style.display = hasFilt ? '' : 'none';
  if(v.style.display==='grid'||v.style.display===''){
    v.innerHTML = _buildInvGridFiltered(filtered);
  }
}
function _buildInvGridFiltered(items){
  if(!items||!items.length) return '<div style="color:var(--text2);font-size:13px;padding:40px 20px;text-align:center">'
    +'<div style="font-size:32px;margin-bottom:10px">📦</div>'
    +'<div style="font-weight:600;color:var(--ink);margin-bottom:6px">No items match the filter</div>'
    +'<button class="btn btn-s btn-sm" onclick="_invClearFilters()" style="margin-top:4px">✕ Clear Filters</button>'
    +'</div>';
  return items.map(function(it){
    var _imgSrc=(it.photoDataUrls&&it.photoDataUrls.length)?it.photoDataUrls[0]:(it.imgDataUrl||null);
    var photo=_imgSrc?'<img loading="lazy" src="'+_imgSrc+'" style="width:100%;height:100%;object-fit:cover;display:block"/>':itemPhoto(it.img||'gown-aline',it.imgC?.[0],it.imgC?.[1],it.imgC?.[2]);
    var price=it.sp?fmt(it.sp):(it.rp?fmt(it.rp)+'/day':(it.cost?fmt(it.cost)+' (cost)':'No price'));
    var avail=(it.qty||0)-(it.rented||0);
    var stockVal=(it.cost||0)*(it.qty||0);
    var minQty = it.minStock||it.minQty||0;  // 0 = disabled
    var isOutOfStock = avail<=0 && (it.qty||0)>=0;
    var isLowStock   = minQty>0 && avail<=minQty && avail>0;  // only when threshold set AND not zero
    var stockBadge=isOutOfStock
      ?'<div style="background:var(--r);color:#fff;font-size:9px;font-weight:700;padding:2px 6px;border-radius:3px;margin-top:3px">OUT OF STOCK</div>'
      :isLowStock
        ?'<div style="background:var(--y);color:#000;font-size:9px;font-weight:700;padding:2px 6px;border-radius:3px;margin-top:3px">⚠ LOW STOCK ('+avail+' left)</div>'
        :'';
    return '<div class="icard" data-inv-id="'+it.id+'"'+(isLowStock||isOutOfStock?' style="outline:2px solid '+(isOutOfStock?'var(--r)':'var(--y)')+';"':'')+'>'
      +'<div class="icard-img">'+photo+_invStatusBadge(it.st)+'</div>'
      +'<div class="icard-body">'
      +'<div class="icard-name">'+_esc(it.name)+'</div>'
      +'<div class="icard-sku">'+_esc(it.sku||'')+'</div>'
      +'<div class="icard-price">'+price+'</div>'
      +stockBadge
      +'<div class="icard-bot">'
        +'<div class="cond '+cc(it.cond)+'"><div class="cdot"></div><span style="font-size:11px;color:var(--text)">'+it.cond+'</span></div>'
        +'<span style="font-size:10px;color:var(--text2)">Avail: '+avail+'</span>'
      +'</div>'
      +(stockVal>0?'<div style="font-size:10px;color:var(--text2);margin-top:3px">Stock value: <strong style="color:var(--ink)">'+fmt(stockVal)+'</strong></div>':'')
      +(it.rented>0?'<div style="font-size:10px;color:var(--c);margin-top:2px">🔄 '+(it.rented||0)+' rented out</div>':'')
      +'<div class="btn-row" style="margin-top:7px">'
        +'<button class="btn btn-g btn-xs" data-edit-id="'+it.id+'">✏ Edit</button>'
        +'<button class="btn btn-g btn-xs" data-dup-id="'+it.id+'">⧉ Dup</button>'
        +'<button class="btn btn-d btn-xs" data-del-id="'+it.id+'">🗑</button>'
      +'</div>'
      +'</div>'
      +'</div>';
  }).join('');
}

// Filter inventory to show only low-stock items
function _filterInvLowStock(){
  _invFilterQ=''; _invFilterCat=''; _invFilterSt=''; _invFilterCond='';
  const v = document.getElementById('inv-view');
  if(!v) return;
  const lowStock = D.inv.filter(function(i){
    const avail=(i.qty||0)-(i.rented||0);
    const min=i.minStock||i.minQty||0;
    return min>0 && avail<=min && avail>0; // threshold must be set; avail>0 separates from out-of-stock
  });
  v.innerHTML = _buildInvGridFiltered(lowStock);
}
function switchInvView(el,mode){
  document.querySelectorAll('.stab').forEach(t=>t.classList.remove('on'));el.classList.add('on');
  const v=$('inv-view');
  if(mode==='table'){
    v.style.display='block';
    v.innerHTML=`<div class="tbl-wrap"><table><thead><tr><th>SKU</th><th>Name</th><th>Category</th><th>Status</th><th>Qty</th><th>Rented</th><th>Avail</th><th>Cost</th><th>Sell</th><th>Rent/Day</th><th class="num">Stock Value</th><th>Cond.</th><th>Actions</th></tr></thead><tbody>
    ${D.inv.map(i=>{const sv=(i.cost||0)*(i.qty||0); return `<tr>
      <td>${mono(i.sku)}</td><td><strong style="color:var(--ink);cursor:pointer" onclick="mItem('${i.id}')">${i.name}</strong></td><td>${i.cat}</td><td>${badge(i.st)}</td>
      <td>${i.qty}</td><td style="color:var(--c)">${i.rented}</td><td style="color:var(--g)">${i.qty-i.rented}</td>
      <td>${canAccess('inventory_cost')?mono(fmt(i.cost)):'<span style=\"color:var(--text3)\">🔒</span>'}</td><td>${mono(fmt(i.sp),'g')}</td><td>${mono(i.rp?fmt(i.rp):'—','c')}</td>
      <td class="num">${canAccess('inventory_cost')?`<span style="font-family:var(--mono);font-size:12px;font-weight:600;color:var(--b,var(--a))">${fmt(sv)}</span>`:'<span style="color:var(--text3)">🔒</span>'}</td>
      <td><div class="cond ${cc(i.cond)}"><div class="cdot"></div><span style="font-size:11px">${i.cond}</span></div></td>
      <td><div class="btn-row">
        <button class="btn btn-g btn-xs" onclick="mItem('${i.id}')">View</button>
        <button class="btn btn-g btn-xs" onclick="mEditItem('${i.id}')">✏</button>
        <button class="btn btn-g btn-xs" onclick="mDuplicateItem('${i.id}')">⧉</button>
        <button class="btn btn-d btn-xs" onclick="_mItemDelete('${i.id}')">🗑</button>
      </div></td>
    </tr>`}).join('')}
    </tbody></table></div>`;
  } else if(mode==='movements'){
    v.style.display='block';
    v.innerHTML=(()=>{
      const rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
      const moves=[];
      D.sales.filter(s=>inRange(s.dt,rng)&&s.invId&&s.invId!=='__custom__').forEach(s=>{
        const it=D.inv.find(i=>i.id===s.invId);
        if(it) moves.push({dt:s.dt,item:it.name,type:'Stock Out',cls:'bx-r',delta:'-1',col:'var(--r)',reason:'Sale '+s.id});
      });
      D.purchases.filter(p=>(p.st==='Paid'||p.st==='Received')&&inRange(p.dt,rng)).forEach(p=>{
        moves.push({dt:p.dt,item:p.items.split(/[,×(]/)[0].trim(),type:'Stock In',cls:'bx-g',delta:p.qty?'+'+p.qty:'+?',col:'var(--g)',reason:'Purchase '+p.id});
      });
      D.rentals.filter(r=>inRange(r.start,rng)).forEach(r=>{
        moves.push({dt:r.start,item:r.item,type:'Rental Out',cls:'bx-c',delta:'-1',col:'var(--c)',reason:'Rental '+r.id});
      });
      D.rentals.filter(r=>r.ret&&inRange(r.ret,rng)).forEach(r=>{
        moves.push({dt:r.ret,item:r.item,type:'Rental In',cls:'bx-g',delta:'+1',col:'var(--g)',reason:'Return '+r.id});
      });
      moves.sort((a,b)=>b.dt.localeCompare(a.dt));
      if(!moves.length) return '<div style="color:var(--text2);font-size:13px;padding:16px 0;text-align:center">No stock movements for '+rng.label+'</div>';
      return '<div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Item</th><th>Type</th><th>Qty Δ</th><th>Reason</th></tr></thead><tbody>'
        +moves.slice(0,20).map(m=>`<tr><td>${m.dt}</td><td style="max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${m.item}</td><td>${bx(m.type,m.cls)}</td><td style="color:${m.col};font-family:var(--mono)">${m.delta}</td><td>${m.reason}</td></tr>`).join('')
        +'</tbody></table></div>';
    })()
  } else {
    v.style.display='grid';
    v.style.gridTemplateColumns='repeat(auto-fill,minmax(190px,1fr))';
  }
}

function _saveItemPrices(id){
  var r2=CUR.rate;
  var itx=D.inv.find(function(i){return i.id===id;});
  if(!itx){toast('Item not found','error');return;}
  var spEl=document.getElementById('mi-sp-'+id);
  var rpEl=document.getElementById('mi-rp-'+id);
  var msEl=document.getElementById('mi-minsp-'+id);
  var spVal=spEl?parseFloat(spEl.value):NaN;
  var rpVal=rpEl?parseFloat(rpEl.value):NaN;
  var msVal=msEl?parseFloat(msEl.value):NaN;
  if(!isNaN(spVal)){
    var _minSpCheckP = _checkMinSp(id, spVal);
    if(_minSpCheckP && _minSpCheckP.block){ toast(_minSpCheckP.msg, 'error'); return; }
    itx.sp=spVal/r2;
  }
  if(!isNaN(rpVal)) itx.rp=rpVal/r2;
  if(!isNaN(msVal)) itx.minSp=msVal/r2;
  addAudit('Prices updated',itx.id+' SP='+fmt(itx.sp)+' RP='+fmt(itx.rp));
  toast('Prices saved','success');
  closeModal();nav('inventory');
}

function _invStatusBadge(st){
  var cfg = {
    'For Sale':  {bg:'#2563eb',color:'#fff',label:'For Sale'},
    'For Rent':  {bg:'#7c3aed',color:'#fff',label:'For Rent'},
    'Both':      {bg:'#059669',color:'#fff',label:'Sale & Rent'},
  };
  var c = cfg[st];
  if(!c) return '';
  return '<div style="position:absolute;top:8px;left:8px;background:'+c.bg
    +';color:'+c.color+';font-size:10px;font-weight:700;padding:3px 8px'
    +';border-radius:4px;letter-spacing:.3px;box-shadow:0 2px 6px rgba(0,0,0,.4)">'
    +c.label+'</div>';
}

