function _previewNewItemPhotos(input){
  const files = Array.from(input.files);
  if(!files.length) return;
  const grid = document.getElementById('ai-photo-grid');
  const status = document.getElementById('ai-photo-status');
  window._pendingPhotos = window._pendingPhotos || {};
  window._pendingPhotos['__new__'] = [];
  window._pendingPhotos['__new__']._expectedCount = files.length;
  if(grid) grid.innerHTML = '';
  files.forEach(function(file, idx){
    const reader = new FileReader();
    reader.onload = function(e){
      window._pendingPhotos['__new__'].push(e.target.result);
      if(grid){
        const thumb = document.createElement('div');
        thumb.style.cssText = 'position:relative;aspect-ratio:1;border-radius:var(--r6);overflow:hidden;border:1px solid var(--border2)';
        const removeIdx = window._pendingPhotos['__new__'].length - 1;
        thumb.innerHTML = '<img loading="lazy" src="'+e.target.result+'" style="width:100%;height:100%;object-fit:cover"/>';
        const xBtn = document.createElement('button');
        xBtn.textContent = 'x';
        xBtn.style.cssText = 'position:absolute;top:3px;right:3px;background:rgba(0,0,0,.7);color:#fff;border:none;border-radius:50%;width:20px;height:20px;font-size:11px;cursor:pointer;line-height:1';
        xBtn.onclick = function(){ thumb.remove(); window._pendingPhotos['__new__'].splice(removeIdx,1); };
        thumb.appendChild(xBtn);
        grid.appendChild(thumb);
      }
      const loaded = window._pendingPhotos['__new__'].length;
      const total  = window._pendingPhotos['__new__']._expectedCount;
      if(status){
        status.style.display = 'block';
        status.textContent = loaded + ' of ' + total + ' photo' + (total>1?'s':'') + ' ready';
      }
    };
    reader.readAsDataURL(file);
  });
}

function _saveNewItem(){
  if(_trialWriteBlocked('Adding a product')) return;
  if(D.inv.length===0) _track('First Product Added');
  var name = document.getElementById('ai-name').value.trim();
  if(!name){ toast('Product name is required','error'); return; }
  var rr3 = CUR.rate;
  // Collision-safe ID: use max existing numeric suffix + 1
  var maxInvNum = D.inv.reduce(function(m,i){
    var n=parseInt((i.id||'').replace(/\D/g,''),10)||0; return n>m?n:m;
  },0);
  var id  = 'INV-'+String(maxInvNum+1).padStart(3,'0');
  // Collision-safe SKU
  var skuInput = document.getElementById('ai-sku').value.trim();
  var sku = skuInput || ('SKU-'+String(maxInvNum+1).padStart(3,'0'));
  var cat = _ssGetVal('ai-cat-wrap')||document.getElementById('ai-cat')?.value||D.invCats[0]||'General';
  // Persist new category if it's not already saved
  if(cat && D.invCats.indexOf(cat)===-1){
    D.invCats.push(cat);
    if(SESSION.bizId&&!SESSION.isSuperAdmin) _dbSaveCategories(SESSION.bizId);
  }
  var newItem = {
    id:id, sku:sku, name:name,
    cat:   cat,
    brand: document.getElementById('ai-brand').value,
    st:    document.getElementById('ai-st').value,
    cond:  document.getElementById('ai-cond').value,
    cost:  (parseFloat(document.getElementById('ai-cost').value)||0)/rr3,
    sp:    (parseFloat(document.getElementById('ai-sp').value)||0)/rr3,
    rp:    (parseFloat(document.getElementById('ai-rp').value)||0)/rr3,
    minSp: (parseFloat(document.getElementById('ai-minsp').value)||0)/rr3,
    dep:   (parseFloat(document.getElementById('ai-dep').value)||0)/rr3,
    qty:   parseInt(document.getElementById('ai-qty').value)||1,
    minStock: parseInt(document.getElementById('ai-minstock')?.value)||0,
    color: document.getElementById('ai-color').value,
    sz:    document.getElementById('ai-sz').value,
    desc:  document.getElementById('ai-desc').value,
    rented: 0, photoDataUrls: [],
    costLines: _cbReadLines('ci'),
  };
  var pending = window._pendingPhotos && window._pendingPhotos['__new__'];
  var expectedCount = pending ? (pending._expectedCount || pending.length) : 0;
  // Validate sp >= minSp when both are set
  var _aiSp    = (parseFloat(document.getElementById('ai-sp').value)||0);
  var _aiMinSp = (parseFloat(document.getElementById('ai-minsp').value)||0);
  if(_aiSp > 0 && _aiMinSp > 0 && _aiSp < _aiMinSp){
    toast('Selling price (' + fmt(_aiSp/CUR.rate) + ') is below the minimum sell price (' + fmt(_aiMinSp/CUR.rate) + ').', 'error');
    return;
  }
  function doFinish(){
    if(pending && pending.length) newItem.photoDataUrls = pending.slice();
    if(window._pendingPhotos) delete window._pendingPhotos['__new__'];
    D.inv.unshift(newItem);
    _dbSaveInv(newItem);
    addAudit('Inventory item added', id+' -- '+name);
    toast(name+' added to inventory','success');
    if(window._retSelAI){ _mPopAndSelect(window._retSelAI, id, name); window._retSelAI=null; }
    else { closeModal(); nav('inventory'); }
  }
  if(pending && expectedCount > 0 && pending.length < expectedCount){
    var waited = 0;
    var poll = setInterval(function(){
      waited += 100;
      if(pending.length >= expectedCount || waited >= 1500){
        clearInterval(poll);
        doFinish();
      }
    }, 100);
  } else {
    doFinish();
  }
}
