// Returns {block, msg} if price < minSp, null if OK
// block=true means hard stop (non-owners), block=false means owner warning/confirm
function _checkMinSp(invId, priceDisplay){
  if(!invId || invId === '__custom__') return null;
  // Service items have no minimum price
  if(invId.startsWith('svc:')) return null;
  var realId = invId.startsWith('inv:') ? invId.replace('inv:','') : invId;
  var it = D.inv.find(function(x){ return x.id === realId; });
  if(!it || !it.minSp) return null;
  var minDisplay = Math.round(it.minSp * CUR.rate);
  if(priceDisplay < minDisplay - 0.01){
    var isOwner = SESSION.level === 'owner' || SESSION.isSuperAdmin;
    if(isOwner){
      return {block:false, msg:'⚠ Price of '+fmt(priceDisplay/CUR.rate)+' is below the minimum sell price of '+fmt(it.minSp)+' for this item. Do you want to proceed?'};
    } else {
      // Alert owner immediately via WhatsApp
      var _sName = SESSION.name || SESSION.level || 'Staff';
      setTimeout(function(){ _waOwnerMinBlock(it.name, priceDisplay, it.minSp, _sName); }, 200);
      return {block:true, msg:'Selling below minimum price for '+it.name+' is not permitted. Minimum: '+fmt(it.minSp)+'. Please ask the owner to approve this sale.'};
    }
  }
  return null;
}

// Updates the warning hint below cs-amt in the Create Sale modal
function _csCheckMinSpWarn(){
  var warn = document.getElementById('cs-minsp-warn');
  if(!warn) return;
  // Check all line item rows for minimum price violations
  var lineRows = Array.from(document.querySelectorAll('#cs-line-rows .cs-line-row'));
  var messages = [];
  var hasBlock = false;
  lineRows.forEach(function(row){
    var sel   = row.querySelector('.cs-inv-sel');
    var price = parseFloat(row.querySelector('.cs-line-price')?.value)||0;
    if(!sel || !sel.value || sel.value==='__custom__' || !price) return;
    var check = _checkMinSp(sel.value, price);
    if(check){ if(check.block) hasBlock=true; messages.push(check.msg); }
  });
  // Also check legacy single-item field
  var legacyInv = document.getElementById('cs-inv');
  var legacyAmt = parseFloat(document.getElementById('cs-amt')?.value)||0;
  if(legacyInv && legacyInv.value && legacyInv.value!=='__custom__' && legacyAmt){
    var lChk = _checkMinSp(legacyInv.value, legacyAmt);
    if(lChk){ if(lChk.block) hasBlock=true; messages.push(lChk.msg); }
  }
  if(messages.length > 0){
    warn.innerHTML = messages.map(function(m){ return '<div>⚠ '+m+'</div>'; }).join('');
    warn.style.display='block';
    warn.style.borderLeftColor = hasBlock?'var(--r)':'var(--y)';
    warn.style.color = hasBlock?'var(--r)':'var(--y)';
    warn.style.background = hasBlock?'rgba(220,38,38,.06)':'rgba(234,179,8,.06)';
    if(hasBlock) warn.innerHTML += '<div style="font-size:10px;margin-top:4px;font-weight:600">Only the owner can approve below-minimum pricing.</div>';
  } else {
    warn.style.display='none';
  }
}


function _saveSale(){
  if(_trialWriteBlocked('Recording a sale')) return;
  if(D.sales.length===0) _track('First Sale Recorded');
  var custId=(document.getElementById('cs-cust-sel')||{}).value||(document.getElementById('cs-cust')||{}).value||(document.getElementById('cs-cust-sel')||{}).value||document.getElementById('cs-cust')?.value||_ssGetVal('cs-cust-wrap');
  if(!custId){toast('Please select a customer','error');return;}
  // Collect line items
  var lineRows = Array.from(document.querySelectorAll('#cs-line-rows .cs-line-row'));
  var lineItems = lineRows.map(function(row){
    var sel = row.querySelector('.cs-inv-sel');
    var qty = parseFloat(row.querySelector('.cs-line-qty')?.value)||1;
    var price = parseFloat(row.querySelector('.cs-line-price')?.value)||0;
    var rawVal = sel ? sel.value : '';
    var isSvc = rawVal.startsWith('svc:');
    var isInv = rawVal.startsWith('inv:');
    var invId2 = isSvc ? '' : (isInv ? rawVal.replace('inv:','') : rawVal);
    var svcId2 = isSvc ? rawVal.replace('svc:','') : '';
    var opt = sel ? sel.options[sel.selectedIndex] : null;
    var name = (opt&&opt.dataset.name) ? opt.dataset.name : (rawVal==='__custom__'?'Custom':'');
    return {invId:invId2, svcId:svcId2, isSvc, qty, price, name};
  }).filter(function(r){ return r.price>0||r.invId||r.svcId; });
  // Primary invId (first real inventory item, or __custom__ for service-only sales)
  var invId = (lineItems.find(function(r){return r.invId&&r.invId!=='__custom__';})||{invId:''}).invId||'__custom__';
  var amtFrs = lineItems.reduce(function(a,r){return a+r.qty*r.price;},0);
  var totalFrs=parseFloat(document.getElementById('cs-total').value)||amtFrs;
  if(!amtFrs){toast('Please add at least one item with a price','error');return;}
  // ── Minimum price enforcement ──────────────────────────────
  var _minBlock=false, _minOwnerWarn=[];
  lineItems.forEach(function(li){
    if(!li.invId||li.invId==='__custom__') return;
    var chk=_checkMinSp(li.invId, li.price);
    if(!chk) return;
    if(chk.block){ _minBlock=true; toast(chk.msg,'error'); }
    else { _minOwnerWarn.push(chk.msg); }
  });
  if(_minBlock) return;
  // Owner sees warning but can proceed — log it
  if(_minOwnerWarn.length>0){
    addAudit('Below-minimum price override', _minOwnerWarn.join(' | '));
  }
  var custObj=D.cust.find(function(x){return x.id===custId;});
  var cust=custObj?custObj.name:custId;
  // Build description from line items or manual field
  var itemsVal=document.getElementById('cs-items').value.trim();
  if(!itemsVal){
    itemsVal = lineItems.map(function(r){ return (r.qty>1?r.qty+'× ':'')+r.name; }).filter(Boolean).join(', ') || 'Sale';
  }
  var paidRaw=document.getElementById('cs-paid').value;
  var paidFrs=paidRaw===''||paidRaw===null?totalFrs:parseFloat(paidRaw)||0;
  var rate=CUR.rate;
  var freight=(parseFloat(document.getElementById('cs-freight').value)||0)/rate;
  var taxes=(parseFloat(document.getElementById('cs-taxes').value)||0)/rate;
  var other=(parseFloat(document.getElementById('cs-other').value)||0)/rate;
  // Sum COGS across ALL line items (qty × item cost price each)
  var multiLineCostFrs = lineItems.reduce(function(sum, li){
    if(li.isSvc || !li.invId || li.invId==='__custom__') return sum;
    var inv = D.inv.find(function(x){return x.id===li.invId;});
    return sum + ((inv&&inv.cost||0) * (li.qty||1) * rate);
  }, 0);
  // Fall back to manual COGS field if no inventory items
  var costFrs = multiLineCostFrs > 0
    ? Math.round(multiLineCostFrs)
    : (parseFloat(document.getElementById('cs-cost').value)||0);
  var amt=amtFrs/rate;
  var total=totalFrs/rate;
  var paid=paidFrs/rate;
  var cost=costFrs/rate;
  var dt=document.getElementById('cs-dt').value;
  var method=document.getElementById('cs-method').value;
  var notes=document.getElementById('cs-notes').value;
  var terms=document.getElementById('cs-terms')?.value||BIZ.paymentTerms||'Net 7';
  var bal=total-paid;
  var st=paid>=total?'Paid':paid>0?'Partial':'Unpaid';
  // Convert lineItems prices from display currency to base USD for storage
  var lineItemsBase = lineItems.map(function(li){
    return { invId:li.invId, svcId:li.svcId||'', name:li.name, qty:li.qty, price:li.price/rate };
  });
  // Generate unique ID: use max existing ID + 1 to avoid collisions after deletions
  var _maxSaleNum = D.sales.reduce(function(m,s){
    var n=parseInt((s.id||'').replace(/\D/g,''),10)||0; return n>m?n:m;
  },0);
  var newId='S-'+String(_maxSaleNum+1).padStart(4,'0');
  var profit=total-cost; // Gross profit = revenue - COGS (not affected by payment timing)
  D.sales.unshift({id:newId,cust,custId,items:itemsVal,lineItems:lineItemsBase,dt,amt,freight,taxes,other,total,paid,cost,profit,st,method,notes,invId,terms});
    _dbSaveSale(D.sales[0]);
  // Deduct stock for inventory line items only (services have no stock)
  // AND immediately persist each affected item to Supabase
  (typeof lineItems!=='undefined'?lineItems:[{invId,qty:1}]).forEach(function(li){
    if(li.invId&&li.invId!=='__custom__'&&!li.isSvc){
      var invObj2=D.inv.find(function(x){return x.id===li.invId;});
      if(invObj2){
        invObj2.qty=Math.max(0,(invObj2.qty||0)-li.qty);
        _dbSaveInv(invObj2); // persist stock deduction immediately
      }
    }
  });
  if(custObj){
    // spent tracks cash received, not invoiced amounts
    custObj.spent  = (custObj.spent||custObj.spend||0) + paid;
    custObj.spend  = custObj.spent;
    custObj.orders = (custObj.orders||0)+1;
    custObj.visits = (custObj.visits||0)+1;
    custObj.last   = dt;
    // bal tracks the unpaid portion (AR owed by this customer)
    if(bal>0) custObj.bal = (custObj.bal||0) + bal;
    _dbSaveCust(custObj);
  }
  refreshLiveKpis();
  addAudit('Sale created',newId+' - '+cust+' - '+fmt(total));
  _notifEvent('newSale',{cust:cust||'Customer',amt:fmt(total)});
  // WA alert to owner
  _waOwnerNewSale(D.sales[0], SESSION.name||'');
  // Check stock for items in THIS sale only
  lineItems.forEach(function(li) {
    if(!li.invId || li.invId==='__custom__' || li.isSvc) return;
    var realId = li.invId.startsWith('inv:') ? li.invId.replace('inv:','') : li.invId;
    var iv2 = D.inv.find(function(x){ return x.id===realId; });
    if(!iv2) return;
    var av2 = (iv2.qty||0)-(iv2.rented||0);
    var mn2 = iv2.minStock||iv2.minQty||0;
    if(av2 <= 0) _waOwnerLowStock(iv2.name, 0, mn2);
    else if(mn2 > 0 && av2 <= mn2) _waOwnerLowStock(iv2.name, av2, mn2);
  });
  closeModal();
  toast(newId+' recorded — '+fmt(total),'success');
  nav('sales');
}


