// ── Switch between sale / rental / service tab ──────────────────
function _photoTabSwitch(el, tab){
  el.closest('#photo-type-tabs').querySelectorAll('.stab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  ['sale','rental','service'].forEach(function(t){
    const p=document.getElementById('photo-pane-'+t);
    if(p) p.style.display = t===tab ? '' : 'none';
  });
  // Clear preview areas when switching
  const grid=document.getElementById('photoPreviewGrid');
  if(grid) grid.innerHTML='';
  const ex=document.getElementById('photo-existing-wrap');
  if(ex) ex.style.display='none';
}

// ── Load existing photos for selected item ──────────────────────
function _photoLoadExisting(tab){
  const sel = document.getElementById('photo-sel-'+tab);
  const id  = sel?.value; if(!id) return;
  const existWrap = document.getElementById('photo-existing-wrap');
  const existGrid = document.getElementById('photo-existing-grid');
  if(!existWrap||!existGrid) return;

  let urls=[];
  if(tab==='service'){
    const svc=(D.services||[]).find(s=>s.id===id);
    if(svc&&svc.imgDataUrl) urls=[svc.imgDataUrl];
  } else {
    const item=D.inv.find(i=>i.id===id);
    if(item){
      urls=(item.photoDataUrls&&item.photoDataUrls.length)
        ? item.photoDataUrls : (item.imgDataUrl?[item.imgDataUrl]:[]);
    }
  }

  if(urls.length){
    existGrid.innerHTML=urls.map(url=>`<div class="pthumb" style="position:relative">
      <img loading="lazy" src="${url}" style="width:100%;height:100%;object-fit:cover;border-radius:var(--r6)"/>
      <div style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,.5);font-size:9px;color:#fff;text-align:center;padding:2px">Current</div>
    </div>`).join('');
    existWrap.style.display='';
  } else {
    existWrap.style.display='none';
  }
}

function _savePhotoUpload(){
  // Detect active tab
  const activeTab = document.querySelector('#photo-type-tabs .stab.on');
  const tab = activeTab ? (activeTab.textContent.includes('Sale')?'sale':activeTab.textContent.includes('Rental')?'rental':'service') : 'sale';
  const sel = document.getElementById('photo-sel-'+tab);
  const id  = sel?.value;
  if(!id){ toast('Please select an item first','error'); sel?.focus(); return; }

  const imgs = document.querySelectorAll('#photoPreviewGrid img');
  const urls = Array.from(imgs).map(img=>img.src).filter(s=>s.startsWith('data:'));
  if(!urls.length){ toast('Please select at least one photo','error'); return; }

  if(tab==='service'){
    const svc=(D.services||[]).find(s=>s.id===id);
    if(!svc){ toast('Service not found','error'); return; }
    svc.imgDataUrl = urls[0]; // services: single featured image
    // Save to DB
    if(typeof _dbSaveService==='function') _dbSaveService(svc);
    addAudit('Service photo updated', svc.name);
    toast('Photo saved for '+svc.name+' ✓','success');
  } else {
    const item=D.inv.find(i=>i.id===id);
    if(!item){ toast('Item not found','error'); return; }
    item.photoDataUrls = urls;
    item.imgDataUrl    = urls[0];
    _dbSaveInv(item);
    addAudit('Photos updated', item.name+' — '+urls.length+' photo'+(urls.length>1?'s':''));
    toast(urls.length+' photo'+(urls.length>1?'s':'')+' saved for '+item.name+' ✓','success');
  }

  closeModal();
  if(curPage==='inventory'||curPage==='inv-detail'||curPage==='services') setTimeout(()=>nav(curPage),100);
}


function handlePhotoSelect(input){
  const grid = document.getElementById('photoPreviewGrid');
  if(!grid) return;
  grid.innerHTML = '';
  const files = Array.from(input.files||[]);
  if(files.length === 0) return;
  files.forEach(file => {
    const reader = new FileReader();
    reader.onload = e => {
      const div = document.createElement('div');
      div.className = 'pthumb';
      div.style.position = 'relative';
      div.innerHTML = `<img loading="lazy" src="${e.target.result}" style="width:100%;height:100%;object-fit:cover;border-radius:var(--r6)"/>
        <div style="position:absolute;top:3px;right:3px;background:rgba(0,0,0,.6);border-radius:4px;padding:1px 4px;font-size:9px;color:#fff">${(file.size/1024).toFixed(0)}KB</div>`;
      grid.appendChild(div);
    };
    reader.readAsDataURL(file);
  });
  toast(`${files.length} photo${files.length>1?'s':''} selected`,'success');
}

// ── DOCUMENT ATTACHMENT HELPERS ─────────────────────────────
// In-memory store for uploaded doc dataUrls — keyed by short unique ID
// Allows view/download buttons to retrieve dataUrl without embedding it in onclick attr
const _DOC_STORE = {};

function docChip(d){
  const isPdf=/\.pdf$/i.test(d.name);
  const isImg=/\.(jpe?g|png|gif|webp)$/i.test(d.name);
  const icon=isPdf?'📄':isImg?'🖼':'📎';
  // Register dataUrl in store so buttons can retrieve it
  const key = d._key || ('doc-'+ Date.now() +'-'+ Math.random().toString(36).slice(2,7));
  if(d.dataUrl) _DOC_STORE[key] = { dataUrl: d.dataUrl, name: d.name, type: d.type||'' };
  const hasData = !!d.dataUrl;
  const viewBtn  = hasData
    ? `<button class="btn btn-g btn-xs" style="padding:2px 5px;font-size:11px" onclick="_docView('${key}')" title="View">👁</button>`
    : `<button class="btn btn-g btn-xs" style="padding:2px 5px;font-size:11px;opacity:.4;cursor:default" title="No preview — file not uploaded in this session">👁</button>`;
  const dlBtn = hasData
    ? `<button class="btn btn-g btn-xs" style="padding:2px 5px;font-size:11px" onclick="_docDownload('${key}')" title="Download">⬇</button>`
    : `<button class="btn btn-g btn-xs" style="padding:2px 5px;font-size:11px;opacity:.4;cursor:default" title="No file data available">⬇</button>`;
  return `<div style="display:inline-flex;align-items:center;gap:6px;background:var(--bg4);border:1px solid var(--border2);border-radius:var(--r6);padding:5px 10px;font-size:12px;max-width:240px">
    <span style="font-size:14px">${icon}</span>
    <span style="flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--ink)">${d.name}</span>
    <span style="font-size:10px;color:var(--text2);flex-shrink:0">${d.size||''}</span>
    <div style="display:flex;gap:3px;flex-shrink:0">
      ${viewBtn}
      ${dlBtn}
      <button class="btn btn-g btn-xs" style="padding:2px 5px;font-size:11px" onclick="shareDoc('${d.name}')" title="Share">🔗</button>
    </div>
  </div>`;
}

function _docView(key){
  const doc = _DOC_STORE[key];
  if(!doc){ toast('File data not available — re-attach the document','error'); return; }
  const win = window.open();
  if(!win){ toast('Pop-up blocked — allow pop-ups for this site to view documents','error'); return; }
  if(doc.dataUrl.startsWith('data:image')){
    win.document.write('<html><body style="margin:0;background:#111;display:flex;justify-content:center;align-items:center;min-height:100vh"><img loading="lazy" src="'+doc.dataUrl+'" style="max-width:100%;max-height:100vh;object-fit:contain"/></body></html>');
  } else {
    win.document.write('<html><body style="margin:0"><iframe src="'+doc.dataUrl+'" style="width:100vw;height:100vh;border:none"></iframe></body></html>');
  }
  win.document.title = doc.name;
}

function _docDownload(key){
  const doc = _DOC_STORE[key];
  if(!doc){ toast('File data not available — re-attach the document','error'); return; }
  const a = document.createElement('a');
  a.href = doc.dataUrl;
  a.download = doc.name;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  toast('Downloading '+doc.name+'…','success');
}

function handleDocAttach(input, listId){
  const list=document.getElementById(listId); if(!list) return;
  const files=Array.from(input.files||[]); if(!files.length) return;
  // Remove "No documents" placeholder if present
  const placeholder=list.querySelector('div');
  if(placeholder && placeholder.textContent.includes('No documents')) placeholder.remove();

  // Resolve which D.* record owns this list, so docs persist on the record
  // listId patterns: 'rent-doc-{id}-list', 'po-vdoc-{id}-list',
  //                  'exp-docs-{ts}-list' (new expense), 'view-exp-{id}-list'
  function _findRecord(lid){
    const s = lid.replace(/-list$/,'');
    if(s.startsWith('rent-doc-')){
      const rid=s.replace('rent-doc-',''); return D.rentals.find(x=>x.id===rid)||null;
    }
    if(s.startsWith('po-vdoc-')){
      const rid=s.replace('po-vdoc-',''); return D.purchases.find(x=>x.id===rid)||null;
    }
    if(s.startsWith('view-exp-')){
      const rid=s.replace('view-exp-',''); return D.exp.find(x=>x.id===rid)||null;
    }
    // exp-docs-{timestamp} is a new expense being created — no D record yet, just show in UI
    return null;
  }
  const record = _findRecord(listId);

  files.forEach(file=>{
    const sz=file.size>1048576?(file.size/1048576).toFixed(1)+'MB':(file.size/1024).toFixed(0)+'KB';
    const reader=new FileReader();
    reader.onload=function(e){
      const dataUrl=e.target.result;
      const key='doc-'+Date.now()+'-'+Math.random().toString(36).slice(2,7);
      const docObj={name:file.name, size:sz, type:file.type, dataUrl, _key:key};
      // Register in store for view/download
      _DOC_STORE[key]={dataUrl, name:file.name, type:file.type};
      // Persist on the D.* record if we have one
      if(record){ if(!record.docs) record.docs=[]; record.docs.push({name:file.name,size:sz,_key:key,dataUrl}); }
      // Render chip in the UI
      const wrap=document.createElement('div');
      wrap.innerHTML=docChip(docObj);
      list.appendChild(wrap.firstChild);
    };
    reader.readAsDataURL(file);
  });
  toast(files.length+' document'+(files.length>1?'s':'')+' attached ✓','success');
}

function shareDoc(name){
  const url=window.location.href.split('?')[0]+'?doc='+encodeURIComponent(name);
  if(navigator.clipboard){navigator.clipboard.writeText(url).then(()=>toast('Share link copied ✓','success')).catch(()=>toast('Link: '+url));}
  else{toast('Share link: '+url);}
}

