// Send WA overdue reminder for a rental — always looks up fresh customer phone
function _rentalWARemind(id){
  var r = D.rentals.find(function(x){return x.id===id;});
  if(!r){ toast('Rental not found','error'); return; }
  // Look up fresh phone from D.cust (picks up any edits)
  var cust = D.cust.find(function(c){return c.id===r.custId||c.name===r.cust;});
  var ph = (cust&&(cust.whatsapp||cust.phone||cust.ph)||'').replace(/[^0-9]/g,'');
  if(!ph){ toast('No phone number for '+r.cust+'. Please edit the customer and add a phone number.','error'); return; }
  var custName = (cust&&cust.name)||r.cust||'Customer';
  var msg = 'Hi '+custName.split(' ')[0]+'! Your rental from *'+BIZ.name+'* is overdue.\n\n'
    + 'Item: '+r.item+'\n'
    + 'Due date: '+r.due+'\n'
    + (r.lf>0?'Late fee: '+fmt(r.lf)+'\n':'')
    + '\nPlease return or contact us to arrange. Thank you!\n'
    + '_'+BIZ.name+'_';
  _sendWA(ph, msg);
  addAudit('Rental overdue WA reminder sent', id+' — '+r.cust);
}

function _crFillPhone(){
  const custId = (document.getElementById('cr-cust-sel')||{}).value||document.getElementById('cr-cust')?.value||(document.getElementById('cr-cust-sel')||{}).value||document.getElementById('cr-cust')?.value||_ssGetVal('cr-cust-wrap') || (document.getElementById('cr-cust-sel')||document.getElementById('cr-cust')||{}).value || '';
  const cust = D.cust.find(c=>c.id===custId);
  const ph = cust ? (cust.phone||cust.whatsapp||'') : '';
  const phEl = document.getElementById('cr-phone');
  if(phEl) phEl.value = ph;
}

function _crAddLine(){
  var row=document.createElement('div');
  row.className='cr-line-row';
  row.style.cssText='display:grid;grid-template-columns:1fr auto;gap:6px;margin-bottom:6px;align-items:center';
  var rentable=D.inv.filter(function(i){return (i.st==='For Rent'||i.st==='Both')&&((i.qty||0)-(i.rented||0))>0;});
  var opts=rentable.map(function(i){
    return '<option value="'+i.id+'" data-rp="'+Math.round((i.rp||0)*CUR.rate)+'" data-dep="'+Math.round((i.dep||0)*CUR.rate)+'" data-name="'+i.name+'">'
      +i.name+' ('+((i.qty||0)-(i.rented||0))+' avail)'+(i.rp?' — '+fmt(i.rp)+'/day':'')+' </option>';
  }).join('');
  row.innerHTML='<select class="fs cr-item-sel" onchange="_crLineChange(this)"><option value="">-- Select Item --</option>'+opts+'</select>'
    +'<button type="button" class="btn btn-d btn-xs" onclick="_crRemoveLine(this)" style="padding:6px 8px">✕</button>';
  var c=document.getElementById('cr-line-rows');if(c)c.appendChild(row);
}
function _crRemoveLine(btn){
  var row=btn.closest('.cr-line-row');
  var c=document.getElementById('cr-line-rows');
  if(c&&c.querySelectorAll('.cr-line-row').length>1){row.remove();_crUpdateFee();}
  else{var s=row.querySelector('.cr-item-sel');if(s)s.value='';_crUpdateFee();}
}
function _crLineChange(sel){
  _crUpdateFee();
}
function _crUpdateFee(){
  // Sum fees and max deposit across all selected rental items
  var totalFee=0, maxDep=0;
  document.querySelectorAll('#cr-line-rows .cr-item-sel').forEach(function(s){
    if(!s.value) return;
    var opt=s.options[s.selectedIndex];
    totalFee+=parseFloat(opt.dataset.rp)||0;
    maxDep=Math.max(maxDep, parseFloat(opt.dataset.dep)||0);
  });
  var feeEl=document.getElementById('cr-fee'); if(feeEl&&totalFee) feeEl.value=totalFee;
  var depEl=document.getElementById('cr-dep'); if(depEl&&maxDep) depEl.value=maxDep;
}
