// ── Init contract settings tab when it first opens ───────────
function _initContractTab(){
  const bodyEl  = document.getElementById('contract-body-input');
  const titleEl = document.getElementById('contract-title-input');
  const tog     = document.getElementById('contract-enabled-toggle');
  const track   = document.getElementById('contract-toggle-track');
  const thumb   = document.getElementById('contract-toggle-thumb');
  const wrap    = document.getElementById('contract-body-wrap');
  if(bodyEl&&!bodyEl.value)  bodyEl.value  = BIZ.contractTemplate||_CONTRACT_DEFAULT;
  if(titleEl&&!titleEl.value) titleEl.value = BIZ.contractTitle||'RENTAL AGREEMENT';
  if(tog){
    tog.checked = BIZ.contractEnabled!==false;
    _updateContractToggle(tog.checked, track, thumb, wrap);
    tog.onchange = function(){
      BIZ.contractEnabled = this.checked;
      _updateContractToggle(this.checked, track, thumb, wrap);
    };
  }
}
function _updateContractToggle(on, track, thumb, wrap){
  if(track){ track.style.background = on?'var(--p)':'var(--bg4)'; }
  if(thumb){ thumb.style.transform = on?'translateX(16px)':'translateX(0)'; thumb.style.background=on?'#fff':'var(--text2)'; }
  if(wrap){  wrap.style.opacity=on?'1':'.45'; wrap.style.pointerEvents=on?'':'none'; }
}

function rdTab(el, showId){
  const box = el.closest('.mo-body')||el.closest('.mo-box');
  if(box){
    box.querySelectorAll('.stab').forEach(b=>b.classList.remove('on'));
    // hide all tab panels
    const base = showId.replace(/timeline|docs/,'');
    ['timeline','docs'].forEach(t=>{
      const p=document.getElementById(showId.replace(/timeline|docs/,t));
      if(p) p.style.display='none';
    });
  }
  el.classList.add('on');
  const panel=document.getElementById(showId);
  if(panel) panel.style.display='';
}

// ============================================================
// PURCHASES
// ============================================================
function pgPurchases(){const _ui=_L();
  // Default to month — keep KPIs in sync with visible rows on load
  const monthRange = PERIOD_RANGES['month'];
  const vis   = D.purchases.filter(p => inRange(p.dt, monthRange));
  const totalSpent = vis.reduce((a,p)=>a+(p.total||0), 0);
  const apOut      = D.vendors.filter(v=>v.bal>0).reduce((a,v)=>a+v.bal, 0);
  const pending    = vis.filter(p=>p.st==='Pending'||p.st==='Partial').length;
  const paid       = vis.filter(p=>p.st==='Paid'||p.st==='Received').length;

  // Vendor breakdown for this month
  const vMap = {};
  vis.forEach(p=>{ vMap[p.vendor]=(vMap[p.vendor]||0)+(p.total||0); });
  const vSorted = Object.entries(vMap).sort((a,b)=>b[1]-a[1]);
  const topVendor = vSorted[0];

  const vBreakdown = vSorted.length
    ? vSorted.map(function([v,val]){
        const pct = totalSpent>0 ? Math.round(val/totalSpent*100) : 0;
        const barW= totalSpent>0 ? Math.round(val/vSorted[0][1]*100) : 0;
        return '<div style="margin-bottom:10px">'
          +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px">'
            +'<span style="font-size:12px;font-weight:600;color:var(--ink)">'+_esc(v)+'</span>'
            +'<span style="font-size:11px;color:var(--text2)">'+fmt(val)+' <span style="margin-left:4px">'+pct+'%</span></span>'
          +'</div>'
          +'<div style="background:var(--border);border-radius:3px;height:5px">'
            +'<div style="background:var(--b);border-radius:3px;height:5px;width:'+barW+'%;transition:width .4s"></div>'
          +'</div>'
        +'</div>';
      }).join('')
    : '<div style="font-size:12px;color:var(--text2);padding:8px 0">No purchases this month.</div>';

  // Build table rows
  const rows = D.purchases.map(p => {
    const landedCosts = (p.freight||0)+(p.duties||0)+(p.taxes||0)+(p.other||0);
    const costBreak = landedCosts > 0
      ? '<span style="font-size:10px;color:var(--text2);display:block;margin-top:1px">+'+fmt(landedCosts)+' landed</span>'
      : '';
    const statusBadge = badge(p.st);
    const isUnpaid = p.st==='Pending'||p.st==='Partial'||p.st==='Unpaid';
    return '<tr data-date="'+p.dt+'" data-vendor="'+_esc(p.vendor)+'" data-st="'+(p.st||'')+'"'
      +' class="po-row" style="cursor:pointer" onclick="mViewPurchase(\''+p.id+'\')">'
      +'<td>'+mono(p.id,'a')+'</td>'
      +'<td style="color:var(--text2);white-space:nowrap">'+p.dt+'</td>'
      +'<td style="font-weight:600;color:var(--ink)">'+_esc(p.vendor)+'</td>'
      +'<td style="font-size:12px;color:var(--text);max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap"'
        +' title="'+_esc(p.items||'')+'">'+_esc((p.items||'').slice(0,60))+(p.items&&p.items.length>60?'…':'')+'</td>'
      +'<td>'+mono(fmt(p.sub),'a')+costBreak+'</td>'
      +'<td>'+mono(fmt(p.total),'b')+'</td>'
      +'<td>'+statusBadge+(isUnpaid?'<span style="display:block;font-size:10px;color:var(--r);margin-top:1px">AP '+fmt(p.total)+'</span>':'')+'</td>'
      +'<td style="font-size:11px;color:var(--text2)">'+_esc(p.method||'—')+'</td>'
      +'<td onclick="event.stopPropagation()">'
        +'<div class="btn-row">'
          +'<button class="btn btn-g btn-xs" onclick="mEditPurchase(\''+p.id+'\')" title="Edit">✏</button>'
          +'<button class="btn btn-g btn-xs" onclick="genPODoc(\''+p.id+'\')" title="Print PO">🖨</button>'
          +'<button class="btn btn-d btn-xs" onclick="deletePurchase(\''+p.id+'\')" title="Delete">🗑</button>'
        +'</div>'
      +'</td>'
    +'</tr>';
  }).join('');

  return `
<div class="ph">
  <div class="bc">ShopTrack / <span>${_ui.nav_purchases}</span></div>
  <div class="ph-row"><h1>${_ui.nav_purchases}</h1>
    <div class="btn-row">
      <button class="btn btn-s btn-sm" onclick="exportPurchasesCSV()">⬇ CSV</button>
      <button class="btn btn-g btn-sm" onclick="exportPurchasesPDF()">⬇ PDF</button>
      <button class="btn btn-p btn-sm" onclick="mRecordPurchase()">${_ui.btn_new_po}</button>
    </div>
  </div>
  <p>${_ui.ph_purchases}</p>
</div>

<div class="kpi-grid" style="grid-template-columns:repeat(auto-fill,minmax(155px,1fr));margin-bottom:14px">
  <div class="kpi b"><div class="kpi-lbl">Total Spent</div><div id="po-kpi-total" class="kpi-val b">${fmtKpi(totalSpent)}</div><div class="kpi-sub">This month</div></div>
  <div class="kpi r"><div class="kpi-lbl">AP Outstanding</div><div id="po-kpi-ap" class="kpi-val r">${fmtKpi(apOut)}</div><div class="kpi-sub">Owed to suppliers</div></div>
  <div class="kpi y"><div class="kpi-lbl">Pending</div><div id="po-kpi-pending" class="kpi-val y">${pending}</div><div class="kpi-sub">Awaiting delivery</div></div>
  <div class="kpi g"><div class="kpi-lbl">Paid/Received</div><div id="po-kpi-paid" class="kpi-val g">${paid}</div><div class="kpi-sub">Completed</div></div>
  ${topVendor?`<div class="kpi b"><div class="kpi-lbl">Top Supplier</div><div class="kpi-val" style="font-size:13px;color:var(--b)">${_esc(topVendor[0])}</div><div class="kpi-sub">${fmt(topVendor[1])}</div></div>`:''}
</div>

<div style="display:grid;grid-template-columns:1fr 240px;gap:14px;align-items:start">
  <div>
    <div class="fbar" style="margin-bottom:10px">
      <input class="fi-s" id="po-search" placeholder="${_ui.flt_search_po}" style="flex:1;min-width:120px" oninput="_poFilter()"/>
      <select class="sel" id="po-vendor-filter" onchange="_poFilter()">
        <option value="">${_ui.flt_all_vendors}</option>
        ${[...new Set(D.purchases.map(p=>p.vendor).filter(Boolean))].sort().map(v=>`<option value="${_esc(v)}">${_esc(v)}</option>`).join('')}
      </select>
      <select class="sel" id="po-st-filter" onchange="_poFilter()">
        <option value="">${_ui.flt_all_status}</option>
        <option value="Pending">Pending</option>
        <option value="Partial">Partial</option>
        <option value="Paid">Paid</option>
        <option value="Received">Received</option>
        <option value="Unpaid">Unpaid</option>
      </select>
      <div class="dtabs">
        <button class="dtab" onclick="setPurchasesPeriod(this,'today')">${_ui.per_today}</button>
        <button class="dtab" onclick="setPurchasesPeriod(this,'week')">${_ui.per_week}</button>
        <button class="dtab" onclick="setPurchasesPeriod(this,'lastweek')">${_ui.per_lastweek}</button>
        <button class="dtab on" onclick="setPurchasesPeriod(this,'month')">${_ui.per_month}</button>
        <button class="dtab" onclick="setPurchasesPeriod(this,'lastmonth')">${_ui.per_lastmonth}</button>
        <button class="dtab" onclick="setPurchasesPeriod(this,'quarter')">${_ui.per_quarter}</button>
        <button class="dtab" onclick="setPurchasesPeriod(this,'ytd')">${_ui.per_ytd}</button>
      </div>
    </div>
    <div class="card" style="padding:0">
      <div class="tbl-wrap"><table id="po-table">
        <thead><tr>
          <th>PO #</th><th>Date</th><th>Vendor</th><th>Items</th>
          <th>Subtotal</th><th>Total Landed</th><th>Status</th><th>Method</th><th></th>
        </tr></thead>
        <tbody id="po-tbody">${rows}</tbody>
      </table></div>
      <div id="po-empty" style="display:none;text-align:center;padding:40px 20px;color:var(--text2)">
        <div style="font-size:32px;margin-bottom:10px">📦</div>
        <div style="font-size:14px;font-weight:600;color:var(--ink);margin-bottom:6px">No purchase orders found</div>
        <div style="font-size:12px;margin-bottom:14px">Try adjusting the filters or date range</div>
        <button class="btn btn-p btn-sm" onclick="mRecordPurchase()">+ New Purchase Order</button>
      </div>
      <div id="po-footer" style="display:flex;justify-content:space-between;align-items:center;padding:10px 16px;border-top:1px solid var(--border);font-size:12px;color:var(--text2)">
        <span id="po-footer-count"></span>
        <span>Total landed: <strong id="po-footer-total" style="font-family:var(--mono);color:var(--b)"></strong></span>
      </div>
    </div>
  </div>

  <div>
    <div class="card">
      <div class="card-hd" style="padding-bottom:8px">
        <div class="card-ttl" style="font-size:12px">By Vendor</div>
        <span id="po-breakdown-period" style="font-size:10px;color:var(--text2)">This month</span>
      </div>
      <div id="po-vendor-breakdown" style="padding:4px 0">${vBreakdown}</div>
    </div>
    <div class="card" style="margin-top:14px">
      <div class="card-hd" style="padding-bottom:8px">
        <div class="card-ttl" style="font-size:12px">Quick Actions</div>
      </div>
      <div style="display:flex;flex-direction:column;gap:7px">
        <button class="btn btn-p btn-sm" onclick="mRecordPurchase()" style="width:100%">+ New Purchase Order</button>
        <button class="btn btn-s btn-sm" onclick="nav('vendors')" style="width:100%">👥 Manage Vendors</button>
        <button class="btn btn-s btn-sm" onclick="exportPurchasesCSV()" style="width:100%">⬇ Export CSV</button>
        <button class="btn btn-g btn-sm" onclick="exportPurchasesPDF()" style="width:100%">⬇ Export PDF</button>
      </div>
    </div>
  </div>
</div>`;
}


function mRecordPurchase(){
  const today=localDateStr();
  const delivery=localDateStr(10);
  const sym=CUR.symbol;
  modal('Record Purchase Order',`
  <div class="fg-2">
    <div class="fg">
    ${_newVendorBtnHTML('po')}
      <div id="po-vendor-wrap" style="position:relative"></div><input type="hidden" id="po-vendor" value=""/>
    ${_inlineVendorFormHTML('po')}
    </div>
    <div class="fg"><label class="fl">Order Date</label><input class="fi" type="date" id="po-dt" value="${today}"/></div>
    <div class="fg"><label class="fl">Expected Delivery</label><input class="fi" type="date" id="po-delivery" value="${delivery}"/></div>
    <div class="fg"><label class="fl">PO Reference</label><input class="fi" id="po-ref" placeholder="Auto-generated if blank"/></div>
  </div>
  <div class="fg">
    <label class="fl" style="margin-bottom:6px">Items Ordered *
      <span style="font-size:10px;color:var(--a);margin-left:6px;cursor:pointer" onclick="_mPush('po-inv-0');mAddItem('po-inv-0')">+ New Item</span>
    </label>
    <div id="po-line-rows">
      <div class="po-line-row" style="display:grid;grid-template-columns:1fr auto auto auto;gap:6px;margin-bottom:6px;align-items:center">
        <select class="fs po-inv-sel" onchange="_poLineChange(this)">
          <option value="">-- Link to inventory (optional) --</option>
          ${D.inv.map(i=>`<option value="${i.id}" data-cost="${Math.round((i.cost||0)*CUR.rate)}" data-name="${i.name}${i.sku?' ('+i.sku+')':''}">${i.name} (stock: ${i.qty||0}) — ${fmt(i.cost||0)}/unit</option>`).join('')}
          <option value="__custom__">── Custom / not in inventory ──</option>
        </select>
        <input class="fi po-line-qty" type="number" value="1" min="1" style="width:56px;text-align:center" placeholder="Qty" oninput="_poRecalcTotal()"/>
        <input class="fi po-line-cost" type="number" placeholder="Unit cost" style="width:90px" oninput="_poRecalcTotal()"/>
        <button type="button" class="btn btn-d btn-xs" onclick="_poRemoveLine(this)" style="padding:6px 8px">✕</button>
      </div>
    </div>
    <button type="button" class="btn btn-s btn-sm" style="margin-top:4px" onclick="_poAddLine()">+ Add Item</button>
  </div>
  <div class="fg-2">
    <div class="fg"><label class="fl">Description / Notes</label><input class="fi" id="po-items" placeholder="e.g. Bridal Wigs ×6 — auto-filled"/></div>
    <div class="fg"><label class="fl">Freight <span style="font-size:10px;color:var(--text2)">(${sym})</span></label>
      <input class="fi" type="number" id="po-freight" placeholder="0" step="any" oninput="_poRecalcTotal()"/>
    </div>
    <div class="fg"><label class="fl">Import Duties <span style="font-size:10px;color:var(--text2)">(${sym})</span></label>
      <input class="fi" type="number" id="po-duties" placeholder="0" step="any" oninput="_poRecalcTotal()"/>
    </div>
    <div class="fg"><label class="fl">Taxes <span style="font-size:10px;color:var(--text2)">(${sym})</span></label>
      <input class="fi" type="number" id="po-taxes" placeholder="0" step="any" oninput="_poRecalcTotal()"/>
    </div>
    <div class="fg"><label class="fl">Other Costs <span style="font-size:10px;color:var(--text2)">(${sym})</span></label>
      <input class="fi" type="number" id="po-other" placeholder="0" step="any" oninput="_poRecalcTotal()"/>
    </div>
    <div class="fg">
      <label class="fl" style="color:var(--g);font-weight:700">Total Cost <span style="font-size:10px;color:var(--text2);font-weight:400">(${sym}) — becomes inventory value</span></label>
      <input class="fi" type="number" id="po-total" placeholder="0" readonly style="background:var(--a-dim);color:var(--g);font-weight:700;cursor:default"/>
    </div>
    <div class="fg"><label class="fl">Payment Status</label>
      <select class="fs" id="po-st"><option>Pending</option><option>Partial</option><option>Paid</option></select>
    </div>
    <div class="fg"><label class="fl">Payment Method</label>
      <select class="fs" id="po-method"><option>Bank Transfer</option><option>Cash</option><option>Mobile Money (MTN)</option><option>Orange Money</option><option>Credit Card</option></select>
    </div>
  </div>
  <div class="fg"><label class="fl">Notes</label><textarea class="ft" id="po-notes" placeholder="Notes to vendor…" style="min-height:48px"></textarea></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="savePO()">Create PO</button>`);
}

function savePO(){
  if(_trialWriteBlocked('Creating a purchase order')) return;
  var vendorId=(document.getElementById('po-vendor-sel')||{}).value||document.getElementById('po-vendor')?.value||(document.getElementById('po-vendor-sel')||{}).value||document.getElementById('po-vendor')?.value||_ssGetVal('po-vendor-wrap')||'';
  if(!vendorId){toast('Please select a vendor','error');return;}
  var rr=CUR.rate;
  // Collect line rows
  var poLines=Array.from(document.querySelectorAll('#po-line-rows .po-line-row')).map(function(row){
    var sel=row.querySelector('.po-inv-sel');
    var qty=parseFloat(row.querySelector('.po-line-qty')?.value)||1;
    var uc=parseFloat(row.querySelector('.po-line-cost')?.value)||0;
    var invId2=sel?sel.value:'';
    var opt=sel?sel.options[sel.selectedIndex]:null;
    var name=(opt&&opt.dataset.name)?opt.dataset.name:(invId2==='__custom__'?'Custom':'');
    return {invId:invId2,qty,uc,name};
  }).filter(function(r){return r.uc>0||r.invId;});
  var sub=poLines.reduce(function(a,r){return a+r.qty*r.uc;},0)/rr;
  var totalQty=poLines.reduce(function(a,r){return a+r.qty;},0)||1;
  var items=document.getElementById('po-items').value.trim();
  if(!items) items=poLines.map(function(r){return (r.qty>1?r.qty+'× ':'')+r.name;}).filter(Boolean).join(', ')||'Order';
  var freight=(parseFloat(document.getElementById('po-freight').value)||0)/rr;
  var duties=(parseFloat(document.getElementById('po-duties').value)||0)/rr;
  var taxes=(parseFloat(document.getElementById('po-taxes').value)||0)/rr;
  var other=(parseFloat(document.getElementById('po-other').value)||0)/rr;
  var total=sub+freight+duties+taxes+other;
  if(!total&&!items){toast('Please add at least one item with a cost','error');return;}
  var vendorObj=D.vendors.find(function(x){return x.id===vendorId;});
  var vendor=vendorObj?vendorObj.name:vendorId;
  var poSt=document.getElementById('po-st').value;
  var poRef=document.getElementById('po-ref').value.trim();
  var _mxPN=D.purchases.reduce(function(m,p){var n=parseInt((p.id||'').replace(/[^0-9]/g,''),10)||0;return n>m?n:m;},0);
  var newId=poRef||('P-'+String(_mxPN+1).padStart(4,'0'));
  // Update inventory stock for all linked items
  poLines.forEach(function(li){
    if(li.invId&&li.invId!=='__custom__'){
      var invObj=D.inv.find(function(x){return x.id===li.invId;});
      if(invObj){
        invObj.qty=(invObj.qty||0)+li.qty;
        if(poSt==='Paid'&&li.uc) invObj.cost=Math.round((li.uc/rr)*10000)/10000;
      }
    }
  });
  var invId=(poLines.find(function(r){return r.invId&&r.invId!=='__custom__';})||{invId:''}).invId;
  var qty=totalQty;
  if(vendorObj){vendorObj.orders=(vendorObj.orders||0)+1;vendorObj.total=(vendorObj.total||0)+total;} // v.bal recomputed by _reconcileVendorTotals in refreshLiveKpis
  D.purchases.unshift({id:newId,vendor,vendorId,items,qty,dt:document.getElementById('po-dt').value,delivery:document.getElementById('po-delivery').value,sub,freight,duties,taxes,other,total,invId,lines:poLines,st:poSt,method:document.getElementById('po-method').value,notes:document.getElementById('po-notes').value,docs:[]});
  _dbSavePurchase(D.purchases[0]);
  refreshLiveKpis();
  addAudit('PO created',newId+' - '+vendor+' - '+fmt(total));
  closeModal();
  toast(newId+' created — '+fmt(total),'success');
  nav('purchases');
}

function mViewPurchaseDocs(id){
  const p=D.purchases.find(x=>x.id===id); if(!p) return;
  const uid='po-vdoc-'+id;
  modal(`📎 Documents — ${p.id}`,`
  <div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0 14px;border-bottom:1px solid var(--border);margin-bottom:14px">
    <div>
      <div style="font-weight:600;color:var(--ink)">${p.vendor}</div>
      <div style="font-size:11px;color:var(--text2)">${p.dt} · ${p.items}</div>
    </div>
    <div style="font-family:var(--mono);font-weight:700;color:var(--b)">${fmt(p.total)}</div>
  </div>
  <div class="fl" style="margin-bottom:8px">Attached Documents</div>
  <div id="${uid}-list" style="display:flex;flex-wrap:wrap;gap:7px;margin-bottom:10px">
    ${p.docs&&p.docs.length?p.docs.map(d=>docChip(d)).join(''):`<div style="font-size:12px;color:var(--text2);padding:6px 0">No documents attached yet.</div>`}
  </div>
  <label style="display:flex;align-items:center;gap:10px;border:2px dashed var(--border2);border-radius:var(--r6);padding:11px 14px;cursor:pointer;transition:border-color .15s" onmouseover="this.style.borderColor='var(--a)'" onmouseout="this.style.borderColor='var(--border2)'" onclick="document.getElementById('${uid}-input').click()">
    <span style="font-size:18px">➕</span>
    <div style="font-size:12px;font-weight:600;color:var(--ink)">Attach vendor invoice, delivery note, or customs docs</div>
    <input id="${uid}-input" type="file" accept="image/*,.pdf" multiple style="display:none" onchange="handleDocAttach(this,'${uid}-list')"/>
  </label>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button>
   <button class="btn btn-g btn-sm" onclick="mViewPurchase('${id}')">View PO</button>
   <button class="btn btn-p btn-sm" onclick="genPODoc('${id}')">🖨 Print PO</button>`);
}


function pgCust(){const _ui=_L();
  const totalAR     = D.cust.filter(c=>c.bal>0).reduce((a,c)=>a+c.bal,0);
  const totalSpend  = D.cust.reduce((a,c)=>a+(c.spend||c.spent||0),0);
  const vipCount    = D.cust.filter(c=>c.type==='VIP'||c.tier==='VIP'||c.vip).length;
  const withBalance = D.cust.filter(c=>c.bal>0).length;

  const rows = D.cust.map(function(c){
    const name    = c.name||'—';
    const initials= name.split(' ').filter(Boolean).map(function(n){return n[0]||'';}).join('').slice(0,2).toUpperCase()||'?';
    const phone   = c.ph||c.phone||'';
    const type    = c.type||c.tier||'Regular';
    const spend   = c.spend||c.spent||0;
    return '<tr data-name="'+(name).toLowerCase()+'" data-email="'+(c.email||'').toLowerCase()+'" data-type="'+type+'" data-bal="'+(c.bal>0?'outstanding':'cleared')+'"'
      +' style="cursor:pointer" onclick="mViewCustomer(\''+c.id+'\')">'
      +'<td>'
        +'<div style="display:flex;align-items:center;gap:9px">'
          +'<div style="width:32px;height:32px;background:linear-gradient(135deg,var(--a),var(--p));border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:#fff;flex-shrink:0">'+initials+'</div>'
          +'<div>'
            +'<div style="font-weight:600;color:var(--ink);font-size:13px">'+_esc(name)+'</div>'
            +(c.notes?'<div style="font-size:10px;color:var(--text2)">'+_esc(c.notes.slice(0,35))+(c.notes.length>35?'…':'')+'</div>':'')
          +'</div>'
        +'</div>'
      +'</td>'
      +'<td>'
        +'<div style="font-size:12px;color:var(--text)">'+_esc(c.email||'—')+'</div>'
        +'<div style="font-size:11px;color:var(--text2)">'+_esc(phone||'—')+'</div>'
      +'</td>'
      +'<td>'+badge(type)+'</td>'
      +'<td>'+mono(c.bal>0?fmt(c.bal):'—',c.bal>0?'r':'text3')+'</td>'
      +'<td>'+mono(fmt(spend),'g')+'</td>'
      +'<td style="color:var(--text2);font-size:12px">'+_esc(c.last||'—')+'</td>'
      +'<td onclick="event.stopPropagation()">'
        +'<div class="btn-row">'
          +'<button class="btn btn-g btn-xs" onclick="mEditCustomer(\''+c.id+'\')">✏</button>'
          +(c.bal>0?'<button class="btn btn-p btn-xs" onclick="mCollectBalance(\''+c.id+'\')" title="Collect outstanding balance">💰</button>':'')
          +'<button class="btn btn-g btn-xs" onclick="mCustomerStatement(\''+c.id+'\')" title="Statement">📄</button>'
          +(phone?'<button class="btn btn-g btn-xs" onclick="_arSendWA(\''+c.id+'\')" title="WhatsApp">💬</button>':'')
          +'<button class="btn btn-d btn-xs" onclick="mDeleteCustomer(\''+c.id+'\')">🗑</button>'
        +'</div>'
      +'</td>'
    +'</tr>';
  }).join('');

  return `
<div class="ph">
  <div class="bc">ShopTrack / <span>${_ui.nav_customers}</span></div>
  <div class="ph-row"><h1>${_ui.nav_customers}</h1>
    <div class="btn-row">
      <button class="btn btn-s btn-sm" onclick="exportCustomersCSV()">⬇ CSV</button>
      <button class="btn btn-g btn-sm" onclick="exportCustomersPDF()">⬇ PDF</button>
      <button class="btn btn-p btn-sm" onclick="mAddCustomer()">${_ui.btn_add_cust}</button>
    </div>
  </div>
  <p>${_ui.ph_customers}</p>
</div>

<div class="kpi-grid" style="grid-template-columns:repeat(auto-fill,minmax(150px,1fr));margin-bottom:14px">
  <div class="kpi b"><div class="kpi-lbl">Total Customers</div><div class="kpi-val b">${D.cust.length}</div><div class="kpi-sub">${_ui.kpi_all_time}</div></div>
  <div class="kpi g"><div class="kpi-lbl">Lifetime Spend</div><div class="kpi-val g">${fmtKpi(totalSpend)}</div><div class="kpi-sub">${_ui.kpi_all_customers}</div></div>
  <div class="kpi r" style="cursor:pointer" onclick="document.getElementById('cust-bal-filter').value='outstanding';filterCustTable()"><div class="kpi-lbl">AR Outstanding</div><div class="kpi-val r">${fmtKpi(totalAR)}</div><div class="kpi-sub">${withBalance} customer${withBalance!==1?'s':''}</div></div>
  <div class="kpi p" style="cursor:pointer" onclick="document.getElementById('cust-type-filter').value='VIP';filterCustTable()"><div class="kpi-lbl">VIP Customers</div><div class="kpi-val p">${vipCount}</div><div class="kpi-sub">Click to filter</div></div>
</div>

<div class="fbar" style="margin-bottom:10px">
  <input class="fi-s" id="cust-search" placeholder="${_ui.flt_search_cust}" style="flex:1;min-width:160px" oninput="filterCustTable()"/>
  <select class="sel" id="cust-type-filter" onchange="filterCustTable()">
    <option value="">${_ui.flt_all_type}</option><option>VIP</option><option>Regular</option><option>New</option>
  </select>
  <select class="sel" id="cust-bal-filter" onchange="filterCustTable()">
    <option value="">${_ui.flt_all_bal}</option>
    <option value="outstanding">${_ui.flt_outstanding}</option>
    <option value="cleared">${_ui.flt_cleared}</option>
  </select>
</div>

<div class="card" style="padding:0">
  <div class="tbl-wrap"><table id="cust-table">
    <thead><tr><th>Customer</th><th>Contact</th><th>Type</th><th>Outstanding</th><th>Total Spend</th><th>Last Activity</th><th>Actions</th></tr></thead>
    <tbody id="cust-tbody">${rows}</tbody>
  </table></div>
  <div id="cust-empty" style="display:none;text-align:center;padding:40px 20px;color:var(--text2)">
    <div style="font-size:32px;margin-bottom:10px">👤</div>
    <div style="font-size:14px;font-weight:600;color:var(--ink);margin-bottom:6px">${_ui.empty_cust}</div>
    <div style="font-size:12px;margin-bottom:14px">${_ui.empty_filter_sub}</div>
    <button class="btn btn-p btn-sm" onclick="mAddCustomer()">${_ui.empty_first_cust}</button>
  </div>
  <div id="cust-footer" style="display:flex;justify-content:space-between;padding:10px 16px;border-top:1px solid var(--border);font-size:12px;color:var(--text2)">
    <span id="cust-footer-count"></span>
    <span>AR: <strong id="cust-footer-ar" style="font-family:var(--mono);color:var(--r)"></strong></span>
  </div>
</div>`;
}

function filterCustTable(){
  var q    = (document.getElementById('cust-search')?.value||'').toLowerCase();
  var type = document.getElementById('cust-type-filter')?.value||'';
  var bal  = document.getElementById('cust-bal-filter')?.value||'';
  var visible=0, visibleAR=0;
  document.querySelectorAll('#cust-tbody tr').forEach(function(row){
    var nameMatch  = !q || (row.dataset.name||'').includes(q) || (row.dataset.email||'').includes(q) || row.textContent.toLowerCase().includes(q);
    var typeMatch  = !type || row.dataset.type === type;
    var balMatch   = !bal  || row.dataset.bal  === bal;
    var show = nameMatch && typeMatch && balMatch;
    row.style.display = show ? '' : 'none';
    if(show){
      visible++;
      // Sum AR for visible rows
      const custId = row.querySelector('[onclick*="mViewCustomer"]')?.getAttribute('onclick')?.match(/'([^']+)'/)?.[1];
      if(custId){ const c=D.cust.find(x=>x.id===custId); if(c) visibleAR+=c.bal||0; }
    }
  });
  const emptyEl = document.getElementById('cust-empty');
  const tblEl   = document.getElementById('cust-table');
  if(emptyEl) emptyEl.style.display = visible===0 ? '' : 'none';
  if(tblEl)   tblEl.style.display   = visible===0 ? 'none' : '';
  const countEl = document.getElementById('cust-footer-count');
  const arEl    = document.getElementById('cust-footer-ar');
  if(countEl) countEl.textContent = visible+' customer'+(visible!==1?'s':'');
  if(arEl)    arEl.textContent    = fmt(visibleAR);
}

function mAddCustomer(_returnSelectId){
  const _retSel=_returnSelectId||null;
  modal('Add Customer',`
  <div class="fg-2">
    <div class="fg"><label class="fl">Full Name *</label><input class="fi" id="ac-name" placeholder="e.g. Jessica Williams"/></div>
    <div class="fg"><label class="fl">Type</label><select class="fs" id="ac-type"><option>Regular</option><option>VIP</option><option>New</option></select></div>
    <div class="fg"><label class="fl">Email</label><input class="fi" type="email" id="ac-email" placeholder="email"+'@'+"example.com"/></div>
    <div class="fg"><label class="fl">Phone</label><input class="fi" id="ac-phone" placeholder="${_ph('phonePh')}" data-locale="phone"/></div>
    <div class="fg"><label class="fl">WhatsApp</label><input class="fi" id="ac-whatsapp" placeholder="${_ph('phonePh')}" data-locale="phone"/></div>
    <div class="fg"><label class="fl">City</label><input class="fi" id="ac-city" placeholder="e.g. ${CUR_LOCALE[CUR.code]?.city||'City'}" data-locale="city"/></div>
  </div>
  <div class="fg"><label class="fl">Birthday <span style="font-size:10px;color:var(--text2);font-weight:400">Optional — enables reminders</span></label><input class="fi" type="date" id="ac-dob" placeholder=""/></div>
  <div class="fg"><label class="fl">Notes</label><textarea class="ft" id="ac-notes" placeholder="Any notes about this customer…" style="min-height:55px"></textarea></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="
    if(_trialWriteBlocked('Adding a customer')) return;
    if(!SESSION.isSuperAdmin && _getPlanTier()==='starter' && D.cust.length>=200){ _showUpsell('customers'); closeModal(); return; }
    var name=document.getElementById('ac-name').value.trim();
    if(!name){toast('Customer name is required','error');return;}
    var type=document.getElementById('ac-type').value;
    var _maxCNum=D.cust.reduce(function(m,c){var n=parseInt((c.id||'').replace(/\D/g,''),10)||0;return n>m?n:m;},0);
    var nid='C-'+String(_maxCNum+1).padStart(3,'0');
    var _ph=document.getElementById('ac-phone').value.trim();
    D.cust.unshift({
      id:nid, name:name,
      type:type, tier:type,  // save both so filter always works
      email:document.getElementById('ac-email').value.trim(),
      phone:_ph, ph:_ph, whatsapp:document.getElementById('ac-whatsapp').value.trim(),
      address:document.getElementById('ac-city').value.trim(),
      city:document.getElementById('ac-city').value.trim(),
      notes:document.getElementById('ac-notes').value.trim(),
      dob:(document.getElementById('ac-dob')||{}).value||'',
      vip:type==='VIP', st:'Active', spend:0, spent:0, bal:0,
      visits:0, orders:0, last:localDateStr()
    });
    _dbSaveCust(D.cust[0]);
    addAudit('Customer added',nid+' — '+name);
    if(D.cust.length===1&&D.inv.length>0&&D.sales.length>0) _track('Activated');
    toast(name+' added','success');
    if(window._retSelAC){
      var _selId = window._retSelAC;
      _mPopAndSelect(_selId, nid, name);
      window._retSelAC = null;
      // After restoring old modal, rebuild _mkSearchSelect widget with new customer
      setTimeout(function(){
        var wrapEl = document.getElementById(_selId);
        var hiddenId = _selId.replace('-wrap','');
        var hiddenEl = document.getElementById(hiddenId);
        if(wrapEl && typeof _mkSearchSelect==='function'){
          var opts=[{val:'',label:'-- Select customer --'}]
            .concat(D.cust.map(function(cu){return {val:cu.id,label:cu.name+(cu.phone?' ('+cu.phone+')':'')};}));
          _mkSearchSelect(_selId, opts, nid, function(val){
            if(hiddenEl) hiddenEl.value=val;
          });
        }
      }, 50);
    } else { closeModal(); nav('customers'); }
   ">Add Customer</button>`);
  window._retSelAC=_retSel;
}
