function _saveEditCustomer(id){
  if(_trialWriteBlocked('Editing a customer')) return;
  var c = D.cust.find(function(x){ return x.id===id; });
  if(!c) return;
  var name = document.getElementById('ec-name').value.trim();
  if(!name){ toast('Customer name is required','error'); return; }
  c.name     = name;
  c.type     = document.getElementById('ec-type').value;
  c.tier     = c.type; // keep tier in sync
  c.email    = document.getElementById('ec-email').value.trim();
  c.ph       = document.getElementById('ec-phone').value.trim();
  c.phone    = c.ph; // keep both fields in sync
  var _waVal = document.getElementById('ec-whatsapp').value.trim();
  c.whatsapp = _waVal || c.ph; // if WhatsApp blank, default to phone
  c.addr     = document.getElementById('ec-city').value.trim();
  c.city     = c.addr;
  c.address  = c.addr; // sync address alias for _custToDB
  c.notes    = document.getElementById('ec-notes').value.trim();
  c.dob      = document.getElementById('ec-dob')?.value||c.dob||'';
  c.vip      = c.type==='VIP';
  _dbSaveCust(D.cust.find(x=>x.id===id));
  addAudit('Customer updated', id+' — '+name);
  toast(name+' updated','success');
  closeModal();
  nav('customers');
}


