function mDeleteCustomer(id){
  var c=D.cust.find(function(x){return x.id===id;}); if(!c) return;
  var openSales=D.sales.filter(function(s){return s.custId===id&&s.st!=='Paid';});
  var activeRentals=D.rentals.filter(function(r){return r.custId===id&&!['Returned','Closed'].includes(r.st);});
  var allSales=D.sales.filter(function(s){return s.custId===id;});
  var allRentals=D.rentals.filter(function(r){return r.custId===id;});
  if(openSales.length||activeRentals.length){
    var blocking=[];
    if(openSales.length) blocking.push(openSales.length+' unpaid sale'+(openSales.length!==1?'s':''));
    if(activeRentals.length) blocking.push(activeRentals.length+' active rental'+(activeRentals.length!==1?'s':''));
    modal('Cannot Delete Customer',
      '<div class="alrt alrt-r" style="margin-bottom:10px"><strong>'+_esc(c.name)+'</strong> has '+blocking.join(' and ')+'.</div>'+
      '<p style="font-size:13px;color:var(--text2)">Settle all balances and return active rentals first.</p>',
      '<button class="btn btn-s" onclick="closeModal()">OK</button>'); return;
  }
  var warnLines=[];
  if(allSales.length) warnLines.push(allSales.length+' sale'+(allSales.length!==1?'s':''));
  if(allRentals.length) warnLines.push(allRentals.length+' rental'+(allRentals.length!==1?'s':''));
  if(c.bal>0) warnLines.push('balance of '+fmt(c.bal));
  var msg='<p style="font-size:13px;color:var(--text2);margin-bottom:8px">Delete <strong>'+_esc(c.name)+'</strong>?</p>';
  if(warnLines.length) msg+='<div class="alrt alrt-y">Has '+warnLines.join(', ')+'. Records preserved.</div>';
  var mid=id, mname=c.name;
  modal('Delete Customer — '+_esc(c.name), msg,
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'+
    '<button class="btn btn-d" id="confirm-del-cust-btn">Delete</button>');
  setTimeout(function(){
    var btn=document.getElementById('confirm-del-cust-btn');
    if(btn) btn.onclick=function(){
      D.cust=D.cust.filter(function(x){return x.id!==mid;});
      _dbDelCust(mid);
      addAudit('Customer deleted',mid+' — '+mname);
      closeModal(); toast(mname+' removed','success'); nav('customers');
    };
  },30);
}

function mCustomerStatement(id){
  const c=D.cust.find(x=>x.id===id);if(!c)return;
  // Match by both custId and name to catch all records
  const custSales = D.sales.filter(s=>s.custId===c.id||s.cust===c.name)
    .sort((a,b)=>b.dt.localeCompare(a.dt));
  const totalCharged = custSales.reduce((a,s)=>a+(s.total||s.amt||0),0);
  const totalPaid    = custSales.reduce((a,s)=>a+(s.paid||0),0);
  const phone = c.ph||c.phone||'';

  modal(`📄 Statement — ${_esc(c.name)}`,`
  <div style="background:var(--bg3);border-radius:var(--r10);padding:16px;margin-bottom:14px">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:14px">
      <div>
        <div style="font-family:var(--display);font-size:14px;font-weight:700;color:var(--ink)">Account Statement</div>
        <div style="font-size:11px;color:var(--text2);margin-top:2px">${_esc(BIZ.name||'ShopTrack')} · Generated ${new Date().toLocaleDateString('en-GB')}</div>
      </div>
      <div style="text-align:right">
        <div style="font-weight:600;color:var(--ink)">${_esc(c.name)}</div>
        <div style="font-size:11px;color:var(--text2)">${_esc(c.email||'—')}</div>
      </div>
    </div>
    ${custSales.length?custSales.map(s=>`
    <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid var(--border);font-size:12px;gap:8px">
      <span style="font-family:var(--mono);color:var(--a);flex-shrink:0">${s.id}</span>
      <span style="color:var(--text2);flex-shrink:0">${s.dt}</span>
      <span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${_esc(s.items||'')}</span>
      <span style="font-family:var(--mono);flex-shrink:0">${fmt(s.total||s.amt)}</span>
      ${badge(s.st)}
    </div>`).join('')
    :'<div style="font-size:12px;color:var(--text2);padding:8px 0">No sales records found.</div>'}
    <div style="display:flex;justify-content:space-between;padding-top:8px;margin-top:4px;border-top:1px solid var(--border)">
      <span style="font-size:12px;color:var(--text2)">Total Charged</span>
      <span style="font-family:var(--mono);color:var(--b)">${fmt(totalCharged)}</span>
    </div>
    <div style="display:flex;justify-content:space-between;padding-top:4px">
      <span style="font-size:12px;color:var(--text2)">Total Paid</span>
      <span style="font-family:var(--mono);color:var(--g)">${fmt(totalPaid)}</span>
    </div>
    <div style="display:flex;justify-content:space-between;padding-top:8px;border-top:2px solid var(--border);margin-top:6px">
      <span style="font-weight:700;color:var(--ink)">Outstanding Balance</span>
      <span style="font-family:var(--mono);font-size:15px;font-weight:800;color:${c.bal>0?'var(--r)':'var(--g)'}">${c.bal>0?fmt(c.bal):'All Clear ✓'}</span>
    </div>
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button>
   ${phone ? `<button class="btn btn-g btn-sm" onclick="_custStmtWA('${c.id}')">💬 WhatsApp</button>` : ''}
   <button class="btn btn-p" onclick="genCustomerStatementPDF('${c.id}')">⬇ Download PDF</button>`);
}

// ── WhatsApp from customer statement modal ─────────────────────
function _custStmtWA(custId){
  const c = D.cust.find(x=>x.id===custId); if(!c) return;
  const ph = (c.whatsapp||c.phone||c.ph||'').replace(/[^0-9]/g,'');
  if(!ph){ toast('No WhatsApp number on record for this customer','error'); return; }
  const firstName = (c.name||'').split(' ')[0]||'there';
  const msg = 'Hi '+firstName+', here is a summary of your account with '+(BIZ.name||'us')+'.'
    +(c.bal>0?' Outstanding balance: '+fmt(c.bal)+'. Please contact us to arrange payment.':' Your account is fully cleared. Thank you!')
    +' — '+(BIZ.name||'ShopTrack');
  _sendWA(ph, msg);
}

// ── Generate customer statement PDF (opens print window) ────────
function genCustomerStatementPDF(custId){
  const c = D.cust.find(x=>x.id===custId); if(!c) return;
  const L = _L();
  const fr = (BIZ.language||'en')==='fr';
  const custSales = D.sales
    .filter(s=>s.custId===c.id||s.cust===c.name)
    .sort((a,b)=>b.dt.localeCompare(a.dt));
  const totalCharged = custSales.reduce((a,s)=>a+(s.total||s.amt||0),0);
  const totalPaid    = custSales.reduce((a,s)=>a+(s.paid||0),0);
  const primary = BIZ.primaryColor||'#4f46e5';
  const locale = fr ? 'fr-FR' : 'en-GB';
  const now = new Date().toLocaleDateString(locale,{day:'2-digit',month:'long',year:'numeric'});
  const paidLabel = fr ? 'Payé ✓' : 'Paid ✓';
  const noTx = fr ? 'Aucune transaction enregistrée.' : 'No transactions on record.';
  const logoHtml = BIZ.logoDataUrl
    ? `<img src="${BIZ.logoDataUrl}" style="height:44px;width:auto;object-fit:contain;border-radius:6px"/>`
    : `<div style="width:44px;height:44px;background:${primary};border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:16px;font-weight:800;color:#fff">${(BIZ.name||'S').slice(0,2).toUpperCase()}</div>`;
  const rows = custSales.map((s,i)=>{
    const tot=s.total||s.amt||0; const bal=tot-(s.paid||0);
    return `<tr style="background:${i%2===0?'#f8fafc':'#ffffff'}">
      <td style="padding:8px 10px;font-family:monospace;color:#4f46e5;font-size:11px">${_esc(s.id)}</td>
      <td style="padding:8px 10px;color:#475569;font-size:11px">${s.dt}</td>
      <td style="padding:8px 10px;font-size:11px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${_esc(s.items||'')}</td>
      <td style="padding:8px 10px;font-family:monospace;text-align:right">${fmt(tot)}</td>
      <td style="padding:8px 10px;font-family:monospace;color:#10b981;text-align:right">${fmt(s.paid||0)}</td>
      <td style="padding:8px 10px;font-family:monospace;font-weight:700;color:${bal>0.01?'#dc2626':'#10b981'};text-align:right">${bal>0.01?fmt(bal):paidLabel}</td>
    </tr>`;
  }).join('');
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>${L.customerStatement} — ${_esc(c.name)}</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:'Segoe UI',Arial,sans-serif;font-size:13px;color:#1e293b;background:#fff;padding:32px}
  .header{display:flex;justify-content:space-between;align-items:flex-start;padding-bottom:18px;border-bottom:3px solid ${primary};margin-bottom:24px}
  .biz-name{font-size:18px;font-weight:800;color:#0f172a}
  .biz-sub{font-size:11px;color:#64748b;margin-top:2px}
  h2{font-size:14px;font-weight:800;color:${primary};text-transform:uppercase;letter-spacing:.5px;margin-bottom:20px}
  .summary{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:24px}
  .sum-box{border:1px solid #e2e8f0;border-radius:8px;padding:12px 14px;border-top:3px solid ${primary}}
  .sum-lbl{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.6px;color:#64748b;margin-bottom:4px}
  .sum-val{font-size:16px;font-weight:800;color:#0f172a;font-family:monospace}
  .sum-val.red{color:#dc2626}.sum-val.green{color:#10b981}
  table{width:100%;border-collapse:collapse;font-size:12px;margin-bottom:20px}
  thead tr{background:${primary};color:#fff}
  thead th{padding:9px 10px;text-align:left;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:.4px}
  thead th:last-child,thead th:nth-child(4),thead th:nth-child(5){text-align:right}
  tbody tr{border-bottom:1px solid #f1f5f9}
  .footer{margin-top:20px;padding-top:12px;border-top:1px solid #e2e8f0;display:flex;justify-content:space-between;font-size:10px;color:#94a3b8}
  @media print{body{padding:16px}}
</style></head><body>
<div class="header">
  <div style="display:flex;align-items:center;gap:14px">${logoHtml}<div><div class="biz-name">${_esc(BIZ.name||'ShopTrack')}</div><div class="biz-sub">${_esc(BIZ.address||'')} ${_esc(BIZ.email||'')} ${_esc(BIZ.phone||'')}</div></div></div>
  <div style="text-align:right"><div style="font-weight:700;font-size:14px;color:#0f172a">${_esc(c.name)}</div><div style="font-size:11px;color:#64748b">${_esc(c.email||'')} · ${_esc(c.ph||c.phone||'')}</div><div style="font-size:11px;color:#64748b;margin-top:2px">${_esc(c.city||c.address||'')}</div></div>
</div>
<h2>${L.customerStatement} · ${now}</h2>
<div class="summary">
  <div class="sum-box"><div class="sum-lbl">${L.totalCharged}</div><div class="sum-val">${fmt(totalCharged)}</div></div>
  <div class="sum-box"><div class="sum-lbl">${L.totalPaid}</div><div class="sum-val green">${fmt(totalPaid)}</div></div>
  <div class="sum-box"><div class="sum-lbl">${L.outstanding}</div><div class="sum-val ${c.bal>0?'red':'green'}">${c.bal>0?fmt(c.bal):(fr?'Soldé ✓':'Clear ✓')}</div></div>
</div>
<table>
  <thead><tr><th>${L.reference}</th><th>${L.date}</th><th>${L.description}</th><th>${L.amount}</th><th>${L.totalPaid}</th><th>${L.balDue}</th></tr></thead>
  <tbody>${rows||'<tr><td colspan="6" style="padding:14px;text-align:center;color:#94a3b8">'+noTx+'</td></tr>'}</tbody>
</table>
<div class="footer">
  <span>${L.generatedOn} ShopTrack · shoptrack.org · ${now}</span>
  <span>${L.customerStatement} — ${_esc(c.name)} · ${c.id}</span>
</div>
<script>window.onload=function(){window.print();}<\/script>
</body></html>`;
  const w = window.open('','_blank');
  if(w){ w.document.write(html); w.document.close(); }
  else { toast(fr?'Autorisez les pop-ups pour télécharger':'Allow pop-ups to download the PDF','error'); }
}

