function initAccounting(){
  setTimeout(function(){
    // Always kick off with the current _acctPeriod so chart matches the P&L rows
    const tab = document.querySelector('.dtabs .dtab.on');
    if(tab) setAcctPeriod(tab, _acctPeriod || 'month');
    else {
      const range = PERIOD_RANGES[_acctPeriod] || PERIOD_RANGES.month;
      const k = computeKPIs(range);
      const r = CUR.rate;
      mkChart('plChart',{type:'bar',data:{
        labels:['Revenue','COGS','Gross Profit','Overhead','Net Profit'],
        datasets:[{data:[k.rev,k.cogs,k.gp,k.oh,Math.max(0,k.np)].map(v=>Math.round(v*r)),
          backgroundColor:['rgba(91,127,255,.7)','rgba(255,95,122,.7)','rgba(45,212,160,.7)','rgba(245,200,66,.7)','rgba(159,122,234,.7)'],borderRadius:5}]},
        options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
          scales:{x:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11}},grid:{display:false}},
            y:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11},callback:v=>fmtRaw(v)},grid:{color:document.body.classList.contains('light')?'rgba(0,0,0,.07)':'rgba(255,255,255,.06)'}}}}});
    }
  }, 0);
}

// ============================================================
// REPORTS
// ============================================================
function pgReports(){const _ui=_L();
  // Use same period as Accounting page for consistency
  const _rptRange = PERIOD_RANGES[_acctPeriod] || PERIOD_RANGES.month;
  const lk = computeKPIs(_rptRange);
  const totalRev=lk.rev;
  const rRev=lk.rentRev; // rental revenue pre-computed (period-filtered)
  // Build revenue map by inventory category — PERIOD-FILTERED
  var _catRevMap={};
  lk.sales.forEach(function(s){
    var rev=s.total||s.amt||0; if(!rev) return;
    var matched=false;
    if(s.lineItems&&s.lineItems.length){
      s.lineItems.forEach(function(li){
        if(!li.invId||li.invId==='__custom__') return;
        var inv=D.inv.find(function(i){return i.id===li.invId;});
        if(inv&&inv.cat){
          _catRevMap[inv.cat]=(_catRevMap[inv.cat]||0)+((li.price||0)*(li.qty||1));
          matched=true;
        }
      });
    }
    if(!matched) _catRevMap['Other']=(_catRevMap['Other']||0)+rev;
  });
  // Add service revenue (already period-filtered in lk)
  if(lk.apptRev>0) _catRevMap['Services']=(_catRevMap['Services']||0)+lk.apptRev;
  // Sort categories by revenue, take top 3
  var _catArr=Object.entries(_catRevMap).sort(function(a,b){return b[1]-a[1];});
  var _top=_catArr.slice(0,3);
  var _restRev=_catArr.slice(3).reduce(function(a,e){return a+e[1];},0)+rRev;
  const gLabel=_top[0]?_top[0][0]:'Sales'; const gRev=_top[0]?_top[0][1]:0;
  const aLabel=_top[1]?_top[1][0]:'Services'; const aRev=_top[1]?_top[1][1]:0;
  const bLabel=_top[2]?_top[2][0]:'Other'; const bRev=_top[2]?_top[2][1]:0;
  const oLabel='Rentals & Other'; const oRev=_restRev;
  const gPct=totalRev>0?Math.min(99,Math.round(gRev/totalRev*100)):0;
  const aPct=totalRev>0?Math.min(99-gPct,Math.round(aRev/totalRev*100)):0;
  const rPct=totalRev>0?Math.round(rRev/totalRev*100):0;
  const oPct=Math.max(0,100-gPct-aPct-rPct);
  const groups=[
    {t:'Sales & Revenue',ico:'💰',reps:[
      {n:'Sales Report',fn:"rptSales()"},
      {n:'Revenue by Product',fn:"rptRevProduct()"},
      {n:'Revenue by Category',fn:"rptRevCat()"},
      {n:'Revenue by Customer',fn:"rptRevCust()"},
      {n:'Product Profitability',fn:"rptProfit()"}
    ]},
    {t:'Rental Reports',ico:'🕐',reps:[
      {n:'Rentals Report',fn:"rptRentals()"},
      {n:'Rental Utilization',fn:"rptRentalUtil()"},
      {n:'Deposit Liability',fn:"rptDeposits()"},
      {n:'Late Fees Report',fn:"rptLateFees()"},
      {n:'Overdue Rentals',fn:"rptOverdue()"}
    ]},
    {t:'Inventory',ico:'📦',reps:[
      {n:'Inventory Valuation',fn:"rptInvVal()"},
      {n:'Inventory Movement',fn:"rptInvMove()"},
      {n:'Low Stock Report',fn:"rptLowStock()"},
      {n:'Items Currently Rented',fn:"rptRentedOut()"},
      {n:'Stock by Category',fn:"rptStockCat()"}
    ]},
    {t:'Financial',ico:'📊',reps:[
      {n:'Gross Profit Report',fn:"rptGP()"},
      {n:'Net Profit Report',fn:"rptNP()"},
      {n:'Cash Flow Summary',fn:"rptCash()"},
      {n:'Monthly Financial Summary',fn:"rptMonthly()"},
      {n:'Expense Breakdown',fn:"rptExpBreak()"}
    ]},
    {t:'AR / AP',ico:'⚖️',reps:[
      {n:'AR Aging Report',fn:"rptAR()"},
      {n:'AP Aging Report',fn:"rptAP()"},
      {n:'Customer Statements',fn:"rptCustStmt()"},
      {n:'Vendor Purchases',fn:"rptVendorPurch()"},
      {n:'Payment History',fn:"rptPayHist()"}
    ]},
    {t:'Expenses & Staff',ico:'💸',reps:[
      {n:'Full Expense Report',fn:"rptExpFull()"},
      {n:'Expense by Category',fn:"rptExpCat()"},
      {n:'Repairs & Maintenance',fn:"rptRepairs()"},
      {n:'Audit Trail Report',fn:"nav('auditlog')"},
      {n:'Staff Activity Log',fn:"toast('Staff report generated','success')"}
    ]},
  ];
  return `
<div class="ph">
  <div class="bc">ShopTrack / <span>${_ui.nav_reports}</span></div>
  <div class="ph-row"><h1>${_ui.nav_reports}</h1>
    <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
      <div class="dtabs"><button class="dtab on" onclick="setReportPeriod(this,'month')">Month</button><button class="dtab" onclick="setReportPeriod(this,'quarter')">Quarter</button><button class="dtab" onclick="setReportPeriod(this,'ytd')">YTD</button><button class="dtab" onclick="setReportPeriod(this,'custom')">Custom</button></div>
      <button class="btn btn-p btn-sm" onclick="exportAllDataXLSX()" title="Export all business data to Excel">&#128190; Export All Data (.xlsx)</button>
    </div>
  </div>
  <p>${_ui.ph_reports}</p>
</div>
<div class="kpi-grid" style="margin-bottom:14px">
  <div class="kpi b"><div class="kpi-lbl">Total Revenue</div><div id="rpt-kpi-rev" class="kpi-val b">${fmtKpi(totalRev)}</div></div>
  <div class="kpi g"><div class="kpi-lbl">Gross Profit</div><div id="rpt-kpi-gp" class="kpi-val g">${fmtKpi(lk.gp)}</div></div>
  <div class="kpi p"><div class="kpi-lbl">Net Profit</div><div id="rpt-kpi-np" class="kpi-val p">${fmtKpi(lk.np)}</div></div>
  <div class="kpi y"><div class="kpi-lbl">Accounts Receivable</div><div id="rpt-kpi-ar" class="kpi-val y">${fmtKpi(lk.ar)}</div></div>
</div>
<div class="g2" style="margin-bottom:14px">
  <div class="card"><div class="card-hd"><div class="card-ttl">Monthly Performance</div><button class="btn btn-g btn-sm" onclick="rptMonthly()">View Full</button></div><div class="ch-wrap" style="height:170px"><canvas id="mChart"></canvas></div></div>
  <div class="card">
    <div class="card-hd"><div class="card-ttl">Revenue by Category</div><button class="btn btn-g btn-sm" onclick="rptRevCat()">View Full</button></div>
    <div style="display:flex;gap:14px;align-items:center">
      <div class="ch-wrap" style="height:130px;width:130px;flex-shrink:0"><canvas id="catChart"></canvas></div>
      <div style="flex:1">
        ${[[gLabel,'rpt-cat-gown',gPct,'b'],[aLabel,'rpt-cat-acc',aPct,'p'],[bLabel,'rpt-cat-rent',rPct,'c'],[oLabel,'rpt-cat-other',oPct,'y']].map(([cat,eid,pct,c])=>`
        <div style="margin-bottom:9px">
          <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:3px"><span>${cat}</span><span id="${eid}-pct" style="color:var(--${c})">${pct}%</span></div>
          <div class="pbar"><div id="${eid}" class="pfill ${c}" style="width:${pct}%"></div></div>
        </div>`).join('')}
      </div>
    </div>
  </div>
</div>
<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:13px;align-items:start">
  ${groups.map(g=>`<div class="card">
    <div class="card-hd"><div class="card-ttl">${g.ico} ${g.t}</div></div>
    ${g.reps.map(r=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:7px 0;border-bottom:1px solid var(--border);gap:10px">
      <span style="font-size:13px;flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${r.n}</span>
      <div style="display:flex;gap:5px;flex-shrink:0">
        <button class="btn btn-g btn-xs" onclick="${r.fn}">View</button>
        <button class="btn btn-g btn-xs" onclick="exportReportCSV('${r.n}')">⬇</button>
      </div>
    </div>`).join('')}
  </div>`).join('')}
</div>`;
}

// ── REPORT FUNCTIONS ─────────────────────────────────────────
function rptSales(){
  const range = PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const periodSales = D.sales.filter(s=>inRange(s.dt,range));
  const rows=periodSales.map(s=>{const tot=s.total||s.amt; return `<tr>
    <td>${mono(s.id)}</td><td>${s.dt}</td>
    <td><strong style="color:var(--ink)">${_esc(s.cust)}</strong></td>
    <td style="font-size:12px;color:var(--text)">${_esc(s.items)}</td>
    <td>${mono(fmt(tot),'g')}</td><td>${mono(fmt(s.paid||0))}</td>
    <td>${mono(fmt(tot-(s.paid||0)),tot-(s.paid||0)>0?'r':'g')}</td><td>${badge(s.st)}</td>
  </tr>`;}).join('');
  const total   = periodSales.reduce((a,s)=>a+(s.total||s.amt||0),0);
  const paid    = periodSales.reduce((a,s)=>a+(s.paid||0),0);
  const arTotal = D.cust.filter(c=>c.bal>0).reduce((a,c)=>a+c.bal,0);
  modal('📊 Sales Report — '+range.label,`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Period Revenue</div><div class="kpi-val g">${fmtKpi(total)}</div></div>
    <div class="kpi b"><div class="kpi-lbl">Cash Collected</div><div class="kpi-val b">${fmtKpi(paid)}</div></div>
    <div class="kpi r"><div class="kpi-lbl">AR Outstanding (all time)</div><div class="kpi-val r">${fmtKpi(arTotal)}</div></div>
    <div class="kpi p"><div class="kpi-lbl">Transactions</div><div class="kpi-val p">${periodSales.length}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Customer</th><th>Items</th><th>Amount</th><th>Paid</th><th>Balance</th><th>Status</th></tr></thead><tbody>${rows}</tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptSalesPDF()">⬇ PDF</button><button class="btn btn-p" onclick="exportSalesCSV()">⬇ CSV</button>`);
}

function rptRevProduct(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const byProd={};
  D.sales.filter(s=>inRange(s.dt,_rng)).forEach(s=>{const k=s.items.split(' ×')[0].split('+')[0].trim().split(',')[0];byProd[k]=(byProd[k]||0)+(s.total||s.amt);});
  const sorted=Object.entries(byProd).sort((a,b)=>b[1]-a[1]);
  const max=sorted[0]?.[1]||1;
  const _rpPeriodLbl=(PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month).label;
  modal('📊 Revenue by Product — '+_rpPeriodLbl,`
  <div class="tbl-wrap"><table><thead><tr><th>Product</th><th>Revenue</th><th>Share</th></tr></thead><tbody>
  ${sorted.map(([p,v])=>`<tr><td>${p}</td><td>${mono(fmt(v),'g')}</td><td><div class="pbar" style="width:120px;display:inline-block"><div class="pfill b" style="width:${Math.round(v/max*100)}%"></div></div></td></tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptRevProductPDF()">⬇ PDF</button><button class="btn btn-p" onclick="exportReportCSV('Revenue by Product')">⬇ Export CSV</button>`);
}

function rptRevCat(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const cats={};
  D.sales.filter(s=>inRange(s.dt,_rng)).forEach(s=>{
    // Use line items for accurate category attribution
    var matched=false;
    if(s.lineItems&&s.lineItems.length){
      s.lineItems.forEach(function(li){
        if(!li.invId||li.invId==='__custom__') return;
        var inv=D.inv.find(i=>i.id===li.invId);
        if(inv&&inv.cat){ cats[inv.cat]=(cats[inv.cat]||0)+((li.price||0)*(li.qty||1)); matched=true; }
      });
    }
    if(!matched){
      const inv=D.inv.find(i=>i.id===s.invId)||D.inv.find(i=>s.items.includes(i.name.split(' ')[0]));
      const cat=inv?inv.cat:'Other';
      cats[cat]=(cats[cat]||0)+(s.total||s.amt);
    }
  });
  D.rentals.filter(r=>inRange(r.start,_rng)&&(r.st==='Returned'||r.st==='Checked Out'||r.st==='Overdue')).forEach(r=>{cats['Rental Revenue']=(cats['Rental Revenue']||0)+r.fee;});
  const sorted=Object.entries(cats).sort((a,b)=>b[1]-a[1]);
  const total=sorted.reduce((a,[,v])=>a+v,0);
  const _rcPeriodLbl=(PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month).label;
  modal('📊 Revenue by Category — '+_rcPeriodLbl,`
  <div class="tbl-wrap"><table><thead><tr><th>Category</th><th>Revenue</th><th>%</th></tr></thead><tbody>
  ${sorted.map(([c,v])=>`<tr><td>${c}</td><td>${mono(fmt(v),'g')}</td><td style="color:var(--text2)">${Math.round(v/total*100)}%</td></tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptRevCatPDF()">⬇ PDF</button>`);
}

function rptRevCust(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const byCust={};
  D.sales.filter(s=>inRange(s.dt,_rng)).forEach(s=>{byCust[s.cust]=(byCust[s.cust]||0)+(s.total||s.amt);});
  const sorted=Object.entries(byCust).sort((a,b)=>b[1]-a[1]);
  const _rcustLbl=(PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month).label;
  modal('📊 Revenue by Customer — '+_rcustLbl,`
  <div class="tbl-wrap"><table><thead><tr><th>Customer</th><th>Total Purchases</th><th>Outstanding</th></tr></thead><tbody>
  ${sorted.map(([c,v])=>{const cust=D.cust.find(x=>x.name===c);return`<tr><td><strong style="color:var(--ink)">${c}</strong></td><td>${mono(fmt(v),'g')}</td><td>${mono(fmt(cust?.bal||0),'y')}</td></tr>`;}).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptRevCustPDF()">⬇ PDF</button>`);
}

function rptProfit(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const periodSales=D.sales.filter(s=>inRange(s.dt,_rng));
  const totRevP=periodSales.reduce((a,s)=>a+(s.total||s.amt||0),0);
  const totCostP=periodSales.reduce((a,s)=>a+(s.cost||0),0);
  const totProfP=totRevP-totCostP;
  const rows=periodSales.map(s=>{
    const tot=s.total||s.amt||0;
    const cost=s.cost||0;
    const gp=tot-cost; // always recompute — don't rely on stale s.profit field
    const margin=tot>0?Math.round(gp/tot*100):0;
    return`<tr>
    <td>${mono(s.id)}</td><td>${s.dt}</td><td>${_esc(s.cust)}</td>
    <td style="font-size:12px">${_esc(s.items)}</td>
    <td>${mono(fmt(tot))}</td><td>${mono(fmt(cost),'r')}</td>
    <td>${mono(fmt(gp),gp>=0?'g':'r')}</td>
    <td style="color:var(--${margin>=0?'g':'r'})">${margin}%</td>
  </tr>`;}).join('');
  const _profitLabel = (PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month).label;
  modal('📊 Product Profitability — '+_profitLabel,`
  <div class="kpi-grid" style="margin-bottom:12px">
    <div class="kpi g"><div class="kpi-lbl">Revenue</div><div class="kpi-val g">${fmtKpi(totRevP)}</div></div>
    <div class="kpi r"><div class="kpi-lbl">COGS</div><div class="kpi-val r">${fmtKpi(totCostP)}</div></div>
    <div class="kpi ${totProfP>=0?'g':'r'}"><div class="kpi-lbl">Gross Profit</div><div class="kpi-val ${totProfP>=0?'g':'r'}">${fmtKpi(totProfP)}</div></div>
    <div class="kpi p"><div class="kpi-lbl">Margin</div><div class="kpi-val p">${totRevP>0?Math.round(totProfP/totRevP*100):0}%</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Sale ID</th><th>Date</th><th>Customer</th><th>Items</th><th>Revenue</th><th>COGS</th><th>Gross Profit</th><th>Margin</th></tr></thead><tbody>${rows}</tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptProfitPDF()">⬇ PDF</button>`);
}

function rptRentals(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const _rents=D.rentals.filter(r=>inRange(r.start,_rng));
  const rows=_rents.map(r=>`<tr>
    <td>${mono(r.id)}</td><td><strong style="color:var(--ink)">${r.cust}</strong></td>
    <td style="font-size:12px">${r.item}</td>
    <td>${r.start}</td><td>${r.due}</td>
    <td>${mono(fmt(r.fee),'g')}</td><td>${mono(fmt(r.dep))}</td>
    <td>${badge(r.st)}</td>
  </tr>`).join('');
  const totalFees=_rents.reduce((a,r)=>a+r.fee,0);
  const totalDep=_rents.reduce((a,r)=>a+r.dep,0);
  modal('📊 Rentals Report',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Total Fees</div><div class="kpi-val g">${fmtKpi(totalFees)}</div></div>
    <div class="kpi b"><div class="kpi-lbl">Total Deposits</div><div class="kpi-val b">${fmtKpi(totalDep)}</div></div>
    <div class="kpi r"><div class="kpi-lbl">Overdue</div><div class="kpi-val r">${D.rentals.filter(r=>r.st==='Overdue').length}</div></div>
    <div class="kpi c"><div class="kpi-lbl">Active</div><div class="kpi-val c">${D.rentals.filter(r=>r.st==='Checked Out').length}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>ID</th><th>Customer</th><th>Item</th><th>Start</th><th>Due</th><th>Fee</th><th>Deposit</th><th>Status</th></tr></thead><tbody>${rows}</tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptRentalsPDF()">⬇ PDF</button><button class="btn btn-p" onclick="exportReportCSV('Rentals Report')">⬇ Export CSV</button>`);
}

