function rptCash(){
  const k=computeKPIs(PERIOD_RANGES[_dashPeriod]||PERIOD_RANGES.month);
  const range=PERIOD_RANGES[_dashPeriod]||PERIOD_RANGES.month;
  // Period-filtered paid purchases (cash out to vendors)
  const paidPurch = D.purchases.filter(p=>p.st==='Paid'&&inRange(p.dt,range)).reduce((a,p)=>a+(p.total||0),0);
  const salePaid  = D.sales.filter(s=>inRange(s.dt,range)).reduce((a,s)=>a+(s.paid||0),0);
  const rentPaid  = D.rentals.filter(r=>(r.st==='Returned'||r.st==='Checked Out'||r.st==='Overdue')&&inRange(r.start,range)).reduce((a,r)=>a+(r.paid||r.fee||0),0);
  const payroll   = D.exp.filter(e=>inRange(e.dt,range)&&(e.cat==='Salaries'||e.cat==='Salaries & Wages'||e.cat==='Payroll')).reduce((a,e)=>a+e.amt,0);
  const otherExp  = D.exp.filter(e=>inRange(e.dt,range)&&e.cat!=='Salaries'&&e.cat!=='Vendor Payment').reduce((a,e)=>a+e.amt,0);
  // Deposits held are a liability, not revenue — show separately
  const depHeld   = D.rentals.filter(r=>inRange(r.start,range)&&(r.st==='Checked Out'||r.st==='Reserved'||r.st==='Overdue')).reduce((a,r)=>a+(r.dep||0),0);
  modal('📊 Cash Flow Summary',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Cash Inflows</div><div class="kpi-val g">${fmtKpi(k.cashIn)}</div></div>
    <div class="kpi r"><div class="kpi-lbl">Cash Outflows</div><div class="kpi-val r">${fmtKpi(k.cashOut)}</div></div>
    <div class="kpi b"><div class="kpi-lbl">Net Cash Flow</div><div class="kpi-val b">${fmtKpi(k.cashIn-k.cashOut)}</div></div>
    <div class="kpi y"><div class="kpi-lbl">Deposits Held (Liability)</div><div class="kpi-val y">${fmtKpi(depHeld)}</div></div>
  </div>
  <div style="padding:10px 0;font-size:13px">
    <div style="font-size:11px;font-weight:700;color:var(--g);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">Inflows</div>
    <div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)"><span>Sales Receipts (cash collected)</span><span style="color:var(--g);font-family:var(--mono)">${fmt(salePaid)}</span></div>
    <div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)"><span>Rental Fees Collected</span><span style="color:var(--g);font-family:var(--mono)">${fmt(rentPaid)}</span></div>
    <div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)"><span>Services Revenue</span><span style="color:var(--g);font-family:var(--mono)">${fmt(k.apptRev)}</span></div>
    <div style="font-size:11px;font-weight:700;color:var(--r);text-transform:uppercase;letter-spacing:.5px;margin:10px 0 6px">Outflows</div>
    <div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)"><span>Payroll</span><span style="color:var(--r);font-family:var(--mono)">-${fmt(payroll)}</span></div>
    <div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border)"><span>Operating Expenses</span><span style="color:var(--r);font-family:var(--mono)">-${fmt(otherExp)}</span></div>
    <div style="display:flex;justify-content:space-between;padding:6px 0"><span>Vendor Payments (purchases)</span><span style="color:var(--r);font-family:var(--mono)">-${fmt(paidPurch)}</span></div>
    <div style="font-size:11px;color:var(--text3);margin-top:10px">⚠ Deposits held (${fmt(depHeld)}) are customer liabilities and are NOT counted as revenue or cash flow until the rental is returned.</div>
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptCashPDF()">⬇ PDF</button>`);
}

function rptMonthly(){
  // Build last 12 months dynamically from real data
  const now = new Date();
  const pad = n=>String(n).padStart(2,'0');
  const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const months = [];
  for(let i=11;i>=0;i--){
    let mo = now.getMonth()-i; let yr = now.getFullYear();
    if(mo<0){mo+=12;yr--;}
    const s = `${yr}-${pad(mo+1)}-01`;
    const e = `${yr}-${pad(mo+1)}-${String(new Date(yr,mo+1,0).getDate()).padStart(2,'0')}`;
    const mSales    = D.sales.filter(x=>x.dt>=s&&x.dt<=e);
    const mRentals  = D.rentals.filter(x=>(x.st==='Returned'||x.st==='Checked Out'||x.st==='Overdue')&&x.start>=s&&x.start<=e);
    const mAppts    = (D.appointments||[]).filter(a=>a.st==='Completed'&&a.date>=s&&a.date<=e);
    const mExp      = D.exp.filter(x=>x.dt>=s&&x.dt<=e&&x.cat!=='Vendor Payment');
    const mRev  = mSales.reduce((a,x)=>a+(x.total||x.amt||0),0) + mRentals.reduce((a,x)=>a+x.fee,0) + mAppts.reduce((a,x)=>a+(x.totalAmt||0),0);
    const mCogs = mSales.reduce((a,x)=>a+(x.cost||0),0);
    const mOh   = mExp.reduce((a,x)=>a+x.amt,0);
    const mGp   = mRev - mCogs;
    const mNp   = mGp - mOh;
    if(mRev>0||i<3) months.push({m:`${MONTH_NAMES[mo]} ${yr}`, rev:mRev, gp:mGp, oh:mOh, np:mNp});
  }
  const totRev = months.reduce((a,m)=>a+m.rev,0);
  const totNp  = months.reduce((a,m)=>a+m.np,0);
  modal('📊 Monthly Financial Summary',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi b"><div class="kpi-lbl">12-Month Revenue</div><div class="kpi-val b">${fmtKpi(totRev)}</div></div>
    <div class="kpi p"><div class="kpi-lbl">12-Month Net Profit</div><div class="kpi-val p">${fmtKpi(totNp)}</div></div>
    <div class="kpi g"><div class="kpi-lbl">Avg Net Margin</div><div class="kpi-val g">${totRev>0?Math.round(totNp/totRev*100):0}%</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Month</th><th>Revenue</th><th>Gross Profit</th><th>Overhead</th><th>Net Profit</th><th>Margin</th></tr></thead><tbody>
  ${months.map(m=>`<tr>
    <td style="font-weight:500">${m.m}</td>
    <td>${mono(fmt(m.rev),'b')}</td>
    <td>${mono(fmt(m.gp),'g')}</td>
    <td>${mono(fmt(m.oh),'r')}</td>
    <td style="font-weight:600">${mono(fmt(m.np),m.np>=0?'g':'r')}</td>
    <td style="color:var(--p)">${m.rev>0?Math.round(m.np/m.rev*100):0}%</td>
  </tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptMonthlyPDF()">⬇ PDF</button>`,'lg');
}

function rptExpBreak(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const _expPeriod=D.exp.filter(e=>inRange(e.dt,_rng));
  const cats={};
  _expPeriod.forEach(e=>{cats[e.cat]=(cats[e.cat]||0)+e.amt;});
  const sorted=Object.entries(cats).sort((a,b)=>b[1]-a[1]);
  const total=_expPeriod.reduce((a,e)=>a+e.amt,0);
  modal('📊 Expense Breakdown — '+(PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month).label,`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi r"><div class="kpi-lbl">Total Expenses</div><div class="kpi-val r">${fmtKpi(total)}</div></div>
    <div class="kpi"><div class="kpi-lbl">Categories</div><div class="kpi-val">${Object.keys(cats).length}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Category</th><th>Amount</th><th>% of Total</th></tr></thead><tbody>
  ${sorted.map(([c,v])=>`<tr><td>${c}</td><td>${mono(fmt(v),'r')}</td><td style="color:var(--text2)">${Math.round(v/total*100)}%</td></tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button>`);
}

function rptAR(){
  const today = localDateStr();
  // Compute AR live from sales (never trust stale c.bal)
  const _arLive={};
  D.sales.forEach(function(s){
    const cid=s.custId||s.cust; if(!cid) return;
    _arLive[cid]=(_arLive[cid]||0)+((s.total||s.amt||0)-(s.paid||0));
  });
  // Build debtor list with live balances
  const ar = D.cust.map(function(c){
    const liveBal=(_arLive[c.id]||_arLive[c.name]||0);
    return {...c, bal:liveBal};
  }).filter(c=>c.bal>0.01).sort((a,b)=>b.bal-a.bal);
  const total = ar.reduce((a,c)=>a+c.bal,0);

  // Age each debtor by their oldest unpaid sale
  function ageDays(c){
    const unpaid = D.sales.filter(s=>(s.custId===c.id||s.cust===c.name)&&s.st!=='Paid').sort((a,b)=>a.dt.localeCompare(b.dt));
    if(!unpaid.length) return 0;
    const oldest = unpaid[0].dt;
    return Math.floor((new Date(today)-new Date(oldest))/(1000*60*60*24));
  }
  function ageBucket(days){
    if(days<=0)  return {label:'Current',    cls:'bx-g'};
    if(days<=30) return {label:'1–30 days',  cls:'bx-y'};
    if(days<=60) return {label:'31–60 days', cls:'bx-o'};
    return             {label:'60+ days',   cls:'bx-r'};
  }

  // Bucket totals
  const buckets = {'Current':0,'1–30 days':0,'31–60 days':0,'60+ days':0};
  ar.forEach(c=>{ const b=ageBucket(ageDays(c)).label; buckets[b]=(buckets[b]||0)+c.bal; });

  modal('📊 AR Aging Report',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Current</div><div class="kpi-val g">${fmtKpi(buckets['Current'])}</div></div>
    <div class="kpi y"><div class="kpi-lbl">1–30 Days</div><div class="kpi-val y">${fmtKpi(buckets['1–30 days'])}</div></div>
    <div class="kpi o"><div class="kpi-lbl">31–60 Days</div><div class="kpi-val o">${fmtKpi(buckets['31–60 days'])}</div></div>
    <div class="kpi r"><div class="kpi-lbl">60+ Days</div><div class="kpi-val r">${fmtKpi(buckets['60+ days'])}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Customer</th><th>Aging</th><th>Oldest Unpaid</th><th>Balance Due</th><th>Last Activity</th></tr></thead><tbody>
  ${ar.map(c=>{const days=ageDays(c);const bkt=ageBucket(days);const unpaid=D.sales.filter(s=>(s.custId===c.id||s.cust===c.name)&&s.st!=='Paid');const oldest=unpaid.length?unpaid.sort((a,b)=>a.dt.localeCompare(b.dt))[0].dt:'—';return`<tr>
    <td><strong style="color:var(--ink)">${_esc(c.name)}</strong>${c.vip?` ${bx('VIP','bx-p')}`:''}
      <div style="font-size:10px;color:var(--text2)">${unpaid.length} unpaid invoice${unpaid.length!==1?'s':''}</div>
    </td>
    <td>${bx(bkt.label,bkt.cls)}</td>
    <td style="font-size:12px;color:var(--text2)">${oldest}</td>
    <td>${mono(fmt(c.bal),'r')}</td>
    <td style="font-size:11px;color:var(--text2)">${c.last||'—'}</td>
  </tr>`;}).join('')}
  <tr style="border-top:2px solid var(--border2)"><td colspan="3"><strong>Total AR</strong></td><td>${mono(fmt(total),'r')}</td><td></td></tr>
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptARPDF()">⬇ PDF</button><button class="btn btn-p btn-sm" onclick="closeModal();mARDetail()">Manage AR →</button>`,'lg');
}

function rptAP(){
  const today = localDateStr();
  // Compute AP live from unpaid purchases (never trust stale v.bal)
  const _apLive={};
  D.purchases.forEach(function(p){
    if(p.st==='Paid'||p.st==='Received') return;
    const vid=p.vendorId||p.vendor; if(!vid) return;
    _apLive[vid]=(_apLive[vid]||0)+(p.total||0);
  });
  // Build creditor list with live balances
  const ap = D.vendors.map(function(v){
    const liveBal=(_apLive[v.id]||_apLive[v.name]||0);
    return {...v, bal:liveBal};
  }).filter(v=>v.bal>0.01).sort((a,b)=>b.bal-a.bal);
  const total = ap.reduce((a,v)=>a+v.bal,0);

  function apAgeDays(v){
    const openPOs = D.purchases.filter(p=>(p.vendor===v.name||p.vendorId===v.id)&&p.st!=='Paid'&&p.st!=='Received').sort((a,b)=>a.dt.localeCompare(b.dt));
    if(!openPOs.length) return 0;
    return Math.floor((new Date(today)-new Date(openPOs[0].dt))/(1000*60*60*24));
  }
  function ageBucket(days){
    if(days<=30) return {label:'Current (≤30d)', cls:'bx-g'};
    if(days<=60) return {label:'31–60 days',     cls:'bx-y'};
    if(days<=90) return {label:'61–90 days',     cls:'bx-o'};
    return             {label:'90+ days',        cls:'bx-r'};
  }
  const buckets={'Current (≤30d)':0,'31–60 days':0,'61–90 days':0,'90+ days':0};
  ap.forEach(v=>{ const b=ageBucket(apAgeDays(v)).label; buckets[b]=(buckets[b]||0)+v.bal; });

  modal('📊 AP Aging Report',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Current (≤30d)</div><div class="kpi-val g">${fmtKpi(buckets['Current (≤30d)'])}</div></div>
    <div class="kpi y"><div class="kpi-lbl">31–60 Days</div><div class="kpi-val y">${fmtKpi(buckets['31–60 days'])}</div></div>
    <div class="kpi o"><div class="kpi-lbl">61–90 Days</div><div class="kpi-val o">${fmtKpi(buckets['61–90 days'])}</div></div>
    <div class="kpi r"><div class="kpi-lbl">90+ Days</div><div class="kpi-val r">${fmtKpi(buckets['90+ days'])}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Vendor</th><th>Aging</th><th>Country</th><th>Open POs</th><th>Balance Owed</th><th>Category</th></tr></thead><tbody>
  ${ap.map(v=>{const days=apAgeDays(v);const bkt=ageBucket(days);const openPOs=D.purchases.filter(p=>(p.vendor===v.name||p.vendorId===v.id)&&p.st!=='Paid'&&p.st!=='Received');return`<tr>
    <td><strong style="color:var(--ink)">${_esc(v.name)}</strong></td>
    <td>${bx(bkt.label,bkt.cls)}</td>
    <td style="font-size:12px;color:var(--text2)">${_esc(v.country||'—')}</td>
    <td style="font-size:12px">${openPOs.length} open PO${openPOs.length!==1?'s':''}</td>
    <td>${mono(fmt(v.bal),'r')}</td>
    <td style="font-size:11px;color:var(--text2)">${_esc(v.cat||'—')}</td>
  </tr>`;}).join('')}
  <tr style="border-top:2px solid var(--border2)"><td colspan="4"><strong>Total AP</strong></td><td>${mono(fmt(total),'r')}</td><td></td></tr>
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptAPPDF()">⬇ PDF</button><button class="btn btn-p btn-sm" onclick="closeModal();mAPDetail()">Manage AP →</button>`,'lg');
}

function rptCustStmt(){
  // Show a customer picker first, then the statement
  const custOpts = D.cust.map(c=>`<option value="${c.id}">${_esc(c.name)}${c.bal>0?' — '+fmt(c.bal)+' outstanding':''}</option>`).join('');
  modal('📊 Customer Statements',`
  <div class="fg"><label class="fl">Select Customer</label>
    <div id="stmt-cust-wrap" style="position:relative"></div>
    <input type="hidden" id="stmt-cust-sel" value=""/>
  </div>
  <div id="stmt-body" style="margin-top:14px"></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button>
   <button class="btn btn-g btn-sm" id="stmt-pdf-btn" style="display:none" onclick="_rptCustStmtPDF()">⬇ PDF</button>`,'lg');
  setTimeout(function(){
    // Native select — reliable, always visible
    var _sw = document.getElementById('stmt-cust-wrap');
    if(_sw){
      _sw.innerHTML = '<select class="fs" id="stmt-cust-wrap-sel" style="width:100%">'
        + '<option value="">— Choose a customer —</option>'
        + D.cust.map(function(cu){
            return '<option value="'+cu.id+'">'+_esc(cu.name)+(cu.bal>0?' (owes '+fmt(cu.bal)+')':'')+'</option>';
          }).join('')
        + '</select>';
      _sw.querySelector('select').onchange = function(){
        document.getElementById('stmt-cust-sel').value = this.value;
        _renderCustStmt(this.value);
      };
    }
    // Auto-select first customer with a balance, else first customer
    var def=D.cust.find(function(c){return c.bal>0;})||D.cust[0];
    if(def){
      document.getElementById('stmt-cust-sel').value=def.id;
      _renderCustStmt(def.id);
    }
  },60);
}
function _renderCustStmt(custId){
  var cust=D.cust.find(c=>c.id===custId); if(!cust) return;
  var sales=D.sales.filter(s=>s.custId===cust.id||s.cust===cust.name).sort(function(a,b){return b.dt.localeCompare(a.dt);});
  var rentals=D.rentals.filter(r=>r.custId===cust.id||r.cust===cust.name).sort(function(a,b){return b.start.localeCompare(a.start);});
  var appts=(D.appointments||[]).filter(a=>(a.custId===cust.id||a.custName===cust.name)&&a.st==='Completed').sort(function(a,b){return b.date.localeCompare(a.date);});
  var totalInvoiced = sales.reduce(function(a,s){return a+(s.total||s.amt||0);},0)
    + rentals.reduce(function(a,r){return a+r.fee;},0)
    + appts.reduce(function(a,a2){return a+(a2.totalAmt||0);},0);
  var totalPaid = sales.reduce(function(a,s){return a+(s.paid||0);},0)
    + rentals.reduce(function(a,r){return a+(r.paid||0);},0)
    + appts.reduce(function(a,a2){return a+(a2.totalAmt||0);},0);
  var body=document.getElementById('stmt-body'); if(!body) return;
  var pdfBtn=document.getElementById('stmt-pdf-btn'); if(pdfBtn) pdfBtn.style.display='';
  window._stmtCustId=custId;
  body.innerHTML=`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Total Invoiced</div><div class="kpi-val g">${fmtKpi(totalInvoiced)}</div></div>
    <div class="kpi b"><div class="kpi-lbl">Total Paid</div><div class="kpi-val b">${fmtKpi(totalPaid)}</div></div>
    <div class="kpi ${cust.bal>0?'r':'g'}"><div class="kpi-lbl">Outstanding Balance</div><div class="kpi-val ${cust.bal>0?'r':'g'}">${fmtKpi(cust.bal||0)}</div></div>
    <div class="kpi p"><div class="kpi-lbl">Transactions</div><div class="kpi-val p">${sales.length+rentals.length+appts.length}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Type</th><th>Description</th><th>Invoiced</th><th>Paid</th><th>Balance</th></tr></thead><tbody>
  ${sales.map(s=>{const tot=s.total||s.amt;const bal=tot-(s.paid||0);return`<tr><td>${s.dt}</td><td>${bx('Sale','bx-g')}</td><td style="font-size:12px">${_esc(s.items)}</td><td>${mono(fmt(tot))}</td><td>${mono(fmt(s.paid||0),'g')}</td><td>${mono(fmt(bal),bal>0?'r':'g')}</td></tr>`;}).join('')}
  ${rentals.map(r=>{const paid=r.paid||0;const bal=r.fee-paid;return`<tr><td>${r.start}</td><td>${bx('Rental','bx-c')}</td><td style="font-size:12px">${_esc(r.item)}</td><td>${mono(fmt(r.fee))}</td><td>${mono(fmt(paid),'g')}</td><td>${mono(fmt(bal),bal>0?'r':'g')}</td></tr>`;}).join('')}
  ${appts.map(a=>{return`<tr><td>${a.date}</td><td>${bx('Service','bx-p')}</td><td style="font-size:12px">${_esc(a.serviceName||'')}</td><td>${mono(fmt(a.totalAmt||0))}</td><td>${mono(fmt(a.totalAmt||0),'g')}</td><td>${mono('—')}</td></tr>`;}).join('')}
  <tr style="border-top:2px solid var(--border2);font-weight:700"><td colspan="3">Totals</td><td>${mono(fmt(totalInvoiced),'b')}</td><td>${mono(fmt(totalPaid),'g')}</td><td>${mono(fmt(cust.bal||0),cust.bal>0?'r':'g')}</td></tr>
  </tbody></table></div>`;
}

function rptVendorPurch(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const _pos=D.purchases.filter(p=>inRange(p.dt,_rng)).sort((a,b)=>b.dt.localeCompare(a.dt));
  const _total=_pos.reduce((a,p)=>a+(p.total||0),0);
  const _paid=_pos.filter(p=>p.st==='Paid'||p.st==='Received').reduce((a,p)=>a+(p.total||0),0);
  const _pending=_pos.filter(p=>p.st!=='Paid'&&p.st!=='Received').reduce((a,p)=>a+(p.total||0),0);
  // Vendor summary
  const _vmap={};
  _pos.forEach(p=>{_vmap[p.vendor]=(_vmap[p.vendor]||0)+(p.total||0);});
  const _vsorted=Object.entries(_vmap).sort((a,b)=>b[1]-a[1]);
  modal('📊 Vendor Purchases — '+_rng.label,`
  <div class="kpi-grid" style="margin-bottom:12px">
    <div class="kpi b"><div class="kpi-lbl">Total Ordered</div><div class="kpi-val b">${fmtKpi(_total)}</div></div>
    <div class="kpi g"><div class="kpi-lbl">Paid / Received</div><div class="kpi-val g">${fmtKpi(_paid)}</div></div>
    <div class="kpi y"><div class="kpi-lbl">Outstanding (AP)</div><div class="kpi-val y">${fmtKpi(_pending)}</div></div>
    <div class="kpi"><div class="kpi-lbl">PO Count</div><div class="kpi-val">${_pos.length}</div></div>
  </div>
  ${_vsorted.length>1?`<div style="margin-bottom:12px"><div style="font-size:11px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">Spend by Vendor</div>${_vsorted.map(([v,amt])=>`<div style="display:flex;justify-content:space-between;padding:4px 0;border-bottom:1px solid var(--border);font-size:12px"><span>${_esc(v)}</span><span style="font-family:var(--mono);color:var(--b)">${fmt(amt)}</span></div>`).join('')}</div>`:''}
  <div class="tbl-wrap"><table><thead><tr><th>PO</th><th>Date</th><th>Vendor</th><th>Items</th><th>Subtotal</th><th>Freight</th><th>Total</th><th>Status</th></tr></thead><tbody>
  ${_pos.map(p=>`<tr><td>${mono(p.id)}</td><td>${p.dt}</td><td style="font-size:12px;color:var(--ink)">${p.vendor}</td><td style="font-size:11px">${p.items}</td><td>${mono(fmt(p.sub||0))}</td><td>${mono(fmt(p.freight||0))}</td><td>${mono(fmt(p.total),'b')}</td><td>${badge(p.st)}</td></tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptVendorPurchPDF()">⬇ PDF</button><button class="btn btn-p" onclick="exportReportCSV('Vendor Purchases')">⬇ CSV</button>`,'lg');
}

function rptPayHist(){
  const range = PERIOD_RANGES[_dashPeriod]||PERIOD_RANGES.month;
  const paid  = D.sales.filter(s=>(s.paid||0)>0).sort((a,b)=>b.dt.localeCompare(a.dt));
  const totalCollected = paid.reduce((a,s)=>a+(s.paid||0),0);
  modal('📊 Payment History',`
  <div class="kpi-grid" style="margin-bottom:14px">
    <div class="kpi g"><div class="kpi-lbl">Total Collected</div><div class="kpi-val g">${fmtKpi(totalCollected)}</div></div>
    <div class="kpi b"><div class="kpi-lbl">Transactions</div><div class="kpi-val b">${paid.length}</div></div>
    <div class="kpi r"><div class="kpi-lbl">Still Outstanding</div><div class="kpi-val r">${fmtKpi(D.cust.filter(c=>c.bal>0).reduce((a,c)=>a+c.bal,0))}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>Sale ID</th><th>Date</th><th>Customer</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th></tr></thead><tbody>
  ${paid.map(s=>{const tot=s.total||s.amt;const bal=tot-(s.paid||0);return`<tr>
    <td>${mono(s.id)}</td><td>${s.dt}</td><td>${_esc(s.cust)}</td>
    <td>${mono(fmt(tot))}</td>
    <td>${mono(fmt(s.paid||0),'g')}</td>
    <td>${mono(fmt(bal),bal>0?'y':'g')}</td>
    <td>${badge(s.st)}</td>
  </tr>`;}).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptPayHistPDF()">⬇ PDF</button>`);
}

function rptExpFull(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const _expP=D.exp.filter(e=>inRange(e.dt,_rng)).sort((a,b)=>b.dt.localeCompare(a.dt));
  const _expTotal=_expP.reduce((a,e)=>a+e.amt,0);
  modal('📊 Full Expense Report — '+_rng.label,`
  <div class="kpi-grid" style="margin-bottom:12px">
    <div class="kpi r"><div class="kpi-lbl">Total Expenses</div><div class="kpi-val r">${fmtKpi(_expTotal)}</div></div>
    <div class="kpi"><div class="kpi-lbl">Transactions</div><div class="kpi-val">${_expP.length}</div></div>
  </div>
  <div class="tbl-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Category</th><th>Payee</th><th>Amount</th><th>Type</th><th>Method</th></tr></thead><tbody>
  ${_expP.map(e=>`<tr><td>${mono(e.id)}</td><td>${e.dt}</td><td>${e.cat}</td><td style="font-size:12px">${e.payee}</td><td>${mono(fmt(e.amt),'r')}</td><td>${bx(e.type,'bx-n')}</td><td style="font-size:11px;color:var(--text2)">${e.method}</td></tr>`).join('')}
  <tr style="border-top:2px solid var(--border2)"><td colspan="4"><strong>Total</strong></td><td>${mono(fmt(_expTotal),'r')}</td><td colspan="2"></td></tr>
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptExpFullPDF()">⬇ PDF</button><button class="btn btn-p" onclick="exportReportCSV('Full Expense Report')">⬇ Export CSV</button>`);
}

function rptExpCat(){rptExpBreak();}
function rptRepairs(){
  const _rng=PERIOD_RANGES[_acctPeriod]||PERIOD_RANGES.month;
  const rep=D.exp.filter(e=>inRange(e.dt,_rng)&&(e.cat==='Repairs'||e.cat==='Repairs & Maintenance'||e.cat==='Cleaning'||e.cat==='Maintenance'));
  modal('📊 Repairs & Maintenance',`
  <div class="tbl-wrap"><table><thead><tr><th>Date</th><th>Payee</th><th>Amount</th><th>Method</th></tr></thead><tbody>
  ${rep.map(e=>`<tr><td>${e.dt}</td><td>${e.payee}</td><td>${mono(fmt(e.amt),'r')}</td><td>${e.method}</td></tr>`).join('')}
  </tbody></table></div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button><button class="btn btn-g btn-sm" onclick="_rptRepairsPDF()">⬇ PDF</button>`);
}

function initReports(){
  // Use the current month as default — same function as period selector
  _applyReportPeriod('month', PERIOD_RANGES.month);
}

// ============================================================
// CATALOG
// ============================================================
function pgCatalog(){
  var defaultCatName = (BIZ.name||'Our') + ' Service Catalog';
  var catName = BIZ.catalogName || defaultCatName;
  var catTagline = BIZ.catalogTagline || BIZ.tagline || '';
  var invCount = D.inv.length;
  var svcCount = (D.services||[]).filter(function(s){return s.active!==false;}).length;
  var totalItems = invCount + svcCount;
  var invCats = [...new Set(D.inv.map(function(i){return i.cat;}).filter(Boolean))];
  var svcCats = [...new Set((D.services||[]).map(function(s){return s.cat;}).filter(Boolean))];
  var allCats = [...new Set([...invCats,...svcCats])];
  var catCount = allCats.length;

  // Category filter options built safely
  var catFilterOpts = '<option value="">All Categories</option>'
    + allCats.map(function(c){ return '<option value="'+_esc(c)+'">'+_esc(c)+'</option>'; }).join('');

  // Build product+service cards safely (string concat, no nested templates)
  var itemCards = '';
  D.inv.forEach(function(it){
    var _src = (it.photoDataUrls&&it.photoDataUrls.length) ? it.photoDataUrls[0] : (it.imgDataUrl||null);
    var _imgHtml = _src
      ? '<img loading="lazy" src="'+_src+'" style="width:100%;height:100%;object-fit:cover;display:block"/>'
      : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:32px;background:var(--bg3)">📦</div>';
    itemCards += '<div class="icard" data-cat="'+_esc(it.cat||'')+'" onclick="mItem(\''+it.id+'\')"><div class="icard-img" style="height:140px;overflow:hidden">'+_imgHtml+'</div><div class="icard-body"><div class="icard-name">'+_esc(it.name)+'</div><div style="font-size:10px;color:var(--text2);margin-bottom:4px">'+_esc(it.cat||'')+'</div><div style="display:flex;gap:7px;flex-wrap:wrap">'+(it.sp?'<span style="font-size:11px;color:var(--g)">💳 '+fmt(it.sp)+'</span>':'')+(it.rp?'<span style="font-size:11px;color:var(--c)">🕐 '+fmt(it.rp)+'/day</span>':'')+'</div></div></div>';
  });
  (D.services||[]).filter(function(s){return s.active!==false;}).forEach(function(s){
    var pt = s.priceType||'flat';
    var ptColor = {flat:'var(--a)',per_session:'#7c3aed',per_hour:'#0284c7',per_day:'#0891b2',per_week:'#0f766e',per_min:'#dc2626',starting:'#d97706'}[pt]||'var(--a)';
    var priceLabel = pt==='starting' ? 'From '+fmt(s.price) : fmt(s.price)+({'per_hour':'/hr','per_min':'/min','per_day':'/day','per_week':'/wk','per_session':'/session'}[pt]||'');
    var durLabel = (!s.duration||s.duration<=0) ? 'Duration TBD' : s.duration+' min';
    var imgHtml = s.imgDataUrl
      ? '<img loading="lazy" src="'+s.imgDataUrl+'" style="width:100%;height:100%;object-fit:cover;display:block"/>'
      : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:32px;background:'+s.color+'18">✂️</div>';
    itemCards += '<div class="icard" data-cat="'+_esc(s.cat||'')+'" onclick="mEditSvc(\''+s.id+'\')"><div class="icard-img" style="height:140px;overflow:hidden">'+imgHtml+'</div><div class="icard-body"><div class="icard-name">'+_esc(s.name)+'</div><div style="font-size:10px;color:var(--text2);margin-bottom:4px">'+_esc(s.cat||'')+'</div><div style="display:flex;gap:6px;flex-wrap:wrap;align-items:center"><span style="font-size:12px;font-weight:700;color:'+ptColor+'">'+_esc(priceLabel)+'</span><span style="font-size:10px;color:var(--text3)">· '+_esc(durLabel)+'</span></div></div></div>';
  });

  if(!itemCards){
    itemCards = '<div style="grid-column:1/-1;text-align:center;padding:32px;color:var(--text2);font-size:13px">No products or services yet — add inventory or services to include them in the catalog.</div>';
  }

  return '<div class="ph">'
    +'<div class="bc">'+_esc(BIZ.name||'ShopTrack')+' / <span>Catalog</span></div>'
    +'<div class="ph-row"><h1>Product Catalog</h1><div class="btn-row">'
    +'<button class="btn btn-s btn-sm" onclick="genCatalogDoc()">👁 Preview</button>'
    +'<button class="btn btn-p btn-sm" onclick="genCatalogDoc()">⬇ Generate PDF</button>'
    +'</div></div>'
    +'<p>Build and publish customer-facing catalogs with pricing and photos</p>'
    +'</div>'
    +'<div class="g2" style="margin-bottom:14px">'
    +'<div class="card">'
    +'<div class="card-hd"><div class="card-ttl">Catalog Settings</div></div>'
    +'<div class="fg"><label class="fl">Catalog Name</label><input class="fi" id="cat-name-input" value="'+_esc(catName)+'"/></div>'
    +'<div class="fg"><label class="fl">Cover Tagline</label><input class="fi" id="cat-tagline-input" value="'+_esc(catTagline)+'"/></div>'
    +'<div class="fg-2">'
    +'<div class="fg"><label class="fl">Show Prices</label><select class="fs"><option>Show All Prices</option><option>Sale Only</option><option>Rental Only</option><option>Hide Prices</option></select></div>'
    +'<div class="fg"><label class="fl">Filter Status</label><select class="fs"><option>Both Sale &amp; Rent</option><option>For Sale Only</option><option>For Rent Only</option></select></div>'
    +'</div>'
    +'<div class="fg"><label class="fl">Contact Info</label><input class="fi" id="cat-contact" value="'+_esc((BIZ.email||'')+(BIZ.phone?' | '+BIZ.phone:''))+'"/></div>'
    +'<button class="btn btn-p" onclick="BIZ.catalogName=document.getElementById(\'cat-name-input\')?.value||BIZ.catalogName||\''+_esc(defaultCatName)+'\';BIZ.catalogTagline=document.getElementById(\'cat-tagline-input\')?.value||\'\';_dbSaveBizProfile(SESSION.bizId);toast(\'Catalog settings saved \u2713\',\'success\')">Save Settings</button>'
    +'</div>'
    +'<div class="card" style="background:linear-gradient(135deg,var(--bg3),var(--bg4));border-style:dashed;text-align:center;padding:28px">'
    +'<div style="font-size:44px;margin-bottom:10px">📋</div>'
    +'<div style="font-family:var(--display);font-size:18px;font-weight:700;color:var(--ink);margin-bottom:4px">'+_esc(catName)+'</div>'
    +'<div style="font-size:12px;color:var(--text2);margin-bottom:14px">'+_esc(BIZ.name||'ShopTrack')+' · '+totalItems+' item'+(totalItems!==1?'s':'')+' · '+catCount+' categor'+(catCount!==1?'ies':'y')+'</div>'
    +'<button class="btn btn-p btn-sm" onclick="genCatalogDoc()">⬇ Generate PDF Catalog</button>'
    +'<div style="margin-top:8px"><button class="btn btn-s btn-sm" onclick="var _u=window.location.href.split(\'#\')[0];navigator.clipboard?.writeText(_u).then(function(){toast(\'Catalog link copied! \u2713\',\'success\');}).catch(function(){toast(\'Link: \'+_u,\'info\');})">🔗 Share Digital Link</button></div>'
    +'</div>'
    +'</div>'
    +'<div class="card">'
    +'<div class="card-hd"><div class="card-ttl">Items in Catalog</div>'
    +'<div class="btn-row">'
    +'<button id="cat-cat-all" class="btn btn-g btn-sm cat-filter-btn on" onclick="document.querySelectorAll(\'.icard\').forEach(function(c){c.style.display=\'\';});document.querySelectorAll(\'.cat-filter-btn\').forEach(function(b){b.classList.remove(\'on\');});this.classList.add(\'on\')">All</button>'
    +(allCats.map(function(c){ return '<button class="btn btn-s btn-sm cat-filter-btn" onclick="var cat=\''+c.replace(/'/g,"\\'")+'\'  ;document.querySelectorAll(\'.icard\').forEach(function(el){el.style.display=(el.dataset.cat===cat)?\'\'  :\'none\';});document.querySelectorAll(\'.cat-filter-btn\').forEach(function(b){b.classList.remove(\'on\');});this.classList.add(\'on\')">'+_esc(c)+'</button>'; }).join(''))
    +'</div>'
    +'</div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:11px">'
    +itemCards
    +'</div>'
    +'</div>';
}


// ============================================================
// AI STUDIO
// ============================================================
function pgAI(){
  const contentGroups = [
    {group:'📱 Social Media',    items:[
      {id:'Instagram Caption',   icon:'📸', desc:'Engaging post for Instagram feed'},
      {id:'New Arrival Post',    icon:'🆕', desc:'Announce a new product or service'},
      {id:'Flash Sale Post',     icon:'⚡', desc:'Limited-time offer with urgency'},
      {id:'Back-in-Stock Announcement', icon:'🙌', desc:'Re-engage customers who missed out'},
    ]},
    {group:'💬 WhatsApp & Messaging', items:[
      {id:'WhatsApp Promo Message',   icon:'💬', desc:'Direct promo to send to contacts'},
      {id:'Customer Follow-up Message',icon:'🤝', desc:'Re-engage past customers'},
    ]},
    {group:'🎨 Branded Documents',   items:[
      {id:'Branded Flyer',       icon:'🖼️', desc:'Full-color flyer with your logo & colors — save as PNG or PDF'},
      {id:'Email Campaign',      icon:'📧', desc:'Subject line + formatted email body ready to send'},
    ]},
    {group:'🤖 AI Image Generation', items:[
      {id:'AI Product Photo',    icon:'🎨', desc:'Generate a professional product image with DALL-E (requires OpenAI key in Settings)'},
    ]},
    {group:'📝 Product & Business',  items:[
      {id:'Product Description', icon:'📦', desc:'Compelling description for any item'},
      {id:'Rental Promotion',    icon:'🕐', desc:'Promote rental availability'},
      {id:'Business Introduction',icon:'🏪',desc:'Introduce your business to new clients'},
    ]},
    {group:'📣 Campaigns',          items:[
      {id:'Seasonal Campaign',   icon:'🌟', desc:'Season or month-themed promotion'},
      {id:'Promotional Offer',   icon:'🎁', desc:'Special deal or discount announcement'},
      {id:'Seasonal Campaign Planner', icon:'📅', desc:'AI-planned week of posts, captions & hashtags for a campaign'},
    ]},
  ];

  const prodByCategory = {};
  D.inv.forEach(i=>{ if(!prodByCategory[i.cat]) prodByCategory[i.cat]=[]; prodByCategory[i.cat].push(i); });
  const hasServices = D.services && D.services.length > 0;
  const hasSvcContent = hasServices ?
    `<optgroup label="— Services —">${D.services.filter(s=>s.active).map(s=>`<option value="${s.name}">${s.name}</option>`).join('')}</optgroup>` : '';
  const invOptions = Object.entries(prodByCategory).map(([cat,items])=>
    `<optgroup label="— ${cat} —">${items.map(i=>`<option value="${i.name}">${i.name}</option>`).join('')}</optgroup>`
  ).join('');

  const tones = [
    {id:'Professional', icon:'💼'},
    {id:'Friendly',     icon:'😊'},
    {id:'Luxury',       icon:'💎'},
    {id:'Trendy',       icon:'🔥'},
    {id:'Urgent Promo', icon:'⚡'},
    {id:'Warm/Personal',icon:'🤗'},
  ];

  return `
<div class="ph">
  <div class="bc">${BIZ.name||'ShopTrack'} / <span>AI Studio</span></div>
  <div class="ph-row"><h1>✨ AI Content Studio</h1>
    <span style="font-size:11px;background:var(--g-dim);color:var(--g);padding:3px 10px;border-radius:10px;font-weight:600">✓ Powered by ShopTrack</span>
  </div>
  <p>Generate ready-to-post social content, branded flyers, email campaigns, and more — in seconds</p>
</div>

<div style="display:grid;grid-template-columns:340px 1fr;gap:16px;align-items:start" id="ai-layout">

  <!-- LEFT: Configuration panel -->
  <div>
    <div class="card" style="margin-bottom:12px">
      <div class="card-hd" style="margin-bottom:10px">
        <div style="display:flex;align-items:center;gap:8px">
          <div style="width:22px;height:22px;background:var(--a);border-radius:50%;color:#fff;font-size:11px;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0">1</div>
          <div class="card-ttl">Choose Content Type</div>
        </div>
      </div>
      <div style="display:flex;flex-direction:column;gap:4px" id="ai-type-list">
        ${contentGroups.map(g=>`
          <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.7px;color:var(--text2);padding:6px 2px 3px">${g.group}</div>
          ${g.items.map(t=>`<button class="ai-type-btn${t.id==='Instagram Caption'?' on':''}" onclick="_selAiType(this,'${t.id}')" data-type="${t.id}">
            <span style="font-size:15px;flex-shrink:0">${t.icon}</span>
            <div style="text-align:left">
              <div style="font-size:12.5px;font-weight:700;line-height:1.2">${t.id}</div>
              <div style="font-size:10.5px;color:var(--text2);font-weight:400;margin-top:1px">${t.desc}</div>
            </div>
          </button>`).join('')}
        `).join('')}
      </div>
    </div>

    <div class="card" style="margin-bottom:12px">
      <div class="card-hd" style="margin-bottom:10px">
        <div style="display:flex;align-items:center;gap:8px">
          <div style="width:22px;height:22px;background:var(--a);border-radius:50%;color:#fff;font-size:11px;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0">2</div>
          <div class="card-ttl">Product or Topic</div>
        </div>
      </div>
      <select class="fs" id="ctProd" style="margin-bottom:8px">
        <option value="">— Select or type below —</option>
        ${hasSvcContent}
        ${invOptions}
        <option value="general">General Business Promotion</option>
      </select>
      <input class="fi" id="ctProdCustom" placeholder="Or type a custom topic…" style="font-size:12.5px" oninput="if(this.value) document.getElementById('ctProd').value=''"/>
    </div>

    <div class="card" style="margin-bottom:12px">
      <div class="card-hd" style="margin-bottom:10px">
        <div style="display:flex;align-items:center;gap:8px">
          <div style="width:22px;height:22px;background:var(--a);border-radius:50%;color:#fff;font-size:11px;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0">3</div>
          <div class="card-ttl">Tone</div>
        </div>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:7px" id="ai-tone-box">
        ${tones.map((t,i)=>`<button class="ai-tone-btn${i===0?' on':''}" onclick="_selAiTone(this,'${t.id}')">${t.icon} ${t.id}</button>`).join('')}
      </div>
    </div>

    <div class="card" style="margin-bottom:12px">
      <div class="card-hd" style="margin-bottom:10px">
        <div style="display:flex;align-items:center;gap:8px">
          <div style="width:22px;height:22px;background:var(--border2);border-radius:50%;color:var(--text2);font-size:11px;font-weight:800;display:flex;align-items:center;justify-content:center;flex-shrink:0">4</div>
          <div class="card-ttl" style="color:var(--text2)">Extra Context <span style="font-weight:400;font-size:11px">(optional)</span></div>
        </div>
      </div>
      <textarea class="ft" id="ctCtx" placeholder="e.g. 20% off this weekend only, DM to order, valid until Sunday…" style="min-height:70px;font-size:12.5px;resize:vertical"></textarea>
    </div>

    <button class="ai-gen-btn" onclick="genAI()" id="ai-gen-main-btn">
      <span id="ai-btn-icon">✨</span>
      <span id="ai-btn-text">Generate Content</span>
    </button>
  </div>

  <!-- RIGHT: Output + History -->
  <div>
    <div class="card" style="margin-bottom:12px">
      <div class="card-hd" style="margin-bottom:14px">
        <div style="font-size:14px;font-weight:700;color:var(--ink)">Generated Content</div>
        <div id="ai-type-badge" style="font-size:11px;font-weight:700;background:rgba(67,97,238,.1);color:var(--a);border-radius:20px;padding:3px 10px">Instagram Caption</div>
      </div>

      <!-- Flyer preview panel (hidden unless Branded Flyer selected) -->
      <div id="ai-flyer-panel" style="display:none;margin-bottom:14px">
        <div style="border:2px solid var(--border2);border-radius:var(--r8);overflow:hidden;background:#f0f2f5;display:flex;align-items:center;justify-content:center;padding:20px;min-height:520px" id="ai-flyer-wrap">
          <div id="ai-flyer-div" style="width:420px;font-family:'Segoe UI',Arial,sans-serif;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 12px 40px rgba(0,0,0,.18)">
            <div style="padding:60px 32px;text-align:center;color:var(--text2)">
              <div style="font-size:36px;margin-bottom:12px">🖼️</div>
              <div style="font-size:14px">Click Generate to create your branded flyer</div>
            </div>
          </div>
        </div>
        <div style="display:flex;gap:8px;margin-top:10px;flex-wrap:wrap">
          <button class="btn btn-p" style="flex:2" id="ai-flyer-png-btn" onclick="_aiFlyerDownloadPNG()" disabled>⬇ Save as PNG</button>
          <button class="btn btn-g btn-sm" style="flex:1" id="ai-flyer-pdf-btn" onclick="_aiFlyerPrint()" disabled>🖨️ Print / PDF</button>
          <button class="btn btn-s btn-sm" onclick="genAI()">🔄 Regenerate</button>
        </div>
        <div style="margin-top:8px;display:none" id="ai-flyer-wa-row">
          <button class="btn btn-g" style="width:100%" onclick="_aiFlyerWhatsApp()">💬 Share via WhatsApp</button>
        </div>
      </div>

      <!-- AI Image panel (hidden unless AI Product Photo selected) -->
      <div id="ai-image-panel" style="display:none;margin-bottom:14px">
        <div style="border:2px solid var(--border2);border-radius:var(--r8);overflow:hidden;background:#f0f2f5;min-height:340px;display:flex;align-items:center;justify-content:center;position:relative" id="ai-img-wrap">
          <div style="text-align:center;color:var(--text2);padding:40px">
            <div style="font-size:40px;margin-bottom:12px">🎨</div>
            <div style="font-size:14px;font-weight:600;margin-bottom:6px">AI Product Photo Generator</div>
            <div style="font-size:12px">Enter your product and click Generate.<br>Requires OpenAI key in Settings.</div>
          </div>
        </div>
        <div style="display:flex;gap:8px;margin-top:10px;flex-wrap:wrap" id="ai-img-actions" style="display:none">
          <button class="btn btn-p" style="flex:1" id="ai-img-dl-btn" onclick="_aiImgDownload()">⬇ Download PNG</button>
          <button class="btn btn-g btn-sm" style="flex:1" onclick="_aiImgWhatsApp()">💬 Share via WhatsApp</button>
          <button class="btn btn-s btn-sm" onclick="genAI()">🔄 Regenerate</button>
        </div>
      </div>

      <!-- Text output area -->
      <div id="ai-text-panel">
        <div class="ai-out" id="aiOut" style="min-height:200px"><span style="color:var(--text2);font-style:italic;font-size:13px">Configure your settings on the left and click Generate. Content appears here ready to copy and post.</span></div>
        <div id="ai-char-count" class="ai-char-count" style="display:none"></div>
        <div id="ai-action-bar" style="display:none;margin-top:14px">
          <div style="display:flex;gap:8px;flex-wrap:wrap">
            <button class="btn btn-p btn-sm" onclick="_aiCopy()" style="flex:1;min-width:120px">📋 Copy</button>
            <button class="btn btn-g btn-sm" onclick="_aiWhatsApp()" style="flex:1;min-width:120px">💬 WhatsApp</button>
            <button class="btn btn-s btn-sm" onclick="_aiInstagram()" style="flex:1;min-width:120px">📸 Instagram</button>
          </div>
          <div style="display:flex;gap:8px;margin-top:8px">
            <button class="btn btn-s btn-sm" onclick="genAI()" style="flex:1">🔄 Regenerate</button>
            <button class="btn btn-s btn-sm" onclick="_aiSaveToHistory()" style="flex:1">💾 Save</button>
          </div>
        </div>
      </div>
    </div>

    <div class="card">
      <div class="card-hd" style="margin-bottom:10px">
        <div class="card-ttl">Recent Generations</div>
        <button class="btn btn-g btn-sm" onclick="_aiClearHistory()" id="ai-clear-hist-btn" style="display:none">Clear</button>
      </div>
      <div id="ai-history-list">
        <div style="text-align:center;padding:20px;color:var(--text2);font-size:13px">
          <div style="font-size:28px;margin-bottom:8px">📋</div>
          Your generated content will appear here.<br>Click Save on any generation to keep it.
        </div>
      </div>
    </div>
  </div>
</div>`;
}

// ── AI Studio state ──────────────────────────────────────────
let _aiType = 'Instagram Caption';
let _tone   = 'Professional';
let _aiHistory = [];

function _selAiType(el, type){
  _aiType = type;
  document.querySelectorAll('.ai-type-btn').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  const badge = document.getElementById('ai-type-badge');
  if(badge) badge.textContent = type;
  // Toggle panels
  const flyerPanel = document.getElementById('ai-flyer-panel');
  const imagePanel = document.getElementById('ai-image-panel');
  const textPanel  = document.getElementById('ai-text-panel');
  const isFlyer    = type === 'Branded Flyer';
  const isImage    = type === 'AI Product Photo';
  if(flyerPanel) flyerPanel.style.display = isFlyer ? 'block' : 'none';
  if(imagePanel) imagePanel.style.display = isImage ? 'block' : 'none';
  if(textPanel)  textPanel.style.display  = (isFlyer||isImage) ? 'none' : 'block';
  if(window.innerWidth < 768) document.getElementById('aiOut')?.scrollIntoView({behavior:'smooth',block:'nearest'});
}

function _selAiTone(el, tone){
  _tone = tone;
  document.querySelectorAll('.ai-tone-btn').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
}

// ── Branded Flyer Generator ───────────────────────────────────
function _genAIFlyer(prod, ctx, btn, btnTxt, btnIco){
  if(btn) btn.disabled=true;
  if(btnTxt) btnTxt.textContent='Designing flyer…';
  if(btnIco) btnIco.textContent='⏳';

  const bizName    = BIZ.name || 'Our Business';
  const bizTagline = BIZ.tagline || '';
  const primary    = BIZ.primaryColor || '#e8667a';
  const accent     = BIZ.accentColor  || '#f5a623';
  const phone      = BIZ.phone || BIZ.whatsapp || '';
  const email      = BIZ.email || '';
  const address    = BIZ.address || '';
  const instagram  = BIZ.instagram ? '@'+BIZ.instagram : '';
  const month      = new Date().toLocaleString('en',{month:'long',year:'numeric'});
  const tone       = _tone || 'Professional';

  const prompt = `You are a professional marketing copywriter creating content for a branded promotional flyer for "${bizName}".

Business: ${bizName}${bizTagline?' — "'+bizTagline+'"':''}
Product/Topic: ${prod}
Tone: ${tone}
${ctx?'Context: '+ctx:''}

Write the flyer content as a JSON object with these exact fields (no markdown, no backticks, raw JSON only):
{
  "headline": "Bold attention-grabbing headline (max 8 words, ALL CAPS preferred)",
  "subheadline": "Supporting line (max 15 words)",
  "body": "2-3 short punchy benefit lines, each starting with an emoji bullet",
  "cta": "Call to action text (max 6 words, e.g. 'DM Us to Order Today!')",
  "tag": "One key hashtag without # symbol (e.g. ZunasChoice)"
}`;

  _aiCall({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 400,
    messages: [{ role: 'user', content: prompt }]
  })
  .then(function(d){
    var raw = (d.content&&d.content[0]&&d.content[0].text)||'{}';
    // Strip any markdown fences
    raw = raw.replace(/```json|```/g,'').trim();
    var copy;
    try{ copy = JSON.parse(raw); } catch(e){
      copy = {
        headline: (prod||bizName).toUpperCase(),
        subheadline: 'Available now at '+bizName,
        body: '✨ Premium quality\n💫 Perfect for any occasion\n📲 Contact us today',
        cta: 'DM Us to Order Now!',
        tag: bizName.replace(/\s+/g,'').substring(0,15)
      };
    }
    _renderAIFlyer(copy, prod, bizName, bizTagline, primary, accent, phone, email, address, instagram, month);
    if(btn){ btn.disabled=false; }
    if(btnTxt) btnTxt.textContent='Regenerate Flyer';
    if(btnIco) btnIco.textContent='🔄';
  })
  .catch(function(e){
    // Fallback flyer with template copy
    const copy = {
      headline: (prod||bizName).toUpperCase(),
      subheadline: 'Available now at '+bizName,
      body: '✨ Premium quality guaranteed\n💫 Perfect for every occasion\n📲 Contact us for availability',
      cta: 'DM Us to Order Today!',
      tag: bizName.replace(/\s+/g,'').substring(0,15)
    };
    _renderAIFlyer(copy, prod, bizName, bizTagline, primary, accent, phone, email, address, instagram, month);
    if(btn){ btn.disabled=false; }
    if(btnTxt) btnTxt.textContent='Regenerate Flyer';
    if(btnIco) btnIco.textContent='🔄';
  });
}

function _renderAIFlyer(copy, prod, bizName, tagline, primary, accent, phone, email, address, instagram, month){
  const logoHtml = BIZ.logoDataUrl
    ? `<img src="${BIZ.logoDataUrl}" style="height:52px;width:auto;object-fit:contain;display:block;margin-bottom:8px" crossorigin="anonymous"/>`
    : `<div style="display:inline-flex;align-items:center;justify-content:center;width:52px;height:52px;background:rgba(255,255,255,0.25);border-radius:12px;font-size:20px;font-weight:900;color:#fff;margin-bottom:8px">${bizName.substring(0,2).toUpperCase()}</div>`;

  const bodyLines = (copy.body||'').split('\n').filter(Boolean).map(l=>
    `<div style="margin-bottom:9px;display:flex;align-items:flex-start;gap:8px;font-size:13.5px;color:#374151"><span style="flex-shrink:0">${l.substring(0,2)}</span><span>${l.substring(2).trim()}</span></div>`
  ).join('');

  const footerText = [phone, email, instagram, address].filter(Boolean).join('  ·  ');

  const flyerDiv = document.getElementById('ai-flyer-div');
  if(!flyerDiv) return;

  flyerDiv.style.cssText = 'width:420px;font-family:Segoe UI,Arial,sans-serif;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 12px 40px rgba(0,0,0,.18)';
  flyerDiv.innerHTML = `
    <div style="background:${primary};padding:32px 28px 24px;position:relative;overflow:hidden">
      <div style="position:absolute;top:-50px;right:-50px;width:180px;height:180px;background:rgba(255,255,255,.07);border-radius:50%"></div>
      <div style="position:absolute;bottom:-35px;left:-35px;width:120px;height:120px;background:rgba(255,255,255,.05);border-radius:50%"></div>
      <div style="position:absolute;top:14px;right:14px;background:rgba(255,255,255,.18);color:#fff;font-size:9px;font-weight:700;padding:3px 9px;border-radius:20px;letter-spacing:.5px;text-transform:uppercase">${month}</div>
      ${logoHtml}
      <div style="font-size:11px;font-weight:700;color:rgba(255,255,255,.75);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:6px">${bizName}${tagline?' — '+tagline:''}</div>
      <div style="font-size:26px;font-weight:900;color:#fff;line-height:1.15;letter-spacing:-.3px;margin-bottom:7px">${copy.headline||prod||bizName}</div>
      <div style="font-size:13px;color:rgba(255,255,255,.85);font-weight:500;line-height:1.4">${copy.subheadline||''}</div>
    </div>
    <div style="height:4px;background:linear-gradient(90deg,${accent},${accent}66)"></div>
    <div style="background:#fff;padding:24px 28px">
      <div style="margin-bottom:18px">${bodyLines}</div>
      <div style="display:block;background:${primary};color:#fff;text-align:center;padding:13px 20px;border-radius:10px;font-size:14px;font-weight:800;letter-spacing:.2px;margin-bottom:16px;box-shadow:0 4px 12px ${primary}44">${copy.cta||'Contact Us Today!'}</div>
      <div style="text-align:center;font-size:12px;color:${primary};font-weight:700">#${copy.tag||bizName.replace(/\s+/g,'')}</div>
    </div>
    <div style="background:#f8fafc;border-top:1px solid #e5e7eb;padding:12px 28px;font-size:10.5px;color:#9ca3af;text-align:center;line-height:1.7">${footerText||bizName}</div>`;

  window._lastFlyerProd = prod;

  // Enable buttons
  const pngBtn = document.getElementById('ai-flyer-png-btn');
  const pdfBtn = document.getElementById('ai-flyer-pdf-btn');
  const waRow  = document.getElementById('ai-flyer-wa-row');
  if(pngBtn){ pngBtn.disabled=false; }
  if(pdfBtn){ pdfBtn.disabled=false; }
  if(waRow)  waRow.style.display='block';

  toast('Flyer ready — save as PNG or print as PDF ✓','success');
}

function _aiFlyerDownloadPNG(){
  const flyerDiv = document.getElementById('ai-flyer-div');
  if(!flyerDiv || !flyerDiv.innerHTML.includes('headline') && !flyerDiv.querySelector('[style*="font-weight:900"]')){
    toast('Generate a flyer first','error'); return;
  }
  const btn = document.getElementById('ai-flyer-png-btn');
  if(btn){ btn.disabled=true; btn.textContent='⏳ Capturing…'; }

  // Load html2canvas from CDN if not already loaded
  function doCapture(){
    window.html2canvas(flyerDiv, {
      scale: 2,           // 2x for retina-quality PNG
      useCORS: true,
      backgroundColor: null,
      logging: false,
    }).then(function(canvas){
      const link = document.createElement('a');
      const prod = (window._lastFlyerProd||'flyer').replace(/[^a-z0-9]/gi,'_').toLowerCase();
      link.download = (BIZ.name||'flyer').replace(/\s+/g,'_')+'_'+prod+'_flyer.png';
      link.href = canvas.toDataURL('image/png');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window._lastFlyerDataUrl = link.href;
      toast('Flyer saved as PNG ✓','success');
      if(btn){ btn.disabled=false; btn.textContent='⬇ Save as PNG'; }
    }).catch(function(err){
      console.error('html2canvas error:', err);
      toast('PNG capture failed — try Print/PDF instead','error');
      if(btn){ btn.disabled=false; btn.textContent='⬇ Save as PNG'; }
    });
  }

  if(window.html2canvas){
    doCapture();
  } else {
    const script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
    script.onload = doCapture;
    script.onerror = function(){
      toast('Could not load image library — try Print/PDF instead','error');
      if(btn){ btn.disabled=false; btn.textContent='⬇ Save as PNG'; }
    };
    document.head.appendChild(script);
  }
}

function _aiFlyerPrint(){
  const flyerDiv = document.getElementById('ai-flyer-div');
  if(!flyerDiv || !flyerDiv.children.length){ toast('Generate a flyer first','error'); return; }
  const primary = BIZ.primaryColor||'#e8667a';
  const printHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:'Segoe UI',Arial,sans-serif;background:#f0f2f5;display:flex;align-items:center;justify-content:center;min-height:100vh;padding:20px}@media print{body{background:#fff;padding:0}@page{margin:0}}</style></head><body>${flyerDiv.outerHTML}<script>window.onload=function(){window.print()}<\/script></body></html>`;
  try{
    const w=window.open('','_blank','width=580,height=820');
    if(w){ w.document.write(printHtml); w.document.close(); }
    else  toast('Allow popups to print','error');
  }catch(e){ toast('Could not open print window','error'); }
}

function _aiFlyerWhatsApp(){
  const waNum = (BIZ.whatsapp||BIZ.phone||'').replace(/[^0-9]/g,'');
  const prod  = window._lastFlyerProd || 'our latest offer';
  const msg   = `✨ Check out our latest from *${BIZ.name||'us'}*!\n\n*${prod}* — available now.\n\n📲 DM us to order!\n${BIZ.phone?'📞 '+BIZ.phone:''}`;
  const url   = waNum ? `https://wa.me/${waNum}?text=${encodeURIComponent(msg)}` : `https://wa.me/?text=${encodeURIComponent(msg)}`;
  // Prompt to save PNG first
  if(window._lastFlyerDataUrl){
    toast('Opening WhatsApp — attach the saved PNG image manually','info');
  } else {
    toast('Tip: Save as PNG first, then attach the image in WhatsApp','info');
  }
  setTimeout(()=>window.open(url,'_blank'), 800);
}

// ── DALL-E AI Product Photo ───────────────────────────────────
function _genDALLEImage(prod, ctx, btn, btnTxt, btnIco){
  const openAiKey = BIZ.openAiKey || '';
  const wrap = document.getElementById('ai-img-wrap');
  const actions = document.getElementById('ai-img-actions');
  if(!wrap) return;

  if(btn) btn.disabled=true;
  if(btnTxt) btnTxt.textContent='Generating image…';
  if(btnIco) btnIco.textContent='⏳';

  wrap.innerHTML = `<div style="text-align:center;padding:40px;color:var(--text2)"><div class="ai-dots"><div class="ai-dot"></div><div class="ai-dot"></div><div class="ai-dot"></div></div><div style="margin-top:14px;font-size:13px">DALL-E is generating your product image…</div></div>`;

  const bizType   = D.adminBiz.find(b=>b.id===SESSION.bizId)?.type || 'boutique';
  const location  = BIZ.address ? BIZ.address.split(',').slice(-1)[0].trim() : 'Cameroon';
  const dallePrompt = `Professional product photography of "${prod}" for a ${bizType} in ${location}. ${ctx||''}. Clean white or neutral background, studio lighting, sharp focus, commercial quality, vibrant colors, suitable for social media marketing.`.trim();

  // Route through proxy or direct if own key
  const body = {
    prompt: dallePrompt,
    model:  'dall-e-3',
    n: 1,
    size: '1024x1024',
    quality: 'standard',
    response_format: 'url',
  };

  const fetchPromise = openAiKey
    ? fetch('https://api.openai.com/v1/images/generations', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer '+openAiKey },
        body: JSON.stringify(body)
      })
    : fetch('/.netlify/functions/dalle-proxy', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ body, bizId: SESSION.bizId||'' })
      });

  fetchPromise
    .then(function(r){
      if(!r.ok) return r.json().then(function(e){ throw new Error(e.error?.message||e.error||('Error '+r.status)); });
      return r.json();
    })
    .then(function(d){
      const url = d.data?.[0]?.url || (d.data?.[0]?.b64_json ? 'data:image/png;base64,'+d.data[0].b64_json : null);
      if(!url) throw new Error('No image returned');
      window._lastAiImgUrl = url;
      wrap.innerHTML = `<img src="${url}" style="width:100%;height:auto;display:block;border-radius:8px" crossorigin="anonymous" alt="AI generated product photo"/>`;
      if(actions) actions.style.display='flex';
      if(btn){ btn.disabled=false; }
      if(btnTxt) btnTxt.textContent='Regenerate Image';
      if(btnIco) btnIco.textContent='🔄';
      toast('AI image ready — download or share ✓','success');
    })
    .catch(function(e){
      const msg = e&&e.message?e.message:String(e);
      const isNoKey = msg.toLowerCase().includes('api key')||msg.toLowerCase().includes('unauthorized')||msg.includes('401');
      wrap.innerHTML = `<div style="text-align:center;padding:40px;color:var(--r)"><div style="font-size:30px;margin-bottom:10px">⚠️</div><div style="font-size:13px;font-weight:600">${isNoKey?'OpenAI API key required':'Image generation failed'}</div><div style="font-size:12px;color:var(--text2);margin-top:6px">${isNoKey?'Add your OpenAI key in Settings → AI Studio to use this feature.':_esc(msg)}</div></div>`;
      if(btn){ btn.disabled=false; }
      if(btnTxt) btnTxt.textContent='Try Again';
      if(btnIco) btnIco.textContent='🔄';
    });
}

function _aiImgDownload(){
  const url = window._lastAiImgUrl;
  if(!url){ toast('Generate an image first','error'); return; }
  const prod = (_aiGetProd()||'product').replace(/[^a-z0-9]/gi,'_').toLowerCase();
  // For DALL-E URLs (external), open in new tab — user can long-press to save
  if(url.startsWith('http')){
    toast('Opening image — long-press or right-click to save','info');
    window.open(url,'_blank');
    return;
  }
  // For base64 data URLs, download directly
  const a = document.createElement('a');
  a.href = url;
  a.download = (BIZ.name||'product').replace(/\s+/g,'_')+'_'+prod+'_ai_photo.png';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
}

function _aiImgWhatsApp(){
  const url = window._lastAiImgUrl;
  if(!url){ toast('Generate an image first','error'); return; }
  const prod = _aiGetProd() || 'our featured product';
  const waNum = (BIZ.whatsapp||BIZ.phone||'').replace(/[^0-9]/g,'');
  const msg = `✨ Check out *${prod}* from *${BIZ.name||'us'}*!\n\nAvailable now — contact us to order.\n${BIZ.phone?'📞 '+BIZ.phone:''}`;
  toast('Opening WhatsApp — note: image must be attached manually','info');
  setTimeout(function(){
    const waUrl = waNum ? `https://wa.me/${waNum}?text=${encodeURIComponent(msg)}` : `https://wa.me/?text=${encodeURIComponent(msg)}`;
    window.open(waUrl,'_blank');
  }, 800);
}

function _aiGetProd(){
  const custom = document.getElementById('ctProdCustom')?.value?.trim();
  if(custom) return custom;
  const sel = document.getElementById('ctProd');
  return sel?.value || 'our featured product';
}

// ── Copy with formatting preserved ──────────────────────────
function _aiCopy(){
  const out = document.getElementById('aiOut');
  if(!out) return;
  const text = out.textContent;
  if(!text || text.includes('Configure your settings')) { toast('Nothing to copy — generate content first','error'); return; }
  navigator.clipboard?.writeText(text)
    .then(()=>{ toast('Copied to clipboard ✓','success'); _aiFlashBtn('📋 Copy','✓ Copied!'); })
    .catch(()=>{ 
      const ta=document.createElement('textarea'); ta.value=text;
      document.body.appendChild(ta); ta.select(); document.execCommand('copy');
      document.body.removeChild(ta); toast('Copied ✓','success');
    });
}

function _aiFlashBtn(oldText, newText){
  const btns = document.querySelectorAll('#ai-action-bar button');
  btns.forEach(b=>{ if(b.textContent.trim()===oldText){ b.textContent=newText; setTimeout(()=>b.textContent=oldText,1600); }});
}

// ── Share to WhatsApp ────────────────────────────────────────
function _aiWhatsApp(){
  const out = document.getElementById('aiOut');
  const text = out?.textContent||'';
  if(!text || text.includes('Configure your settings')) { toast('Generate content first','error'); return; }
  const waNum = (BIZ.whatsapp||BIZ.phone||'').replace(/[^0-9]/g,'');
  const url = waNum
    ? `https://wa.me/${waNum}?text=${encodeURIComponent(text)}`
    : `https://wa.me/?text=${encodeURIComponent(text)}`;
  window.open(url, '_blank');
}

// ── Open Instagram (copy + go) ───────────────────────────────
function _aiInstagram(){
  const out = document.getElementById('aiOut');
  const text = out?.textContent||'';
  if(!text || text.includes('Configure your settings')) { toast('Generate content first','error'); return; }
  navigator.clipboard?.writeText(text).then(()=>{
    toast('Caption copied — opening Instagram…','success');
    setTimeout(()=>window.open('https://www.instagram.com/','_blank'), 800);
  }).catch(()=>window.open('https://www.instagram.com/','_blank'));
}

// ── Save to history ──────────────────────────────────────────
function _aiSaveToHistory(){
  const out = document.getElementById('aiOut');
  const text = out?.textContent||'';
  if(!text || text.includes('Configure your settings')) { toast('Nothing to save','error'); return; }
  const prod = _aiGetProd();
  _aiHistory.unshift({type:_aiType, prod, tone:_tone, text, ts: new Date().toLocaleTimeString('en',{hour:'2-digit',minute:'2-digit'})});
  if(_aiHistory.length > 10) _aiHistory.pop(); // keep last 10
  _aiRenderHistory();
  toast('Saved to history ✓','success');
  // Also save to localStorage for persistence
  try{ localStorage.setItem('shoptrack_ai_history', JSON.stringify(_aiHistory.slice(0,10))); }catch(e){}
}

function _aiLoadHistory(){
  try{
    const saved = localStorage.getItem('shoptrack_ai_history');
    if(saved) _aiHistory = JSON.parse(saved);
  }catch(e){ _aiHistory = []; }
  _aiRenderHistory();
}

function _aiRenderHistory(){
  const el = document.getElementById('ai-history-list');
  const clearBtn = document.getElementById('ai-clear-hist-btn');
  if(!el) return;
  if(!_aiHistory.length){
    el.innerHTML = '<div style="text-align:center;padding:20px;color:var(--text2);font-size:13px"><div style="font-size:28px;margin-bottom:8px">📋</div>Your saved generations appear here.</div>';
    if(clearBtn) clearBtn.style.display='none';
    return;
  }
  if(clearBtn) clearBtn.style.display='';
  el.innerHTML = _aiHistory.map((h,i)=>`
    <div class="ai-hist-item" onclick="_aiLoadHistItem(${i})">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
        <div style="min-width:0">
          <div style="font-size:12.5px;font-weight:700;color:var(--ink);margin-bottom:2px">${h.type}</div>
          <div style="font-size:11px;color:var(--text2)">${h.prod} · ${h.tone} · ${h.ts}</div>
          <div style="font-size:12px;color:var(--text);margin-top:4px;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical">${h.text.replace(/\n/g,' ')}</div>
        </div>
        <button onclick="event.stopPropagation();_aiDeleteHistItem(${i})" style="background:none;border:none;color:var(--text2);cursor:pointer;font-size:14px;flex-shrink:0;padding:0 2px" title="Remove">×</button>
      </div>
    </div>
  `).join('');
}

function _aiLoadHistItem(i){
  const h = _aiHistory[i];
  if(!h) return;
  const out = document.getElementById('aiOut');
  if(out){ typewrite(out, h.text); out.classList.add('has-content'); }
  _aiShowActionBar();
  _aiUpdateCharCount(h.text);
  // Scroll to output
  out?.scrollIntoView({behavior:'smooth', block:'nearest'});
  toast('Loaded from history','success');
}

function _aiDeleteHistItem(i){
  _aiHistory.splice(i,1);
  try{ localStorage.setItem('shoptrack_ai_history', JSON.stringify(_aiHistory)); }catch(e){}
  _aiRenderHistory();
}

function _aiClearHistory(){
  if(!confirm('Clear all saved generations?')) return;
  _aiHistory = [];
  try{ localStorage.removeItem('shoptrack_ai_history'); }catch(e){}
  _aiRenderHistory();
  toast('History cleared','success');
}

function _aiShowActionBar(){
  const bar = document.getElementById('ai-action-bar');
  if(bar) bar.style.display='block';
}

function _aiUpdateCharCount(text){
  const el = document.getElementById('ai-char-count');
  if(!el) return;
  const len = (text||'').length;
  if(!len){ el.style.display='none'; return; }
  el.style.display='block';
  // Instagram: 2200 limit, WhatsApp: practical ~1000
  const limit = _aiType.includes('Instagram') ? 2200 : 1000;
  el.textContent = `${len} / ${limit} chars`;
  el.className = 'ai-char-count' + (len > limit ? ' over' : len > limit*0.85 ? ' warn' : '');
}

