// ── Central AI API call helper ────────────────────────────────
function _aiCall(payload){
  // ── If the business has their own API key, call directly (Pro/Enterprise perk) ──
  var ownKey = BIZ.aiKey || '';
  if(ownKey){
    return fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': ownKey,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true'
      },
      body: JSON.stringify(payload)
    })
    .then(function(r){
      if(!r.ok) return r.text().then(function(t){
        var msg=t; try{ msg=JSON.parse(t).error.message; }catch(e){}
        throw new Error('API '+r.status+': '+msg);
      });
      return r.json();
    })
    .then(function(d){
      if(d.error) throw new Error(d.error.message||JSON.stringify(d.error));
      return d;
    });
  }

  // ── Route through secure server-side proxy (platform key, plan-limited) ──
  var bizPlan = (D.adminBiz.find(function(b){return b.id===SESSION.bizId;})||{}).plan || 'Trial';
  return fetch('/.netlify/functions/ai-proxy', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      payload:  payload,
      bizId:    SESSION.bizId || '',
      bizPlan:  bizPlan,
      userId:   SESSION.userId || ''
    })
  })
  .then(function(r){
    if(!r.ok) return r.json().then(function(e){
      throw new Error(e.error || ('Request failed: '+r.status));
    }).catch(function(parseErr){
      if(parseErr.message&&parseErr.message!=='Unexpected end of JSON input') throw parseErr;
      throw new Error('AI service unavailable ('+r.status+')');
    });
    return r.json();
  })
  .then(function(d){
    if(d.error) throw new Error(d.error);
    return d;
  });
}

function genAI(){
  const type  = _aiType || 'Instagram Caption';
  const prod  = _aiGetProd();
  const ctx   = document.getElementById('ctCtx')?.value||'';
  const btn   = document.getElementById('ai-gen-main-btn');
  const btnTxt= document.getElementById('ai-btn-text');
  const btnIco= document.getElementById('ai-btn-icon');

  // Route branded flyer to dedicated generator
  if(type === 'Branded Flyer') { _genAIFlyer(prod, ctx, btn, btnTxt, btnIco); return; }
  // Route AI image generation to DALL-E handler
  if(type === 'AI Product Photo') { _genDALLEImage(prod, ctx, btn, btnTxt, btnIco); return; }

  const out   = document.getElementById('aiOut');
  if(!out) return;

  // Loading state
  out.innerHTML=`<div class="ai-dots"><div class="ai-dot"></div><div class="ai-dot"></div><div class="ai-dot"></div><span style="margin-left:10px;color:var(--text2);font-size:13px">Writing your ${type}…</span></div>`;
  out.classList.remove('has-content');
  document.getElementById('ai-action-bar').style.display='none';
  document.getElementById('ai-char-count').style.display='none';
  if(btn){ btn.disabled=true; }
  if(btnTxt) btnTxt.textContent='Generating…';
  if(btnIco) btnIco.textContent='⏳';

  // Build rich business context
  const bizName    = BIZ.name || 'our business';
  const bizTagline = BIZ.tagline || '';
  const bizType    = D.adminBiz.find(b=>b.id===SESSION.bizId)?.type || 'business';
  const invCats    = [...new Set(D.inv.map(i=>i.cat).filter(Boolean))].slice(0,6);
  const svcNames   = (D.services||[]).filter(s=>s.active).map(s=>s.name).slice(0,6);
  const allOfferings = [...invCats, ...svcNames].join(', ') || 'various products';
  const hasSale    = D.inv.some(i=>i.st==='For Sale'||i.st==='Both');
  const hasRent    = D.inv.some(i=>i.st==='For Rent'||i.st==='Both');
  const offerStr   = hasSale && hasRent ? 'sale and rental' : hasSale ? 'sale' : hasRent ? 'rental' : 'sale and services';
  const location   = BIZ.address ? BIZ.address.split(',').slice(-2).join(',').trim() : 'Cameroon';
  const whatsapp   = BIZ.whatsapp || BIZ.phone || '';
  const instaHandle= BIZ.instagram || ('@'+(bizName.replace(/\s+/g,'').toLowerCase())).substring(0,20);

  const systemPrompt = `You are a creative marketing content writer for "${bizName}"${bizTagline?` ("${bizTagline}")`:''}. This is a ${bizType} based in ${location} offering ${offerStr} of: ${allOfferings}.${whatsapp?` WhatsApp: ${whatsapp}.`:''} Instagram: ${instaHandle}.

RULES (follow exactly):
- Write ONLY for ${bizName} — never reference other businesses
- Output the content ONLY — no preamble, no "Here is your..." intro
- Tone: ${_tone}
- Be compelling, specific, and ready to use immediately
- Use emojis naturally (not excessively)
- Keep hashtags relevant to the actual business and products`;

  // Email Campaign: structured subject + body
  const emailInstructions = type==='Email Campaign'
    ? '\n\nFormat the email exactly as:\nSUBJECT: [subject line here]\n\n[full email body here]'
    : '';

  // Seasonal Campaign Planner: 7 days of content
  const plannerInstructions = (type==='Seasonal Campaign Planner'||type==='Weekly Content Plan')
    ? '\n\nCreate a 7-day social media content plan. For each day write:\nDAY X — [Day name]: [Platform] — [Post idea 1-2 sentences] + [2 relevant hashtags]\n\nMake it specific to the product/topic and season. Include mix of Instagram, WhatsApp, and Facebook.'
    : '';

  const maxTokens = (type==='Seasonal Campaign Planner'||type==='Weekly Content Plan') ? 1400 : 900;

  _aiCall({
      model:'claude-sonnet-4-6',
      max_tokens:maxTokens,
      messages:[{role:'user',content:systemPrompt+'\n\nWrite a '+type+' for: "'+prod+'"'+(ctx?'\nAdditional context: '+ctx:'')+emailInstructions+plannerInstructions+'\n\nWrite now:'}]
  })
  .then(function(d){
    var text = d.content&&d.content[0]&&d.content[0].text||'';
    if(!text) throw new Error('Empty response');
    typewrite(out, text);
    out.classList.add('has-content');
    _aiShowActionBar();
    _aiUpdateCharCount(text);
    window._lastAiText = text;
  })
  .catch(function(e){
    var msg = e&&e.message?e.message:String(e);
    if(msg.includes('No API key')){
      var fn = _aiTpls[type] || _aiTpls['Product Description'];
      var text = fn(prod||bizName, _tone, bizName, allOfferings);
      typewrite(out, text);
      out.classList.add('has-content');
      _aiShowActionBar();
      _aiUpdateCharCount(text);
      window._lastAiText = text;
      toast('Using template — add API key in Settings for real AI','warn');
    } else {
      out.innerHTML='<span style="color:var(--r)">Error: '+msg+'</span>';
    }
  })
  .finally(function(){
    if(btn){ btn.disabled=false; }
    if(btnTxt) btnTxt.textContent='Generate Content';
    if(btnIco) btnIco.textContent='✨';
  });
}

function copyAIContent(){ _aiCopy(); }

function typewrite(el,text){
  if(!el) return;
  el.textContent=''; el.classList.add('typing-cur');
  let i=0;
  const iv=setInterval(()=>{
    if(i<text.length){ el.textContent=text.slice(0,i+1); i+=3; }
    else{ el.textContent=text; el.classList.remove('typing-cur'); clearInterval(iv); _aiUpdateCharCount(text); }
  },16);
}

