// ── Audit category classifier ─────────────────────────────────
function _auditCat(action){
  const a = (action||'').toLowerCase();
  if(/login|logout|sign/.test(a))                          return 'Session';
  if(/sale|payment|invoice|receipt/.test(a))               return 'Sales';
  if(/rental|return|checked/.test(a))                      return 'Rentals';
  if(/item|inventory|stock|price|sku|duplicat.*inv/.test(a)) return 'Inventory';
  if(/expense|duplicat.*exp/.test(a))                      return 'Expenses';
  if(/purchase|po|vendor added|vendor upd/.test(a))        return 'Purchases';
  if(/customer/.test(a))                                   return 'Customers';
  if(/user|rights|password|suspend.*user|reactivat.*user/.test(a)) return 'Users';
  if(/business|provision|activat.*biz|suspend.*biz/.test(a)) return 'Business';
  if(/profile|settings|document|currency|plan/.test(a))   return 'Settings';
  if(/import/.test(a))                                     return 'Import';
  return 'Other';
}

const _AUDIT_CAT_COLOR = {
  'Session':'bx-p','Sales':'bx-g','Rentals':'bx-c','Inventory':'bx-b',
  'Expenses':'bx-r','Purchases':'bx-y','Customers':'bx-a','Users':'bx-n',
  'Business':'bx-p','Settings':'bx-n','Import':'bx-b','Other':'bx-n'
};

