function filterAuditLog(){
  const q    = (document.getElementById('audit-q')?.value||'').toLowerCase().trim();
  const cat  = document.getElementById('audit-cat')?.value||'';
  const user = (document.getElementById('audit-user')?.value||'').toLowerCase();
  const role = (document.getElementById('audit-role')?.value||'').toLowerCase();
  const from = document.getElementById('audit-date-from')?.value||'';
  const to   = document.getElementById('audit-date-to')?.value||'';

  const rows = document.querySelectorAll('#audit-tbody tr');
  let visible = 0;

  rows.forEach(row=>{
    const rUser   = row.dataset.user||'';
    const rRole   = row.dataset.role||'';
    const rAction = row.dataset.action||'';
    const rDetail = row.dataset.detail||'';
    const rCat    = row.dataset.cat||'';
    const rTs     = row.dataset.ts||'';

    // Date range check — ts stored as "14 Jan 2025 15:42" — extract YYYY-MM-DD for comparison
    let tsDate = '';
    const tsM = rTs.match(/(\d{2})\s+([A-Za-z]{3})\s+(\d{4})/);
    if(tsM){
      const months={Jan:'01',Feb:'02',Mar:'03',Apr:'04',May:'05',Jun:'06',
                    Jul:'07',Aug:'08',Sep:'09',Oct:'10',Nov:'11',Dec:'12'};
      tsDate = tsM[3]+'-'+(months[tsM[2]]||'01')+'-'+tsM[1];
    }

    const matchQ    = !q    || rAction.includes(q) || rDetail.includes(q) || rUser.includes(q);
    const matchCat  = !cat  || cat==='All Categories' || rCat===cat;
    const matchUser = !user || rUser===user;
    const matchRole = !role || rRole===role;
    const matchFrom = !from || !tsDate || tsDate >= from;
    const matchTo   = !to   || !tsDate || tsDate <= to;

    const show = matchQ && matchCat && matchUser && matchRole && matchFrom && matchTo;
    row.style.display = show ? '' : 'none';
    if(show) visible++;
  });

  const countEl = document.getElementById('audit-count');
  if(countEl) countEl.textContent = visible+' of '+rows.length+' entries';

  const emptyEl = document.getElementById('audit-empty');
  if(emptyEl) emptyEl.style.display = visible===0 ? 'block' : 'none';
}

function _auditQuick(period){
  const pad = n=>String(n).padStart(2,'0');
  const now = new Date();
  const ymd = d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
  let from='', to=ymd(now);
  if(period==='today'){
    from=to;
  } else if(period==='week'){
    const dow=now.getDay();
    const ws=new Date(now); ws.setDate(now.getDate()-((dow+6)%7));
    from=ymd(ws);
  } else if(period==='month'){
    from=`${now.getFullYear()}-${pad(now.getMonth()+1)}-01`;
  }
  const fromEl=document.getElementById('audit-date-from');
  const toEl=document.getElementById('audit-date-to');
  if(fromEl) fromEl.value=from;
  if(toEl)   toEl.value=to;
  filterAuditLog();
}

function _auditSort(field){
  const tbody=document.getElementById('audit-tbody');
  if(!tbody) return;
  const rows=[...tbody.querySelectorAll('tr')];
  const asc=tbody.dataset.sortAsc==='1';
  rows.sort((a,b)=>{
    const av=a.dataset[field]||''; const bv=b.dataset[field]||'';
    return asc ? bv.localeCompare(av) : av.localeCompare(bv);
  });
  tbody.dataset.sortAsc=asc?'0':'1';
  rows.forEach(r=>tbody.appendChild(r));
}

