// ── SA unified filter ─────────────────────────────────────────
function _saFilter(status, billing, plan){
  // Accept direct arguments OR read from DOM selectors
  if(status !== undefined) {
    const stEl = document.getElementById('sa-st-filter');
    const blEl = document.getElementById('sa-billing-filter');
    const plEl = document.getElementById('sa-plan-filter');
    if(stEl && status !== undefined) stEl.value = status || '';
    if(blEl && billing !== undefined) blEl.value = billing || '';
    if(plEl && plan !== undefined) plEl.value = plan || '';
  }

  const q   = (document.getElementById('sa-search')?.value || '').toLowerCase();
  const st  = (document.getElementById('sa-st-filter')?.value || '').toLowerCase();
  const pl  = (document.getElementById('sa-plan-filter')?.value || '').toLowerCase();
  const bl  = (document.getElementById('sa-billing-filter')?.value || '').toLowerCase();

  let visible = 0;
  document.querySelectorAll('#sa-biz-tbody tr').forEach(function(r){
    const txt = r.textContent.toLowerCase();
    const matchQ  = !q  || txt.includes(q);
    const matchSt = !st || txt.includes(st);
    const matchPl = !pl || txt.includes(pl);
    let matchBl   = true;
    if(bl === 'overdue')   matchBl = txt.includes('overdue') || txt.includes('due today');
    else if(bl === 'expiring') matchBl = txt.includes('d!') || (txt.includes('day') && !txt.includes('current'));
    else if(bl === 'current')  matchBl = txt.includes('current');
    else if(bl === 'trial')    matchBl = txt.includes('trial');
    else if(bl === 'nophone')  matchBl = txt.includes('no phone');

    const show = matchQ && matchSt && matchPl && matchBl;
    r.style.display = show ? '' : 'none';
    if(show) visible++;
  });

  const emptyEl = document.getElementById('sa-empty');
  if(emptyEl) emptyEl.style.display = visible === 0 ? '' : 'none';
}

// Legacy alias so old code calling filterAdminBiz() still works
function filterAdminBiz(q){ _saFilter(); }

async function _doPermDelete(bizId, bizName, reason){
  // reason passed directly from button onclick - no DOM re-read needed

  // ── 1. Persist tombstone in localStorage FIRST ────────────────
  // This covers the current browser across refreshes
  _markBizDeleted(bizId);

  // ── 2. Remove from _DEMO_DATA in memory ──────────────────────
  // So it doesn't get re-injected by _loadAdminBiz() later this session
  const demoIdx = _DEMO_DATA.adminBiz.findIndex(function(b){ return b.id === bizId; });
  if(demoIdx > -1) _DEMO_DATA.adminBiz.splice(demoIdx, 1);

  var errors = [];
  if(_sb){
    // ── 3. Mark as deleted in Supabase businesses table ──────────
    // We set deleted=true BEFORE cascading deletes so the flag persists
    // even if child deletions partially fail. This is the server-side tombstone
    // that prevents ghost reappearance across browsers and devices.
    var _rflag = await _sb.from('businesses').update({ status: 'Deleted', deleted: true }).eq('id', bizId);
    if(_rflag.error) console.warn('[ShopTrack] Could not flag business as deleted:', _rflag.error.message);

    // ── 4. Cascade delete all child data ─────────────────────────
    var tables = ['sales','rentals','inventory','customers','expenses',
      'purchases','vendors','audit_log','categories','services','appointments'];
    for(var _i=0; _i<tables.length; _i++){
      var _r = await _sb.from(tables[_i]).delete().eq('biz_id', bizId);
      if(_r.error) errors.push(tables[_i]+': '+_r.error.message);
    }
    var _ru = await _sb.from('platform_users').delete().eq('biz_id', bizId);
    if(_ru.error) errors.push('users: '+_ru.error.message);
    var _rb = await _sb.from('businesses').delete().eq('id', bizId);
    if(_rb.error) errors.push('business: '+_rb.error.message);
  }

  // ── 5. Remove from all in-memory lists and DOM ────────────────
  D.adminBiz = D.adminBiz.filter(function(x){ return x.id !== bizId; });
  // Remove both desktop and mobile rows
  ['bizrow-'+bizId, 'bizrow-'+bizId+'-mob'].forEach(function(rowId){
    var _row = document.getElementById(rowId);
    if(_row && _row.parentNode) _row.parentNode.removeChild(_row);
  });

  addAudit('Business permanently deleted', bizId+' — '+bizName+' — '+reason);
  closeModal();
  if(errors.length){
    console.warn('[ShopTrack] Delete Supabase errors:', errors);
    toast((bizName||bizId)+' removed. Note: some data tables may need DELETE RLS policies in Supabase.','warn');
  } else {
    toast((bizName||bizId)+' permanently deleted ✓','success');
  }
  nav('admin-biz');
}

