function provAutoFill(email){
  const disp = document.getElementById('prov-email-display');
  const errEl = document.getElementById('prov-email-error');
  if(disp) disp.textContent = email.trim() || '— enter email above —';
  if(errEl){
    const exists = AUTH_STORE[email.toLowerCase().trim()];
    if(exists){ errEl.textContent = '⚠ This email is already registered on the platform.'; errEl.style.display='block'; }
    else { errEl.style.display='none'; }
  }
}

function doProvision(){
  if(!SESSION.isSuperAdmin){ toast('Super Admin access required','error'); return; }

  const email   = (document.getElementById('prov-email')?.value  || '').toLowerCase().trim();
  const name    = (document.getElementById('prov-name')?.value   || '').trim();
  const owner   = (document.getElementById('prov-owner')?.value  || '').trim();
  const plan    = document.getElementById('prov-plan')?.value    || 'Trial (30 Days)';
  const type    = document.getElementById('prov-type')?.value    || 'General Retail';
  const country = (document.getElementById('prov-country')?.value || '').trim();
  const phone   = (document.getElementById('prov-phone')?.value  || '').trim();
  const pass    = document.getElementById('prov-pass-display')?.textContent || _genTempPassword();
  const errEl   = document.getElementById('prov-email-error');

  // Validation
  if(!email || !name || !owner){
    if(errEl){ errEl.textContent='Please fill in all required fields (email, business name, owner name).'; errEl.style.display='block'; }
    return;
  }
  if(!phone){
    if(errEl){ errEl.textContent='Owner WhatsApp number is required for billing reminders.'; errEl.style.display='block'; }
    return;
  }
  const emailRx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if(!emailRx.test(email)){
    if(errEl){ errEl.textContent='Please enter a valid email address.'; errEl.style.display='block'; }
    return;
  }
  if(AUTH_STORE[email]){
    if(errEl){ errEl.textContent='This email is already registered on the platform.'; errEl.style.display='block'; }
    return;
  }

  // Generate unique IDs
  const bizNum  = 100 + D.adminBiz.length;
  const bizId   = 'BIZ-' + String(bizNum).padStart(3,'0');
  const userId  = 'U-' + String(200 + BIZ_USERS.length).padStart(3,'0');
  const today   = localDateStr();

  // Calculate subscription expiry — trial gets 30 days, paid plans get 30 days from today
  const isTrial = plan.toLowerCase().includes('trial');
  const subExpiryDate = (function(){
    var d = new Date(); d.setDate(d.getDate()+30); return d.toISOString().slice(0,10);
  })();

  // 1. Register in AUTH_STORE
  AUTH_STORE[email] = {
    password: pass, userId, bizId, level: 'owner',
    isSuperAdmin: false, name: owner, mustChangePassword: true
  };

  // 2. Add to BIZ_USERS
  BIZ_USERS.push({
    id: userId, name: owner, email, level: 'owner',
    bizId, st: 'Active', last: 'Never', rights: null
  });

  // 3. Add to platform business list
  const newBiz = {
    id: bizId, name, owner, email, type,
    country: country || '',
    phone:   phone   || '',
    whatsapp: phone  || '',
    st: 'Active', plan,
    trialEnd:    isTrial ? subExpiryDate : null,
    subExpires:  subExpiryDate,
    billingCycle: 'monthly',
    users: 1, rev: 0, created: today
  };
  D.adminBiz.push(newBiz);

  // Save to Supabase
  _dbSaveBusiness(newBiz);
  _dbSavePlatformUser(BIZ_USERS[BIZ_USERS.length-1], pass);
  addAudit('Business provisioned', bizId+' — '+name+' | Owner: '+owner+' | Plan: '+plan+' | Phone: '+phone);
  closeModal();

  // Show confirmation with credentials summary
  modal('✅ Business Onboarded Successfully',`
  <div class="alrt alrt-g" style="margin-bottom:16px">
    <strong>${name}</strong> has been created and the owner account is ready.
  </div>
  <div style="background:var(--bg3);border-radius:var(--r8);padding:14px;margin-bottom:14px">
    <div style="font-size:12px;font-weight:700;color:var(--ink);margin-bottom:10px">📋 Credentials to share with owner</div>
    <div style="display:flex;flex-direction:column;gap:7px;font-size:13px">
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Business</span><strong style="color:var(--ink)">${name}</strong></div>
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Business ID</span><span style="font-family:var(--mono);color:var(--p)">${bizId}</span></div>
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Owner</span><strong style="color:var(--ink)">${owner}</strong></div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <span style="color:var(--text2)">Login Email</span>
        <span style="font-family:var(--mono);color:var(--c)">${email}</span>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <span style="color:var(--text2)">Temp Password</span>
        <div style="display:flex;align-items:center;gap:8px">
          <span style="font-family:var(--mono);font-weight:700;color:var(--g);background:rgba(45,212,160,.1);padding:3px 10px;border-radius:5px">${pass}</span>
          <button onclick="navigator.clipboard.writeText('Email: ${email}\\nPassword: ${pass}').then(()=>toast('Credentials copied','success'))" style="background:var(--bg4);border:1px solid var(--border2);border-radius:5px;padding:3px 9px;cursor:pointer;font-size:11px;color:var(--text);font-family:inherit">📋 Copy all</button>
        </div>
      </div>
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Plan</span>${bx(plan,'bx-b')}</div>
    </div>
  </div>
  <div style="font-size:11px;color:var(--text2)">⚠ Share credentials securely. The owner should change their password after first login via Settings → Security.</div>`,
  `<button class="btn btn-p" onclick="closeModal();nav('admin-biz')">Done</button>`,'lg');
}


async function _purgeUnverifiedBiz(bizId, bizName){
  if(!confirm('Delete unverified signup "'+bizName+'" ('+bizId+')? This cannot be undone.')) return;
  try {
    if(_sb){
      // Delete user first (FK constraint), then business
      await _sb.from('platform_users').delete().eq('biz_id', bizId);
      const {error} = await _sb.from('businesses').delete().eq('id', bizId);
      if(error) throw new Error(error.message);
    }
    // Remove from in-memory list
    D.adminBizUnverified = (D.adminBizUnverified||[]).filter(b=>b.id!==bizId);
    const row = document.getElementById('bizrow-unv-'+bizId);
    if(row) row.remove();
    // If table is now empty, remove the card
    const tbody = document.querySelector('#tab-unverified tbody');
    if(tbody && !tbody.children.length) nav('admin-biz');
    addAudit('Purged unverified signup', bizId+' — '+bizName);
    toast('✔ Deleted unverified signup: '+bizName,'success');
  } catch(e){
    toast('Could not delete: '+e.message,'error');
  }
}

async function _purgeAllUnverified(){
  const list = D.adminBizUnverified||[];
  if(!list.length){ toast('No unverified signups to purge','info'); return; }
  if(!confirm('Delete ALL '+list.length+' unverified signup(s)? This cannot be undone.')) return;
  let deleted = 0, failed = 0;
  for(const b of list){
    try{
      if(_sb){
        await _sb.from('platform_users').delete().eq('biz_id', b.id);
        const {error} = await _sb.from('businesses').delete().eq('id', b.id);
        if(error) throw new Error(error.message);
      }
      deleted++;
    } catch(e){
      console.error('[purgeAll] failed for '+b.id+':', e.message);
      failed++;
    }
  }
  D.adminBizUnverified = [];
  addAudit('Purged all unverified signups', deleted+' deleted'+(failed?' | '+failed+' failed':''));
  toast('✔ Purged '+deleted+' unverified signup(s)'+(failed?' ('+failed+' failed)':''),'success');
  nav('admin-biz');
}

