// ─── PROFILE ACCESS REQUEST SYSTEM ────────────────────────────────────────────

// Super Admin clicks "👤 View Profile" — sends a request to the business owner
function mRequestProfileAccess(userId){
  if(!SESSION.isSuperAdmin){ toast('Super Admin only','error'); return; }
  const u = BIZ_USERS.find(x=>x.id===userId); if(!u) return;
  const biz = D.adminBiz.find(b=>b.id===u.bizId);
  const ownerEntry = Object.entries(AUTH_STORE).find(([,v])=>v.bizId===u.bizId&&v.level==='owner');
  const ownerEmail = ownerEntry?.[0] || biz?.email || '—';
  const ownerName  = ownerEntry ? ownerEntry[1].name : (biz?.owner || 'Business Owner');

  // Check for existing live request
  const existing = ACCESS_REQUESTS.find(r=>r.userId===userId&&r.status==='pending');
  if(existing){
    modal('⏳ Request Already Pending',`
    <div class="alrt alrt-y" style="margin-bottom:14px">A profile access request for <strong>${u.name}</strong> is already awaiting approval from <strong>${ownerName}</strong>.</div>
    <div style="background:var(--bg3);border-radius:var(--r8);padding:13px 14px;font-size:12px;display:flex;flex-direction:column;gap:7px">
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Requested</span><span>${existing.requestedAt}</span></div>
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Owner notified</span><span style="font-family:var(--mono);font-size:11px;color:var(--c)">${ownerEmail}</span></div>
      <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Expires</span><span>${existing.expiresAt}</span></div>
    </div>`,
    `<button class="btn btn-s" onclick="closeModal()">Close</button>
     <button class="btn btn-d btn-sm" onclick="
       ACCESS_REQUESTS.splice(ACCESS_REQUESTS.findIndex(r=>r.id==='${existing.id}'),1);
       closeModal(); toast('Request cancelled','success'); nav('admin-users');
     ">Cancel Request</button>`);
    return;
  }

  // Approved request — can go straight to profile view
  const approved = ACCESS_REQUESTS.find(r=>r.userId===userId&&r.status==='approved');
  if(approved){
    closeModal && closeModal();
    mViewApprovedProfile(userId, approved.id);
    return;
  }

  modal(`👤 Request Profile Access — ${u.name}`,`
  <div class="alrt alrt-b" style="margin-bottom:16px">
    <strong>Owner Confirmation Required</strong><br>
    <span style="font-size:12px">To protect user privacy, the business owner must approve this request via email confirmation before you can view this profile.</span>
  </div>
  <div style="background:var(--bg3);border-radius:var(--r8);padding:13px 14px;margin-bottom:16px;display:flex;flex-direction:column;gap:8px;font-size:13px">
    <div style="display:flex;justify-content:space-between;align-items:center">
      <span style="color:var(--text2)">User</span>
      <div style="display:flex;align-items:center;gap:8px">
        <div style="width:24px;height:24px;background:linear-gradient(135deg,var(--a),var(--p));border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:9px;font-weight:700;color:#fff">${u.name.split(' ').map(n=>n[0]).join('')}</div>
        <strong style="color:var(--ink)">${u.name}</strong>
      </div>
    </div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Role</span>${bx(USER_LEVEL_LABELS[u.level]||u.level,'bx-b')}</div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Business</span><strong style="color:var(--ink)">${biz?.name||u.bizId}</strong></div>
    <div style="display:flex;justify-content:space-between;align-items:center"><span style="color:var(--text2)">Owner to notify</span><span style="font-family:var(--mono);font-size:11px;color:var(--c)">${ownerEmail}</span></div>
  </div>
  <div class="fg">
    <label class="fl">Reason for Access <span style="color:var(--r)">*</span></label>
    <select class="fs" id="par-reason-sel" onchange="document.getElementById('par-reason-other').style.display=this.value==='Other'?'block':'none'">
      <option value="">— Select reason —</option>
      <option>Routine compliance check</option>
      <option>Support request from business</option>
      <option>Security audit</option>
      <option>Account verification</option>
      <option>Billing dispute investigation</option>
      <option>Other</option>
    </select>
    <input class="fi" id="par-reason-other" placeholder="Describe the reason…" style="display:none;margin-top:8px"/>
  </div>
  <div style="margin-top:10px;padding:10px 12px;background:rgba(91,127,255,.07);border-radius:var(--r6);font-size:11px;color:var(--text2);line-height:1.6">
    📧 An email confirmation will be sent to <strong style="color:var(--c)">${ownerName}</strong> at <strong style="color:var(--c)">${ownerEmail}</strong>.<br>
    The request expires in <strong>7 days</strong>. Access is read-only and logged in the audit trail.
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="doSubmitProfileRequest('${userId}','${ownerEmail}','${ownerName}','${u.bizId}')">📧 Send Request to Owner</button>`);
}

function doSubmitProfileRequest(userId, ownerEmail, ownerName, bizId){
  const sel   = document.getElementById('par-reason-sel')?.value;
  const other = document.getElementById('par-reason-other')?.value?.trim();
  const reason = sel === 'Other' ? other : sel;
  if(!reason){ toast('Please select a reason for the request','error'); return; }

  const u   = BIZ_USERS.find(x=>x.id===userId);
  const biz = D.adminBiz.find(b=>b.id===bizId);
  const now = new Date();
  const expires = new Date(now.getTime() + 7*24*60*60*1000);
  const fmt = d => d.toISOString().slice(0,16).replace('T',' ');
  const token = 'TOK-' + Math.random().toString(36).substr(2,8).toUpperCase();
  const reqId = 'AR-' + String(ACCESS_REQUESTS.length+1).padStart(3,'0');

  ACCESS_REQUESTS.push({
    id: reqId,
    userId, userName: u.name, userEmail: u.email,
    userLevel: u.level, bizId, bizName: biz?.name || bizId,
    ownerEmail, ownerName,
    requestedAt: fmt(now),
    reason,
    status: 'pending',
    token,
    expiresAt: fmt(expires),
    resolvedAt: null
  });

  closeModal();

  // Show confirmation with simulated email preview
  modal('📧 Request Sent',`
  <div class="alrt alrt-g" style="margin-bottom:16px">
    ✅ <strong>Access request submitted.</strong> A confirmation email has been sent to the business owner.
  </div>
  <div style="background:var(--bg3);border:1px solid var(--border2);border-radius:var(--r8);padding:16px;font-size:12px">
    <div style="font-size:10px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">📧 Email Preview (sent to owner)</div>
    <div style="color:var(--text2);margin-bottom:4px"><strong style="color:var(--ink)">To:</strong> ${ownerName} &lt;${ownerEmail}&gt;</div>
    <div style="color:var(--text2);margin-bottom:12px"><strong style="color:var(--ink)">Subject:</strong> ShopTrack — Platform Admin requests profile access for ${u.name}</div>
    <div style="background:var(--bg4);border-radius:var(--r6);padding:12px;line-height:1.7;color:var(--text)">
      Hello <strong>${ownerName}</strong>,<br><br>
      A ShopTrack Platform Administrator has requested read-only access to the user profile of <strong>${u.name}</strong> (${USER_LEVEL_LABELS[u.level]||u.level}) in your business <strong>${biz?.name||bizId}</strong>.<br><br>
      <strong>Reason:</strong> ${reason}<br>
      <strong>Access type:</strong> Read-only · No edits or password visibility<br>
      <strong>Request expires:</strong> ${fmt(expires)}<br><br>
      To <span style="color:var(--g);font-weight:700">approve</span> or <span style="color:var(--r);font-weight:700">deny</span> this request, log into ShopTrack and go to <strong>Platform Users → Review Requests</strong>.<br><br>
      If you did not expect this request, please ignore it or contact support.<br><br>
      — ShopTrack Platform
    </div>
  </div>
  <div style="margin-top:12px;font-size:11px;color:var(--text2)">Request ID: <span style="font-family:var(--mono);color:var(--a)">${reqId}</span> · Token: <span style="font-family:var(--mono);color:var(--text2)">${token}</span></div>`,
  `<button class="btn btn-p" onclick="closeModal();nav('admin-users')">Done</button>`,'lg');
}

// Owner (or SA) reviews all pending requests
function mViewAccessRequests(){
  const relevant = SESSION.isSuperAdmin
    ? ACCESS_REQUESTS
    : ACCESS_REQUESTS.filter(r=>r.bizId===SESSION.bizId);

  const pending  = relevant.filter(r=>r.status==='pending');
  const resolved = relevant.filter(r=>r.status!=='pending');

  const reqRow = (r, isPending) => `
  <div style="background:var(--bg3);border:1px solid ${isPending?'rgba(245,200,66,.2)':'var(--border)'};border-radius:var(--r8);padding:14px;margin-bottom:10px">
    <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;flex-wrap:wrap">
      <div style="flex:1">
        <div style="font-weight:700;color:var(--ink);margin-bottom:4px">👤 ${r.userName} <span style="font-size:10px;font-weight:400;color:var(--text)">— ${r.bizName}</span></div>
        <div style="font-size:11px;color:var(--text2);margin-bottom:2px">📧 ${r.userEmail} · ${USER_LEVEL_LABELS[r.userLevel]||r.userLevel}</div>
        <div style="font-size:11px;color:var(--text)">📋 Reason: <em>${r.reason}</em></div>
        <div style="font-size:10px;color:var(--text2);margin-top:4px">Requested ${r.requestedAt} · Expires ${r.expiresAt} · ID: <span style="font-family:var(--mono)">${r.id}</span></div>
      </div>
      <div style="display:flex;flex-direction:column;gap:6px;align-items:flex-end">
        ${isPending && !SESSION.isSuperAdmin
          ? `<button class="btn btn-g btn-sm" onclick="resolveAccessRequest('${r.id}','approved')">✅ Approve</button>
             <button class="btn btn-d btn-sm" onclick="resolveAccessRequest('${r.id}','denied')">✕ Deny</button>`
          : isPending && SESSION.isSuperAdmin
          ? `<span style="font-size:11px;color:var(--y)">⏳ Awaiting owner approval</span>
             <button class="btn btn-d btn-xs" onclick="resolveAccessRequest('${r.id}','cancelled')">Cancel</button>`
          : `<span style="font-size:11px;font-weight:700;color:${r.status==='approved'?'var(--g)':r.status==='denied'?'var(--r)':'var(--text3)'}">${r.status==='approved'?'✅ Approved':r.status==='denied'?'✕ Denied':'Cancelled'}</span>
             <span style="font-size:10px;color:var(--text2)">${r.resolvedAt||''}</span>
             ${r.status==='approved'&&SESSION.isSuperAdmin?`<button class="btn btn-b btn-xs" onclick="closeModal();mViewApprovedProfile('${r.userId}','${r.id}')">👤 View Profile</button>`:''}`
        }
      </div>
    </div>
  </div>`;

  modal('🔔 Profile Access Requests',`
  ${pending.length ? `
    <div style="font-size:12px;font-weight:700;color:var(--y);margin-bottom:10px;text-transform:uppercase;letter-spacing:.4px">⏳ Pending (${pending.length})</div>
    ${pending.map(r=>reqRow(r,true)).join('')}
  ` : '<div class="alrt alrt-g" style="margin-bottom:14px">✅ No pending requests.</div>'}
  ${resolved.length ? `
    <div style="font-size:12px;font-weight:700;color:var(--text2);margin-top:14px;margin-bottom:10px;text-transform:uppercase;letter-spacing:.4px">History (${resolved.length})</div>
    ${resolved.slice(0,5).map(r=>reqRow(r,false)).join('')}
  ` : ''}`,
  `<button class="btn btn-p" onclick="closeModal()">Close</button>`,'lg');
}

// Resolve a request (approve / deny / cancel)
function resolveAccessRequest(reqId, newStatus){
  const req = ACCESS_REQUESTS.find(r=>r.id===reqId); if(!req) return;
  req.status = newStatus;
  req.resolvedAt = new Date().toISOString().slice(0,16).replace('T',' ');
  closeModal();
  refreshNotifPanel();
  if(newStatus === 'approved'){
    toast('Access approved — Super Admin can now view the profile','success');
    // Show profile immediately if SA is resolving (demo: SA approves own request)
    if(SESSION.isSuperAdmin) setTimeout(()=>mViewApprovedProfile(req.userId, reqId), 300);
    else { toast('The platform admin has been notified of your approval','success'); nav('admin-users'); }
  } else if(newStatus === 'denied'){
    toast('Access request denied — owner has been notified','success');
    nav('admin-users');
  } else {
    toast('Request cancelled','success');
    nav('admin-users');
  }
}

// View a read-only user profile (only when approved)
function mViewApprovedProfile(userId, reqId){
  const req = ACCESS_REQUESTS.find(r=>r.id===reqId);
  if(!req || req.status !== 'approved'){
    toast('Access not approved — request owner confirmation first','error'); return;
  }
  const u   = BIZ_USERS.find(x=>x.id===userId); if(!u) return;
  const biz = D.adminBiz.find(b=>b.id===u.bizId);
  const initials = u.name.split(' ').map(n=>n[0]).join('');
  const levelColors={owner:'#e8667a',manager:'#38bdf8',accountant:'#2dd4a0',staff:'#f5c842'};
  const lc = levelColors[u.level]||'#8890b0';

  modal(`👤 User Profile — ${u.name}`,`
  <div style="display:flex;align-items:center;gap:14px;margin-bottom:20px;padding-bottom:16px;border-bottom:1px solid var(--border)">
    <div style="width:56px;height:56px;background:linear-gradient(135deg,var(--a),var(--p));border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:#fff;flex-shrink:0">${initials}</div>
    <div>
      <div style="font-size:18px;font-weight:800;color:var(--ink)">${u.name}</div>
      <div style="font-size:12px;color:var(--text2);margin-top:2px">${u.email}</div>
      <div style="margin-top:5px;display:flex;gap:6px;align-items:center">
        ${bx(USER_LEVEL_LABELS[u.level]||u.level,'bx-b')}
        ${badge(u.st)}
      </div>
    </div>
  </div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px">
    ${[
      ['User ID',    u.id],
      ['Business',   biz?.name||u.bizId],
      ['Business ID',u.bizId],
      ['Role',       USER_LEVEL_LABELS[u.level]||u.level],
      ['Status',     u.st],
      ['Last Login', u.last||'Never'],
    ].map(([label,val])=>`
    <div style="background:var(--bg3);border-radius:var(--r6);padding:10px 12px">
      <div style="font-size:10px;font-weight:600;color:var(--text2);text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">${label}</div>
      <div style="font-size:13px;color:var(--ink);font-weight:500">${val}</div>
    </div>`).join('')}
  </div>
  <div style="background:var(--bg3);border-radius:var(--r6);padding:10px 12px;margin-bottom:14px">
    <div style="font-size:10px;font-weight:600;color:var(--text2);text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px">Module Access Rights</div>
    <div style="display:flex;flex-wrap:wrap;gap:5px">
      ${Object.entries(DEFAULT_RIGHTS[u.level]||{}).slice(0,10).map(([mod,t])=>{
        const mm=TIER_META[t]||TIER_META.none;
        return `<span style="font-size:9px;padding:2px 7px;border-radius:3px;background:${mm.bg};color:${mm.color};font-weight:600">${mm.icon} ${mod.replace(/_/g,' ')}</span>`;
      }).join('')}
    </div>
  </div>
  <div style="background:rgba(245,200,66,.07);border:1px solid rgba(245,200,66,.2);border-radius:var(--r6);padding:10px 12px;font-size:11px;color:var(--text)">
    🔒 <strong style="color:var(--y)">Read-only view</strong> · Approved by ${req.ownerName} · ${req.resolvedAt} · Access expires ${req.expiresAt}<br>
    Passwords and sensitive credentials are never shown to platform admins.
  </div>`,
  `<button class="btn btn-p" onclick="closeModal()">Close</button>`,'lg');
}

function filterAdminUsers(){
  const q   = (document.getElementById('usr-search')?.value||'').toLowerCase().trim();
  const biz = document.getElementById('usr-biz-filter')?.value||'';
  const lvl = document.getElementById('usr-level-filter')?.value||'';
  const sta = document.getElementById('usr-status-filter')?.value||'';
  const rows = document.querySelectorAll('#usr-tbody tr');
  let visible = 0;
  rows.forEach(row=>{
    const matchQ   = !q   || (row.dataset.search||'').includes(q);
    const matchBiz = !biz || row.dataset.biz === biz;
    const matchLvl = !lvl || row.dataset.level === lvl;
    const matchSta = !sta || row.dataset.status === sta;
    const show = matchQ && matchBiz && matchLvl && matchSta;
    row.style.display = show ? '' : 'none';
    if(show) visible++;
  });
  const cnt = document.getElementById('usr-count');
  if(cnt) cnt.textContent = (q||biz||lvl||sta) ? visible+' result'+(visible!==1?'s':'') : '';
}

function _getPlanTier(){
  var p=(BIZ.plan||'').toLowerCase();
  if(p.includes('enterprise')) return 'enterprise';
  if(p==='pro'||p==='professional'||p.includes('pro')) return 'pro';
  if(p.includes('starter')) return 'starter';
  return 'trial';
}
