      +'var idx=BIZ_USERS.findIndex(x=>x.id===\''+uid+'\');'
      +'if(idx>-1) BIZ_USERS.splice(idx,1);'
      +'addAudit(\'User removed\',\''+uid+' — '+_esc(u.name)+'\');'
