// ╔══════════════════════════════════════════════════════════════╗
// ║  SA BILLING PAGE — Subscription management & CamPay billing ║
// ╚══════════════════════════════════════════════════════════════╝

// Plan prices in XAF
const BILLING_PLANS = {
  'Free':         { monthly: 0,     yearly: 0      },
  'Premium':      { monthly: 8900,  yearly: 89000  },
  
  
  'Demo Test':    { monthly: 10,  yearly: 10 },  // CamPay demo — max 25 XAF
  'Trial (30 Days)': { monthly: 0, yearly: 0 },
};

function _billingAmtXAF(biz){
  const p = BILLING_PLANS[biz.plan||'Free'] || BILLING_PLANS['Free'];
  return (biz.billingCycle||'monthly') === 'yearly' ? p.yearly : p.monthly;
}

function _billingDaysLeft(biz){
  const exp = biz.subExpires || biz.trialEnd;
  if(!exp) return null;
  const now  = new Date(); now.setHours(0,0,0,0);
  const then = new Date(exp+'T00:00:00');
  return Math.round((then-now)/86400000);
}

function _billingStatus(biz){
  const d = _billingDaysLeft(biz);
  if(d === null) return {label:'No Expiry', cls:'bx-n', urgent:false};
  if(biz.st==='Suspended') return {label:'Suspended',cls:'bx-r',urgent:true};
  if(d > 7)  return {label:'Current — '+d+'d',    cls:'bx-g', urgent:false};
  if(d > 3)  return {label:'Expiring — '+d+'d',   cls:'bx-b', urgent:false};
  if(d > 0)  return {label:'⚠ '+d+' day'+(d>1?'s':'')+'!', cls:'bx-y', urgent:true};
  if(d === 0)return {label:'🚨 Due Today',          cls:'bx-r', urgent:true};
  return       {label:'🔴 Overdue '+Math.abs(d)+'d', cls:'bx-r', urgent:true};
}

function _billingWAMsg(biz, daysLeft){
  const amt   = _billingAmtXAF(biz).toLocaleString();
  const plan  = biz.plan||'Starter';
  const expiry= biz.subExpires || biz.trialEnd || '';
  const name  = (biz.owner||'').split(' ')[0] || 'there';
  const urg   = daysLeft <= 0 ? '🚨 URGENT — ' : daysLeft <= 2 ? '⚠️ ' : '📅 ';
  let msg = urg+'Hi '+name+'! 👋\n\n';
  if(daysLeft > 0){
    msg += 'Your *ShopTrack '+plan+' Plan* expires in *'+daysLeft+' day'+(daysLeft>1?'s':'')+
           '* on '+expiry+'.\n\n';
  } else if(daysLeft === 0){
    msg += 'Your *ShopTrack '+plan+' Plan* expires *today*.\n\n';
  } else {
    msg += 'Your *ShopTrack '+plan+' Plan* expired '+Math.abs(daysLeft)+' day'+
           (Math.abs(daysLeft)>1?'s':'')+' ago on '+expiry+'.\n\n';
    msg += '⛔ Your access will be suspended if payment is not received.\n\n';
  }
  msg += '💰 *Amount due:* '+amt+' XAF\n';
  msg += '🏢 *Business:* '+biz.name+'\n\n';
  msg += 'To renew, approve the Mobile Money payment request you will receive — ';
  msg += 'or log in to shoptrack.org.\n\n';
  msg += 'Thank you! 🙏\n_ShopTrack — shoptrack.org_';
  return msg;
}

// ── WhatsApp: real API send via Netlify function ─────────────
// Falls back to wa.me link if the function fails or is unconfigured.
async function _sendWA(phone, message, opts){
  const digits = String(phone||'').replace(/\D/g,'');
  if(!digits || digits.length < 7){
    toast('No valid WhatsApp number','error'); return { success:false };
  }
  // Try real API first
  try {
    const resp = await fetch('/.netlify/functions/whatsapp-notify', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ to: digits, message, ...(opts||{}) })
    });
    const data = await resp.json();
    if(data.success){
      toast('✅ WhatsApp message sent!','success');
      return { success:true, messageId: data.messageId };
    }
    // API returned an error — show it and fall back to wa.me
    console.warn('[WA] API send failed:', data.error);
    toast('WhatsApp API: '+( data.error||'failed')+'\nOpening WhatsApp instead…','warn');
  } catch(e){
    console.warn('[WA] fetch error:', e.message);
  }
  // Fallback: open wa.me link
  _openWA(digits, message);
  return { success:false, fallback:true };
}

// Legacy helper kept for non-API contexts (share links, flyer sharing etc.)
function _openWA(phone, message){
  const digits = String(phone||'').replace(/\D/g,'');
  // Normalise: US 10-digit → add 1, international → use as-is
  const norm = digits.length === 10 ? '1'+digits
             : digits.length === 11 && digits.startsWith('1') ? digits
             : digits;
  if(!norm || norm.length < 7){ toast('No valid phone number','error'); return; }
  const url = 'https://wa.me/'+norm+'?text='+encodeURIComponent(message);
  window.open(url, '_blank');
}

async function _callBillingFn(action, bizId, extra){
  // Pure GET request — Netlify WAF blocks POST bodies with payment keywords.
  // All params go in the query string which WAF does not inspect.
  const params = new URLSearchParams({ a: action });
  if(bizId)            params.set('b', bizId);
  if(extra?.days)      params.set('d', String(extra.days));
  if(extra?.phone)     params.set('p', extra.phone);
  if(extra?.newExpiry) params.set('e', extra.newExpiry);
  const url = '/.netlify/functions/sub-engine?' + params.toString();
  let resp, data;
  try { resp = await fetch(url); } // GET — no body
  catch(netErr){ throw new Error('Network error: ' + netErr.message); }
  const text = await resp.text();
  try { data = JSON.parse(text); }
  catch(e){ throw new Error('Server error (HTTP ' + resp.status + ') — check Netlify logs'); }
  if(!resp.ok) throw new Error(data.error || 'HTTP ' + resp.status);
  if(data.error) throw new Error(data.error);
  return data;
}

async function mBillingCharge(bizId){
  const b = D.adminBiz.find(x=>x.id===bizId); if(!b) return;
  const amt = _billingAmtXAF(b);
  if(!amt){ toast(b.name+' is on a free trial — no charge needed','info'); return; }
  if(!(b.phone||b.whatsapp)){
    toast('No phone number on record for '+b.name+'. Edit the business to add one.','error'); return;
  }
  const phone = b.phone||b.whatsapp;
  modal('📱 Charge Subscription — '+_esc(b.name),`
  <div class="alrt alrt-b" style="margin-bottom:14px">
    A Mobile Money payment request will be sent to the business owner's phone.
    They must approve it within ~2 minutes.
  </div>
  <div style="background:var(--bg3);border-radius:var(--r8);padding:13px 14px;display:flex;flex-direction:column;gap:8px;font-size:13px">
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Business</span><strong>${_esc(b.name)}</strong></div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Owner</span><span>${_esc(b.owner||'—')}</span></div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Plan</span>${bx(b.plan||'Starter','bx-b')}</div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Amount</span><strong style="color:var(--g);font-family:var(--mono)">${amt.toLocaleString()} XAF</strong></div>
    <div style="display:flex;justify-content:space-between"><span style="color:var(--text2)">Phone</span><span style="font-family:var(--mono);color:var(--c)">${_esc(phone)}</span></div>
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" id="mbc-send-btn" onclick="(async function(){
     var btn=document.getElementById('mbc-send-btn');
     btn.disabled=true; btn.textContent='⏳ Sending…';
     try{
       var r = await _callBillingFn('charge_one','${bizId}');
       console.log('[mBillingCharge] result:', r);
       if(r.charged&&r.charged.length){
         closeModal();
         toast('✅ Payment request sent to ${_esc(b.owner||b.name)} — waiting for approval','success');
         addAudit('Subscription charge initiated','${bizId} — ${_esc(b.name)} — ${amt} XAF');
       } else if(r.errors&&r.errors.length){
         var errMsg = r.errors[0].error || 'Unknown error';
         toast('❌ '+errMsg,'error');
         btn.disabled=false; btn.textContent='📱 Send Request';
       } else if(r.skipped&&r.skipped.length){
         var skipMsg = r.skipped[0].reason || 'Business was skipped';
         toast('⚠ Skipped: '+skipMsg,'error');
         btn.disabled=false; btn.textContent='📱 Send Request';
       } else {
         toast('⚠ No response from CamPay — check Netlify function logs','error');
         btn.disabled=false; btn.textContent='📱 Send Request';
       }
     }catch(e){
       console.error('[mBillingCharge] error:', e);
       toast('❌ '+e.message,'error');
       btn.disabled=false; btn.textContent='📱 Send Request';
     }
   })()">📱 Send Payment Request</button>`);
}

function mBillingRemind(bizId, daysOverride){
  const b = D.adminBiz.find(x=>x.id===bizId); if(!b) return;
  const phone = b.phone||b.whatsapp;
  const dLeft = daysOverride !== undefined ? daysOverride : (_billingDaysLeft(b)||0);
  const msg   = _billingWAMsg(b, dLeft);
  modal('💬 WhatsApp Reminder — '+_esc(b.name),`
  <div class="fg"><label class="fl">Phone / WhatsApp</label>
    <input class="fi" id="br-phone" value="${_esc(phone||'')}" placeholder="237XXXXXXXXX"/>
  </div>
  <div class="fg"><label class="fl">Message Preview</label>
    <textarea class="ft" id="br-msg" style="min-height:220px;font-size:12px;line-height:1.6">${_esc(msg)}</textarea>
  </div>
  <div class="alrt alrt-b" style="margin-top:8px;font-size:11px">
    Clicking Send opens WhatsApp with this message pre-filled. You send it manually.
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="(async function(){
     var ph=document.getElementById('br-phone').value;
     var ms=document.getElementById('br-msg').value;
     var r=await _sendWA(ph,ms);
     addAudit('WhatsApp reminder '+(r.success?'sent':'fallback'),'${bizId} — ${_esc(b.name)}');
     if(!r.fallback) closeModal();
   })()">💬 Send WhatsApp</button>`);
}

function mBillingExtend(bizId){
  const b = D.adminBiz.find(x=>x.id===bizId); if(!b) return;
  const curExp = b.subExpires || b.trialEnd || localDateStr();
  modal('⏱ Extend Subscription — '+_esc(b.name),`
  <div class="fg-2">
    <div class="fg"><label class="fl">Current Expiry</label>
      <div style="padding:9px 12px;background:var(--bg3);border-radius:var(--r6);font-size:13px;font-family:var(--mono)">${curExp||'—'}</div>
    </div>
    <div class="fg"><label class="fl">Extend By</label>
      <select class="fs" id="be-days">
        <option value="7">7 days</option>
        <option value="14">14 days</option>
        <option value="30" selected>30 days (1 month)</option>
        <option value="60">60 days (2 months)</option>
        <option value="90">90 days (3 months)</option>
        <option value="365">365 days (1 year)</option>
      </select>
    </div>
  </div>
  <div class="fg"><label class="fl">Reason (optional)</label>
    <input class="fi" id="be-reason" placeholder="e.g. Manual renewal, Goodwill extension, Issue resolution…"/>
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="(async function(){
     var days = parseInt(document.getElementById('be-days').value)||30;
     var reason = document.getElementById('be-reason').value||'Manual extension';
     try{
       var r = await _callBillingFn('extend','${bizId}',{days});
       if(r.extended&&r.extended.length){
         var nb=r.extended[0].newExpiry;
         var bObj=D.adminBiz.find(x=>x.id==='${bizId}');
         if(bObj){ bObj.subExpires=nb; bObj.st='Active'; }
         closeModal();
         toast('${_esc(b.name)} extended to '+nb+' ✓','success');
         addAudit('Subscription extended','${bizId} — ${_esc(b.name)} — '+days+'d — '+reason);
         nav('admin-biz');
       }
     }catch(e){ toast(e.message,'error'); }
   })()">⏱ Extend</button>`);
}

// ── mBillingRunReminders — send WhatsApp reminders to all expiring businesses ──
function mBillingRunReminders(){
  const expiring = D.adminBiz.filter(function(b){
    const d = _billingDaysLeft(b);
    return d !== null && d <= 3 && d >= 0 && b.st === 'Active' && _billingAmtXAF(b) > 0;
  });
  const overdue = D.adminBiz.filter(function(b){
    const d = _billingDaysLeft(b);
    return d !== null && d < 0 && b.st === 'Active' && _billingAmtXAF(b) > 0;
  });
  const all = [...expiring, ...overdue];
  if(!all.length){ toast('No businesses need reminders right now','info'); return; }

  // Store reminder list in window so onclick can access it safely
  window._reminderQueue = all.map(function(b){ return b.id; });

  const listHtml = all.map(function(b){
    const d = _billingDaysLeft(b);
    const label = d < 0
      ? '<span style="color:var(--r)">'+Math.abs(d)+'j en retard</span>'
      : '<span style="color:var(--y)">'+d+'j restants</span>';
    return '<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border);font-size:12px">'
      +'<span><strong>'+_esc(b.name)+'</strong><span style="color:var(--text2);margin-left:6px">'+_esc(b.plan||'')+'</span></span>'
      +'<span>'+label+'</span></div>';
  }).join('');

  modal('💬 Send WhatsApp Reminders',
    '<div class="alrt alrt-b" style="margin-bottom:12px;font-size:12px">This opens WhatsApp for each business below — pre-filled with a payment reminder. You send it manually.</div>'
    +'<div style="max-height:240px;overflow-y:auto;margin-bottom:12px">'+listHtml+'</div>'
    +'<div style="font-size:12px;color:var(--text2)">Tap "Send All" to open WhatsApp for each business one by one.</div>',
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +'<button class="btn btn-p" onclick="_sendReminderQueue()">💬 Send All ('+all.length+')</button>');
}

// Called from the Send All button — iterates window._reminderQueue safely
function _sendReminderQueue(){
  const queue = window._reminderQueue || [];
  if(!queue.length){ closeModal(); return; }
  closeModal();
  var i = 0;
  function next(){
    if(i >= queue.length){
      toast('Reminders opened for '+queue.length+' business'+(queue.length>1?'es':''),'success');
      return;
    }
    var bizId = queue[i]; i++;
    var biz = D.adminBiz.find(function(x){ return x.id === bizId; });
    if(biz) mBillingRemind(bizId);
    setTimeout(next, 900);
  }
  next();
}

// ── mBillingChargeAll — charge all overdue businesses via CamPay ──
async function mBillingChargeAll(){
  const due = D.adminBiz.filter(function(b){
    const d = _billingDaysLeft(b);
    return d !== null && d <= 0 && b.st === 'Active' && _billingAmtXAF(b) > 0 && (b.phone||b.whatsapp);
  });
  if(!due.length){ toast('No overdue businesses with phone numbers to charge','info'); return; }

  const listHtml = due.map(function(b){
    const amt = _billingAmtXAF(b);
    return '<div style="display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--border);font-size:12px">'
      +'<span><strong>'+_esc(b.name)+'</strong></span>'
      +'<span style="font-family:var(--mono);color:var(--g)">'+amt.toLocaleString()+' XAF</span>'
      +'</div>';
  }).join('');

  const total = due.reduce(function(s,b){return s+_billingAmtXAF(b);},0);

  confirmDo(
    '<div style="margin-bottom:10px">Send CamPay payment requests to <strong>'+due.length+'</strong> overdue business'+(due.length>1?'es':'')+' — total <strong>'+total.toLocaleString()+' XAF</strong>?</div>'
    +'<div style="max-height:180px;overflow-y:auto">'+listHtml+'</div>',
    async function(){
      const r = await _callBillingFn('charge_all');
      const charged   = (r.charged||[]).length;
      const errors    = (r.errors||[]).length;
      const skipped   = (r.skipped||[]).length;
      let msg = '';
      if(charged)  msg += charged+' charged. ';
      if(errors)   msg += errors+' failed. ';
      if(skipped)  msg += skipped+' skipped.';
      toast(msg || 'Done','success');
      if(errors) console.warn('[mBillingChargeAll] errors:', r.errors);
      nav('admin-biz');
    },
    'Charge All', 'btn-p'
  );
}

function initAdminAnalytics(){
  const statuses = ['Active','Suspended','Inactive','Pending'];
  const statusCounts = statuses.map(s=>D.adminBiz.filter(b=>b.st===s).length);
  mkChart('admStatusChart',{type:'doughnut',data:{
    labels:statuses,
    datasets:[{data:statusCounts,backgroundColor:['rgba(45,212,160,.75)','rgba(245,200,66,.75)','rgba(255,95,122,.75)','rgba(159,122,234,.75)'],borderWidth:0}]
  },options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11}}}}}});

  const plans = [...new Set(D.adminBiz.map(b=>b.plan||'Starter'))];
  const planCounts = plans.map(p=>D.adminBiz.filter(b=>(b.plan||'Starter')===p).length);
  mkChart('admPlanChart',{type:'doughnut',data:{
    labels:plans,
    datasets:[{data:planCounts,backgroundColor:['rgba(91,127,255,.75)','rgba(56,189,248,.75)','rgba(232,102,122,.75)'],borderWidth:0}]
  },options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11}}}}}});
}


