// AFFILIATE PROGRAM — Super Admin Dashboard
// ============================================================
var _affiliates = [];

// ── Affiliate Partial Payment ─────────────────────────────────────────────────
// ── Affiliate receipt upload helpers (multi-file) ─────────────────────────────
var _affReceiptList = []; // [{name, type, dataUrl}] current payment modal

function _affReceiptSelect(input){
  if(!input.files || !input.files.length) return;
  Array.from(input.files).forEach(function(f){ _affReceiptLoad(f); });
  input.value = '';
}

function _affReceiptDrop(event){
  event.preventDefault();
  var wrap = document.getElementById('aff-receipt-wrap');
  if(wrap) wrap.style.borderColor = 'var(--border2)';
  Array.from(event.dataTransfer.files).forEach(function(f){
    if(f.type.startsWith('image/') || f.type === 'application/pdf'){
      _affReceiptLoad(f);
    } else {
      toast('"'+f.name+'" is not an image or PDF — skipped','error');
    }
  });
}

function _affReceiptLoad(file){
  if(file.size > 5*1024*1024){ toast('"'+file.name+'" exceeds 5MB — skipped','error'); return; }
  var reader = new FileReader();
  reader.onload = function(e){
    _affReceiptList.push({name:file.name, type:file.type, dataUrl:e.target.result});
    _affReceiptRenderGrid();
  };
  reader.readAsDataURL(file);
}

function _affReceiptRemove(idx){
  _affReceiptList.splice(idx,1);
  _affReceiptRenderGrid();
}

function _affReceiptRenderGrid(){
  var wrap = document.getElementById('aff-receipt-wrap');
  if(!wrap) return;
  var grid = document.getElementById('aff-receipt-grid');
  var placeholder = document.getElementById('aff-receipt-placeholder');
  if(!grid) return;
  if(!_affReceiptList.length){
    if(placeholder) placeholder.style.display='block';
    grid.innerHTML='';
    wrap.style.borderColor='var(--border2)';
    return;
  }
  if(placeholder) placeholder.style.display='none';
  wrap.style.borderColor='var(--g)';
  grid.innerHTML = _affReceiptList.map(function(r,i){
    var thumb = r.type.startsWith('image/')
      ? '<img src="'+r.dataUrl+'" style="width:72px;height:72px;object-fit:cover;border-radius:var(--r6);display:block;cursor:pointer" onclick="_affPreviewReceiptLocal('+i+')" title="'+_esc(r.name)+'"/>'
      : '<div style="width:72px;height:72px;background:var(--bg4);border-radius:var(--r6);display:flex;flex-direction:column;align-items:center;justify-content:center;cursor:pointer;font-size:22px" onclick="_affPreviewReceiptLocal('+i+')" title="'+_esc(r.name)+'">📄<span style="font-size:9px;color:var(--text2);margin-top:3px">PDF</span></div>';
    return '<div style="position:relative;display:inline-block">'+
      thumb+
      '<button type="button" onclick="event.stopPropagation();_affReceiptRemove('+i+')" style="position:absolute;top:-6px;right:-6px;background:var(--r);border:none;color:#fff;border-radius:50%;width:18px;height:18px;font-size:11px;cursor:pointer;line-height:18px;text-align:center;padding:0">✕</button>'+
      '<div style="font-size:9px;color:var(--text2);text-align:center;max-width:72px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-top:2px" title="'+_esc(r.name)+'">'+_esc(r.name.slice(0,12))+'</div>'+
    '</div>';
  }).join('');
}

function _affPreviewReceiptLocal(idx){
  var r = _affReceiptList[idx];
  if(r) _affViewReceipt(r.dataUrl, r.name);
}

function _affReceiptClear(){
  _affReceiptList = [];
  _affReceiptRenderGrid();
}

function _affViewReceipt(dataUrl, fileName){
  if(!dataUrl) return;
  if(dataUrl.startsWith('data:application/pdf')){
    var w = window.open('','_blank');
    if(w) w.document.write('<iframe src="'+dataUrl+'" style="width:100%;height:100vh;border:none"></iframe>');
    else toast('Allow popups to view PDF','info');
  } else {
    modal('🧾 Receipt'+(fileName?' — '+_esc(fileName):''),
      '<div style="text-align:center"><img src="'+dataUrl+'" style="max-width:100%;max-height:70vh;border-radius:var(--r8)"/></div>'+
      '<div style="text-align:center;margin-top:10px"><a href="'+dataUrl+'" download="'+(fileName||'receipt')+'" class="btn btn-s btn-sm">⬇ Download</a></div>',
      '<button class="btn btn-p" onclick="closeModal()">Close</button>','md'
    );
  }
}

// window._affVR: called from dynamic table HTML (avoids complex string escaping)
window._affVR = function(pi, ri){
  var hist = window._affHistData;
  if(!hist || !hist[pi]) return;
  var p = hist[pi];
  var receipts = p.receipts || (p.receipt_data_url ? [{name:'Receipt',type:'image/',dataUrl:p.receipt_data_url}] : []);
  var r = receipts[ri];
  if(!r || !r.dataUrl){ toast('Receipt not found','info'); return; }
  _affViewReceipt(r.dataUrl, r.name||'Receipt');
};

function _affViewReceiptByIdx(affId, payIdx, recIdx){
  var a = _affiliates.find(function(x){ return x.id===affId; });
  if(!a || !a.payment_history || !a.payment_history[payIdx]) return;
  var p = a.payment_history[payIdx];
  var receipts = p.receipts || (p.receipt_data_url ? [{name:'Receipt',type:'image/',dataUrl:p.receipt_data_url}] : []);
  var r = receipts[recIdx||0];
  if(!r || !r.dataUrl){ toast('Receipt not found','info'); return; }
  _affViewReceipt(r.dataUrl, r.name||'Receipt');
}

// ── Affiliate partial payment modal ──────────────────────────────────────────
function _affPayPartial(id){
  var a = _affiliates.find(function(x){ return x.id===id; });
  if(!a) return;
  var unpaid = a.unpaid_xaf || 0;
  _affReceiptList = []; // reset receipts
  modal('💳 Process Payment — '+_esc(a.name),
    '<div style="margin-bottom:16px">'+
    '<div style="display:flex;justify-content:space-between;align-items:center;padding:12px 16px;background:var(--bg3);border-radius:var(--r8);margin-bottom:12px">'+
      '<div><div style="font-size:12px;color:var(--text2);margin-bottom:2px">Affiliate</div>'+
      '<div style="font-weight:600;color:var(--ink)">'+_esc(a.name)+'</div>'+
      '<div style="font-size:11px;color:var(--a)">'+_esc(a.email)+'</div></div>'+
      '<div style="text-align:right">'+
      '<div style="font-size:12px;color:var(--text2);margin-bottom:2px">Total Unpaid</div>'+
      '<div style="font-size:20px;font-weight:700;color:var(--r)">'+fmt(unpaid)+' XAF</div></div>'+
    '</div>'+
    '<div class="fg">'+
      '<label class="fl">Payment Amount (XAF) *</label>'+
      '<input class="fi" id="aff-pay-amt" type="number" min="1" max="'+unpaid+'" placeholder="Enter amount..." style="font-size:18px;font-weight:600"/>'+
    '</div>'+
    '<div class="fg" style="margin-top:10px">'+
      '<label class="fl">Payment Method</label>'+
      '<select class="fs" id="aff-pay-method">'+
        '<option>Mobile Money</option><option>Bank Transfer</option><option>Cash</option>'+
        '<option>Orange Money</option><option>MTN Mobile Money</option><option>PayPal</option><option>Other</option>'+
      '</select>'+
    '</div>'+
    '<div class="fg" style="margin-top:10px">'+
      '<label class="fl">Reference / Transaction ID</label>'+
      '<input class="fi" id="aff-pay-ref" placeholder="e.g. TXN123456789"/>'+
    '</div>'+
    '<div class="fg" style="margin-top:10px">'+
      '<label class="fl">Notes <span style="font-size:11px;color:var(--text2)">(optional)</span></label>'+
      '<textarea class="ft" id="aff-pay-notes" placeholder="Any notes about this payment..." style="min-height:55px"></textarea>'+
    '</div>'+
    '<div class="fg" style="margin-top:10px">'+
      '<label class="fl">Receipts <span style="font-size:11px;color:var(--text2)">(optional — attach multiple images or PDFs)</span></label>'+
      '<div id="aff-receipt-wrap" style="border:2px dashed var(--border2);border-radius:var(--r8);padding:14px;transition:border-color .2s" ondragover="event.preventDefault();this.style.borderColor=\'var(--a)\'" ondragleave="this.style.borderColor=\'var(--border2)\'" ondrop="_affReceiptDrop(event)">'+
        '<input type="file" id="aff-receipt-inp" accept="image/*,.pdf" multiple style="display:none" onchange="_affReceiptSelect(this)"/>'+
        '<div id="aff-receipt-grid" style="display:flex;flex-wrap:wrap;gap:10px;margin-bottom:8px"></div>'+
        '<div id="aff-receipt-placeholder" style="text-align:center;padding:8px 0">'+
          '<div style="font-size:26px;margin-bottom:4px">📎</div>'+
          '<div style="font-size:13px;color:var(--ink);font-weight:500">Drop files here or</div>'+
        '</div>'+
        '<div style="text-align:center;margin-top:4px">'+
          '<button type="button" class="btn btn-s btn-sm" id="aff-add-files-btn">+ Add Files</button>'+
          '<span style="font-size:11px;color:var(--text2);margin-left:8px">Image or PDF • Max 5MB each</span>'+
        '</div>'+
      '</div>'+
    '</div>'+
    '<div id="aff-pay-preview" style="margin-top:12px;padding:10px 14px;background:var(--bg3);border-radius:var(--r6);display:none">'+
      '<div style="font-size:12px;color:var(--text2);margin-bottom:4px">After payment</div>'+
      '<div style="display:flex;justify-content:space-between">'+
        '<span style="color:var(--ink)">Remaining unpaid:</span>'+
        '<span id="aff-pay-remaining" style="font-weight:700;color:var(--g)"></span>'+
      '</div>'+
    '</div>'+
    '</div>',
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'+
    '<button class="btn btn-p" id="aff-pay-submit">💳 Process Payment</button>'
  );
  setTimeout(function(){
    var addBtn = document.getElementById('aff-add-files-btn');
    if(addBtn) addBtn.onclick = function(){ document.getElementById('aff-receipt-inp').click(); };
    var submitBtn = document.getElementById('aff-pay-submit');
    if(submitBtn) submitBtn.onclick = function(){ _affDoPayPartial(id, unpaid); };
    var inp = document.getElementById('aff-pay-amt');
    if(!inp) return;
    inp.focus();
    inp.oninput = function(){
      var amt = parseFloat(this.value)||0;
      var remaining = Math.max(0, unpaid - amt);
      var prev = document.getElementById('aff-pay-preview');
      var remEl = document.getElementById('aff-pay-remaining');
      if(prev && remEl){
        prev.style.display = amt > 0 ? 'block' : 'none';
        remEl.textContent = fmt(remaining)+' XAF';
        remEl.style.color = remaining === 0 ? 'var(--g)' : 'var(--a)';
      }
    };
  }, 80);
}

async function _affDoPayPartial(id, totalUnpaid){
  var amt = parseFloat((document.getElementById('aff-pay-amt')||{}).value||'');
  var method = (document.getElementById('aff-pay-method')||{}).value||'Mobile Money';
  var ref = ((document.getElementById('aff-pay-ref')||{}).value||'').trim();
  var notes = ((document.getElementById('aff-pay-notes')||{}).value||'').trim();
  var receipts = _affReceiptList.slice(); // [{name,type,dataUrl}]

  if(!amt || amt <= 0){ toast('Enter a valid payment amount','error'); return; }
  if(amt > totalUnpaid){ toast('Amount exceeds unpaid balance of '+fmt(totalUnpaid)+' XAF','error'); return; }

  var newUnpaid = Math.max(0, Math.round(totalUnpaid - amt));
  var isFullPayment = newUnpaid === 0;

  var r = await _affManage('partial-pay', id, {
    amount: amt, new_unpaid: newUnpaid, method: method,
    reference: ref, notes: notes, receipts: receipts,
    paid_at: new Date().toISOString(), paid_by: SESSION.name||'SA'
  });

  if(r.ok){
    var a = _affiliates.find(function(x){ return x.id===id; });
    if(a){
      a.unpaid_xaf = newUnpaid;
      if(!a.payment_history) a.payment_history = [];
      a.payment_history.unshift({
        amt:amt, method:method, ref:ref, notes:notes, receipts:receipts,
        date:new Date().toISOString().slice(0,10)
      });
    }
    _affReceiptList = [];
    _affUpdateKPIs();
    _affRenderTable();
    closeModal();
    toast(isFullPayment
      ? '✅ Full payment of '+fmt(amt)+' XAF processed — balance cleared!'
      : '✅ Partial payment of '+fmt(amt)+' XAF processed — '+fmt(newUnpaid)+' XAF remaining',
      'success');
  } else {
    toast('Payment failed: '+(r.error||'Unknown error'),'error');
  }
}

// Payment history modal with receipt thumbnails
function _affViewHistory(id){
  var a = _affiliates.find(function(x){ return x.id===id; });
  if(!a) return;
  var hist = a.payment_history || [];
  window._affHistId = id;
  window._affHistData = hist;

  var rows = hist.map(function(p, i){
    var receipts = p.receipts || (p.receipt_data_url ? [{name:'Receipt',type:'image/',dataUrl:p.receipt_data_url}] : []);
    var thumbsHtml = receipts.map(function(r, ri){
      return r.type && r.type.startsWith('image')
        ? '<img src="'+r.dataUrl+'" style="width:36px;height:36px;object-fit:cover;border-radius:4px;cursor:pointer;border:1px solid var(--border)" title="'+_esc(r.name||'')+'" onclick="window._affVR('+i+','+ri+')" />'
        : '<div style="width:36px;height:36px;background:var(--bg3);border-radius:4px;border:1px solid var(--border);display:flex;align-items:center;justify-content:center;cursor:pointer;font-size:16px" title="'+_esc(r.name||'')+'" onclick="window._affVR('+i+','+ri+')">📄</div>';
    }).join('');
    var receiptCell = receipts.length
      ? '<div style="display:flex;flex-wrap:wrap;gap:3px">'+thumbsHtml+'</div>'+
        '<div style="font-size:10px;color:var(--text2)">'+receipts.length+' file'+(receipts.length>1?'s':'')+'</div>'
      : '<span style="color:var(--text3);font-size:11px">None</span>';
    return '<tr>'+
      '<td style="white-space:nowrap">'+_esc(p.date||'')+'</td>'+
      '<td style="color:var(--g);font-weight:600;white-space:nowrap">'+fmt(p.amt||0)+' XAF</td>'+
      '<td>'+_esc(p.method||'')+'</td>'+
      '<td style="font-family:var(--mono);font-size:12px">'+_esc(p.ref||'—')+'</td>'+
      '<td style="color:var(--text2);font-size:12px">'+_esc(p.notes||'—')+'</td>'+
      '<td>'+receiptCell+'</td>'+
    '</tr>';
  }).join('');

  modal('📋 Payment History — '+_esc(a.name),
    '<div style="margin-bottom:12px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">'+
      '<div><span style="color:var(--text2)">Total Earned:</span> <strong>'+fmt(a.total_earned_xaf||0)+' XAF</strong></div>'+
      '<div><span style="color:var(--text2)">Unpaid:</span> <strong style="color:var(--r)">'+fmt(a.unpaid_xaf||0)+' XAF</strong></div>'+
      '<div style="font-size:12px;color:var(--text2)">'+hist.length+' payment'+(hist.length!==1?'s':'')+'</div>'+
    '</div>'+
    (hist.length
      ? '<div class="tbl-wrap"><table>'+
          '<thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th><th>Notes</th><th>Receipts</th></tr></thead>'+
          '<tbody>'+rows+'</tbody></table></div>'
      : '<div style="text-align:center;padding:30px;color:var(--text2)"><div style="font-size:32px;margin-bottom:8px">📭</div>No payment history yet.</div>'
    ),
    '<button class="btn btn-p" onclick="closeModal()">Close</button>',
    'md'
  );
}


