// ── DB helper: silent error logging ──────────────────────────
function _dbErr(ctx, err){
  const msg  = err?.message || String(err);
  const code = err?.code    || '';
  const hint = err?.hint    || err?.details || '';
  console.error('[DB:'+ctx+']', code, msg, hint);
  // PGRST204 = column not found — this is a schema mismatch, not a connection issue
  if(code==='PGRST204'){
    console.warn('[DB:'+ctx+'] Schema mismatch — column missing in Supabase. Msg:', msg);
    // Don't show error toast for schema mismatches after a successful in-memory save
    // (data is saved locally, will persist after schema is fixed)
    return;
  }
  // Show toast for user-visible save operations
  const saveCtx = ['saveInv','saveSale','saveRental','saveExp','savePurchase',
                   'saveCust','saveVendor','savePlatformUser','saveBusiness'];
  if(saveCtx.some(s=>ctx.includes(s))){
    const display = code ? '⚠ Save error ('+code+'): '+msg : '⚠ '+msg;
    toast(display.slice(0,120),'error');
  }
}

// ── Load all business data from Supabase into D ──────────────
async function _dbLoadBizData(bizId){
  if(!_sb || !bizId) return;
  try {
    const [inv, cust, sales, rentals, exp, vendors, purchases, audit, cats, svcs, appts] = await Promise.all([
      _sb.from('inventory').select('*').eq('biz_id', bizId),
      _sb.from('customers').select('*').eq('biz_id', bizId),
      _sb.from('sales').select('*').eq('biz_id', bizId).order('created_at', {ascending:false}),
      _sb.from('rentals').select('*').eq('biz_id', bizId).order('created_at', {ascending:false}),
      _sb.from('expenses').select('*').eq('biz_id', bizId).order('created_at', {ascending:false}),
      _sb.from('vendors').select('*').eq('biz_id', bizId),
      _sb.from('purchases').select('*').eq('biz_id', bizId).order('created_at', {ascending:false}),
      _sb.from('audit_log').select('*').eq('biz_id', bizId).order('created_at', {ascending:false}).limit(500),
      _sb.from('categories').select('*').eq('biz_id', bizId),
      _sb.from('services').select('*').eq('biz_id', bizId).order('name'),
      _sb.from('appointments').select('*').eq('biz_id', bizId).order('date', {ascending:false}).limit(500),
    ]);

    // Map DB rows → app format
    // For BIZ-107: only override if Supabase has data (preserves demo data when empty)
    const _is107 = bizId === 'BIZ-107';
    if(!_is107 || (inv.data||[]).length)       D.inv       = (inv.data||[]).map(_dbToInv);
    else {
      // Overlay: apply saved photos/edits onto demo items from Supabase
      // (Supabase may have individual items saved — merge by id)
    }
    var _dbCusts = (cust.data||[]).map(_dbToCust);
    console.log('[_dbLoadBizData] customers from DB:', _dbCusts.length, '| local D.cust:', D.cust.length, '| error:', cust.error?.message||'none');
    if(!_is107 || _dbCusts.length){
      // Merge: DB records are authoritative, but preserve any local-only records
      // (customers added but not yet confirmed in DB) to avoid race condition
      var _dbIds = new Set(_dbCusts.map(function(cu){ return cu.id; }));
      var _localOnly = D.cust.filter(function(cu){ return !_dbIds.has(cu.id); });
      D.cust = _dbCusts.concat(_localOnly);
    }
      _cacheCust(); // update cache with fresh DB data
    if(!_is107 || (sales.data||[]).length)     D.sales     = (sales.data||[]).map(_dbToSale);
    if(!_is107 || (rentals.data||[]).length)   D.rentals   = (rentals.data||[]).map(_dbToRental);
    if(!_is107 || (exp.data||[]).length)       D.exp       = (exp.data||[]).map(_dbToExp);
    if(!_is107 || (vendors.data||[]).length)   D.vendors   = (vendors.data||[]).map(_dbToVendor);
    if(!_is107 || (purchases.data||[]).length) D.purchases = (purchases.data||[]).map(_dbToPurchase);
    if(!_is107 || (audit.data||[]).length)     D.audit     = (audit.data||[]).map(_dbToAudit);
    // Services and appointments — always load from Supabase for real businesses
    if(!_is107 || (svcs.data||[]).length){
      if(svcs.error) console.error('Services load error:', svcs.error.message);
      else D.services = (svcs.data||[]).map(function(r){ return {id:r.id,name:r.name,duration:r.duration_mins!=null?r.duration_mins:60,price:r.price||0,priceType:r.price_type||'flat',cat:r.category||'',color:r.color||'#4361ee',staffIds:r.staff_ids||[],active:r.active!==false,desc:r.description||'',imgDataUrl:r.img_data_url||null}; });
    }
    if(!_is107 || (appts.data||[]).length){
      if(appts.error) console.error('Appointments load error:', appts.error.message);
      else D.appointments = (appts.data||[]).map(_dbToAppt);
    }
    // For BIZ-107: also merge any individually saved inventory items (e.g. updated photos)
    if(_is107 && (inv.data||[]).length){
      const dbInvMap = {};
      (inv.data||[]).forEach(r=>{ dbInvMap[r.id] = _dbToInv(r); });
      D.inv = D.inv.map(item => dbInvMap[item.id] ? {...item, ...dbInvMap[item.id]} : item);
      // Also add any new items added via Supabase that aren't in demo data
      (inv.data||[]).forEach(r=>{ if(!D.inv.find(i=>i.id===r.id)) D.inv.push(_dbToInv(r)); });
    }

    // Categories — load from DB, or seed defaults for new businesses
    const invCats    = (cats.data||[]).filter(c=>c.type==='inv').map(c=>c.name);
    const vendorCats = (cats.data||[]).filter(c=>c.type==='vendor').map(c=>c.name);
    const expCats    = (cats.data||[]).filter(c=>c.type==='exp').map(c=>c.name);
    const svcCats    = (cats.data||[]).filter(c=>c.type==='svc').map(c=>c.name);
    if(invCats.length)    D.invCats    = invCats;    else _ensureDArrays(); // seeds defaults
    if(vendorCats.length) D.vendorCats = vendorCats; else _ensureDArrays();
    if(expCats.length)    D.expCats    = expCats;    else _ensureDArrays();
    if(svcCats.length)    D.svcCats    = svcCats;    else _ensureDArrays();
    // If brand new business (no categories saved), persist defaults to Supabase immediately
    if(!(cats.data||[]).length && bizId && !_is107){
      setTimeout(function(){ _dbSaveCategories(bizId); }, 1000);
    }

    // Reconcile customer spent/orders/balance from actual sales in DB
    // This ensures spend totals survive sale deletions and re-entries
    _reconcileCustomerTotals();

    refreshLiveKpis();
    // Re-render current page if already showing (e.g. background refresh)
    // Rebuild open dropdowns BEFORE nav (nav destroys the modal)
    if(D.cust.length){
      if(typeof window._rebuildCsSel === 'function') window._rebuildCsSel();
      if(typeof window._rebuildCrSel === 'function') window._rebuildCrSel();
    }
    // Only re-render current page if NO modal is open (modal takes priority)
    var _mcEl = document.getElementById('mc');
    var _modalOpen = _mcEl && _mcEl.innerHTML && _mcEl.innerHTML.trim().length > 0;
    if(!_modalOpen && typeof curPage!=='undefined' && curPage && curPage !== 'login'){
      try{ nav(curPage); }catch(_ne){}
    }
  } catch(e){
    _dbErr('loadBizData', e);
    // Even on error, try to show whatever data is available
    try{ refreshLiveKpis(); }catch(_re){}
  }
  // Load this business's team members from Supabase
  if(_sb && bizId){
    _sb.from('platform_users').select('*').eq('biz_id', bizId).then(({data})=>{
      if(data && data.length){
        // Replace any in-memory entries for this biz, keep others
        BIZ_USERS = BIZ_USERS.filter(u=>u.bizId!==bizId).concat(
          data.filter(u=>!u.is_super_admin).map(u=>({
            id:u.id, name:u.name, email:u.email, level:u.level,
            bizId:u.biz_id, st:u.status, last:u.last_login||'Never', rights:u.rights
          }))
        );
      }
    }).catch(e=>_dbErr('loadBizTeam',e));
  }
}

// ── Load all businesses for SA ────────────────────────────────
async function _dbLoadAdminBiz(){
  if(!_sb) return;
  try {
    // Exclude any businesses flagged as deleted server-side (status='Deleted' or deleted=true)
    const {data, error} = await _sb.from('businesses')
      .select('*')
      .neq('status', 'Deleted')
      .order('created_at');
    if(error) throw error;
    const deleted = _getDeletedBizIds(); // also check local tombstones

    // Load platform_users to check email_verified status per business
    const {data:users} = await _sb.from('platform_users')
      .select('biz_id,email_verified,status,verify_token_expiry').eq('level','owner');
    const userMap = {};
    (users||[]).forEach(u=>{ if(u.biz_id) userMap[u.biz_id] = u; });

    // Separate fully verified/active businesses from unverified pending signups
    D.adminBiz = [];
    D.adminBizUnverified = [];

    (data||[]).filter(b => !deleted.has(b.id)).forEach(b => {
      const u = userMap[b.id];
      // Catch both new (status=Pending) and legacy (status=Trial but email not yet verified)
      const isUnverified = (b.status === 'Pending' || (u && u.email_verified === false && u.verify_token_expiry)) && u && u.email_verified === false;
      const mapped = {
        id:b.id, name:b.name, owner:b.owner, email:b.email,
        type:b.type, st:b.status, plan:b.plan, trialEnd:b.trial_end,
        users:b.users||1, rev:b.rev||0, created:b.created,
        country:b.country||'',
        phone:b.phone||'', whatsapp:b.whatsapp||'',
        subExpires:b.sub_expires||null,
        billingCycle:b.billing_cycle||'monthly',
        subChargeStatus:b.sub_charge_status||null,
        tokenExpiry: u?.verify_token_expiry || null,
        emailVerified: u?.email_verified ?? true
      };
      if(isUnverified){
        D.adminBizUnverified.push(mapped);
      } else {
        D.adminBiz.push(mapped);
      }
    });
  } catch(e){ _dbErr('loadAdminBiz', e); }
}

