// ── Upsert helpers (fire-and-forget) ─────────────────────────
// ── Reconcile customer spent/orders/balance from actual D.sales data ──
// Called after every data load to ensure totals match reality
function _reconcileCustomerTotals(){
  if(!D.cust || !D.cust.length) return;
  // Build spend map from sales
  const spendMap  = {};  // custId → total revenue (invoiced)
  const orderMap  = {};  // custId → count
  const paidMap   = {};  // custId → total paid
  D.sales.forEach(function(s){
    const cid = s.custId || s.cust; // fall back to name if no id
    if(!cid) return;
    spendMap[cid]  = (spendMap[cid]  || 0) + (s.total || s.amt || 0);
    paidMap[cid]   = (paidMap[cid]   || 0) + (s.paid  || 0);
    orderMap[cid]  = (orderMap[cid]  || 0) + 1;
  });
  // Update each customer in memory (DB save happens lazily on next action)
  let changed = 0;
  D.cust.forEach(function(c){
    const cid   = c.id;
    const spent  = spendMap[cid]  || spendMap[c.name] || 0;
    const paid   = paidMap[cid]   || paidMap[c.name]  || 0;
    const orders = orderMap[cid]  || orderMap[c.name] || 0;
    const bal    = spent - paid;
    if(Math.abs((c.spent||0) - spent) > 0.5 ||
       Math.abs((c.bal||0)   - bal)   > 0.5 ||
       (c.orders||0) !== orders){
      c.spent  = spent;
      c.spend  = spent;
      c.orders = orders;
      c.bal    = bal;
      changed++;
      // Persist to DB
      _dbSaveCust(c);
    }
  });
  if(changed > 0) console.log('[reconcile] Updated', changed, 'customer totals');
}

function _reconcileVendorTotals(){
  // Recompute AP (vendor balances) from purchases
  // AP = sum of unpaid purchases per vendor
  if(!D.vendors||!D.vendors.length) return;
  const poMap  = {}; // vendorId → total ordered
  const paidMap= {}; // vendorId → total paid
  D.purchases.forEach(function(p){
    const vid = p.vendorId || p.vendor;
    if(!vid) return;
    poMap[vid]   = (poMap[vid]   ||0) + (p.total||0);
    if(p.st==='Paid') paidMap[vid] = (paidMap[vid]||0) + (p.total||0);
  });
  D.vendors.forEach(function(v){
    const vid = v.id;
    const ordered = poMap[vid] || poMap[v.name] || 0;
    const paid    = paidMap[vid] || paidMap[v.name] || 0;
    const newBal  = Math.max(0, ordered - paid);
    if(Math.abs((v.bal||0)-newBal)>0.5){
      v.bal = newBal;
    }
  });
}

async function _dbSaveInv(item){
  if(!_sb||!SESSION.bizId||SESSION.isSuperAdmin) return;
  await _safeUpsert('inventory', _invToDB(item, SESSION.bizId), 'saveInv');
}
async function _dbDelInv(id){
  if(!_sb||!SESSION.bizId) return;
  await _sb.from('inventory').delete().eq('id',id).eq('biz_id',SESSION.bizId);
}
async function _dbSaveCust(cu){
  if(!_sb||!SESSION.bizId||SESSION.isSuperAdmin) return;
  const payload = _custToDB(cu, SESSION.bizId);
  const res = await _safeUpsert('customers', payload, 'saveCust');
  if(res.ok && res.data && res.data[0]){
    var saved = _dbToCust(res.data[0]);
    saved.dob      = cu.dob      || cu.birthday || '';
    saved.birthday = cu.birthday || cu.dob      || '';
    var idx = D.cust.findIndex(function(x){ return x.id === saved.id; });
    if(idx >= 0) D.cust[idx] = saved;
    else {
      var localIdx = D.cust.findIndex(function(x){ return x.id === cu.id; });
      if(localIdx >= 0) D.cust.splice(localIdx, 1);
      D.cust.unshift(saved);
    }
    // Persist to localStorage so dropdown works on next page load instantly
    _cacheCust();
    if(typeof curPage !== 'undefined' && curPage === 'customers'){
      try{ nav('customers'); }catch(_e){}
    }
  } else {
    // Even if DB save status unclear, cache current D.cust
    _cacheCust();
  }
}

function _cacheCust(){
  if(!SESSION.bizId) return;
  try{ localStorage.setItem('st_cust_'+SESSION.bizId, JSON.stringify(D.cust)); }catch(_e){}
}

function _loadCustCache(){
  if(!SESSION.bizId) return;
  try{
    var raw = localStorage.getItem('st_cust_'+SESSION.bizId);
    if(raw){
      var cached = JSON.parse(raw);
      if(Array.isArray(cached) && cached.length && !D.cust.length){
        D.cust = cached;
        console.log('[cache] restored', D.cust.length, 'customers from localStorage');
      }
    }
  }catch(_e){}
}
