function updateSidebarForRole(){
  // Update topbar business name
  const _topBizEl = document.getElementById('topbar-biz-name');
  if(_topBizEl) _topBizEl.textContent = SESSION.isSuperAdmin ? 'Super Admin' : (BIZ.name||'ShopTrack');
  // Update sidebar user chip
  const sbName = document.getElementById('sb-user-name');
  if(sbName && !sbName.textContent) sbName.textContent = SESSION.isSuperAdmin ? (SA_PROFILE&&SA_PROFILE.name)||'Super Admin' : SESSION.name||'';
  const sbRole = document.getElementById('sb-user-role');
  if(sbRole && !sbRole.textContent) sbRole.textContent = SESSION.isSuperAdmin ? 'Super Admin' : (USER_LEVEL_LABELS[SESSION.level]||SESSION.level||'');
  const sbAva2 = document.getElementById('sb-user-avatar');
  if(sbAva2 && !sbAva2.textContent){ const nm3=SESSION.isSuperAdmin?(SA_PROFILE&&SA_PROFILE.name)||'SA':SESSION.name||''; sbAva2.textContent=nm3.split(' ').filter(Boolean).map(w=>w[0]).join('').substring(0,2).toUpperCase()||'U'; }
  const isSA = SESSION.isSuperAdmin;
  // Business sections: hidden for Super Admin, visible for everyone else
  ['sb-sect-biz','sb-sect-people','sb-sect-finance','sb-sect-tools'].forEach(id=>{
    const el = document.getElementById(id);
    if(el){ el.style.display = isSA ? 'none' : ''; }
  });
  // Platform Admin section: visible ONLY for Super Admin
  const adminSect = document.getElementById('sb-sect-admin');
  if(adminSect){ adminSect.style.display = isSA ? '' : 'none'; }
  // Hide the prev dividers to avoid orphaned lines — only show dividers that have visible content below
  const dividers = document.querySelectorAll('#sb .sb-div');
  dividers.forEach((d,i) => {
    if(isSA){
      d.style.display = i === dividers.length-1 ? '' : 'none';
    } else {
      d.style.display = '';
    }
  });
  // Update overdue rentals badge
  const overdueR = (D.rentals||[]).filter(r=>r.st==='Overdue'||r.st==='overdue').length;
  const rBadge = document.getElementById('sb-rentals-badge');
  if(rBadge){ if(overdueR>0){rBadge.textContent=overdueR;rBadge.style.display='';}else{rBadge.style.display='none';} }
// Update billing badge on Businesses sidebar item
  if(isSA){
    const billingAlert = D.adminBiz.filter(function(b){
      var d = _billingDaysLeft(b);
      return d !== null && d <= 0 && b.st === 'Active' && _billingAmtXAF(b) > 0;
    }).length;
    const billingBadge = document.getElementById('sb-billing-badge');
    if(billingBadge){
      if(billingAlert > 0){ billingBadge.textContent = billingAlert; billingBadge.style.display = ''; }
      else { billingBadge.style.display = 'none'; }
    }
  }
  // Update today's appointments badge
  const todayAppts = (D.appointments||[]).filter(a=>a.date===localDateStr()&&a.st!=='Cancelled').length;
  const aBadge = document.getElementById('sb-appt-badge');
  if(aBadge){ if(todayAppts>0){aBadge.textContent=todayAppts;aBadge.style.display='';}else{aBadge.style.display='none';} }
  // Mobile drawer: hide biz items for SA, hide SA items for biz users
  document.querySelectorAll('.dr-biz-item').forEach(el=>{ el.style.display=isSA?'none':''; });
  document.querySelectorAll('.dr-sa-item').forEach(el=>{ el.style.display=isSA?'':'none'; });
  // Apply language to sidebar labels (silent — no toast, no page re-render here)
  if(typeof BIZ !== 'undefined' && BIZ.language && BIZ.language !== 'en'){
    const _Lnav = _L();
    const _sbMap = {
      'dashboard':'nav_dashboard','inventory':'nav_inventory','sales':'nav_sales',
      'rentals':'nav_rentals','purchases':'nav_purchases','customers':'nav_customers',
      'vendors':'nav_vendors','expenses':'nav_expenses','accounting':'nav_accounting',
      'reports':'nav_reports','appointments':'nav_appointments','services':'nav_services',
      'booking-settings':'nav_booking','catalog':'nav_catalog','ai-studio':'nav_ai',
      'auditlog':'nav_audit','settings':'nav_settings',
      'admin-biz':'nav_businesses','admin-users':'nav_users','admin-analytics':'nav_analytics'
    };
    document.querySelectorAll('.sb-item[data-p]').forEach(function(el){
      var lbl=el.querySelector('.sb-lbl-txt');
      var key=_sbMap[el.dataset.p];
      if(lbl&&key&&_Lnav[key]) lbl.textContent=_Lnav[key];
    });
    var _drMap={'dr-appointments':'nav_appointments','dr-services':'nav_services',
      'dr-biz-purchases':'nav_purchases','dr-customers':'nav_customers',
      'dr-vendors':'nav_vendors','dr-expenses':'nav_expenses',
      'dr-accounting':'nav_accounting','dr-reports':'nav_reports',
      'dr-catalog':'nav_catalog','dr-ai-studio':'nav_ai','dr-auditlog':'nav_audit',
      'dr-admin-biz':'nav_businesses','dr-admin-users':'nav_users',
      'dr-admin-analytics':'nav_analytics','dr-settings':'nav_settings',
      'dr-signout':'nav_signout'};
    Object.entries(_drMap).forEach(function(e){
      var el=document.getElementById(e[0]);
      if(el){var sp=el.querySelector('span');if(sp&&_Lnav[e[1]])sp.textContent=_Lnav[e[1]];}
    });
    var _bnMap={'bn-dashboard':'nav_home','bn-inventory':'nav_inventory',
      'bn-sales':'nav_sales','bn-rentals':'nav_rentals'};
    Object.entries(_bnMap).forEach(function(e){
      var el=document.getElementById(e[0]);
      if(el){var sp=el.querySelector('.bni-lbl');if(sp&&_Lnav[e[1]])sp.textContent=_Lnav[e[1]];}
    });
  }
}

