async function doResetPwd(email, btn){
  const np  = document.getElementById('fp-new')?.value  || '';
  const cf  = document.getElementById('fp-conf')?.value || '';
  const err = document.getElementById('fp-err');
  const showErr = msg => { if(err){ err.textContent=msg; err.style.display='block'; } };

  if(!np || np.length < 8){ showErr('Password must be at least 8 characters.'); return; }
  if(!/[A-Z]/.test(np))   { showErr('Password must contain at least one uppercase letter.'); return; }
  if(!/[0-9]/.test(np))   { showErr('Password must contain at least one number.'); return; }
  if(np !== cf)            { showErr('Passwords do not match.'); return; }

  if(btn){ btn.textContent='Saving…'; btn.disabled=true; }

  // Hash with SHA-256 (same as signup flow)
  let newHash = np;
  try{
    const enc = new TextEncoder().encode(np);
    const buf = await crypto.subtle.digest('SHA-256', enc);
    newHash = Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
  }catch(e){ /* use plaintext if SubtleCrypto unavailable */ }

  // ── Persist to Supabase (real users) ──
  await _dbUpdatePassword(email, newHash);

  // ── Keep AUTH_STORE in sync (demo/offline accounts) ──
  if(AUTH_STORE[email]) AUTH_STORE[email].password = newHash;
  const uid   = AUTH_STORE[email]?.userId;
  const bUser = uid ? BIZ_USERS.find(u=>u.id===uid) : null;
  if(bUser) bUser.password = newHash;

  btn.closest('[style*="position:fixed"]').remove();
  showLoginError('');
  const errEl = document.getElementById('ln-error');
  if(errEl){ errEl.style.background='rgba(45,212,160,.12)'; errEl.style.borderColor='rgba(45,212,160,.3)'; errEl.style.color='#2dd4a0'; errEl.textContent='✅ Password updated — you can now sign in.'; errEl.style.display='block'; }
}

function doLogout(){
  addAudit('Logout', (SESSION.name||SESSION.email||'User')+' signed out');
  try{ localStorage.removeItem('st_session'); sessionStorage.removeItem('st_session'); }catch(e){}
  const ls = document.getElementById('login-screen');
  if(ls){ ls.style.opacity='1'; ls.style.transition='none'; ls.style.display='flex'; }
  // Clear form
  ['ln-email','ln-pass'].forEach(id=>{ const el=document.getElementById(id); if(el) el.value=''; });
  const err=document.getElementById('ln-error'); if(err) err.style.display='none';
}

// Manage passwords from Settings → Security tab
function mChangePassword(){
  modal('🔑 Change Password',`
  <div class="alrt alrt-b" style="margin-bottom:14px">Changing password for <strong>${SESSION.name}</strong> (${SESSION.isSuperAdmin?'Super Admin':USER_LEVEL_LABELS[SESSION.level]})</div>
  <div class="fg"><label class="fl">Current Password</label><input class="fi" id="cp-cur" type="password" placeholder="Current password"/></div>
  <div class="fg"><label class="fl">New Password</label><input class="fi" id="cp-new" type="password" placeholder="At least 8 characters"/></div>
  <div class="fg"><label class="fl">Confirm New Password</label><input class="fi" id="cp-conf" type="password" placeholder="Repeat new password"/></div>
  <div style="margin-top:8px;font-size:11px;color:var(--text2)">
    Password requirements: min 8 chars, at least 1 number, 1 special character
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="_doChangePassword()">Update Password</button>`);
}

async function _doChangePassword(){
  const cur = document.getElementById('cp-cur')?.value || '';
  const np  = document.getElementById('cp-new')?.value || '';
  const cf  = document.getElementById('cp-conf')?.value || '';

  if(!cur){ toast('Enter your current password','error'); return; }
  if(!np || np.length < 8){ toast('New password must be at least 8 characters','error'); return; }
  if(!/[0-9]/.test(np)){ toast('New password must contain at least one number','error'); return; }
  if(!/[!@#$%^&*()_+\-=\[\]{}|;:,.<>?]/.test(np)){ toast('New password must contain at least one special character','error'); return; }
  if(np !== cf){ toast('Passwords do not match','error'); return; }

  const btn = document.querySelector('#mc .btn-p');
  if(btn){ btn.textContent='Updating…'; btn.disabled=true; }

  // ── Fetch the stored hash from Supabase (works for ALL users, not just AUTH_STORE) ──
  let storedHash = null;
  let userEmail  = null;
  if(_sb){
    try{
      const {data} = await _sb.from('platform_users')
        .select('email,password_hash').eq('id', SESSION.userId).maybeSingle();
      if(data){ storedHash = data.password_hash; userEmail = data.email; }
    }catch(e){ console.warn('mChangePassword DB fetch error:', e.message); }
  }
  // Fallback: AUTH_STORE (demo accounts)
  if(!storedHash){
    userEmail = Object.keys(AUTH_STORE).find(k => AUTH_STORE[k].userId === SESSION.userId);
    if(userEmail) storedHash = AUTH_STORE[userEmail].password;
  }

  if(!storedHash || !userEmail){
    toast('Could not verify your identity — please log out and back in','error');
    if(btn){ btn.textContent='Update Password'; btn.disabled=false; }
    return;
  }

  // Verify current password (supports plaintext legacy AND SHA-256)
  const matched = await _pwdMatch(cur, storedHash);
  if(!matched){
    toast('Current password is incorrect','error');
    if(btn){ btn.textContent='Update Password'; btn.disabled=false; }
    return;
  }

  // Hash the new password before saving
  let newHash = np;
  try{
    const enc = new TextEncoder().encode(np);
    const buf = await crypto.subtle.digest('SHA-256', enc);
    newHash = Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
  }catch(e){ /* SubtleCrypto unavailable, store plaintext */ }

  // Save to Supabase
  await _dbUpdatePassword(userEmail, newHash);

  // Keep AUTH_STORE in sync for demo accounts
  if(AUTH_STORE[userEmail]) AUTH_STORE[userEmail].password = newHash;

  toast('Password changed successfully ✓','success');
  closeModal();
}

