// Save the new customer and inject into the select
function _inlineSaveNewCust(prefix){
  const name  = (document.getElementById(prefix+'-nc-name')?.value||'').trim();
  const phone = (document.getElementById(prefix+'-nc-phone')?.value||'').trim();
  if(!name){ toast('Customer name is required','error'); document.getElementById(prefix+'-nc-name')?.focus(); return; }
  if(!phone){ toast('Phone number is required','error'); document.getElementById(prefix+'-nc-phone')?.focus(); return; }

  // Generate unique ID
  var _maxC=D.cust.reduce(function(m,cu){var n=parseInt((cu.id||'').replace(/\D/g,''),10)||0;return n>m?n:m;},0);
  const newId='C-'+String(_maxC+1).padStart(3,'0');
  const email = (document.getElementById(prefix+'-nc-email')?.value||'').trim();
  const city  = (document.getElementById(prefix+'-nc-city')?.value||'').trim();

  const newCust = {
    id:newId, name, email, phone, whatsapp:phone,
    address:city, city, vip:false, notes:'',
    spent:0, orders:0, bal:0, st:'Active', last:localDateStr()
  };

  // Add to D.cust and save to DB
  D.cust.unshift(newCust);
  _dbSaveCust(D.cust[0]);
  addAudit('Customer added', newId+' — '+name);

  // Inject into ALL native <select> customer dropdowns in current modal
  document.querySelectorAll('.mo-box select, .modal-box select, #mc select').forEach(function(sel){
    if(!sel.querySelector('option[value="'+newId+'"]')){
      var opt=document.createElement('option');
      opt.value=newId; opt.textContent=name+(phone?' ('+phone+')':'');
      opt.dataset.ph=phone;
      sel.appendChild(opt);
    }
    if(sel.id===prefix+'-cust'||sel.id===prefix+'-c'){
      sel.value=newId;
      sel.dispatchEvent(new Event('change'));
    }
  });

  // ── Also update _mkSearchSelect custom dropdown widgets ────────────────
  // The sale modal uses prefix+'cust-wrap' as a searchable div dropdown
  var wrapId = prefix+'-cust-wrap';
  var hiddenId = prefix+'-cust';
  var wrapEl = document.getElementById(wrapId);
  var hiddenEl = document.getElementById(hiddenId);
  if(wrapEl){
    // Re-build the searchable select with the new customer included
    var custOpts = [{val:'',label:'-- Select customer --'}]
      .concat(D.cust.map(function(cu){ return {val:cu.id, label:cu.name+(cu.phone?' ('+cu.phone+')':'')}; }));
    _mkSearchSelect(wrapId, custOpts, newId, function(val){
      if(hiddenEl) hiddenEl.value=val;
      // Fill phone field
      var found=D.cust.find(function(cu){return cu.id===val;});
      var phEl=document.getElementById(prefix+'-cust-phone')||document.getElementById(prefix+'-ph')||document.getElementById(prefix+'-phone');
      if(phEl&&found) phEl.value=found.phone||found.whatsapp||'';
    });
  } else {
    // Fallback: set hidden input and fill phone
    if(hiddenEl){ hiddenEl.value=newId; hiddenEl.dispatchEvent(new Event('change')); }
    var phEl2=document.getElementById(prefix+'-ph')||document.getElementById(prefix+'-phone')||document.getElementById(prefix+'-cust-phone');
    if(phEl2) phEl2.value=phone;
  }

  // Hide the inline form
  _inlineCancelNewCust(prefix);
  toast(name+' added to customers ✓','success');
}

