// ── Searchable business type dropdown ────────────────────────
var _SU_TYPES = [
  {g:'Fashion & Beauty',     items:['Boutique / Fashion Retail','Fashion Designer','Tailor / Seamstress','Bridal Shop & Rentals','Hair Salon / Stylist','Barber Shop','Spa & Beauty Center','Nail Studio','Makeup Artist','Wig & Hair Extensions']},
  {g:'Home & Construction',  items:['Interior Decorator / Designer','Furniture Shop','Carpenter / Joinery','Plumber / Plumbing Services','Electrician / Electrical Works','Painter & Decorator','Building Materials','Real Estate']},
  {g:'Food & Hospitality',   items:['Restaurant / Eatery','Bakery & Pastry','Catering Services','Bar & Lounge','Hotel / Guesthouse','Food Delivery']},
  {g:'Tech & Electronics',   items:['Electronics Shop','Phone Repair','Computer Repair & IT','Photography & Videography','Printing & Design Studio']},
  {g:'Services & Professional',items:['Event Planning & Decoration','Cleaning Services','Laundry & Dry Cleaning','Transport & Logistics','Travel Agency','Legal / Consulting Services','Pharmacy & Health','Gym & Fitness']},
  {g:'Retail & Trade',       items:['General Retail / Supermarket','Agriculture & Farm Products','Wholesale / Distribution','Auto Parts & Garage','Stationery & Office Supplies']},
  {g:'Other',                items:['Other']},
];
function _suTypeBuildList(q){
  var html='';
  var qL=(q||'').toLowerCase();
  _SU_TYPES.forEach(function(grp){
    var matched=grp.items.filter(function(i){ return !qL||i.toLowerCase().includes(qL); });
    if(!matched.length) return;
    if(!qL) html+='<div style="padding:5px 11px 3px;font-size:9px;font-weight:700;letter-spacing:1px;text-transform:uppercase;color:#6366f1;background:#1a1d2e;position:sticky;top:0">'+grp.g+'</div>';
    matched.forEach(function(item){
      html+='<div onclick="_suTypeSelect(\''+item.replace(/'/g,"\\'")+'\')" '
        +'style="padding:9px 14px;font-size:13px;color:#e2e8f0;cursor:pointer;transition:background .1s;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" '
        +'onmouseover="this.style.background=\'rgba(99,102,241,.18)\'" '
        +'onmouseout="this.style.background=\'transparent\'">'+item+'</div>';
    });
  });
  if(!html) html='<div style="padding:12px 14px;font-size:13px;color:#64748b;text-align:center">No match — try another word</div>';
  return html;
}
function _suTypeOpen(){
  var el=document.getElementById('su-type-list');
  if(el){ el.style.display='block'; el.innerHTML=_suTypeBuildList(''); }
}
function _suTypeClose(){
  var el=document.getElementById('su-type-list');
  if(el) el.style.display='none';
}

// ── Universal Searchable Select ────────────────────────────────
// Usage: _mkSearchSelect(containerId, opts, currentVal, onSelect, placeholder)
// opts: [{val, label}]  onSelect: function(val, label)
function _mkSearchSelect(id, opts, currentVal, onSelect, placeholder){
  var wrap = document.getElementById(id);
  if(!wrap) return;
  var currentLabel = '';
  opts.forEach(function(o){ if(String(o.val)===String(currentVal)) currentLabel=o.label; });
  wrap.style.position = 'relative';
  // Build: visible search input + hidden value field + dropdown list
  wrap.innerHTML =
    // Search input — shows selected label; clears on focus to allow typing
    '<input class="fi" id="'+id+'-inp" autocomplete="off" '
    +'placeholder="'+(placeholder||'Search or select…')+'" '
    +'value="'+_esc(currentLabel)+'" '
    +'style="padding-right:28px;cursor:pointer;box-sizing:border-box;width:100%" '
    +'onfocus="_ssOpen(\''+id+'\')" '
    +'onblur="setTimeout(function(){_ssClose(\''+id+'\')},220)" '
    +'oninput="_ssFilter(\''+id+'\')" />'
    // Chevron icon
    +'<span onclick="_ssToggle(\''+id+'\')" '
    +'style="position:absolute;right:10px;top:50%;transform:translateY(-50%);'
    +'color:var(--text2);cursor:pointer;font-size:11px;user-select:none">▾</span>'
    // Hidden value field (source of truth for form save)
    +'<input type="hidden" id="'+id+'-val" value="'+_esc(currentVal)+'" />'
    // Dropdown list panel — fixed width, search bar at top
    +'<div id="'+id+'-list" style="display:none;position:absolute;top:calc(100% + 3px);left:0;right:0;'
    +'background:var(--bg3);border:1.5px solid var(--a);border-radius:var(--r8);'
    +'z-index:9999;box-shadow:0 8px 24px rgba(0,0,0,.35);overflow:hidden">'
      // Sticky search bar inside the list panel
      +'<div style="padding:7px 8px;border-bottom:1px solid var(--border2);background:var(--bg3);position:sticky;top:0">'
        +'<input id="'+id+'-search" autocomplete="off" '
        +'placeholder="🔍 Search…" '
        +'style="width:100%;background:var(--bg2);border:1px solid var(--border2);color:var(--ink);'
        +'border-radius:var(--r6);padding:6px 10px;font-size:12px;font-family:inherit;'
        +'outline:none;box-sizing:border-box" '
        +'oninput="_ssSearchFilter(\''+id+'\')" />'
      +'</div>'
      // Scrollable items container
      +'<div id="'+id+'-items" style="max-height:180px;overflow-y:auto"></div>'
    +'</div>';
  wrap._ssOpts     = opts;
  wrap._ssOnSelect = onSelect;
  wrap._ssCurVal   = currentVal;
  wrap._ssCurLbl   = currentLabel;
  _ssRenderList(id, '');
}
function _ssOpen(id){
  var inp = document.getElementById(id+'-inp');
  var wrap = document.getElementById(id);
  // Save current label so we can restore on blur-without-select
  if(wrap) wrap._ssCurLbl = inp ? inp.value : '';
  // Clear the input so the search field shows empty and full list appears
  if(inp) inp.value = '';
  var list = document.getElementById(id+'-list');
  if(list){ list.style.display='block'; }
  // Clear the search box inside the dropdown
  var srch = document.getElementById(id+'-search');
  if(srch){ srch.value=''; srch.focus(); }
  _ssRenderList(id, '');
}
function _ssToggle(id){
  var list = document.getElementById(id+'-list');
  if(!list) return;
  if(list.style.display==='none'||!list.style.display){
    _ssOpen(id);
  } else {
    _ssClose(id);
  }
}
function _ssClose(id){
  var list = document.getElementById(id+'-list');
  if(list) list.style.display='none';
  // Restore the display input to show the currently selected label
  var wrap = document.getElementById(id);
  var inp  = document.getElementById(id+'-inp');
  var hiddenEl = document.getElementById(id+'-val');
  if(inp && hiddenEl){
    // Find label for current value
    var lbl = '';
    if(wrap && wrap._ssOpts){
      wrap._ssOpts.forEach(function(o){ if(String(o.val)===String(hiddenEl.value)) lbl=o.label; });
    }
    // Only restore if user didn't type a new selection (inp is empty after open)
    inp.value = lbl || (wrap && wrap._ssCurLbl ? wrap._ssCurLbl : '');
  }
}
function _ssSearchFilter(id){
  // Called by the search box INSIDE the dropdown panel
  var srch = document.getElementById(id+'-search');
  var q = srch ? srch.value.toLowerCase() : '';
  _ssRenderList(id, q);
}
function _ssFilter(id){
  // Called by the main visible input (oninput) — filter as user types
  var inp = document.getElementById(id+'-inp');
  var q = inp ? inp.value.toLowerCase() : '';
  // Also sync the dropdown search box
  var srch = document.getElementById(id+'-search');
  if(srch) srch.value = inp ? inp.value : '';
  var list = document.getElementById(id+'-list');
  if(list) list.style.display='block';
  _ssRenderList(id, q);
}
function _ssRenderList(id, q){
  var wrap = document.getElementById(id);
  if(!wrap||!wrap._ssOpts) return;
  var items = document.getElementById(id+'-items');
  if(!items) return;
  var filtered = wrap._ssOpts.filter(function(o){
    return !q || o.label.toLowerCase().includes(q) || (o.val+'').toLowerCase().includes(q);
  });
  var curVal = (document.getElementById(id+'-val')||{}).value || '';
  if(!filtered.length){
    items.innerHTML='<div style="padding:10px 12px;color:var(--text2);font-size:12px;text-align:center">No results</div>';
    return;
  }
  items.innerHTML = filtered.map(function(o){
    var isSelected = String(o.val) === String(curVal);
    return '<div onmousedown="event.preventDefault();_ssSelect(\''+id+'\',\''+_esc(o.val)+'\',\''+_esc(o.label)+'\')" '
      +'style="padding:9px 12px;cursor:pointer;font-size:13px;color:var(--ink);'
      +(isSelected?'background:var(--a-dim);font-weight:600;':'')+'" '
      +'onmouseover="this.style.background=\'var(--bg4)\'" '
      +'onmouseout="this.style.background=\''+(isSelected?'var(--a-dim)':'')+'\'">'+_esc(o.label)+'</div>';
  }).join('');
}
function _ssSelect(id, val, label){
  var hiddenEl = document.getElementById(id+'-val');
  var inpEl    = document.getElementById(id+'-inp');
  var wrap     = document.getElementById(id);
  if(hiddenEl) hiddenEl.value = val;
  if(inpEl){ inpEl.value = label; }
  if(wrap){ wrap._ssCurVal=val; wrap._ssCurLbl=label; }
  _ssClose(id);
  if(wrap && wrap._ssOnSelect) wrap._ssOnSelect(val, label);
}
function _ssGetVal(id){
  var el = document.getElementById(id+'-val');
  return el ? el.value : '';
}

// ── Init all searchable selects visible in DOM right now ───────
function _initModalSearchSelects(context){
  var ctx = context || document;

  function custOpts(blank){ return (blank?[{val:'',label:blank}]:[]).concat(D.cust.map(function(c){ return {val:c.id, label:c.name+(c.phone?' · '+c.phone:'')+(c.vip?' ⭐':'')}; })); }
  function vendOpts(blank){ return (blank?[{val:'',label:blank}]:[]).concat(D.vendors.map(function(v){ return {val:v.id, label:v.name+(v.cat?' ('+v.cat+')':'')}; })); }
  function catOpts(cats,blank){ return (blank?[{val:'',label:blank}]:[]).concat((cats||[]).map(function(c){ return {val:c,label:c}; })); }
  function svcOpts(blank){ return (blank?[{val:'',label:blank}]:[]).concat((D.services||[]).filter(function(s){return s.active!==false;}).map(function(s){ return {val:s.id,label:s.name+(s.cat?' · '+s.cat:'')+(s.price?' — '+fmt(s.price):'') }; })); }

  // ── Native customer selects (reliable, always visible) ─────────────────────
  function _nativeCustSel(wrapId, hiddenId, blank, onChangeFn){
    var w = document.getElementById(wrapId);
    if(!w || w.querySelector('select')) return;
    w.innerHTML = '<select class="fs" style="width:100%"><option value="">'+blank+'</option>'
      + D.cust.map(function(cu){ return '<option value="'+cu.id+'">'+_esc(cu.name)+(cu.phone?' ('+cu.phone+')':'')+'</option>'; }).join('')
      + '</select>';
    var sel = w.querySelector('select');
    sel.id = hiddenId+'-sel';
    sel.onchange = function(){
      var val = this.value;
      var h = document.getElementById(hiddenId); if(h) h.value = val;
      if(typeof onChangeFn === 'function') onChangeFn(val);
    };
  }

  function _nativeVendorSel(wrapId, hiddenId, blank, onChangeFn){
    var w = document.getElementById(wrapId);
    if(!w || w.querySelector('select')) return;
    w.innerHTML = '<select class="fs" style="width:100%"><option value="">'+blank+'</option>'
      + D.vendors.map(function(v){ return '<option value="'+v.id+'">'+_esc(v.name)+(v.cat?' ('+v.cat+')':'')+'</option>'; }).join('')
      + '</select>';
    var sel = w.querySelector('select');
    sel.id = hiddenId+'-sel';
    sel.onchange = function(){
      var val = this.value;
      var h = document.getElementById(hiddenId); if(h) h.value = val;
      if(typeof onChangeFn === 'function') onChangeFn(val);
    };
  }

  // Customer selects
  _nativeCustSel('cs-cust-wrap','cs-cust','-- Select customer --', function(val){
    var cu=D.cust.find(function(x){return x.id===val;});
    if(cu){var ph=cu.phone||cu.whatsapp||''; var phEl=document.getElementById('cs-cust-phone'); if(phEl)phEl.value=ph;}
  });
  _nativeCustSel('cr-cust-wrap','cr-cust','-- Select customer --', function(val){
    if(typeof _crFillPhone==='function') _crFillPhone();
  });
  _nativeCustSel('rp-cust-wrap','rp-cust','— Choose a customer —', function(val){
    if(typeof _rpFillFromCustomer==='function') _rpFillFromCustomer();
  });
  _nativeCustSel('stmt-cust-wrap','stmt-cust-sel','— Choose a customer —', null);
  _nativeCustSel('na-c-wrap','na-c','— Walk-in / Select —', function(val){
    if(typeof _naCust==='function') _naCust();
  });

  // Vendor selects
  _nativeVendorSel('po-vendor-wrap','po-vendor','-- Select vendor --', null);

  // Category selects (kept as searchable — small, fast arrays)
// Category selects — ALWAYS rebuild so added/removed cats show immediately
  if(document.getElementById('ai-cat-wrap')){
    var cur=document.getElementById('ai-cat')?document.getElementById('ai-cat').value:'';
    _mkSearchSelect('ai-cat-wrap', catOpts(D.invCats,''), cur||D.invCats[0]||'General', function(val){ document.getElementById('ai-cat').value=val; }, 'Category…');
  }
  if(document.getElementById('ei-cat-wrap')){
    var cur=document.getElementById('ei-cat')?document.getElementById('ei-cat').value:'';
    _mkSearchSelect('ei-cat-wrap', catOpts(D.invCats,''), cur, function(val){ document.getElementById('ei-cat').value=val; }, 'Category…');
  }

  // Vendor categories
  if(document.getElementById('av-cat-wrap')){
    var cur=document.getElementById('av-cat')?document.getElementById('av-cat').value:'';
    _mkSearchSelect('av-cat-wrap', catOpts(D.vendorCats,''), cur||D.vendorCats[0]||'General', function(val){ document.getElementById('av-cat').value=val; }, 'Category…');
  }
  if(document.getElementById('ev-cat-wrap')){
    var cur=document.getElementById('ev-cat')?document.getElementById('ev-cat').value:'';
    _mkSearchSelect('ev-cat-wrap', catOpts(D.vendorCats,''), cur, function(val){ document.getElementById('ev-cat').value=val; }, 'Category…');
  }

  // Expense category
  if(document.getElementById('ae-cat-wrap')){
    var expCats=D.expCats.length?D.expCats:['Rent & Lease','Salaries & Wages','Utilities','Internet & Phone','Marketing & Advertising','Transport & Fuel','Packaging & Supplies','Repairs & Maintenance','Insurance','Staff Bonus','Cleaning','Photography','Bank Charges','Taxes & Duties','Miscellaneous','Other'];
    var cur=document.getElementById('ae-cat')?document.getElementById('ae-cat').value:'';
    _mkSearchSelect('ae-cat-wrap', catOpts(expCats,''), cur||expCats[0], function(val){ document.getElementById('ae-cat').value=val; }, 'Expense category…');
  }
  // Edit expense category
  if(document.getElementById('edit-exp-cat-wrap')){
    var editExpCats=D.expCats.length?D.expCats:['Rent & Lease','Salaries & Wages','Utilities','Internet & Phone','Marketing & Advertising','Transport & Fuel','Packaging & Supplies','Repairs & Maintenance','Insurance','Staff Bonus','Cleaning','Photography','Bank Charges','Taxes & Duties','Miscellaneous','Other'];
    var editExpCur=document.getElementById('edit-exp-cat')?document.getElementById('edit-exp-cat').value:'';
    _mkSearchSelect('edit-exp-cat-wrap', catOpts(editExpCats,''), editExpCur||editExpCats[0]||'', function(val){ document.getElementById('edit-exp-cat').value=val; }, 'Expense category…');
  }
  // Service category (new + edit)
  if(document.getElementById('sv-cat-wrap')){
    var svCats2=D.svcCats&&D.svcCats.length?D.svcCats:['Consultation','Installation','Maintenance & Repair','Training','Design & Planning','Delivery & Logistics','Cleaning','Beauty & Grooming','Health & Wellness','Events & Catering','Photography & Media','IT & Tech Support','Other'];
    var svCatCur=document.getElementById('sv-cat')?document.getElementById('sv-cat').value:'';
    _mkSearchSelect('sv-cat-wrap', [{val:'',label:'— No category —'}].concat(catOpts(svCats2,'')), svCatCur||'', function(val){ document.getElementById('sv-cat').value=val; }, 'Service category…');
  }

  // Appointment service
  if(document.getElementById('na-s-wrap') && !document.getElementById('na-s-wrap-val')){
    var svcs=svcOpts('— Select service —');
    var cur=document.getElementById('na-s')?document.getElementById('na-s').value:'';
    _mkSearchSelect('na-s-wrap', svcs, cur, function(val){ document.getElementById('na-s').value=val; if(typeof _naSync==='function')_naSync(); }, 'Search service…');
  }
}


