// ── Data loading overlay ─────────────────────────────────────
function _showDataLoading(msg){
  var el = document.getElementById('data-loading-overlay');
  if(el){ var t=el.querySelector('.dl-msg'); if(t)t.textContent=msg||'Loading…'; return; }
  var d = document.createElement('div');
  d.id = 'data-loading-overlay';
  d.style.cssText = 'position:fixed;inset:0;z-index:99999;background:#0f1120;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:16px';
  d.innerHTML = '<div style="width:44px;height:44px;border:4px solid rgba(99,102,241,.2);border-top-color:#6366f1;border-radius:50%;animation:_dlspin .8s linear infinite"></div>'
    +'<div class="dl-msg" style="font-size:14px;color:#8892b0;font-weight:500">'+(msg||'Loading…')+'</div>'
    +'<style>@keyframes _dlspin{to{transform:rotate(360deg)}}</style>';
  if(document.body) document.body.appendChild(d);
}
function _hideDataLoading(){
  var el = document.getElementById('data-loading-overlay');
  if(el){ el.style.opacity='0'; el.style.transition='opacity .3s'; setTimeout(function(){if(el.parentNode)el.parentNode.removeChild(el);},320); }
}

