// Current document state for sharing
let _currentDoc = { title:'', html:'' };

function _uploadDocImage(input, type){
  const file = input.files[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = function(e){
    const dataUrl = e.target.result;
    if(type === 'sign'){
      BIZ.signDataUrl = dataUrl;
      const prev = document.getElementById('sign-preview');
      if(prev){ prev.style.display='block'; prev.innerHTML='<img loading="lazy" src="'+dataUrl+'" style="max-height:52px;max-width:200px;object-fit:contain;border-radius:6px;border:1px solid var(--border)"/>'; }
    } else {
      BIZ.stampDataUrl = dataUrl;
      const prev = document.getElementById('stamp-preview');
      if(prev){ prev.style.display='block'; prev.innerHTML='<img loading="lazy" src="'+dataUrl+'" style="max-height:64px;max-width:120px;object-fit:contain;border-radius:6px;border:1px solid var(--border)"/>'; }
    }
    toast((type==='sign'?'Signature':'Stamp')+' uploaded — will appear on documents','success');
  };
  reader.readAsDataURL(file);
}
function _clearDocImage(type){
  if(type==='sign'){ BIZ.signDataUrl=null; const p=document.getElementById('sign-preview'); if(p){p.style.display='none';p.innerHTML='';} }
  else { BIZ.stampDataUrl=null; const p=document.getElementById('stamp-preview'); if(p){p.style.display='none';p.innerHTML='';} }
  toast((type==='sign'?'Signature':'Stamp')+' removed','success');
}


function openDoc(title, htmlContent){
  _currentDoc = { title, html: htmlContent };
  const overlay = document.getElementById('doc-overlay');
  const toolbarTitle = document.getElementById('doc-toolbar-title');
  if(!overlay){ toast('Document viewer not found — please refresh','error'); return; }
  if(toolbarTitle) toolbarTitle.textContent = title;

  // Write content directly into doc-content div
  const dc = document.getElementById('doc-content');
  if(dc){
    dc.style.display = '';
    dc.innerHTML = htmlContent;
  }

  // Remove any stale iframe
  const old = document.getElementById('doc-iframe');
  if(old) old.remove();

  overlay.style.display = 'flex';
  overlay.classList.add('open');

  // Share button visibility
  const shareBtn = document.getElementById('doc-share-btn');
  if(shareBtn) shareBtn.style.display = navigator.share ? 'inline-block' : 'none';
}
function closeDoc(){
  const overlay = document.getElementById('doc-overlay');
  if(overlay){ overlay.classList.remove('open'); overlay.style.display='none'; }
  const dc = document.getElementById('doc-content');
  if(dc) dc.innerHTML = '';
}
function printDoc(){
  if(!_currentDoc || !_currentDoc.html){
    toast('Nothing to print','error'); return;
  }
  try {
    const fullHtml = '<!DOCTYPE html><html><head><meta charset="UTF-8"><title>'+_currentDoc.title+'</title>'
      +'<link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet"/>'
      +'<style>@media print{.no-print,button,#doc-toolbar{display:none!important}}body{margin:0;padding:24px;font-family:"Plus Jakarta Sans",sans-serif;background:#fff;color:#1e2130;-webkit-print-color-adjust:exact;print-color-adjust:exact}</style>'
      +'</head><body>'+_currentDoc.html+'</body></html>';
    const blob = new Blob([fullHtml],{type:'text/html'});
    const url = URL.createObjectURL(blob);
    const w = window.open(url,'_blank');
    if(w){ setTimeout(()=>{ w.print(); setTimeout(()=>URL.revokeObjectURL(url),2000); },700); return; }
  } catch(e){}
  toast('Please allow pop-ups for shoptrack.org to print documents','error');
}

// Build a plain-text version of the current doc for message sharing
function _docTextSummary(){
  const tmp = document.createElement('div');
  tmp.innerHTML = _currentDoc.html;
  const text = tmp.innerText || tmp.textContent || '';
  return _currentDoc.title + '\n\n' + text.replace(/\s{3,}/g,'\n').substring(0,600) + '...';
}

function shareDocWhatsApp(){
  const msg = encodeURIComponent(
    '📄 *' + _currentDoc.title + '*\n' +
    '🏪 ' + BIZ.name + '\n' +
    '📞 ' + BIZ.phone + '\n' +
    (BIZ.website ? '🌐 ' + BIZ.website + '\n' : '') +
    '\nThis document was sent from ShopTrack. Please contact us for payment or queries.'
  );
  // On mobile opens WhatsApp directly; on desktop opens web.whatsapp.com
  const url = /Mobi|Android/i.test(navigator.userAgent)
    ? 'whatsapp://send?text=' + msg
    : 'https://web.whatsapp.com/send?text=' + msg;
  window.open(url, '_blank');
}

function shareDocEmail(){
  const subject = encodeURIComponent(_currentDoc.title + ' — ' + BIZ.name);
  const body = encodeURIComponent(
    'Dear Customer,\n\nPlease find your ' + _currentDoc.title + ' attached from ' + BIZ.name + '.\n\n' +
    '— ' + BIZ.name + '\n' + BIZ.email + ' | ' + BIZ.phone + (BIZ.website ? ' | ' + BIZ.website : '') + '\n\n' +
    'This was generated by ShopTrack.'
  );
  window.location.href = 'mailto:?subject=' + subject + '&body=' + body;
}

function shareDocNative(){
  if(!navigator.share){ toast('Sharing not supported on this browser','error'); return; }
  navigator.share({
    title: _currentDoc.title + ' — ' + BIZ.name,
    text: _docTextSummary(),
    url: window.location.href,
  }).catch(()=>{});
}

function docSignStamp(){
  const hasSign  = BIZ.signDataUrl;
  const hasStamp = BIZ.stampDataUrl;
  if(!hasSign && !hasStamp) return '';
  var html = '<div style="display:flex;justify-content:space-between;align-items:flex-end;margin-top:28px;padding-top:18px;border-top:1px dashed #e5e7eb;">';
  html += '<div style="text-align:left">';
  if(hasSign){
    html += '<img loading="lazy" src="'+BIZ.signDataUrl+'" style="height:52px;max-width:160px;object-fit:contain;display:block;margin-bottom:4px"/>';
    html += '<div style="font-size:10px;color:#475569;border-top:1px solid #e5e7eb;padding-top:3px;width:160px">Authorised Signature</div>';
  } else {
    html += '<div style="width:160px;border-top:1px solid #e5e7eb;padding-top:3px;font-size:10px;color:#475569">Authorised Signature</div>';
  }
  html += '</div>';
  if(hasStamp){
    html += '<div style="text-align:right"><img loading="lazy" src="'+BIZ.stampDataUrl+'" style="height:72px;max-width:120px;object-fit:contain;display:block;opacity:.88"/></div>';
  }
  html += '</div>';
  return html;
}


function bizLogo(){
  if(BIZ.logoDataUrl) return `<img loading="lazy" src="${BIZ.logoDataUrl}" style="height:56px;object-fit:contain;display:block"/>`;
  return `<div style="width:56px;height:56px;background:linear-gradient(135deg,${BIZ.primaryColor},${BIZ.accentColor});border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:22px;font-weight:800;color:#fff;font-family:'Plus Jakarta Sans',sans-serif;letter-spacing:-1px">${BIZ.name.substring(0,2).toUpperCase()}</div>`;
}

function docStyles(primary, accent){
  var p = primary||'#4361ee';
  var a = accent||'#059669';
  var pDim = p+'18';
  var pLight = p+'0d';
  return `<link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,400&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet"/>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:'Plus Jakarta Sans',sans-serif;color:#1e293b;background:#fff;-webkit-font-smoothing:antialiased;font-size:13px;line-height:1.5}
    /* Header */
    .doc-header{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:0;padding:28px 32px 22px;background:${p};border-radius:0}
    .doc-header-inner{background:#fff;padding:22px 28px 22px;margin-bottom:0}
    .doc-biz-name{font-size:20px;font-weight:800;color:#0f172a;letter-spacing:-0.5px;margin-top:10px;line-height:1.1}
    .doc-biz-sub{font-size:11px;color:#64748b;margin-top:3px}
    .doc-biz-contact{font-size:10.5px;color:#94a3b8;margin-top:5px;line-height:1.7}
    /* Title block */
    .doc-title-block{text-align:right}
    .doc-number{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,.7);margin-bottom:6px}
    .doc-number-val{font-size:30px;font-weight:900;color:#fff;font-family:'Plus Jakarta Sans',sans-serif;letter-spacing:-1px;line-height:1}
    .doc-date{font-size:11px;color:rgba(255,255,255,.75);margin-top:8px;line-height:1.8}
    /* Status badge */
    .doc-badge{display:inline-flex;align-items:center;gap:5px;padding:5px 14px;border-radius:20px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.8px}
    .doc-badge-paid{background:#dcfce7;color:#166534}
    .doc-badge-unpaid{background:#fee2e2;color:#991b1b}
    .doc-badge-partial{background:#fef9c3;color:#854d0e}
    /* Body area */
    .doc-body{padding:22px 28px}
    /* Bill To / Meta */
    .doc-meta{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:24px;background:#f8fafc;border-radius:10px;padding:16px 20px;border:1px solid #f0f4f8}
    .doc-meta-full{grid-template-columns:1fr;margin-bottom:24px}
    .doc-label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:1.4px;color:#94a3b8;margin-bottom:5px}
    .doc-value{font-size:13px;color:#1e293b;font-weight:600}
    .doc-value-sub{font-size:11px;color:#64748b;margin-top:2px}
    /* Items table */
    .doc-items{width:100%;border-collapse:collapse;margin-bottom:20px}
    .doc-items thead{background:${p}}
    .doc-items thead th{padding:11px 14px;text-align:left;font-size:9.5px;font-weight:700;text-transform:uppercase;letter-spacing:.9px;color:#fff}
    .doc-items tbody tr{border-bottom:1px solid #f1f5f9}
    .doc-items tbody tr:last-child{border-bottom:none}
    .doc-items td{padding:11px 14px;font-size:12.5px;color:#374151;vertical-align:middle}
    .doc-items td.num{font-family:'JetBrains Mono',monospace;font-size:12px;text-align:right;color:#1e293b;font-weight:500}
    .doc-items td.desc{font-weight:500;color:#1e293b}
    /* Totals */
    .doc-totals{display:flex;justify-content:flex-end;margin-bottom:24px}
    .doc-totals-box{width:280px;background:#f8fafc;border-radius:10px;border:1px solid #e2e8f0;overflow:hidden}
    .doc-total-row{display:flex;justify-content:space-between;align-items:center;padding:9px 16px;border-bottom:1px solid #e2e8f0;font-size:12.5px;color:#475569}
    .doc-total-row .num{font-family:'JetBrains Mono',monospace;font-size:12px;color:#374151}
    .doc-total-final{display:flex;justify-content:space-between;align-items:center;padding:13px 16px;background:${p};font-weight:800;font-size:15px;color:#fff;letter-spacing:-.3px}
    .doc-total-final .num{font-family:'JetBrains Mono',monospace;font-size:14px;color:#fff}
    /* Payment */
    .doc-section-title{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:1.6px;color:#94a3b8;margin-bottom:10px;margin-top:20px}
    .doc-pay-methods{display:flex;flex-wrap:wrap;gap:7px;margin-bottom:20px}
    .doc-pay-pill{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:5px 13px;font-size:10.5px;color:#475569;font-weight:500}
    /* Footer */
    .doc-footer{background:${pLight};border-top:3px solid ${p};padding:16px 20px;display:flex;justify-content:space-between;align-items:flex-end;gap:20px;margin:0 -28px -0px}
    .doc-footer-note{font-size:11px;color:#374151;max-width:360px;line-height:1.65}
    .doc-footer-biz{text-align:right;font-size:11px;color:#64748b;line-height:1.7;flex-shrink:0}
    .doc-footer-biz strong{color:#374151;font-weight:700}
    /* Receipt */
    .receipt-amount{font-size:48px;font-weight:900;color:${p};font-family:'Plus Jakarta Sans',sans-serif;text-align:center;letter-spacing:-2px;margin:20px 0;line-height:1}
    /* Catalog */
    .catalog-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:8px}
    .cat-card{border:1px solid #e5e7eb;border-radius:10px;overflow:hidden}
    .cat-card-img{height:90px;background:linear-gradient(135deg,#f0f0f5,#e8e8f0);display:flex;align-items:center;justify-content:center;font-size:36px}
    .cat-card-body{padding:10px 12px}
    .cat-card-name{font-size:12px;font-weight:700;color:#1e293b;margin-bottom:2px}
    .cat-card-price{font-size:13px;font-weight:800;color:${p};margin-top:6px;font-family:'JetBrains Mono',monospace}
    /* Watermark */
    .doc-watermark{position:fixed;bottom:30px;right:30px;font-size:9px;color:#e2e8f0;font-weight:700;letter-spacing:1.5px;text-transform:uppercase;pointer-events:none}
    @media print{.no-print,button{display:none!important}.doc-footer{position:relative;margin-top:20px}}
  </style>`;
}


function genInvoiceDoc(saleId){
  const s = saleId ? D.sales.find(x=>x.id===saleId) : {id:'INV-'+Date.now(),cust:'Customer',items:'Items',amt:0,paid:0,dt:'2026-03-02',st:'Unpaid',profit:0};
  if(!s) return;
  const total = s.total || s.amt || 0;
  const bal = total - s.paid;
  const stBadge = s.st==='Paid'?'paid':s.st==='Partial'?'partial':'unpaid';
  const primary = BIZ.primaryColor;
  const accent = BIZ.accentColor;
  const L = _L();
  const stLabel = s.st==='Paid'?L.stPaid : s.st==='Partial'?L.stPartial : L.stUnpaid;
  const html = `${docStyles(primary,accent)}
  <div class="doc-header" style="background:${primary};padding:24px 28px 20px;display:flex;justify-content:space-between;align-items:flex-start">
    <div>
      ${bizLogo()}
      <div class="doc-biz-name" style="color:#fff;margin-top:8px">${_esc(BIZ.name)}</div>
      ${BIZ.tagline?`<div class="doc-biz-sub" style="color:rgba(255,255,255,.75)">${_esc(BIZ.tagline)}</div>`:''}
    </div>
    <div class="doc-title-block">
      <div class="doc-number">${L.invoice}</div>
      <div class="doc-number-val">${s.id}</div>
      <div class="doc-date">
        ${L.date}: ${s.dt}<br>
        <span class="doc-badge doc-badge-${stBadge}" style="margin-top:8px;display:inline-flex">${stLabel}</span>
      </div>
    </div>
  </div>
  <div class="doc-body">
    <div class="doc-meta">
      <div>
        <div class="doc-label">${L.billTo}</div>
        <div class="doc-value" style="font-size:15px">${_esc(s.cust)}</div>
        ${s.custPhone?`<div class="doc-value-sub">${_esc(s.custPhone)}</div>`:''}
      </div>
      <div style="text-align:right">
        <div style="display:inline-grid;grid-template-columns:auto auto;gap:4px 16px;text-align:left">
          <div class="doc-label">${L.invoiceNo}</div><div class="doc-value" style="font-family:var(--mono,monospace)">${s.id}</div>
          <div class="doc-label">${L.date}</div><div class="doc-value">${s.dt}</div>
          <div class="doc-label">${L.terms}</div><div class="doc-value" style="color:${primary};font-weight:600">${_esc(s.terms||BIZ.paymentTerms||'Net 7')}</div>
          ${BIZ.taxRate>0?`<div class="doc-label">${L.taxId}</div><div class="doc-value">${_esc(BIZ.taxId||BIZ.taxRegNumber||'—')}</div>`:''}
        </div>
      </div>
    </div>
    <table class="doc-items">
      <thead><tr><th style="width:50%">${L.description}</th><th>${L.qty}</th><th class="num">${L.unitPrice}</th><th class="num">${L.amount}</th></tr></thead>
      <tbody>
        ${(s.lineItems&&s.lineItems.length?s.lineItems:null) ? s.lineItems.map(li=>`<tr><td class="desc">${_esc(li.name||li.item||li.desc||'Item')}</td><td>${li.qty||1}</td><td class="num">${fmtDoc((li.price||0))}</td><td class="num" style="font-weight:700">${fmtDoc((li.qty||1)*(li.price||0))}</td></tr>`).join('') : `<tr><td class="desc">${_esc(s.items)}</td><td>1</td><td class="num">${fmtDoc(s.total||s.amt)}</td><td class="num" style="font-weight:700">${fmtDoc(s.total||s.amt)}</td></tr>`}
        ${s.freight>0?`<tr><td class="desc" style="color:#64748b">${L.freight}</td><td>—</td><td class="num">${fmtDoc(s.freight)}</td><td class="num">${fmtDoc(s.freight)}</td></tr>`:''}
      </tbody>
    </table>
    <div class="doc-totals">
      <div class="doc-totals-box">
        ${BIZ.taxRate>0?`<div class="doc-total-row"><span>${L.subtotal}</span><span class="num">${fmtDoc((s.total||s.amt)/(1+BIZ.taxRate/100))}</span></div><div class="doc-total-row"><span>${L.tax}</span><span class="num">${fmtDoc((s.total||s.amt)-(s.total||s.amt)/(1+BIZ.taxRate/100))}</span></div>`:`<div class="doc-total-row"><span>${L.subtotal}</span><span class="num">${fmtDoc(s.total||s.amt)}</span></div>`}
        ${(s.freight||0)>0?`<div class="doc-total-row"><span>${L.freight}</span><span class="num">${fmtDoc(s.freight)}</span></div>`:''}
        ${(s.taxes||0)>0?`<div class="doc-total-row"><span>${L.taxes}</span><span class="num">${fmtDoc(s.taxes)}</span></div>`:''}
        ${(s.other||0)>0?`<div class="doc-total-row"><span>${L.other}</span><span class="num">${fmtDoc(s.other)}</span></div>`:''}
        ${s.paid>0?`<div class="doc-total-row"><span style="color:var(--g);font-weight:600">${L.amtPaid}</span><span class="num" style="color:var(--g);font-weight:600">(${fmtDoc(s.paid)})</span></div>`:''}
        <div class="doc-total-final"><span>${L.balDue}</span><span class="num">${fmtDoc(bal)}</span></div>
      </div>
    </div>
    <div class="doc-section-title">${L.payMethods}</div>
    <div class="doc-pay-methods">${(BIZ.paymentMethods||'Cash, Bank Transfer, Mobile Money (MTN), Orange Money').split(',').map(m=>m.trim()).filter(Boolean).map(m=>`<span class="doc-pay-pill">${_esc(m)}</span>`).join('')}</div>
    ${BIZ.bankDetails?`<div class="doc-section-title" style="margin-top:14px">${L.bankDetails}</div><div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:12px 16px;font-size:11px;line-height:1.8;color:#374151;white-space:pre-line;margin-bottom:16px">${_esc(BIZ.bankDetails)}</div>`:''}
    ${docSignStamp()}
  </div>
  <div class="doc-footer">
    <div class="doc-footer-note">
      <strong style="display:block;margin-bottom:4px;font-size:12px">${_esc(BIZ.invoiceNote)}</strong>
      ${BIZ.email?`<div>📧 ${_esc(BIZ.email)}</div>`:''}${BIZ.phone?`<div>📞 ${_esc(BIZ.phone)}</div>`:''}
    </div>
    <div class="doc-footer-biz">
      <strong>${_esc(BIZ.name)}</strong>
      ${BIZ.address?`<div>${_esc(BIZ.address)}</div>`:''}
      ${BIZ.website?`<div style="color:${primary}">${_esc(BIZ.website)}</div>`:''}
    </div>
  </div>
  <div class="doc-watermark">ShopTrack</div>`;
  openDoc(`${L.invoice} — ${s.id}`, html);
}

function genReceiptDoc(saleId){
  const s = saleId ? D.sales.find(x=>x.id===saleId) : D.sales[0];
  if(!s) return;
  const primary = BIZ.primaryColor;
  const accent = BIZ.accentColor;
  const R = _L();
  const html = `${docStyles(primary,accent)}
  <div style="background:${primary};padding:24px 28px 32px;text-align:center">
    <div style="display:inline-block;margin-bottom:12px">${bizLogo()}</div>
    <div style="font-size:18px;font-weight:800;color:#fff;letter-spacing:-.3px">${_esc(BIZ.name)}</div>
    ${BIZ.tagline?`<div style="font-size:11px;color:rgba(255,255,255,.75);margin-top:3px">${_esc(BIZ.tagline)}</div>`:''}
    ${BIZ.address?`<div style="font-size:10.5px;color:rgba(255,255,255,.6);margin-top:6px">${_esc(BIZ.address)}</div>`:''}
    <div style="font-size:10px;color:rgba(255,255,255,.55);margin-top:3px">${BIZ.phone?_esc(BIZ.phone):''} ${BIZ.email?'&nbsp;·&nbsp; '+_esc(BIZ.email):''}</div>
  </div>
  <div class="doc-body">
    <div style="text-align:center;background:#f0fdf4;border:2px solid #bbf7d0;border-radius:14px;padding:28px 20px;margin-bottom:22px">
      <div style="width:48px;height:48px;background:#22c55e;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 12px;font-size:22px;color:#fff">✓</div>
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1.8px;color:#166534;margin-bottom:8px">${R.payReceived}</div>
      <div class="receipt-amount" style="color:${primary}">${fmtDoc(s.paid||s.total||s.amt)}</div>
      <span class="doc-badge ${(s.paid||0)>=(s.total||s.amt||0)?'doc-badge-paid':'doc-badge-partial'}" style="margin-top:10px">${(s.paid||0)>=(s.total||s.amt||0)?R.paidFull:R.partial}</span>
    </div>
    <div class="doc-meta" style="grid-template-columns:1fr 1fr 1fr 1fr">
      <div><div class="doc-label">${R.receiptNo}</div><div class="doc-value" style="font-family:monospace">${s.id.replace('S-','RCT-')}</div></div>
      <div><div class="doc-label">${R.date}</div><div class="doc-value">${s.dt}</div></div>
      <div><div class="doc-label">${R.customer}</div><div class="doc-value">${_esc(s.cust)}</div></div>
      <div><div class="doc-label">${R.method}</div><div class="doc-value">${_esc(s.method||'Cash')}</div></div>
    </div>
    <table class="doc-items">
      <thead><tr><th style="width:65%">${R.description}</th><th class="num">${R.amount}</th></tr></thead>
      <tbody>
      <tr><td class="desc">${_esc(s.items)}</td><td class="num" style="font-weight:700">${fmtDoc(s.total||s.amt)}</td></tr>
      ${(s.paid>0&&s.paid<(s.total||s.amt))?`<tr><td class="desc" style="color:#64748b">${R.amtPaid}</td><td class="num" style="color:#059669">${fmtDoc(s.paid)}</td></tr>`:''}
      ${(s.total||s.amt)-s.paid>0?`<tr><td class="desc" style="font-weight:700">${R.balDue}</td><td class="num" style="font-weight:700;color:#dc2626">${fmtDoc((s.total||s.amt)-s.paid)}</td></tr>`:''}
    </tbody>
    </table>
    ${docSignStamp()}
  </div>
  <div class="doc-footer">
    <div class="doc-footer-note">
      <strong>${R.thanks}${_esc(s.cust.split(' ')[0])}!</strong> ${R.keepRec}
      ${BIZ.invoiceNote?`<div style="margin-top:4px;color:#64748b">${_esc(BIZ.invoiceNote)}</div>`:''}
    </div>
    <div class="doc-footer-biz">
      <strong>${_esc(BIZ.name)}</strong>
      ${BIZ.website?`<div style="color:${primary}">${_esc(BIZ.website)}</div>`:''}
    </div>
  </div>
  <div class="doc-watermark">ShopTrack</div>`;
  openDoc(`${R.receipt} — ${s.id}`, html);
}

function genCatalogDoc(){
  const primary  = BIZ.primaryColor  || '#e8667a';
  const accent   = BIZ.accentColor   || '#f5a623';
  const p        = primary;
  const invItems = D.inv.filter(i=>(i.sp||i.rp) && i.st!=='Archived');
  const svcItems = (D.services||[]).filter(s=>s.active!==false);
  const catName  = BIZ.catalogName   || ((BIZ.name||'Our') + ' Service Catalog');
  const tagline  = BIZ.catalogTagline|| BIZ.tagline || '';
  const totalCount = invItems.length + svcItems.length;

  const footerContact = [BIZ.phone, BIZ.email, BIZ.website].filter(Boolean).join('  |  ');
  const footerSocials = [
    BIZ.whatsapp  ? '\u{1F4AC} '+BIZ.whatsapp  : '',
    BIZ.instagram ? '\u{1F4F8} @'+BIZ.instagram : '',
    BIZ.facebook  ? '\u{1F464} '+BIZ.facebook  : '',
    BIZ.tiktok    ? '\u{1F3B5} @'+BIZ.tiktok   : '',
  ].filter(Boolean).join('   ');

  // Build service cards section
  const svcCatsList = [...new Set(svcItems.map(s=>s.cat||'Services').filter(Boolean))];
  var svcSections = '';
  svcCatsList.forEach(function(cat){
    var catSvcs = svcItems.filter(function(s){return (s.cat||'Services')===cat;});
    svcSections += '<div class="cat-section-hd">'+_esc(cat)+' <span style="font-weight:400;opacity:.6">('+catSvcs.length+' service'+(catSvcs.length>1?'s':'')+')</span></div>';
    svcSections += '<div class="cat-grid">';
    catSvcs.forEach(function(s){
      var pt = s.priceType||'flat';
      var ptSfx = {'per_hour':'/hr','per_min':'/min','per_day':'/day','per_week':'/wk','per_session':'/session'}[pt]||'';
      var priceDisp = pt==='starting' ? 'From '+fmtDoc(s.price) : fmtDoc(s.price)+ptSfx;
      var dur = (!s.duration||s.duration<=0) ? 'Duration TBD' : s.duration+' min';
      var imgHtml = s.imgDataUrl
        ? '<img src="'+s.imgDataUrl+'" style="width:100%;height:100%;object-fit:cover;display:block;background:#f9fafb"/>'
        : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,'+(s.color||primary)+'22,'+(s.color||primary)+'11);font-size:52px">✂️</div>';
      svcSections += '<div class="cat-card">'
        +'<div class="cat-card-photo">'+imgHtml+'</div>'
        +'<div class="cat-card-body">'
        +'<div class="cat-card-name">'+_esc(s.name)+'</div>'
        +'<div class="cat-card-meta">'+_esc(dur)+(pt!=='flat'?' · '+_ptLabel(pt):'')+'</div>'
        +(s.desc?'<div class="cat-card-desc">'+_esc(s.desc.substring(0,110))+(s.desc.length>110?'…':'')+'</div>':'')
        +'<div class="cat-card-prices"><div><span class="cat-price-sale">'+_esc(priceDisp)+'</span></div></div>'
        +'</div></div>';
    });
    svcSections += '</div>';
  });

  // Build inventory sections
  var invSections = '';
  const invCats = [...new Set(invItems.map(i=>i.cat).filter(Boolean))];
  invCats.forEach(function(cat){
    var catItems = invItems.filter(i=>i.cat===cat);
    invSections += '<div class="cat-section-hd">'+_esc(cat)+' <span style="font-weight:400;opacity:.6">('+catItems.length+' item'+(catItems.length>1?'s':'')+')</span></div>';
    invSections += '<div class="cat-grid">';
    catItems.forEach(function(it){
      var avail=(it.qty||0)-(it.rented||0);
      var _src=(it.photoDataUrls&&it.photoDataUrls.length)?it.photoDataUrls[0]:(it.imgDataUrl||null);
      var imgHtml=_src
        ?'<img src="'+_src+'" style="width:100%;height:100%;object-fit:contain;display:block;background:#f9fafb"/>'
        :'<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;background:linear-gradient(135deg,#f0f0f8,#e8e8f0);font-size:52px">&#x1F457;</div>';
      var meta=[it.color,it.sz?'Size '+it.sz:null,it.cond,it.brand].filter(Boolean).join(' · ');
      invSections += '<div class="cat-card">'
        +'<div class="cat-card-photo">'+imgHtml+'</div>'
        +'<div class="cat-card-body">'
        +'<div class="cat-card-name">'+_esc(it.name)+'</div>'
        +(meta?'<div class="cat-card-meta">'+_esc(meta)+'</div>':'')
        +(it.desc?'<div class="cat-card-desc">'+_esc(it.desc.substring(0,110))+(it.desc.length>110?'…':'')+'</div>':'')
        +'<div class="cat-card-prices">'
        +(it.sp?'<div><span class="cat-price-sale">'+fmtDoc(it.sp)+'</span> <span class="cat-price-label">Buy</span></div>':'')
        +(it.rp?'<div><span class="cat-price-rent">'+fmtDoc(it.rp)+'<span style="font-size:9px">/day</span></span> <span class="cat-price-label">Rent</span></div>':'')
        +(avail>0?'<span class="cat-avail-badge" style="margin-left:auto">'+avail+' avail</span>':'')
        +'</div></div></div>';
    });
    invSections += '</div>';
  });

  const html = `${docStyles(primary,accent)}
<style>
  body{background:#fff;margin:0;padding:0}
  .cat-page-footer{position:fixed;bottom:0;left:0;right:0;background:#fff;border-top:2.5px solid ${p};padding:7px 28px;display:flex;justify-content:space-between;align-items:center;gap:16px;font-size:9px;color:#64748b;line-height:1.6;z-index:100}
  .cat-page-footer-biz{font-weight:700;color:#1e293b;font-size:9.5px}
  .cat-body{padding:0 28px 70px}
  .cat-cover{background:linear-gradient(145deg,${p} 0%,${accent} 100%);border-radius:14px;padding:48px 44px 44px;margin-bottom:0;color:#fff;position:relative;overflow:hidden;page-break-after:always;break-after:page;display:flex;justify-content:space-between;align-items:flex-end;gap:24px;min-height:200px}
  .cat-cover::before{content:'';position:absolute;top:-80px;right:-80px;width:300px;height:300px;background:rgba(255,255,255,.08);border-radius:50%}
  .cat-cover::after{content:'';position:absolute;bottom:-60px;left:-60px;width:200px;height:200px;background:rgba(255,255,255,.05);border-radius:50%}
  .cat-section-hd{font-size:8.5px;font-weight:700;text-transform:uppercase;letter-spacing:2px;color:${p};border-bottom:1.5px solid ${p}33;padding-bottom:6px;margin:28px 0 16px}
  .cat-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px}
  .cat-card{border:1px solid #e8ecf1;border-radius:12px;overflow:hidden;page-break-inside:avoid;break-inside:avoid;background:#fff;box-shadow:0 2px 8px rgba(0,0,0,.05)}
  .cat-card-photo{width:100%;height:280px;background:#f9fafb;display:flex;align-items:center;justify-content:center;overflow:hidden;border-bottom:1px solid #f1f5f9}
  .cat-card-photo img{width:100%;height:100%;object-fit:contain;display:block}
  .cat-card-body{padding:13px 15px 14px}
  .cat-card-name{font-size:13.5px;font-weight:800;color:#0f172a;letter-spacing:-.2px;margin-bottom:3px;line-height:1.3}
  .cat-card-meta{font-size:10px;color:#94a3b8;margin-bottom:8px;line-height:1.5}
  .cat-card-desc{font-size:10.5px;color:#475569;line-height:1.55;margin-bottom:10px}
  .cat-card-prices{display:flex;gap:10px;flex-wrap:wrap;align-items:baseline;border-top:1px solid #f1f5f9;padding-top:9px;margin-top:4px}
  .cat-price-sale{font-size:15px;font-weight:900;color:${p};font-family:'JetBrains Mono',monospace;letter-spacing:-.5px}
  .cat-price-rent{font-size:11px;font-weight:600;color:#059669;font-family:'JetBrains Mono',monospace}
  .cat-price-label{font-size:8.5px;font-weight:600;text-transform:uppercase;letter-spacing:.6px;color:#94a3b8;align-self:flex-end;margin-left:1px}
  .cat-avail-badge{display:inline-block;background:#dcfce7;color:#166534;font-size:8px;font-weight:700;padding:2px 7px;border-radius:10px;letter-spacing:.4px;text-transform:uppercase}
  @media print{
    .no-print,button{display:none!important}
    body{margin:0}
    .cat-body{padding-bottom:56px}
    .cat-page-footer{position:fixed;bottom:0;left:0;right:0;-webkit-print-color-adjust:exact;print-color-adjust:exact}
    .cat-card{page-break-inside:avoid;break-inside:avoid}
    .cat-cover{page-break-after:always;break-after:page;-webkit-print-color-adjust:exact;print-color-adjust:exact}
    @page{margin:14mm 14mm 22mm 14mm}
  }
</style>

<div class="cat-page-footer">
  <div>
    <div class="cat-page-footer-biz">${_esc(BIZ.name||'')}</div>
    ${BIZ.address?`<div>${_esc(BIZ.address)}</div>`:''}
  </div>
  <div style="text-align:center;flex:1">
    ${footerContact?`<div>${_esc(footerContact)}</div>`:''}
    ${footerSocials?`<div style="margin-top:2px">${_esc(footerSocials)}</div>`:''}
  </div>
  <div style="text-align:right">
    <div style="color:${p};font-weight:700;font-size:8px;letter-spacing:.5px;text-transform:uppercase">All prices in ${CUR.code||'XAF'}</div>
    <div style="margin-top:1px;color:#94a3b8">Prices subject to change</div>
  </div>
</div>

<div class="cat-body">
  <div class="cat-cover">
    <div style="position:relative;z-index:1">
      ${BIZ.logoDataUrl
        ? `<div style="background:rgba(255,255,255,.2);border-radius:12px;padding:10px 14px;display:inline-block;margin-bottom:20px"><img src="${BIZ.logoDataUrl}" style="height:44px;width:auto;object-fit:contain;display:block"/></div>`
        : ''}
      <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:2.5px;opacity:.75;margin-bottom:8px">Service Catalog</div>
      <div style="font-size:34px;font-weight:900;letter-spacing:-1.2px;line-height:1.1;margin-bottom:10px;font-family:'Plus Jakarta Sans',sans-serif">${_esc(catName)}</div>
      ${tagline?`<div style="font-size:13px;opacity:.82;max-width:360px;line-height:1.5;font-weight:400">${_esc(tagline)}</div>`:''}
    </div>
    <div style="position:relative;z-index:1;text-align:right;flex-shrink:0;align-self:flex-start;padding-top:4px">
      <div style="font-size:13px;font-weight:700;opacity:.8;margin-bottom:6px">${_esc(BIZ.name||'')}</div>
      <div style="font-size:11px;opacity:.65;line-height:1.8">${[BIZ.phone,BIZ.email].filter(Boolean).join('<br/>')}</div>
      <div style="margin-top:12px;background:rgba(255,255,255,.15);border-radius:20px;padding:4px 12px;display:inline-block;font-size:10px;font-weight:600">${totalCount} Item${totalCount!==1?'s':''}</div>
    </div>
  </div>
  ${svcSections}
  ${invSections}
</div>`;
  openDoc(_esc(catName), html);
}

// ============================================================
// SETTINGS — BUSINESS PROFILE WITH LOGO UPLOAD
