function handleImportUpload(input){
  if(!input.files || !input.files[0]) return;
  if(!_importProfileReady()){
    // Reset the file input so the gate fires again next attempt
    input.value = '';
    const lbl = document.getElementById('import-file-name');
    if(lbl) lbl.textContent = 'Choose .xlsx File';
    return;
  }
  const file = input.files[0];
  if(!file.name.match(/\.(xlsx|xls)$/i)){ toast('Please upload an Excel file (.xlsx or .xls)','error'); return; }

  // Update file label
  const fileNameEl = document.getElementById('import-file-name');
  if(fileNameEl) fileNameEl.textContent = '✓ ' + file.name;

  const progress = document.getElementById('import-progress');
  const bar      = document.getElementById('import-bar');
  const result   = document.getElementById('import-result');
  if(progress) { progress.style.display = 'block'; progress.scrollIntoView({behavior:'smooth',block:'nearest'}); }
  if(result)   result.style.display   = 'none';
  if(bar)      bar.style.width = '5%';

  _loadSheetJS(()=>{
    const reader = new FileReader();
    reader.onload = function(e){
      try{
        if(bar) bar.style.width = '25%';
        const data = new Uint8Array(e.target.result);
        const wb   = XLSX.read(data, {type:'array', cellDates:true});
        const log  = [];
        let imported = 0;

        const str  = v => (v===null||v===undefined)?'':String(v).trim();
        const num  = v => { const n=parseFloat(str(v)); return isNaN(n)?0:n; };
        const int_ = v => { const n=parseInt(str(v)); return isNaN(n)?0:n; };
        const dateStr = v => {
          if(!v) return '';
          if(v instanceof Date) return v.toISOString().slice(0,10);
          const s=str(v);
          if(/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0,10);
          const d=new Date(s); return isNaN(d)?s:d.toISOString().slice(0,10);
        };
        const sheetObjs = name => {
          const ws=wb.Sheets[name]; if(!ws) return null;
          return XLSX.utils.sheet_to_json(ws,{defval:'',raw:false});
        };

        // ── Business Info ──────────────────────────────────
        if(bar) bar.style.width = '30%';
        const bizWs = wb.Sheets['Business Info'];
        if(bizWs){
          const rows = XLSX.utils.sheet_to_json(bizWs,{header:1,defval:'',raw:false});
          const m = {};
          rows.forEach(r=>{ if(r[0]&&r[1]) m[str(r[0])]=str(r[1]); });
          const bname = m['Business Name']||'';
          if(bname && bname!=='My Business Name' && bname!==BIZ.name){
            if(m['Business Name']) BIZ.name     = m['Business Name'];
            if(m['Tagline'])       BIZ.tagline  = m['Tagline'];
            if(m['Email'])         BIZ.email    = m['Email'];
            if(m['Phone'])         BIZ.phone    = m['Phone'];
            if(m['WhatsApp'])      BIZ.whatsapp = m['WhatsApp'];
            if(m['Website'])       BIZ.website  = m['Website'];
            if(m['Address'])       BIZ.address  = m['Address'];
            if(m['Instagram'])     BIZ.instagram= m['Instagram'];
            if(m['Facebook'])      BIZ.facebook = m['Facebook'];
            if(m['TikTok'])        BIZ.tiktok   = m['TikTok'];
            if(m['Twitter / X'])   BIZ.twitter  = m['Twitter / X'];
            if(m['Currency'] && m['Currency']!==CUR.code) setCurrency(m['Currency']);
            log.push({sheet:'Business Info',status:'success',count:1,msg:'Business profile updated'});
            imported++;
          } else {
            log.push({sheet:'Business Info',status:'skip',count:0,msg:'No changes detected (example data or matches current profile)'});
          }
        } else {
          log.push({sheet:'Business Info',status:'skip',count:0,msg:'Sheet not found'});
        }

        // ── Inventory ──────────────────────────────────────
        if(bar) bar.style.width = '45%';
        const invRows = sheetObjs('Inventory');
        if(invRows && invRows.length){
          const valid = invRows.filter(r=>str(r['Name *']||r['Name']));
          const rate  = CUR.rate||615;
          valid.forEach((r,i)=>{
            const _idTs=Date.now(); const id = str(r['SKU *']||r['SKU'])||('IMP-'+_idTs+'-'+i+'-'+Math.random().toString(36).slice(2,5));
            const sp_  = num(r['Selling_Price *']||r['Selling Price']||r['Sale Price']||0)/rate;
            const cost_= num(r['Cost_Price']||r['Cost Price']||r['Cost']||0)/rate;
            const rp_  = num(r['Rental_Price_Day']||r['Rental Price']||0)/rate;
            const minSp= num(r['Min_Sell_Price']||r['Min Sell Price']||0)/rate;
            const rawSt= str(r['Status *']||r['Status']||'For Sale');
            // Normalise status to app values
            const stMap={'for sale':'For Sale','forsale':'For Sale','sale':'For Sale',
                         'for rent':'For Rent','forrent':'For Rent','rent':'For Rent',
                         'both':'Both','archived':'Archived','active':'For Sale'};
            const st = stMap[rawSt.toLowerCase().replace(/\s+/g,'')] || rawSt || 'For Sale';
            D.inv.push({
              id, sku:str(r['SKU *']||r['SKU']||id),
              name:str(r['Name *']||r['Name']),
              cat:str(r['Category']||'General'),
              brand:str(r['Brand']||''),
              st, cond:str(r['Condition']||'Good'),
              sp:sp_, cost:cost_, rp:rp_, minSp,
              minStock:int_(r['Min_Stock_Level']||r['Min Stock Level']||r['Min Stock']||0),
              qty:int_(r['Qty *']||r['Qty']||r['Stock Qty']||1),
              color:str(r['Color']||''), sz:str(r['Size']||''),
              desc:str(r['Description']||''),
              rented:0, img:'gown-aline', imgC:['#a8b4c8','#c8b4a0','#e0d4bc']
            });
          });
          if(valid.length){ log.push({sheet:'Inventory',status:'success',count:valid.length,msg:valid.length+' items imported'}); imported+=valid.length; }
          else log.push({sheet:'Inventory',status:'skip',count:0,msg:'No rows with a Name found'});
        } else {
          log.push({sheet:'Inventory',status:'skip',count:0,msg:'Sheet not found'});
        }

        // ── Customers ──────────────────────────────────────
        if(bar) bar.style.width = '58%';
        const custRows = sheetObjs('Customers');
        if(custRows && custRows.length){
          const valid = custRows.filter(r=>str(r['Full Name *']||r['Full Name']));
          valid.forEach((r,i)=>{
            const _cts=Date.now(); const id='C-IMP-'+_cts+'-'+i+'-'+Math.random().toString(36).slice(2,5);
            D.cust.push({
              id, name:str(r['Full Name *']||r['Full Name']),
              email:str(r['Email']||''), phone:str(r['Phone']||''),
              whatsapp:str(r['WhatsApp']||r['Whatsapp']||''),
              address:str(r['Address']||''), city:str(r['City']||''),
              vip:(str(r['VIP']||r['VIP (Yes/No)']).toLowerCase()==='yes'),
              notes:str(r['Notes']||''), spent:0, st:'Active', orders:0
            });
    _dbSaveCust(D.cust[0]);
          });
          if(valid.length){ log.push({sheet:'Customers',status:'success',count:valid.length,msg:valid.length+' customers imported'}); imported+=valid.length; }
          else log.push({sheet:'Customers',status:'skip',count:0,msg:'No rows with a Full Name found'});
        } else {
          log.push({sheet:'Customers',status:'skip',count:0,msg:'Sheet not found'});
        }

        // ── Vendors ────────────────────────────────────────
        if(bar) bar.style.width = '68%';
        const vendRows = sheetObjs('Vendors');
        if(vendRows && vendRows.length){
          const valid = vendRows.filter(r=>str(r['Vendor Name *']||r['Vendor Name']));
          valid.forEach((r,i)=>{
            D.vendors.push({
              id:'V-IMP-'+Date.now()+'-'+i+'-'+Math.random().toString(36).slice(2,5),
              name:str(r['Vendor Name *']||r['Vendor Name']),
              contact:str(r['Contact Person']||''),
              email:str(r['Email']||''), phone:str(r['Phone']||''),
              country:str(r['Country']||''),
              cat:str(r['Category']||'General'),
              terms:str(r['Payment Terms']||''),
              notes:str(r['Notes']||''),
              st:'Active', bal:0
            });
  _dbSaveVendor(D.vendors[D.vendors.length-1]);
          });
          if(valid.length){ log.push({sheet:'Vendors',status:'success',count:valid.length,msg:valid.length+' vendors imported'}); imported+=valid.length; }
          else log.push({sheet:'Vendors',status:'skip',count:0,msg:'No rows with a Vendor Name found'});
        } else {
          log.push({sheet:'Vendors',status:'skip',count:0,msg:'Sheet not found'});
        }

        // ── Sales ──────────────────────────────────────────
        if(bar) bar.style.width = '78%';
        const salesRows = sheetObjs('Sales');
        if(salesRows && salesRows.length){
          const rate = CUR.rate||615;
          const valid = salesRows.filter(r=>str(r['Amount *']||r['Amount']||r['Total Amount']));
          valid.forEach((r,i)=>{
            const num2=String(D.sales.length+i+1).padStart(4,'0');
            const rawAmt = num(r['Amount *']||r['Amount']||r['Total Amount']||0);
            const rawPaid= num(r['Amount_Paid']||r['Amount Paid']||r['Paid']||0);
            D.sales.unshift({
              id:'S-IMP-'+Date.now()+'-'+i+'-'+Math.random().toString(36).slice(2,5),
              dt:dateStr(r['Date (YYYY-MM-DD) *']||r['Date (YYYY-MM-DD)']||r['Date']||''),
              cust:str(r['Customer Name *']||r['Customer Name']||r['Customer']||'Walk-in'),
              items:str(r['Items Description']||r['Item Name']||r['Items']||'Imported'),
              amt:rawAmt/rate, paid:rawPaid/rate,
              profit:num(r['Profit']||0)/rate,
              st:str(r['Status *']||r['Status']||r['Payment Status']||'Paid'),
              method:str(r['Payment Method']||r['Method']||'Cash'),
              notes:str(r['Notes']||'')
            });
          });
          if(valid.length){ log.push({sheet:'Sales',status:'success',count:valid.length,msg:valid.length+' sales imported'}); imported+=valid.length; }
          else log.push({sheet:'Sales',status:'skip',count:0,msg:'No rows with an Amount found'});
        } else {
          log.push({sheet:'Sales',status:'skip',count:0,msg:'Sheet not found'});
        }

        // ── Expenses ───────────────────────────────────────
        if(bar) bar.style.width = '82%';
        const purchRows = sheetObjs('Purchases');
        if(purchRows && purchRows.length){
          const rate = CUR.rate||615;
          const valid = purchRows.filter(r=>str(r['Vendor Name *']||r['Vendor Name']||r['Vendor']));
          const _pts = Date.now();
          valid.forEach((r,i)=>{
            const sub_  = num(r['Subtotal']||r['Sub Total']||0)/rate;
            const fr_   = num(r['Freight']||r['Shipping']||0)/rate;
            const dut_  = num(r['Duties']||r['Import Duties']||0)/rate;
            const tot_  = num(r['Total']||r['Total Amount']||0)/rate || (sub_+fr_+dut_);
            D.purchases.unshift({
              id:'P-IMP-'+_pts+'-'+i+'-'+Math.random().toString(36).slice(2,5),
              dt:dateStr(r['Date (YYYY-MM-DD)']||r['Date']||''),
              vendor:str(r['Vendor Name *']||r['Vendor Name']||r['Vendor']||''),
              items:str(r['Items Description']||r['Items']||''),
              sub:sub_, freight:fr_, duties:dut_, total:tot_,
              st:str(r['Status']||r['Payment Status']||'Pending'),
              notes:str(r['Notes']||'')
            });
          });
          if(valid.length){ log.push({sheet:'Purchases',status:'success',count:valid.length,msg:valid.length+' purchase orders imported'}); imported+=valid.length; }
          else log.push({sheet:'Purchases',status:'skip',count:0,msg:'No rows with a Vendor Name found'});
        } else {
          log.push({sheet:'Purchases',status:'skip',count:0,msg:'Sheet not found'});
        }

        if(bar) bar.style.width = '90%';
        const expRows = sheetObjs('Expenses');
        if(expRows && expRows.length){
          const rate = CUR.rate||615;
          const valid = expRows.filter(r=>str(r['Amount *']||r['Amount']));
          valid.forEach((r,i)=>{
            const num2=String(D.exp.length+i+1).padStart(3,'0');
            D.exp.unshift({
              id:'EX-IMP-'+Date.now()+'-'+i+'-'+Math.random().toString(36).slice(2,5),
              dt:dateStr(r['Date (YYYY-MM-DD) *']||r['Date (YYYY-MM-DD)']||r['Date']||''),
              cat:str(r['Category *']||r['Category']||'Other'),
              payee:str(r['Payee']||r['Vendor / Payee']||r['Vendor']||''),
              amt:num(r['Amount *']||r['Amount']||0)/rate,
              type:str(r['Type']||'One-time'),
              method:str(r['Payment_Method']||r['Payment Method']||r['Paid By']||'Cash'),
              notes:str(r['Notes']||''), st:'Paid'
            });
          });
          if(valid.length){ log.push({sheet:'Expenses',status:'success',count:valid.length,msg:valid.length+' expenses imported'}); imported+=valid.length; }
          else log.push({sheet:'Expenses',status:'skip',count:0,msg:'No rows with an Amount found'});
        } else {
          log.push({sheet:'Expenses',status:'skip',count:0,msg:'Sheet not found'});
        }

        if(bar) bar.style.width = '100%';

        // ── Render results ─────────────────────────────────
        if(imported>0){
          // Bulk save imported data to Supabase
          if(_sb && SESSION.bizId && SESSION.bizId!=='BIZ-001'){
            // Each entity type tracks its own count; save only the newly added slice
            if(invRows&&invRows.length){
              const _invAdded=invRows.filter(r=>str(r['Name *']||r['Name'])).length;
              D.inv.slice(-_invAdded).forEach(item=>_dbSaveInv(item));
            }
            if(custRows&&custRows.length){
              const _custAdded=custRows.filter(r=>str(r['Full Name *']||r['Full Name'])).length;
              D.cust.slice(-_custAdded).forEach(c=>_dbSaveCust(c));
            }
            if(vendRows&&vendRows.length){
              const _vendAdded=vendRows.filter(r=>str(r['Vendor Name *']||r['Vendor Name'])).length;
              D.vendors.slice(-_vendAdded).forEach(v=>_dbSaveVendor(v));
            }
            if(purchRows&&purchRows.length){
              const _purchAdded=purchRows.filter(r=>str(r['Vendor Name *']||r['Vendor Name']||r['Vendor'])).length;
              D.purchases.slice(0,_purchAdded).forEach(p=>_dbSavePurchase(p));
            }
            if(salesRows&&salesRows.length){
              const _salesAdded=salesRows.filter(r=>str(r['Amount *']||r['Amount']||r['Total Amount'])).length;
              D.sales.slice(0,_salesAdded).forEach(s=>_dbSaveSale(s));
            }
            if(expRows&&expRows.length){
              const _expAdded=expRows.filter(r=>str(r['Amount *']||r['Amount'])).length;
              D.exp.slice(0,_expAdded).forEach(e=>_dbSaveExp(e));
            }
          }
        }
        if(imported>0) addAudit('Excel import', imported+' total records across '+log.filter(l=>l.status==='success').length+' sheets');
        if(imported>0) refreshLiveKpis();

        setTimeout(()=>{
          if(progress) progress.style.display = 'none';
          if(result)   result.style.display   = 'block';
          const icon = s => s==='success'
            ? '<span style="color:var(--g);font-size:14px">✅</span>'
            : '<span style="color:var(--text2);font-size:14px">—</span>';
          result.innerHTML = `
          <div class="alrt ${imported>0?'alrt-g':'alrt-y'}" style="margin-bottom:14px">
            ${imported>0?'✅':'⚠'} <strong>${imported>0
              ? 'Import complete — '+imported+' records imported successfully.'
              : 'Nothing was imported.'}</strong><br>
            <span style="font-size:12px">${imported>0
              ? 'Your data is now live. Review each section and adjust where needed.'
              : 'Please check your file uses the ShopTrack template format.'}</span>
          </div>
          <div style="border:1px solid var(--border);border-radius:var(--r8);overflow:hidden">
            <div style="display:grid;grid-template-columns:150px 1fr 70px;font-size:11px;font-weight:700;color:var(--text2);padding:9px 16px;background:var(--bg3);text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid var(--border)">
              <span>Sheet</span><span>Result</span><span style="text-align:right">Records</span>
            </div>
            ${log.map(l=>`<div style="display:grid;grid-template-columns:150px 1fr 70px;padding:10px 16px;border-bottom:1px solid var(--border);font-size:12px;align-items:center">
              <span style="font-weight:600;color:var(--ink)">${l.sheet}</span>
              <span style="color:${l.status==='success'?'var(--text)':'var(--text3)'}">${icon(l.status)} ${l.msg}</span>
              <span style="text-align:right;font-family:var(--mono);font-weight:700;color:${l.status==='success'?'var(--g)':'var(--text3)'}">${l.count>0?l.count:'—'}</span>
            </div>`).join('')}
          </div>
          ${imported>0?`<div class="btn-row" style="margin-top:16px">
            <button class="btn btn-p" onclick="nav('dashboard')">🏠 Go to Dashboard</button>
            <button class="btn btn-s btn-sm" onclick="nav('inventory')">📦 Inventory</button>
            <button class="btn btn-s btn-sm" onclick="nav('customers')">👥 Customers</button>
            <button class="btn btn-s btn-sm" onclick="nav('sales')">🛒 Sales</button>
          </div>`:''}
          `;
        }, 500);
      } catch(err){
        if(progress) progress.style.display='none';
        if(result){ result.style.display='block'; result.innerHTML='<div class="alrt alrt-r">❌ <strong>Error reading file:</strong> '+err.message+'.<br><span style="font-size:12px">Make sure you\'re using the ShopTrack template and the file is not open in Excel.</span></div>'; }
        console.error('Import error:',err);
      }
    };
    reader.readAsArrayBuffer(file);
  });
}

function handleLogoUpload(input){
  if(!input.files || !input.files[0]) return;
  const reader = new FileReader();
  reader.onload = e => {
    BIZ.logoDataUrl = e.target.result;
    const prev = document.getElementById('logo-preview');
    if(prev) prev.innerHTML = `<img loading="lazy" src="${BIZ.logoDataUrl}" style="width:100%;height:100%;object-fit:cover"/>`;
    toast('Logo uploaded successfully','success');
    // Refresh settings page to show remove button
    nav(curPage);
  };
  reader.readAsDataURL(input.files[0]);
}

function saveBizProfile(){
  BIZ.name      = document.getElementById('biz-name')?.value      || BIZ.name;
  BIZ.tagline   = document.getElementById('biz-tagline')?.value   || BIZ.tagline;
  BIZ.email     = document.getElementById('biz-email')?.value     || BIZ.email;
  BIZ.phone     = document.getElementById('biz-phone')?.value     || BIZ.phone;
  BIZ.whatsapp  = document.getElementById('biz-whatsapp')?.value  || BIZ.whatsapp;
  BIZ.address   = document.getElementById('biz-address')?.value   || BIZ.address;
  BIZ.website   = document.getElementById('biz-website')?.value   || BIZ.website;
  BIZ.instagram = document.getElementById('biz-instagram')?.value || BIZ.instagram;
  BIZ.facebook  = document.getElementById('biz-facebook')?.value  || BIZ.facebook;
  BIZ.tiktok    = document.getElementById('biz-tiktok')?.value    || BIZ.tiktok;
  BIZ.twitter   = document.getElementById('biz-twitter')?.value   || BIZ.twitter;
  BIZ.primaryColor = document.getElementById('biz-primary')?.value || BIZ.primaryColor;
  BIZ.accentColor  = document.getElementById('biz-accent')?.value  || BIZ.accentColor;
  // Country — auto-set currency when country changes
  var newCountry = document.getElementById('biz-country')?.value || BIZ.country;
  if(newCountry !== BIZ.country){
    BIZ.country = newCountry;
    var autoCur = COUNTRY_CURRENCY[newCountry];
    if(autoCur && autoCur !== CUR.code){
      var flagMap3 = {XAF:'🇨🇲',NGN:'🇳🇬',GHS:'🇬🇭',USD:'🇺🇸',GBP:'🇬🇧',EUR:'🇪🇺'};
      setCurrency(autoCur, flagMap3[autoCur]||'');
      toast('Currency auto-set to '+autoCur+' for '+newCountry,'info');
    }
    // Auto-fill tax defaults for the new country
    var taxDef = COUNTRY_TAX_DEFAULTS[newCountry];
    if(taxDef){
      BIZ.taxRate = taxDef.rate;
      BIZ.taxName = taxDef.name;
    }
  } else {
    BIZ.country = newCountry;
  }
  // Language
  var newLang = document.getElementById('biz-language')?.value || BIZ.language;
  if(newLang !== BIZ.language){
    BIZ.language = newLang;
    _applyLanguage(newLang);
  }
  BIZ.aiKey = document.getElementById('biz-ai-key')?.value !== undefined
    ? document.getElementById('biz-ai-key').value
    : BIZ.aiKey;
  addAudit('Business profile updated', BIZ.name+' — profile saved');
  _dbSaveBizProfile(SESSION.bizId);
  _showSaved();
  toast('Business profile saved ✓','success');
}

