function saveEditRental(id){
  const r=D.rentals.find(x=>x.id===id);if(!r)return;
  const custSel=document.getElementById('er-cust');
  if(custSel&&custSel.value){
    r.custId=custSel.value;
    const custObj=D.cust.find(c=>c.id===custSel.value);
    if(custObj) r.cust=custObj.name;
  }
  const start=document.getElementById('er-start')?.value; if(start) r.start=start;
  const due=document.getElementById('er-due')?.value; if(due) r.due=due;
  var rER=CUR.rate;
  const fee=document.getElementById('er-fee')?.value; if(fee!==undefined&&fee!=='') r.fee=(parseFloat(fee)||0)/rER;
  const dep=document.getElementById('er-dep')?.value; if(dep!==undefined&&dep!=='') r.dep=(parseFloat(dep)||0)/rER;
  const paid=document.getElementById('er-paid')?.value; if(paid!==undefined&&paid!=='') r.paid=(parseFloat(paid)||0)/rER;
  const lf=document.getElementById('er-lf')?.value; if(lf!==undefined&&lf!=='') r.lf=(parseFloat(lf)||0)/rER;
  const st=document.getElementById('er-st')?.value; if(st) r.st=st;
  const notes=document.getElementById('er-notes')?.value; if(notes!==undefined) r.notes=notes;
  if(typeof r.paid==='undefined') r.paid=0;
  addAudit('Rental edited',id+' — '+r.cust);
  _dbSaveRental(D.rentals.find(x=>x.id===id));
  refreshLiveKpis();
  closeModal();toast('Rental updated','success');nav('rentals');
}
function _updateReturnSettlement(rid){
  const r=D.rentals.find(x=>x.id===rid); if(!r) return;
  const dmg=(parseFloat(document.getElementById('ret-dmg-'+rid)?.value)||0)/CUR.rate;
  const unpaidFee=Math.max(0,(r.fee||0)-(r.paid||0));
  const refund=Math.max(0,(r.dep||0)-(r.lf||0)-dmg-unpaidFee);
  const dmgDisplay=document.getElementById('ret-dmg-display-'+rid);
  const refDisplay=document.getElementById('ret-refund-display-'+rid);
  if(dmgDisplay) dmgDisplay.textContent='− '+fmt(dmg);
  if(refDisplay){
    refDisplay.textContent=fmt(refund);
    refDisplay.style.color=refund>0?'var(--g)':refund===0?'var(--text2)':'var(--r)';
  }
}

function mDuplicateRental(id){
  if(!requireRight('edit_rentals','Duplicate Rental')) return;
  const src=D.rentals.find(x=>x.id===id);if(!src)return;
  const maxNum=D.rentals.reduce(function(m,r){
    var n=parseInt((r.id||'').replace(/\D/g,''),10)||0; return n>m?n:m;
  },0);
  const newId='R-'+String(maxNum+1).padStart(4,'0');
  D.rentals.unshift({...src,id:newId,st:'Reserved',lf:0,paid:0,refund:0,returnDate:null,contractSigned:false,docs:[]});
  _dbSaveRental(D.rentals[0]);
  addAudit('Rental duplicated', newId+' from '+id+' — '+src.item);
  toast('Rental duplicated — edit to adjust','success');nav('rentals');
  setTimeout(()=>mEditRental(newId),200);
}

// ============================================================
// PERIOD FILTERS — fully data-driven
// ============================================================

// Each period: [startDate, endDate] in YYYY-MM-DD  (null = no cutoff)
function buildPeriodRanges(){
  const now   = new Date();
  const pad   = n=>String(n).padStart(2,'0');
  const ymd   = d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
  const months= ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const days  = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];

  const todayStr = ymd(now);
  const y=now.getFullYear(), m=now.getMonth(), d=now.getDate();

  // Start of current week (Monday)
  const dow = now.getDay(); // 0=Sun
  const weekStart = new Date(now); weekStart.setDate(d - ((dow+6)%7));
  const weekEnd   = new Date(weekStart); weekEnd.setDate(weekStart.getDate()+6);

  // Month bounds
  const monthStart = `${y}-${pad(m+1)}-01`;
  const monthEnd   = ymd(new Date(y, m+1, 0));

  // Quarter
  const qStart = new Date(y, Math.floor(m/3)*3, 1);
  const qEnd   = new Date(y, Math.floor(m/3)*3+3, 0);
  const qNum   = Math.floor(m/3)+1;

  // Format helpers
  const fmtDate = dt=>{
    const mo=months[dt.getMonth()].substring(0,3);
    return `${mo} ${dt.getDate()}, ${dt.getFullYear()}`;
  };
  const fmtShort = dt=>`${months[dt.getMonth()].substring(0,3)} ${dt.getDate()}`;

  // Last week: previous Mon–Sun
  const lastWeekEnd   = new Date(weekStart); lastWeekEnd.setDate(weekStart.getDate()-1);
  const lastWeekStart = new Date(lastWeekEnd); lastWeekStart.setDate(lastWeekEnd.getDate()-6);
  // Week end: extend to today if today is past weekEnd (handles partial weeks & timezone)
  const weekEndAdj = new Date(weekEnd);
  if(now > weekEndAdj) weekEndAdj.setDate(now.getDate()+1);
  const weekEndStr = ymd(weekEndAdj) >= todayStr ? ymd(weekEndAdj) : todayStr;
  // Last month
  const lastMonthDate  = new Date(y, m, 0);
  const lastMonthStart = `${lastMonthDate.getFullYear()}-${pad(lastMonthDate.getMonth()+1)}-01`;
  const lastMonthEnd   = ymd(lastMonthDate);
  const lastMonthName  = months[lastMonthDate.getMonth()];
  const yesterdayDate = new Date(now); yesterdayDate.setDate(d-1);
  const yesterdayStr  = ymd(yesterdayDate);
  return {
    today:     {start:todayStr, end:todayStr, label:`Today — ${fmtDate(now)}`},
    yesterday: {start:yesterdayStr, end:yesterdayStr, label:`Yesterday — ${fmtDate(yesterdayDate)}`},
    week:      {start:ymd(weekStart), end:weekEndStr,
                label:`This Week — ${fmtShort(weekStart)}–${fmtShort(weekEnd)}, ${y}`},
    lastweek:  {start:ymd(lastWeekStart), end:ymd(lastWeekEnd),
                label:`Last Week — ${fmtShort(lastWeekStart)}–${fmtShort(lastWeekEnd)}, ${y}`},
    month:     {start:monthStart, end:monthEnd, label:`${months[m]} ${y}`},
    lastmonth: {start:lastMonthStart, end:lastMonthEnd, label:`${lastMonthName} ${lastMonthDate.getFullYear()}`},
    quarter:   {start:ymd(qStart), end:ymd(qEnd), label:`Q${qNum} ${y}`},
    ytd:       {start:`${y}-01-01`, end:`${y}-12-31`, label:`Year to Date ${y}`},
    custom:    {start:monthStart, end:todayStr, label:'Custom Range'},
  };
}
// ── Runtime: update newest mock sales dates to current week so demo always looks live
(function(){
  const ld=localDateStr;
  if(D.sales.length>0) D.sales[0].dt=ld(0);
  if(D.sales.length>1) D.sales[1].dt=ld(-1);
  if(D.sales.length>2) D.sales[2].dt=ld(-2);
  // Also update rentals newest
  if(D.rentals.length>0) D.rentals[0].start=ld(0);
  if(D.rentals.length>1) D.rentals[1].start=ld(-1);
})();

function inRange(dateStr, range){
  if(!range) return true;
  if(!dateStr) return false;
  var d = String(dateStr).trim();
  // Normalise DD/MM/YYYY → YYYY-MM-DD
  if(/^\d{2}\/\d{2}\/\d{4}$/.test(d)){ var p=d.split('/'); d=p[2]+'-'+p[1]+'-'+p[0]; }
  // Normalise DD-MM-YYYY → YYYY-MM-DD
  if(/^\d{2}-\d{2}-\d{4}$/.test(d)){ var p2=d.split('-'); d=p2[2]+'-'+p2[1]+'-'+p2[0]; }
  return d >= range.start && d <= range.end;
}

// Compute KPI block for a given period range from actual data
function computeKPIs(range){
  const sales    = D.sales.filter(s=>inRange(s.dt, range));
  // Only count rentals that have actually started (not merely Reserved)
  const rentals  = D.rentals.filter(r=>inRange(r.start, range));
  const expenses = D.exp.filter(e=>inRange(e.dt, range));

  // ── Revenue ──────────────────────────────────────────────────
  // Sales: use total (includes freight/tax), not amt (subtotal only)
  const saleRev  = sales.reduce((a,s)=>a+(s.total||s.amt||0), 0);
  // Rental revenue: only count fees on rentals that are active or completed
  // Reserved rentals have not yet been earned; Returned and Checked Out have.
  const earnedRentals = rentals.filter(r=>r.st==='Returned'||r.st==='Checked Out'||r.st==='Overdue');
  const rentRev  = earnedRentals.reduce((a,r)=>a+(r.fee||0), 0);
  // Appointments: only Completed
  const apptArr  = (D.appointments||[]).filter(a=>
    a.st==='Completed' && (a.totalAmt||0)>0 && inRange(a.date, range));
  const apptRev  = apptArr.reduce((a,ap)=>a+(ap.totalAmt||0), 0);
  const rev      = saleRev + rentRev + apptRev;

  // ── COGS ─────────────────────────────────────────────────────
  // Cost of goods for sales in the period. Rentals & services have no COGS here
  // (rental item cost is captured in inventory valuation; service cost is overhead).
  const cogs     = sales.reduce((a,s)=>a+(s.cost||0), 0);

  // ── Gross Profit ─────────────────────────────────────────────
  // GP = Revenue – COGS. Rental and service revenue flows straight to GP
  // because their direct costs are either in inventory or operating expenses.
  const gp       = rev - cogs;

  // ── Overhead ─────────────────────────────────────────────────
  // Exclude vendor payments that were recorded as expenses — those reduce AP,
  // not operating overhead (they are balance sheet movements, not P&L items).
  const oh       = expenses
    .filter(e => e.cat !== 'Vendor Payment')
    .reduce((a,e)=>a+e.amt, 0);

  // ── Net Profit ───────────────────────────────────────────────
  const np       = gp - oh;

  // ── Balance sheet snapshots (point-in-time, not period-filtered) ─
  // AR: recompute live from sales (total invoiced - total paid), never trust stale c.bal
  const _arMap = {};
  D.sales.forEach(function(s){
    const cid=s.custId||s.cust; if(!cid) return;
    _arMap[cid] = (_arMap[cid]||0) + ((s.total||s.amt||0)-(s.paid||0));
  });
  const ar = Object.values(_arMap).filter(v=>v>0.01).reduce((a,v)=>a+v,0);
  // AP: recompute live from unpaid purchases
  const _apMap = {};
  D.purchases.forEach(function(p){
    if(p.st==='Paid') return;
    const vid=p.vendorId||p.vendor; if(!vid) return;
    _apMap[vid] = (_apMap[vid]||0) + (p.total||0);
  });
  const ap = Object.values(_apMap).filter(v=>v>0.01).reduce((a,v)=>a+v,0);

  // ── Cash flow (cash basis) ────────────────────────────────────
  // Cash in = actual cash collected (paid amounts on sales) + rental fees received
  // + appointment revenue (appointments are cash at checkout)
  const saleCashIn  = sales.reduce((a,s)=>a+(s.paid||0), 0);
  const rentCashIn  = earnedRentals.reduce((a,r)=>a+(r.paid||r.fee||0), 0);
  const cashIn      = saleCashIn + rentCashIn + apptRev;
  // Cash out = expenses paid + purchases paid in the period
  const paidPurchases = D.purchases
    .filter(p=>p.st==='Paid' && inRange(p.dt, range))
    .reduce((a,p)=>a+(p.total||0), 0);
  const cashOut     = oh + paidPurchases;

  const invVal   = D.inv.reduce(function(a,i){return a+(i.cost||0)*(i.qty||0);},0);
  return {rev, saleRev, rentRev, apptRev, cogs, gp, np, oh,
          ar, ap, cashIn, saleCashIn, cashOut, invVal,
          sales, rentals: earnedRentals, allRentals: rentals, expenses};
}

