// ── AR Outstanding detail modal ───────────────────────────────
function mARDetail(){
  const debtors = D.cust.filter(c=>c.bal>0).sort((a,b)=>b.bal-a.bal);
  const total   = debtors.reduce((a,c)=>a+c.bal,0);
  if(!debtors.length){
    toast('No outstanding AR — all balances are clear ✓','success'); return;
  }
  // ── Aging buckets ─────────────────────────────────────────────────
  const today = localDateStr();
  function _arAgeDays(cust){
    // Find oldest unpaid sale for this customer
    const unpaid = D.sales.filter(s=>(s.custId===cust.id||s.cust===cust.name)&&s.st!=='Paid');
    if(!unpaid.length) return 0;
    const oldest = unpaid.sort((a,b)=>a.dt<b.dt?-1:1)[0];
    const diff = Math.floor((new Date(today)-new Date(oldest.dt))/(1000*60*60*24));
    return Math.max(0,diff);
  }
  const age0_30  = debtors.filter(c=>_arAgeDays(c)<=30).reduce((a,c)=>a+c.bal,0);
  const age31_60 = debtors.filter(c=>{const d=_arAgeDays(c);return d>30&&d<=60;}).reduce((a,c)=>a+c.bal,0);
  const age61_90 = debtors.filter(c=>{const d=_arAgeDays(c);return d>60&&d<=90;}).reduce((a,c)=>a+c.bal,0);
  const age90p   = debtors.filter(c=>_arAgeDays(c)>90).reduce((a,c)=>a+c.bal,0);
  const rows = debtors.map(c=>{
    const ageDays = _arAgeDays(c);
    const ageLabel = ageDays<=30?'<30d':ageDays<=60?'31-60d':ageDays<=90?'61-90d':'<span style="color:var(--r)">90d+</span>';
    const unpaidSales = D.sales.filter(s=>(s.custId===c.id||s.cust===c.name)&&s.st!=='Paid');
    const lastSale    = D.sales.filter(s=>s.custId===c.id||s.cust===c.name).sort((a,b)=>b.dt>a.dt?1:-1)[0];
    return `<tr>
      <td><strong style="color:var(--ink)">${_esc(c.name)}</strong>${c.vip?` <span style="font-size:9px;background:var(--p-dim);color:var(--p);padding:1px 5px;border-radius:8px">VIP</span>`:''}</td>
      <td style="font-size:11px;color:var(--text2)">${c.phone||c.whatsapp||'—'}</td>
      <td style="font-size:11px">${unpaidSales.length} unpaid invoice${unpaidSales.length!==1?'s':''}</td>
      <td style="font-size:11px;color:var(--text2)">${lastSale?lastSale.dt:'—'}</td>
      <td style="font-size:11px;white-space:nowrap">${ageLabel}</td>
      <td><span style="font-family:var(--mono);font-weight:700;color:var(--r)">${fmt(c.bal)}</span></td>
      <td>
        <div class="btn-row">
          ${c.phone||c.whatsapp?`<button class="btn btn-g btn-xs" onclick="_arSendWA('${c.id}')" title="Send WhatsApp reminder">💬 WA</button>`:''}
          <button class="btn btn-y btn-xs" onclick="_arWriteOff('${c.id}')" title="Write off balance">✕ Write Off</button>
        </div>
      </td>
    </tr>`;
  }).join('');

  modal('📋 Accounts Receivable',`
  <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;padding:10px 14px;background:var(--r-dim);border:1px solid rgba(255,96,128,.25);border-radius:var(--r8)">
    <div>
      <div style="font-size:11px;color:var(--text2);text-transform:uppercase;letter-spacing:.5px;margin-bottom:2px">Total AR Outstanding</div>
      <div style="font-size:22px;font-weight:800;font-family:var(--mono);color:var(--r)">${fmt(total)}</div>
    </div>
    <div style="display:flex;gap:6px">
      <button class="btn btn-g btn-sm" onclick="_arExportPDF()" title="Download branded AR PDF">⬇ PDF</button>
      <button class="btn btn-p btn-sm" onclick="closeModal();_arBulkCollect()">💰 Collect All</button>
      <button class="btn btn-d btn-sm" onclick="_arWriteOffAll()">✕ Write Off All</button>
    </div>
  </div>
  <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px">
    ${[['0–30 days',age0_30,'g'],['31–60 days',age31_60,'y'],['61–90 days',age61_90,'o'],['90+ days',age90p,'r']].map(([lbl,amt,col])=>`
    <div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--r8);padding:8px 10px;text-align:center">
      <div style="font-size:10px;color:var(--text2);margin-bottom:3px">${lbl}</div>
      <div style="font-size:13px;font-weight:700;font-family:var(--mono);color:var(--${col})">${fmt(amt)}</div>
    </div>`).join('')}
  </div>
  <div class="tbl-wrap"><table>
    <thead><tr><th>Customer</th><th>Phone</th><th>Invoices</th><th>Last Sale</th><th>Age</th><th>Balance</th><th>Actions</th></tr></thead>
    <tbody>${rows}</tbody>
  </table></div>
  <div style="font-size:11px;color:var(--text3);margin-top:10px">💡 Write Off removes the balance from AR without deleting the sale record. Use for bad debts or corrections.</div>`,
  `<button class="btn btn-s" onclick="closeModal()">Close</button>
   <button class="btn btn-g btn-sm" onclick="_arExportPDF()">⬇ Download PDF</button>
   <button class="btn btn-p btn-sm" onclick="closeModal();nav('customers')">View All Customers →</button>`,'lg');
}

