function addAudit(action, detail){
  const now = new Date();
  const ts  = now.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})
            + ' ' + now.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});
  if(!D.audit) D.audit = [];
  const entry = {
    id: 'AUD-'+Date.now()+'-'+Math.random().toString(36).slice(2,6),
    ts, action, detail,
    user: SESSION.name || 'System',
    role: SESSION.isSuperAdmin ? 'Super Admin' : (SESSION.level||'staff')
  };
  D.audit.unshift(entry);
  // Persist to Supabase (fire and forget)
  _dbSaveAudit(entry);
}

let _dashPeriod = 'month';
let _acctPeriod = 'month';

function refreshLiveKpis(){
  const range=PERIOD_RANGES[_dashPeriod]||PERIOD_RANGES.month;
  // Reconcile customer balances from live sales data before computing KPIs
  // This ensures AR is always in sync after payments are recorded in-session
  _reconcileCustomerTotals();
  // Reconcile vendor balances from purchases
  _reconcileVendorTotals();
  const k=computeKPIs(range);
  D.kpis.saleRev=k.saleRev;D.kpis.rentRev=k.rentRev;D.kpis.apptRev=k.apptRev||0;D.kpis.rev=k.rev;
  D.kpis.cogs=k.cogs;D.kpis.gp=k.gp;D.kpis.np=k.np;D.kpis.oh=k.oh;
  D.kpis.ar=k.ar;D.kpis.ap=k.ap;D.kpis.cashIn=k.cashIn;D.kpis.cashOut=k.cashOut;
  // Inventory value = cost × qty for all items (rented items still owned at cost)
  D.kpis.invVal=D.inv.reduce(function(a,i){return a+(i.cost||0)*(i.qty||0);},0);
  return k;
}

function setDashPeriod(el, period){
  _dashPeriod = period;
  document.querySelectorAll('#dash-period-tabs .dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  const range = PERIOD_RANGES[period];
  const lbl = document.getElementById('dash-period-label');
  if(lbl) lbl.textContent = range.label + ' — Business performance at a glance';
  const k = computeKPIs(range);

  // Update KPI tiles
  _setKpiVal('dash-kpi-rev',   fmtKpi(k.rev));
  _setKpiVal('dash-kpi-sale',  fmtKpi(k.saleRev));
  _setKpiVal('dash-kpi-rent',  fmtKpi(k.rentRev));
  _setKpiVal('dash-kpi-gp',    fmtKpi(k.gp));
  _setKpiVal('dash-kpi-np',    fmtKpi(k.np));
  _setKpiVal('dash-kpi-ar',    fmtKpi(k.ar));
  _setKpiVal('dash-kpi-ap',    fmtKpi(k.ap));
  _setKpiVal('dash-kpi-inv',   fmtKpi(k.invVal));

  // Sub-labels with transaction counts
  const salesCount  = k.sales.length;
  const rentCount   = k.rentals.length;
  const apptCount   = (D.appointments||[]).filter(a=>a.st==='Completed'&&inRange(a.date,range)).length;
  const totalTx     = salesCount + rentCount + apptCount;
  _setKpiSub('dash-kpi-rev-sub',  totalTx + ' transaction' + (totalTx!==1?'s':''));
  _setKpiSub('dash-kpi-sale-sub', salesCount + ' sale' + (salesCount!==1?'s':''));
  _setKpiSub('dash-kpi-rent-sub', rentCount + ' rental' + (rentCount!==1?'s':''));
  _setKpiSub('dash-kpi-appt-sub', apptCount + ' appointment' + (apptCount!==1?'s':''));
  _setKpiSub('dash-kpi-gp-sub',   k.rev>0 ? Math.round(k.gp/k.rev*100)+'% margin' : '');
  _setKpiSub('dash-kpi-np-sub',   k.rev>0 ? Math.round(k.np/k.rev*100)+'% margin' : '');
  _setKpiSub('dash-kpi-ar-sub',   D.cust.filter(c=>c.bal>0).length + ' customer' + (D.cust.filter(c=>c.bal>0).length!==1?'s':'')+' owe');
  _setKpiSub('dash-kpi-ap-sub',   D.vendors.filter(v=>v.bal>0).length + ' vendor' + (D.vendors.filter(v=>v.bal>0).length!==1?'s':'')+' to pay');
  _setKpiSub('dash-kpi-inv-sub',  D.inv.length + ' active item' + (D.inv.length!==1?'s':''));

  // Update charts with filtered data
  _updateDashCharts(k, period);

  // Rebuild Top Products for the selected period
  var topBody = document.getElementById('dash-top-products-body');
  if(topBody) topBody.innerHTML = _buildTopProducts(range);

  // Rebuild Recent Sales and Rentals for the period
  _updateDashRecentSales(k.sales);
  _updateDashRecentRentals(k.rentals);
}

function _setKpiVal(id, txt){
  const el = document.getElementById(id);
  if(el) el.innerHTML = txt;
}
function _setKpiSub(id, txt){
  const el = document.getElementById(id);
  if(el) el.textContent = txt;
}

function _updateDashCharts(k, period){
  destroyCharts();
  const r = CUR.rate;
  // Build bar data labels per period
  let labels, salesData, rentData;
  if(period==='today'){
    labels=['Morning','Afternoon','Evening'];
    salesData=[Math.round(k.saleRev*0.3*r),Math.round(k.saleRev*0.5*r),Math.round(k.saleRev*0.2*r)];
    rentData =[Math.round(k.rentRev*0.4*r),Math.round(k.rentRev*0.4*r),Math.round(k.rentRev*0.2*r)];
  } else if(period==='week'){
    const d=k.sales; const rn=k.rentals;
    // Build 7-day labels from real week range
    const wRange = PERIOD_RANGES.week;
    const wDays=[]; let wCur=new Date(wRange.start+'T00:00:00');
    const months3=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    for(let i=0;i<7;i++){
      wDays.push({label:`${months3[wCur.getMonth()]} ${wCur.getDate()}`, iso:wRange.start.substring(0,8)+String(wCur.getDate()).padStart(2,'0')});
      // Actually build proper iso from wCur
      wDays[i].iso = `${wCur.getFullYear()}-${String(wCur.getMonth()+1).padStart(2,'0')}-${String(wCur.getDate()).padStart(2,'0')}`;
      wCur.setDate(wCur.getDate()+1);
    }
    labels = wDays.map(x=>x.label);
    salesData = wDays.map(x=>Math.round(D.sales.filter(s=>s.dt===x.iso).reduce((a,s)=>a+s.amt,0)*r));
    rentData  = wDays.map(x=>Math.round(D.rentals.filter(rr=>rr.start===x.iso).reduce((a,rr)=>a+rr.fee,0)*r));
  } else if(period==='month'){
    labels=['Week 1','Week 2','Week 3','Week 4'];
    const ms=PERIOD_RANGES.month.start; // e.g. 2026-03-01
    const my=ms.substring(0,4); const mm=ms.substring(5,7);
    const w=i=>{const s=`${my}-${mm}-${String(i*7-6).padStart(2,'0')}`;const e=`${my}-${mm}-${String(Math.min(i*7,new Date(+my,+mm,0).getDate())).padStart(2,'0')}`;return{s,e};};
    salesData=[1,2,3,4].map(i=>{const{s,e}=w(i);return Math.round(D.sales.filter(x=>x.dt>=s&&x.dt<=e).reduce((a,s)=>a+s.amt,0)*r);});
    rentData =[1,2,3,4].map(i=>{const{s,e}=w(i);return Math.round(D.rentals.filter(x=>x.start>=s&&x.start<=e).reduce((a,rr)=>a+rr.fee,0)*r);});
  } else if(period==='quarter'){
    // Dynamic quarter: use last 4 months ending this month
    const months3=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const qLabels=[]; const qRanges=[];
    const now2=new Date(); const curM=now2.getMonth(); const curY=now2.getFullYear();
    for(let i=3;i>=0;i--){
      let mo=curM-i; let yr=curY;
      if(mo<0){mo+=12;yr--;}
      const pad=n=>String(n).padStart(2,'0');
      const s=`${yr}-${pad(mo+1)}-01`;
      const e=`${yr}-${pad(mo+1)}-${String(new Date(yr,mo+1,0).getDate()).padStart(2,'0')}`;
      qLabels.push(months3[mo]);
      qRanges.push({s,e});
    }
    labels=qLabels;
    salesData=qRanges.map(({s,e})=>Math.round(D.sales.filter(x=>x.dt>=s&&x.dt<=e).reduce((a,x)=>a+(x.total||x.amt||0),0)*r));
    rentData =qRanges.map(({s,e})=>Math.round(D.rentals.filter(x=>(x.st==='Returned'||x.st==='Checked Out'||x.st==='Overdue')&&x.start>=s&&x.start<=e).reduce((a,x)=>a+x.fee,0)*r));
  } else {
    // YTD: months from Jan to current month
    const months3=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const curM=new Date().getMonth(); const curY=new Date().getFullYear();
    const pad=n=>String(n).padStart(2,'0');
    labels=months3.slice(0,curM+1);
    salesData=labels.map((_,i)=>{
      const s=`${curY}-${pad(i+1)}-01`;const e=`${curY}-${pad(i+1)}-${String(new Date(curY,i+1,0).getDate()).padStart(2,'0')}`;
      return Math.round(D.sales.filter(x=>x.dt>=s&&x.dt<=e).reduce((a,x)=>a+(x.total||x.amt||0),0)*r);
    });
    rentData=labels.map((_,i)=>{
      const s=`${curY}-${pad(i+1)}-01`;const e=`${curY}-${pad(i+1)}-${String(new Date(curY,i+1,0).getDate()).padStart(2,'0')}`;
      return Math.round(D.rentals.filter(x=>(x.st==='Returned'||x.st==='Checked Out'||x.st==='Overdue')&&x.start>=s&&x.start<=e).reduce((a,x)=>a+x.fee,0)*r);
    });
  } // end YTD else

  // Theme-aware chart colors
  var _lt = document.body.classList.contains('light');
  var _tc = _lt ? '#374151' : '#c8cee8';
  var _gc = _lt ? 'rgba(0,0,0,.06)' : 'rgba(255,255,255,.06)';
  var _bg = _lt ? '#f5f6fa' : '#1a1d2b';

  const chartOpts = {responsive:true,maintainAspectRatio:false,
    plugins:{legend:{display:true,labels:{color:_tc,font:{size:10.5},boxWidth:10,padding:10}}},
    scales:{
      x:{ticks:{color:_tc,font:{size:11}},grid:{color:_gc}},
      y:{ticks:{color:_tc,font:{size:11},callback:v=>fmtRaw(v)},grid:{color:_gc}}
    }};

  mkChart('revChart',{type:'bar',data:{labels,datasets:[
    {label:'Sales',data:salesData,backgroundColor:'rgba(45,212,160,.75)',borderRadius:4,borderSkipped:false},
    {label:'Rentals',data:rentData,backgroundColor:'rgba(91,127,255,.75)',borderRadius:4,borderSkipped:false}
  ]},options:chartOpts});

  mkChart('donutChart',{type:'doughnut',
    data:{labels:['Net Profit','COGS','Overhead'],
      datasets:[{data:[Math.round(Math.max(0,k.np)*r),Math.round(k.cogs*r),Math.round(k.oh*r)],
        backgroundColor:['#2dd4a0','#ff5f7a','#f5c842'],borderWidth:0,hoverOffset:5}]},
    options:{responsive:true,maintainAspectRatio:false,
      plugins:{legend:{position:'bottom',labels:{color:_tc,font:{size:11},boxWidth:10,padding:10}}},
      cutout:'66%'}});
}

// ── ACCOUNTING PERIOD ─────────────────────────────────────────
function setAcctPeriod(el, period){
  _acctPeriod = period;
  // Scope to parent .dtabs only — avoids clearing other pages' tabs
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  const range = PERIOD_RANGES[period];
  const k = computeKPIs(range);
  const r = CUR.rate;

  // Update P&L rows
  const rows=[
    {id:'acct-sale-rev',  v:k.saleRev},
    {id:'acct-rent-rev',  v:k.rentRev},
    {id:'acct-appt-rev',  v:k.apptRev||0},
    {id:'acct-tot-rev',   v:k.rev},
    {id:'acct-cogs',      v:k.cogs},
    {id:'acct-gp',        v:k.gp},
    {id:'acct-gp-pct',    v:null, pct: k.rev>0?Math.round(k.gp/k.rev*100):0},
    {id:'acct-oh',        v:k.oh},
    {id:'acct-np',        v:k.np},
    {id:'acct-np-pct',    v:null, pct: k.rev>0?Math.round(k.np/k.rev*100):0},
  ];
  rows.forEach(row=>{
    const el2=document.getElementById(row.id);
    if(el2){
      if(row.pct!==undefined && row.v===null) el2.textContent=row.pct+'%';
      else el2.textContent=fmt(row.v);
    }
  });

  // Rebuild P&L chart
  destroyCharts();
  mkChart('plChart',{type:'bar',data:{
    labels:['Revenue','COGS','Gross Profit','Overhead','Net Profit'],
    datasets:[{data:[k.rev,k.cogs,k.gp,k.oh,Math.max(0,k.np)].map(v=>Math.round(v*r)),
      backgroundColor:['rgba(91,127,255,.7)','rgba(255,95,122,.7)','rgba(45,212,160,.7)','rgba(245,200,66,.7)','rgba(159,122,234,.7)'],borderRadius:5}]
  },options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},
    scales:{x:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11}},grid:{display:false}},
      y:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11},callback:v=>fmtRaw(v)},grid:{color:document.body.classList.contains('light')?'rgba(0,0,0,.07)':'rgba(255,255,255,.06)'}}}}});

  // Rebuild ledger for new period
  const ledgerEl = document.getElementById('ledger-container');
  if(ledgerEl && window._buildLedgerHTML) ledgerEl.innerHTML = window._buildLedgerHTML(range);

  // Update cash flow section
  const cashNetFlow = k.cashIn - k.cashOut;
  const cfColor = cashNetFlow >= 0 ? 'var(--g)' : 'var(--r)';
  const ciEl = document.getElementById('acct-cash-in');   if(ciEl) ciEl.textContent = fmt(k.cashIn);
  const coEl = document.getElementById('acct-cash-out');  if(coEl) coEl.textContent = fmt(k.cashOut);
  const ncEl = document.getElementById('acct-net-cash');
  if(ncEl){ ncEl.textContent = fmt(cashNetFlow); ncEl.style.color = cfColor; }

  // Update net profit color based on sign
  const npEl  = document.getElementById('acct-np');
  const nppEl = document.getElementById('acct-np-pct');
  const npColor = k.np >= 0 ? 'var(--g)' : 'var(--r)';
  if(npEl)  npEl.style.color  = npColor;
  if(nppEl) nppEl.style.color = npColor;

  // Update P&L period label
  const titleEl=document.getElementById('acct-pl-title');
  if(titleEl) titleEl.textContent='Profit & Loss — '+range.label;
}

// ── REPORTS PERIOD ────────────────────────────────────────────
function setReportPeriod(el, period){
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  // Keep _acctPeriod in sync so all report modal functions use the correct period
  if(period !== 'custom') _acctPeriod = period;
  if(period==='custom'){
    modal('Custom Date Range',`
    <div class="fg-2">
      <div class="fg"><label class="fl">Start Date</label><input class="fi" type="date" id="rpt-start" value="${PERIOD_RANGES.month.start}"/></div>
      <div class="fg"><label class="fl">End Date</label><input class="fi" type="date" id="rpt-end" value="${localDateStr()}"/></div>
    </div>`,
    `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
     <button class="btn btn-p" onclick="applyCustomReportRange()">Apply Range</button>`);
    return;
  }
  _applyReportPeriod(period, PERIOD_RANGES[period]);
  // _applyReportPeriod handles KPI update + chart rebuild
  _applyReportPeriod(period, PERIOD_RANGES[period]||PERIOD_RANGES.month);
}

function applyCustomReportRange(){
  const _nm=PERIOD_RANGES.month;
  const s=document.getElementById('rpt-start')?.value||_nm.start;
  const e=document.getElementById('rpt-end')?.value||_nm.end;
  closeModal();
  _applyReportPeriod('custom',{start:s,end:e,label:s+' → '+e});
}

// ── Build dynamic performance chart buckets from real data ─────────────────────
function _buildPerfBuckets(range, period){
  const pad = n=>String(n).padStart(2,'0');
  const ymd = d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
  const MONTH_SHORT = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const DAY_SHORT   = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

  // Determine bucket strategy
  const start = new Date(range.start + 'T00:00:00');
  const end   = new Date(range.end   + 'T00:00:00');
  const spanDays = Math.round((end - start) / 86400000) + 1;

  let buckets = []; // [{label, start, end}]

  if(period === 'today'){
    // Hourly stubs — since we don't have time data, show "Today" as one bar
    buckets = [{label:'Today', start:range.start, end:range.end}];
  } else if(spanDays <= 14){
    // Daily buckets
    for(let i=0; i<spanDays; i++){
      const d = new Date(start); d.setDate(start.getDate()+i);
      const ds = ymd(d);
      buckets.push({label:DAY_SHORT[d.getDay()]+' '+d.getDate(), start:ds, end:ds});
    }
  } else if(spanDays <= 92){
    // Weekly buckets (Mon–Sun)
    let cur = new Date(start);
    // Snap to Monday
    const dow = cur.getDay();
    cur.setDate(cur.getDate() - ((dow+6)%7));
    while(cur <= end){
      const ws = ymd(cur);
      const we_d = new Date(cur); we_d.setDate(cur.getDate()+6);
      const we = ymd(we_d);
      const clampS = ws < range.start ? range.start : ws;
      const clampE = we > range.end   ? range.end   : we;
      const mo = MONTH_SHORT[cur.getMonth()];
      buckets.push({label: mo+' '+cur.getDate(), start:clampS, end:clampE});
      cur.setDate(cur.getDate()+7);
    }
  } else {
    // Monthly buckets
    let curY = start.getFullYear(), curM = start.getMonth();
    const endY = end.getFullYear(),  endM = end.getMonth();
    while(curY < endY || (curY===endY && curM<=endM)){
      const ms = `${curY}-${pad(curM+1)}-01`;
      const me_d = new Date(curY, curM+1, 0);
      const me   = ymd(me_d);
      const clampS = ms < range.start ? range.start : ms;
      const clampE = me > range.end   ? range.end   : me;
      buckets.push({label: MONTH_SHORT[curM]+(curY!==start.getFullYear()||spanDays>366?' '+curY:''), start:clampS, end:clampE});
      curM++; if(curM>11){curM=0;curY++;}
    }
  }

  // Compute rev and np per bucket
  const labels=[], revData=[], npData=[];
  buckets.forEach(b=>{
    const bSales   = D.sales.filter(s=>s.dt>=b.start&&s.dt<=b.end);
    const bRentals = D.rentals.filter(r=>r.start>=b.start&&r.start<=b.end);
    const bExp     = D.exp.filter(e=>e.dt>=b.start&&e.dt<=b.end);
    const bRev  = bSales.reduce((a,s)=>a+(s.total||s.amt||0),0)
                + bRentals.filter(r=>r.st==='Returned'||r.st==='Checked Out'||r.st==='Overdue').reduce((a,r)=>a+r.fee,0)
                + (D.appointments||[]).filter(a=>a.st==='Completed'&&a.date>=b.start&&a.date<=b.end).reduce((a,a2)=>a+(a2.totalAmt||0),0);
    const bCogs = bSales.reduce((a,s)=>a+(s.cost||0),0);
    const bOh   = bExp.filter(e=>e.cat!=='Vendor Payment').reduce((a,e)=>a+e.amt,0);
    const bNp   = bRev - bCogs - bOh;
    labels.push(b.label);
    revData.push(Math.round(bRev * CUR.rate));
    npData.push(Math.round(Math.max(0,bNp) * CUR.rate));
  });
  return {labels, revData, npData};
}

function _applyReportPeriod(period, range){
  // Store custom range so report modals can access it
  if(period === 'custom') PERIOD_RANGES.custom = range;
  _acctPeriod = period;
  const k = computeKPIs(range);
  const r = CUR.rate;
  // Update KPI tiles in reports page
  ['rpt-kpi-rev','rpt-kpi-gp','rpt-kpi-np','rpt-kpi-ar'].forEach((id,i)=>{
    const el2=document.getElementById(id);
    if(el2) el2.innerHTML=fmtKpi([k.rev,k.gp,k.np,k.ar][i]);
  });
  // Rebuild charts from real data
  destroyCharts();

  // ── Monthly Performance bar chart (fully dynamic) ──────────────────
  const {labels, revData, npData} = _buildPerfBuckets(range, period);
  const barOpts = {
    responsive:true, maintainAspectRatio:false,
    plugins:{legend:{labels:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:10.5},boxWidth:10,padding:12}}},
    scales:{
      x:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11},maxRotation:45},grid:{color:document.body.classList.contains('light')?'rgba(0,0,0,.07)':'rgba(255,255,255,.06)'}},
      y:{ticks:{color:document.body.classList.contains('light')?'#374151':'#c8cee8',font:{size:11},callback:v=>fmtRaw(v)},grid:{color:document.body.classList.contains('light')?'rgba(0,0,0,.07)':'rgba(255,255,255,.06)'}}
    }
  };
  mkChart('mChart',{type:'bar',data:{labels,datasets:[
    {label:'Revenue',   data:revData, backgroundColor:'rgba(91,127,255,.65)',borderRadius:4},
    {label:'Net Profit',data:npData,  backgroundColor:'rgba(45,212,160,.65)',borderRadius:4}
  ]},options:barOpts});

  // ── Revenue by category donut (dynamic for selected period) ──────────
  const gownRev = k.sales.filter(s=>s.items.toLowerCase().includes('gown')||s.items.toLowerCase().includes('ballgown')).reduce((a,s)=>a+s.amt,0);
  const accRev  = k.sales.filter(s=>s.items.toLowerCase().includes('tiara')||s.items.toLowerCase().includes('veil')||s.items.toLowerCase().includes('gloves')||s.items.toLowerCase().includes('necklace')||s.items.toLowerCase().includes('crown')||s.items.toLowerCase().includes('heels')).reduce((a,s)=>a+s.amt,0);
  const rentRev = k.rentals.reduce((a,rr)=>a+rr.fee,0);
  const otherRev= Math.max(0,k.rev-gownRev-accRev-rentRev);
  mkChart('catChart',{type:'doughnut',data:{labels:['Gowns','Accessories','Rentals','Other'],
    datasets:[{data:[gownRev,accRev,rentRev,otherRev].map(v=>Math.round(v*r)),
      backgroundColor:['#5b7fff','#9f7aea','#38bdf8','#f5c842'],borderWidth:0}]},
    options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},cutout:'68%'}});

  // Update period label and category bars in the card
  const lbl=document.getElementById('rpt-period-label');
  if(lbl) lbl.textContent=range.label;
  const totalRev = k.rev||1;
  const catBars = {
    'rpt-cat-gown': gownRev/totalRev,
    'rpt-cat-acc':  accRev/totalRev,
    'rpt-cat-rent': rentRev/totalRev,
    'rpt-cat-other':otherRev/totalRev,
  };
  Object.entries(catBars).forEach(([id, pct])=>{
    const el=document.getElementById(id);
    if(el) el.style.width = Math.round(pct*100)+'%';
    const pEl=document.getElementById(id+'-pct');
    if(pEl) pEl.textContent = Math.round(pct*100)+'%';
  });
}

// ── SALES PERIOD ──────────────────────────────────────────────
function _navWithPeriod(page, period){
  var p = period || _dashPeriod || 'month';
  nav(page);
  setTimeout(function(){
    if(page === 'sales'){
      var tabs = document.querySelectorAll('.fbar .dtabs .dtab');
      var btn = null;
      tabs.forEach(function(b){
        var oc = b.getAttribute('onclick')||'';
        if(oc.indexOf("'"+p+"'") !== -1) btn = b;
      });
      if(!btn && tabs.length) btn = tabs[3]; // default month tab (index 3)
      if(btn) setSalesPeriod(btn, p);
    } else if(page === 'rentals'){
      var tabs2 = document.querySelectorAll('#rental-period-tabs .dtab');
      if(!tabs2.length) tabs2 = document.querySelectorAll('.fbar .dtabs .dtab');
      var btn2 = null;
      tabs2.forEach(function(b){
        var oc = b.getAttribute('onclick')||'';
        if(oc.indexOf("'"+p+"'") !== -1) btn2 = b;
      });
      if(!btn2 && tabs2.length) btn2 = tabs2[0];
      if(btn2) setRentalsPeriod(btn2, p);
    }
  }, 100);
}


// ── Sales period/filter state ─────────────────────────────────
let _salesCurrentRange = null;

function setSalesPeriod(el, period){
  // Scope to the parent .dtabs only — avoids clearing rental period tabs
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  _salesCurrentRange = PERIOD_RANGES[period] || null;
  _salesFilter();
}

function _salesFilter(){
  const q       = (document.getElementById('sales-search')?.value||'').toLowerCase();
  const status  = document.getElementById('sales-status-filter')?.value||'';
  const cust    = document.getElementById('sales-customer-filter')?.value||'';
  const product = (document.getElementById('sales-product-filter')?.value||'').toLowerCase();
  const range   = _salesCurrentRange;

  let visible=0;
  document.querySelectorAll('#sales-tbody tr').forEach(function(row){
    const dt       = row.dataset.date||'';
    const rowSt    = row.dataset.status||'';
    const rowCust  = row.dataset.cust||'';
    const rowItems = row.dataset.items||'';
    const inR = !range   || inRange(dt, range);
    const inS = !status  || rowSt===status;
    const inC = !cust    || rowCust===cust;
    const inP = !product || rowItems.includes(product);
    const inQ = !q       || row.textContent.toLowerCase().includes(q);
    const show = inR && inS && inC && inP && inQ;
    row.style.display = show ? '' : 'none';
    if(show) visible++;
  });

  // Recompute KPIs from matching records
  const matching = D.sales.filter(function(s){
    const inR = !range   || inRange(s.dt, range);
    const inS = !status  || s.st===status;
    const inC = !cust    || s.cust===cust;
    const inP = !product || (s.items||'').toLowerCase().includes(product);
    const inQ = !q       || ((s.cust||'')+(s.items||'')+(s.id||'')).toLowerCase().includes(q);
    return inR && inS && inC && inP && inQ;
  });
  const kRev  = matching.reduce(function(a,s){return a+(s.total||s.amt||0);},0);
  const kCash = matching.reduce(function(a,s){return a+(s.paid||0);},0);
  const kAR   = matching.reduce(function(a,s){return a+Math.max(0,(s.total||s.amt||0)-(s.paid||0));},0);
  const kGP   = matching.reduce(function(a,s){return a+(s.profit!==undefined?s.profit:(s.total||s.amt||0)-(s.cost||0));},0);
  _setKpiVal('sales-kpi-rev',  fmtKpi(kRev));
  _setKpiVal('sales-kpi-cash', fmtKpi(kCash));
  _setKpiVal('sales-kpi-ar',   fmtKpi(kAR));
  _setKpiVal('sales-kpi-gp',   fmtKpi(kGP));
}

function _salesFilterInit(){
  _salesCurrentRange = PERIOD_RANGES['month'];
  _salesFilter();
}

// Legacy alias
function filterSalesTable(){ _salesFilter(); }

