// ── Rental filter state ───────────────────────────────────────
let _rentalsCurrentRange = null;
let _rentalsCurrentStatus = '';

function setRentalsPeriod(el, period){
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  _rentalsCurrentRange = PERIOD_RANGES[period] || null;
  _rentalsFilter();
}

function filterRentals(el, status){
  // Update tab UI
  if(el && el.parentElement){
    el.parentElement.querySelectorAll('.stab').forEach(b=>b.classList.remove('on'));
  }
  if(el) el.classList.add('on');
  // Sync status dropdown
  const sel = document.getElementById('rent-status-sel');
  if(sel) sel.value = status||'';
  _rentalsCurrentStatus = status||'';
  _rentalsFilter();
  setTimeout(function(){
    const tbl = document.getElementById('rentals-tbody');
    if(tbl) tbl.closest('.card')?.scrollIntoView({behavior:'smooth',block:'start'});
  }, 50);
}

function filterRentalsSearch(){
  _rentalsFilter();
}

// Overdue filter — clears period range so ALL overdue show regardless of date
function filterRentalsOverdue(){
  // Clear period range — overdue rentals span all time, not just current period
  _rentalsCurrentRange = null;
  // Deselect all period tabs
  document.querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  // Set status filter to Overdue
  const sel = document.getElementById('rent-status-sel');
  if(sel) sel.value = 'Overdue';
  _rentalsCurrentStatus = 'Overdue';
  // Update tab UI
  const tabs = document.querySelectorAll('#rental-tabs .stab');
  tabs.forEach(b=>b.classList.remove('on'));
  if(tabs[1]) tabs[1].classList.add('on'); // 'Overdue' tab
  _rentalsFilter();
  setTimeout(function(){
    const tbl = document.getElementById('rentals-tbody');
    if(tbl) tbl.closest('.card')?.scrollIntoView({behavior:'smooth',block:'start'});
  }, 50);
}

// ── Master rentals filter ─────────────────────────────────────
function _rentalsFilter(){
  const q      = (document.getElementById('rent-search')?.value||'').toLowerCase();
  const status = (document.getElementById('rent-status-sel')?.value||'') || _rentalsCurrentStatus;
  const range  = _rentalsCurrentRange;

  let visible = 0;
  document.querySelectorAll('#rentals-tbody tr').forEach(function(row){
    const dt  = row.dataset.start || row.dataset.date || '';
    const rst = row.dataset.status || '';
    const inR = !range  || inRange(dt, range);
    const inS = !status || rst === status;
    const inQ = !q      || row.textContent.toLowerCase().includes(q);
    const show = inR && inS && inQ;
    row.style.display = show ? '' : 'none';
    if(show) visible++;
  });
}

function _rentalsFilterInit(){
  _rentalsCurrentRange = PERIOD_RANGES['month'];
  _rentalsCurrentStatus = '';
  _rentalsFilter();
}

// ── Purchase period state ─────────────────────────────────────
let _poCurrentRange = null;

function setPurchasesPeriod(el, period){
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  _poCurrentRange = PERIOD_RANGES[period] || null;
  _poFilter();
  const lbl = document.getElementById('po-breakdown-period');
  const labels={today:'Today',week:'This week',lastweek:'Last week',month:'This month',lastmonth:'Last month',quarter:'This quarter',ytd:'Year to date'};
  if(lbl) lbl.textContent = labels[period]||period;
}

// ── Master PO filter — search + vendor + status + period ─────
function _poFilter(){
  const q      = (document.getElementById('po-search')?.value||'').toLowerCase();
  const vendor = document.getElementById('po-vendor-filter')?.value||'';
  const st     = document.getElementById('po-st-filter')?.value||'';
  const range  = _poCurrentRange;

  let visible=0, totalLanded=0;

  document.querySelectorAll('#po-tbody tr.po-row').forEach(function(row){
    const dt  = row.dataset.date||'';
    const rv  = row.dataset.vendor||'';
    const rst = row.dataset.st||'';
    const inR = !range  || inRange(dt, range);
    const inV = !vendor || rv===vendor;
    const inS = !st     || rst===st;
    const inQ = !q      || row.textContent.toLowerCase().includes(q);
    const show = inR && inV && inS && inQ;
    row.style.display = show ? '' : 'none';
    if(show){
      visible++;
      const poId = row.querySelector('td')?.textContent?.trim();
      if(poId){
        const po = D.purchases.find(function(p){ return p.id===poId; });
        if(po) totalLanded += po.total||0;
      }
    }
  });

  // Empty state
  const emptyEl = document.getElementById('po-empty');
  const tblEl   = document.getElementById('po-table');
  if(emptyEl) emptyEl.style.display = visible===0 ? '' : 'none';
  if(tblEl)   tblEl.style.display   = visible===0 ? 'none' : '';

  // Footer
  const countEl = document.getElementById('po-footer-count');
  const totalEl = document.getElementById('po-footer-total');
  if(countEl) countEl.textContent = visible+' order'+(visible!==1?'s':'');
  if(totalEl) totalEl.textContent = fmt(totalLanded);

  // Recompute KPIs from matching records
  const matching = D.purchases.filter(function(p){
    const inR = !range  || inRange(p.dt, range);
    const inV = !vendor || p.vendor===vendor;
    const inS = !st     || p.st===st;
    const inQ = !q      || ((p.vendor||'')+(p.items||'')+(p.id||'')).toLowerCase().includes(q);
    return inR && inV && inS && inQ;
  });
  const kTotal   = matching.reduce(function(a,p){return a+(p.total||0);},0);
  const kPending = matching.filter(function(p){return p.st==='Pending'||p.st==='Partial';}).length;
  const kPaid    = matching.filter(function(p){return p.st==='Paid'||p.st==='Received';}).length;
  _setKpiVal('po-kpi-total',   fmtKpi(kTotal));
  _setKpiVal('po-kpi-pending', String(kPending));
  _setKpiVal('po-kpi-paid',    String(kPaid));

  // Vendor breakdown sidebar
  const breakdownEl = document.getElementById('po-vendor-breakdown');
  if(breakdownEl && matching.length){
    const vMap={};
    matching.forEach(function(p){ vMap[p.vendor]=(vMap[p.vendor]||0)+(p.total||0); });
    const sorted=Object.entries(vMap).sort(function(a,b){return b[1]-a[1];});
    const maxVal=sorted[0]?sorted[0][1]:1;
    breakdownEl.innerHTML=sorted.map(function(pair){
      const v=pair[0]; const val=pair[1];
      const pct=kTotal>0?Math.round(val/kTotal*100):0;
      const barW=maxVal>0?Math.round(val/maxVal*100):0;
      return '<div style="margin-bottom:10px">'
        +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px">'
          +'<span style="font-size:12px;font-weight:600;color:var(--ink)">'+_esc(v)+'</span>'
          +'<span style="font-size:11px;color:var(--text2)">'+fmt(val)+' <span style="margin-left:4px">'+pct+'%</span></span>'
        +'</div>'
        +'<div style="background:var(--border);border-radius:3px;height:5px">'
          +'<div style="background:var(--b);border-radius:3px;height:5px;width:'+barW+'%;transition:width .3s"></div>'
        +'</div>'
      +'</div>';
    }).join('');
  } else if(breakdownEl){
    breakdownEl.innerHTML='<div style="font-size:12px;color:var(--text2);padding:8px 0">No purchases in this period.</div>';
  }
}

function _poFilterInit(){
  _poCurrentRange = PERIOD_RANGES['month'];
  _poFilter();
}

// Legacy alias
function filterPurchasesTable(){ _poFilter(); }


// ── Expense period state ──────────────────────────────────────
let _expCurrentRange = null; // null = show all, set by setExpPeriod

function setExpPeriod(el, period){
  el.closest('.dtabs').querySelectorAll('.dtab').forEach(b=>b.classList.remove('on'));
  el.classList.add('on');
  _expCurrentRange = PERIOD_RANGES[period] || null;
  _expFilter();

  // Update breakdown sidebar period label
  const lbl = document.getElementById('exp-breakdown-period');
  if(lbl){ const labels={today:'Today',week:'This week',lastweek:'Last week',month:'This month',lastmonth:'Last month',quarter:'This quarter',ytd:'Year to date'}; lbl.textContent=labels[period]||period; }
}

// ── Master expense filter — called by search, category, type, period ─
function _expFilter(){
  const q    = (document.getElementById('exp-search')?.value||'').toLowerCase();
  const cat  = document.getElementById('exp-cat-filter')?.value||'';
  const type = document.getElementById('exp-type-filter')?.value||'';
  const range = _expCurrentRange;

  let visible=0, totalAmt=0;
  const catMap={};

  document.querySelectorAll('#exp-tbody tr').forEach(row=>{
    const dt   = row.dataset.date||'';
    const rCat = row.dataset.cat||'';
    const rTyp = row.dataset.type||'';
    const inR  = !range || inRange(dt, range);
    const inC  = !cat  || rCat===cat;
    const inT  = !type || rTyp===type;
    const inQ  = !q    || row.textContent.toLowerCase().includes(q);
    const show = inR && inC && inT && inQ;
    row.style.display = show ? '' : 'none';

    if(show){
      visible++;
      // Parse amount from the row's data (get from D.exp by ID)
      const expId = row.querySelector('td')?.textContent?.trim();
      if(expId){
        const exp = D.exp.find(function(e){ return e.id===expId; });
        if(exp){ totalAmt += exp.amt||0; }
      }
      // Also track category for breakdown
      if(rCat) catMap[rCat]=(catMap[rCat]||0)+1;
    }
  });

  // Empty state
  const emptyEl = document.getElementById('exp-empty');
  const tblEl   = document.getElementById('exp-table');
  const footerEl= document.getElementById('exp-footer');
  if(emptyEl) emptyEl.style.display = visible===0 ? '' : 'none';
  if(tblEl)   tblEl.style.display   = visible===0 ? 'none' : '';

  // Footer: count + total
  const countEl = document.getElementById('exp-footer-count');
  const totalEl = document.getElementById('exp-footer-total');
  if(countEl) countEl.textContent = visible+' expense'+(visible!==1?'s':'');
  if(totalEl) totalEl.textContent = fmt(totalAmt);

  // KPI tiles — update to reflect filtered rows
  // Re-compute from D.exp matching all active filters
  const matchingExps = D.exp.filter(function(e){
    const inR = !range || inRange(e.dt, range);
    const inC = !cat   || e.cat===cat;
    const inT = !type  || e.type===type;
    const inQ = !q     || (e.cat+e.payee+(e.notes||'')).toLowerCase().includes(q);
    return inR && inC && inT && inQ;
  });
  const kTotal = matchingExps.reduce(function(a,e){ return a+e.amt; },0);
  const kRec   = matchingExps.filter(function(e){ return e.type==='Recurring'; }).reduce(function(a,e){ return a+e.amt; },0);
  const kOne   = matchingExps.filter(function(e){ return e.type!=='Recurring'; }).reduce(function(a,e){ return a+e.amt; },0);
  _setKpiVal('exp-kpi-total', fmtKpi(kTotal));
  _setKpiVal('exp-kpi-rec',   fmtKpi(kRec));
  _setKpiVal('exp-kpi-one',   fmtKpi(kOne));
  _setKpiVal('exp-kpi-count', String(matchingExps.length));

  // Rebuild category breakdown sidebar
  const catBreakdownEl = document.getElementById('exp-cat-breakdown');
  if(catBreakdownEl && matchingExps.length){
    const catTotals={};
    matchingExps.forEach(function(e){ catTotals[e.cat]=(catTotals[e.cat]||0)+e.amt; });
    const sorted=Object.entries(catTotals).sort(function(a,b){return b[1]-a[1];});
    const maxVal=sorted[0]?sorted[0][1]:1;
    catBreakdownEl.innerHTML=sorted.map(function(pair){
      const c=pair[0]; const v=pair[1];
      const pct=kTotal>0?Math.round(v/kTotal*100):0;
      const barW=maxVal>0?Math.round(v/maxVal*100):0;
      return '<div style="margin-bottom:10px">'
        +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px">'
          +'<span style="font-size:12px;font-weight:600;color:var(--ink)">'+_esc(c)+'</span>'
          +'<span style="font-size:11px;color:var(--text2)">'+fmt(v)+' <span style="margin-left:4px">'+pct+'%</span></span>'
        +'</div>'
        +'<div style="background:var(--border);border-radius:3px;height:5px">'
          +'<div style="background:var(--r);border-radius:3px;height:5px;width:'+barW+'%;transition:width .3s"></div>'
        +'</div>'
      +'</div>';
    }).join('');
  } else if(catBreakdownEl){
    catBreakdownEl.innerHTML='<div style="font-size:12px;color:var(--text2);padding:8px 0">No expenses in this period.</div>';
  }
}

// Apply default "Month" filter on page render — called after pgExp builds DOM
function _expFilterInit(){
  _expCurrentRange = PERIOD_RANGES['month'];
  _expFilter();
}

// Legacy alias so any old code calling filterExpTable() still works
function filterExpTable(range){
  if(range) _expCurrentRange = range;
  _expFilter();
}



// filterSalesTable is aliased above to _salesFilter

// ============================================================
// RENTAL FILTER & CALENDAR
// ============================================================
// filterRentals is defined above in the unified rental filter system

// ── Rental Calendar state ────────────────────────────────────────────────
let _calYear  = new Date().getFullYear();
let _calMonth = new Date().getMonth(); // 0-indexed
let _calSelDay = null; // selected day dateStr e.g. '2026-03-16'

function showRentalCalendar(year, month){
  if(year  !== undefined) _calYear  = year;
  if(month !== undefined) _calMonth = month;
  _renderRentalCalendar();
}

function _renderRentalCalendar(){
  const year  = _calYear;
  const month = _calMonth;
  const todayStr = localDateStr();
  const todayY   = parseInt(todayStr.slice(0,4));
  const todayM   = parseInt(todayStr.slice(5,7))-1;
  const todayD   = parseInt(todayStr.slice(8));
  const isCurrentMonth = (year===todayY && month===todayM);

  const MONTH_NAMES=['January','February','March','April','May','June',
                     'July','August','September','October','November','December'];
  const DAY_NAMES=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const firstDay    = new Date(year,month,1).getDay();
  const daysInMonth = new Date(year,month+1,0).getDate();
  const prevY = month===0?year-1:year,  prevM = month===0?11:month-1;
  const nextY = month===11?year+1:year, nextM = month===11?0:month+1;

  // ── Build per-day rental map ──────────────────────────────
  const dayMap = {}; // dateStr -> [{rental, isSt, isEnd, isMid}]
  D.rentals.forEach(r=>{
    if(!r.start||!r.due) return;
    let cur = new Date(r.start+'T00:00:00');
    const endD = new Date(r.due+'T00:00:00');
    while(cur<=endD){
      const k = cur.toISOString().slice(0,10);
      if(!dayMap[k]) dayMap[k]=[];
      dayMap[k].push({r, isSt:r.start===k, isEnd:r.due===k});
      cur.setDate(cur.getDate()+1);
    }
  });

  // ── Status colours ────────────────────────────────────────
  function rentColour(r, isSt, isEnd){
    if(r.st==='Overdue')     return {bg:'rgba(255,95,122,.25)',border:'#ff5f7a',text:'#ff5f7a',dot:'#ff5f7a'};
    if(r.st==='Returned')    return {bg:'rgba(100,110,150,.18)',border:'#4d5480',text:'var(--text3)',dot:'#4d5480'};
    if(isSt)                 return {bg:'rgba(45,212,160,.22)',border:'#2dd4a0',text:'#2dd4a0',dot:'#2dd4a0'};
    if(isEnd)                return {bg:'rgba(245,200,66,.22)',border:'#f5c842',text:'#f5c842',dot:'#f5c842'};
    return                          {bg:'rgba(91,127,255,.18)',border:'rgba(91,127,255,.5)',text:'#5b7fff',dot:'#5b7fff'};
  }

  // ── Month stats ────────────────────────────────────────────
  const mStr = `${year}-${String(month+1).padStart(2,'0')}`;
  const mRentals = D.rentals.filter(r=>(r.start||'').startsWith(mStr)||(r.due||'').startsWith(mStr));
  const mActive  = mRentals.filter(r=>['Checked Out','Reserved'].includes(r.st)).length;
  const mOverdue = mRentals.filter(r=>r.st==='Overdue').length;
  const mRev     = mRentals.filter(r=>r.st!=='Reserved').reduce((a,r)=>a+r.fee,0);

  // ── Selected day (default today if in month, else 1st) ───
  const selDay = (_calSelDay && _calSelDay.startsWith(mStr))
    ? parseInt(_calSelDay.slice(8))
    : (isCurrentMonth ? todayD : 1);
  const selDs = `${year}-${String(month+1).padStart(2,'0')}-${String(selDay).padStart(2,'0')}`;
  _calSelDay = selDs;
  const selRentals = dayMap[selDs]||[];

  // ── Build calendar grid cells ────────────────────────────
  let cells = '';
  // Empty cells before month starts
  for(let i=0;i<firstDay;i++){
    const prevMonthDays = new Date(year,month,0).getDate();
    const dayNum = prevMonthDays - firstDay + i + 1;
    cells += `<div class="cal-cell cal-other"><span class="cal-dn">${dayNum}</span></div>`;
  }

  for(let d=1;d<=daysInMonth;d++){
    const ds = `${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const dayR   = dayMap[ds]||[];
    const isToday   = isCurrentMonth && d===todayD;
    const isSel     = d===selDay;
    const hasOverdue= dayR.some(x=>x.r.st==='Overdue');
    const isWeekend = new Date(year,month,d).getDay()===0||new Date(year,month,d).getDay()===6;

    // Day cell chips — show up to 3, with +N more
    const chips = dayR.slice(0,3).map(({r,isSt,isEnd})=>{
      const c = rentColour(r,isSt,isEnd);
      const icon = r.st==='Overdue'?'⚠':isSt?'▶':isEnd?'■':'─';
      const name = r.cust.split(' ')[0];
      return `<div class="cal-chip" style="background:${c.bg};border-left:2px solid ${c.border};color:${c.text}"
        onclick="event.stopPropagation();_calSelRental('${r.id}')" title="${r.cust} — ${r.item} (${r.st})"
      >${icon} ${name}</div>`;
    }).join('');
    const more = dayR.length>3
      ? `<div class="cal-more">+${dayR.length-3} more</div>` : '';

    const cellClass = ['cal-cell',
      isToday?'cal-today':'',
      isSel?'cal-sel':'',
      hasOverdue?'cal-overdue':'',
      isWeekend?'cal-wknd':'',
    ].filter(Boolean).join(' ');

    cells += `<div class="${cellClass}" onclick="_calSelectDay(${d})">
      <div class="cal-dn-row">
        <span class="cal-dn${isToday?' cal-today-num':''}">${d}</span>
        ${dayR.length===0?`<span class="cal-add-btn" onclick="event.stopPropagation();_calNewRental('${ds}')" title="Book rental on ${ds}">+</span>`:''}
      </div>
      ${chips}${more}
    </div>`;
  }

  // Trailing empty cells
  const totalCells = firstDay + daysInMonth;
  const trailingCells = totalCells%7===0 ? 0 : 7-(totalCells%7);
  for(let i=1;i<=trailingCells;i++){
    cells += `<div class="cal-cell cal-other"><span class="cal-dn">${i}</span></div>`;
  }

  // ── Sidebar: selected day panel ──────────────────────────
  const selDateFmt = new Date(selDs+'T00:00:00').toLocaleDateString('en-GB',{weekday:'long',day:'numeric',month:'long'});
  const sideItems = selRentals.length===0
    ? `<div style="text-align:center;padding:32px 0;color:var(--text2)">
        <div style="font-size:28px;margin-bottom:8px">📅</div>
        <div style="font-size:12px">No rentals on this day</div>
        <button class="btn btn-p btn-sm" style="margin-top:12px" onclick="_calNewRental('${selDs}')">+ Book Rental</button>
       </div>`
    : selRentals.map(({r, isSt, isEnd})=>{
        const c = rentColour(r, isSt, isEnd);
        const statusLabel = r.st==='Overdue'?'⚠ OVERDUE':isSt?'▶ Starts today':isEnd?'■ Due today':'─ Active';
        const custObj = D.cust.find(cu=>cu.id===r.cust||cu.name===r.cust)||{};
        return `<div class="cal-side-item" style="border-left:3px solid ${c.border}">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:6px">
            <div style="flex:1;min-width:0">
              <div style="font-weight:700;font-size:12px;color:var(--ink);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${r.cust}</div>
              <div style="font-size:11px;color:var(--text2);margin-top:1px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${r.item}">${r.item}</div>
            </div>
            <span style="font-size:10px;font-weight:700;color:${c.text};white-space:nowrap;flex-shrink:0">${statusLabel}</span>
          </div>
          <div style="display:flex;gap:8px;margin-top:5px;font-size:10px;color:var(--text)">
            <span>📅 ${r.start}→${r.due}</span>
            <span style="color:var(--g);font-family:var(--mono)">${fmt(r.fee)}</span>
            ${r.lf>0?`<span style="color:var(--r)">⚠ ${fmt(r.lf)} late</span>`:''}
          </div>
          ${custObj.phone?`<div style="font-size:10px;color:var(--text2);margin-top:2px">📞 ${custObj.phone}</div>`:''}
          <div style="display:flex;gap:5px;margin-top:7px;flex-wrap:wrap">
            <button class="btn btn-g btn-xs" onclick="closeModal();setTimeout(()=>mRentalDetail('${r.id}'),60)">View</button>
            ${(r.st==='Checked Out'||r.st==='Overdue')?`<button class="btn btn-p btn-xs" onclick="closeModal();setTimeout(()=>mReturn('${r.id}'),60)">↩ Return</button>`:''}
            ${BIZ.contractEnabled?`<button class="btn btn-c btn-xs" onclick="closeModal();setTimeout(()=>mRentalContract('${r.id}'),60)">📋</button>`:''}
          </div>
        </div>`;
      }).join('')+`<button class="btn btn-p btn-sm" style="width:100%;margin-top:10px" onclick="_calNewRental('${selDs}')">+ Book on this day</button>`;

  // ── Modal HTML ────────────────────────────────────────────
  modal('',`
  <div id="cal-root">
    <style>
      #cal-root{display:flex;gap:0;height:580px;overflow:hidden}
      .cal-main{flex:1;min-width:0;display:flex;flex-direction:column;padding:0 2px}
      .cal-sidebar{width:230px;flex-shrink:0;border-left:1px solid var(--border2);padding:0 14px 14px 14px;overflow-y:auto;display:flex;flex-direction:column}
      .cal-header{display:flex;align-items:center;justify-content:space-between;padding:14px 12px 10px;flex-shrink:0}
      .cal-month-title{font-size:18px;font-weight:800;color:var(--ink);font-family:var(--display)}
      .cal-month-sub{font-size:11px;color:var(--text2);margin-top:1px}
      .cal-nav-btn{background:var(--bg4);border:1px solid var(--border2);color:var(--text);border-radius:7px;padding:5px 12px;cursor:pointer;font-size:14px;font-weight:700;transition:background .15s}
      .cal-nav-btn:hover{background:var(--bg5);color:var(--ink)}
      .cal-stats{display:flex;gap:8px;padding:0 12px 10px;flex-shrink:0}
      .cal-stat{flex:1;background:var(--bg3);border-radius:7px;padding:6px 8px;text-align:center}
      .cal-stat-val{font-size:15px;font-weight:800;font-family:var(--mono)}
      .cal-stat-lbl{font-size:9px;color:var(--text2);margin-top:1px;text-transform:uppercase;letter-spacing:.04em}
      .cal-daynames{display:grid;grid-template-columns:repeat(7,1fr);gap:3px;padding:0 12px;flex-shrink:0}
      .cal-dayname{text-align:center;font-size:10px;font-weight:700;color:var(--text2);padding:4px 0;letter-spacing:.05em}
      .cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:3px;padding:0 12px 12px;overflow-y:auto;flex:1}
      .cal-cell{background:var(--bg3);border:1px solid var(--border);border-radius:7px;padding:4px 5px;cursor:pointer;min-height:72px;transition:border-color .13s,background .13s;position:relative}
      .cal-cell:hover{border-color:var(--a);background:var(--bg4)}
      .cal-cell.cal-sel{border-color:var(--a)!important;background:var(--a-dim)!important}
      .cal-cell.cal-today{border-color:var(--p)!important}
      .cal-cell.cal-overdue{border-color:rgba(255,95,122,.5)!important;background:rgba(255,95,122,.06)!important}
      .cal-cell.cal-wknd{background:var(--bg4)}
      .cal-cell.cal-other{background:transparent;border-color:transparent;cursor:default;opacity:.3}
      .cal-cell.cal-other:hover{background:transparent;border-color:transparent}
      .cal-dn-row{display:flex;align-items:center;justify-content:space-between;margin-bottom:3px}
      .cal-dn{font-size:11px;font-weight:700;color:var(--text2)}
      .cal-today-num{background:var(--p);color:#fff;border-radius:50%;width:19px;height:19px;display:inline-flex;align-items:center;justify-content:center;font-size:10px}
      .cal-add-btn{font-size:14px;color:var(--text2);line-height:1;opacity:0;transition:opacity .13s;cursor:pointer;padding:0 2px}
      .cal-cell:hover .cal-add-btn{opacity:1}
      .cal-chip{font-size:9px;font-weight:600;border-radius:3px;padding:2px 4px;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer;line-height:1.4}
      .cal-chip:hover{filter:brightness(1.2)}
      .cal-more{font-size:9px;color:var(--text2);padding:1px 3px;margin-top:1px}
      .cal-legend{display:flex;flex-wrap:wrap;gap:8px;padding:0 12px 8px;flex-shrink:0}
      .cal-leg-item{display:flex;align-items:center;gap:4px;font-size:10px;color:var(--text2)}
      .cal-leg-dot{width:9px;height:9px;border-radius:2px;flex-shrink:0}
      .cal-sidebar-hd{font-size:11px;font-weight:700;color:var(--ink);padding:14px 0 8px;flex-shrink:0;border-bottom:1px solid var(--border);margin-bottom:8px}
      .cal-sidebar-date{font-size:13px;font-weight:800;color:var(--a);margin-bottom:2px}
      .cal-side-item{background:var(--bg3);border-radius:7px;padding:10px 10px 10px 10px;margin-bottom:7px;border:1px solid var(--border)}
      @media(max-width:700px){.cal-sidebar{display:none}.cal-main{padding:0}}
    </style>

    <!-- LEFT: Calendar -->
    <div class="cal-main">
      <!-- Header -->
      <div class="cal-header">
        <button class="cal-nav-btn" onclick="_calNav(${prevY},${prevM})">&#8249;</button>
        <div style="text-align:center">
          <div class="cal-month-title">${MONTH_NAMES[month]} ${year}</div>
          <div class="cal-month-sub">${mRentals.length} rental${mRentals.length!==1?'s':''} this month</div>
        </div>
        <button class="cal-nav-btn" onclick="_calNav(${nextY},${nextM})">&#8250;</button>
      </div>

      <!-- Stats strip -->
      <div class="cal-stats">
        <div class="cal-stat"><div class="cal-stat-val" style="color:var(--a)">${mActive}</div><div class="cal-stat-lbl">Active</div></div>
        <div class="cal-stat"><div class="cal-stat-val" style="color:var(--r)">${mOverdue}</div><div class="cal-stat-lbl">Overdue</div></div>
        <div class="cal-stat"><div class="cal-stat-val" style="color:var(--g)">${fmt(mRev)}</div><div class="cal-stat-lbl">Revenue</div></div>
        <div class="cal-stat"><div class="cal-stat-val" style="color:var(--y)">${D.rentals.filter(r=>!['Returned','Closed'].includes(r.st)).reduce((a,r)=>a+r.dep,0)>0?fmt(D.rentals.filter(r=>!['Returned','Closed'].includes(r.st)).reduce((a,r)=>a+r.dep,0)):'—'}</div><div class="cal-stat-lbl">Deposits</div></div>
      </div>

      <!-- Legend -->
      <div class="cal-legend">
        <div class="cal-leg-item"><div class="cal-leg-dot" style="background:rgba(45,212,160,.4);border:1px solid #2dd4a0"></div>Starts</div>
        <div class="cal-leg-item"><div class="cal-leg-dot" style="background:rgba(91,127,255,.3);border:1px solid rgba(91,127,255,.6)"></div>Active</div>
        <div class="cal-leg-item"><div class="cal-leg-dot" style="background:rgba(245,200,66,.3);border:1px solid #f5c842"></div>Due</div>
        <div class="cal-leg-item"><div class="cal-leg-dot" style="background:rgba(255,95,122,.3);border:1px solid #ff5f7a"></div>Overdue</div>
        <div class="cal-leg-item"><div class="cal-leg-dot" style="background:var(--p);border-radius:50%;width:9px;height:9px"></div>Today</div>
      </div>

      <!-- Day names -->
      <div class="cal-daynames">
        ${DAY_NAMES.map(d=>`<div class="cal-dayname">${d}</div>`).join('')}
      </div>

      <!-- Grid -->
      <div class="cal-grid">${cells}</div>
    </div>

    <!-- RIGHT: Sidebar -->
    <div class="cal-sidebar">
      <div class="cal-sidebar-hd">
        <div class="cal-sidebar-date">${selDateFmt}</div>
        <div style="font-size:11px;color:var(--text2)">${selRentals.length} rental${selRentals.length!==1?'s':''}</div>
      </div>
      ${sideItems}
    </div>
  </div>`,

  `<button class="btn btn-s btn-sm" onclick="closeModal()">Close</button>
   <button class="btn btn-g btn-sm" onclick="_calNav(${todayY},${todayM})">&#8962; Today</button>
   <button class="btn btn-p btn-sm" onclick="_calNewRental('${selDs}')">+ Book on ${selDs.slice(5).replace('-','/')}</button>`,
  'xl');
}

// ── Calendar navigation ───────────────────────────────────────
function _calNav(y, m){
  _calYear=y; _calMonth=m; _calSelDay=null;
  _renderRentalCalendar();
}

// ── Select a day in the calendar (updates sidebar) ────────────
function _calSelectDay(d){
  _calSelDay = `${_calYear}-${String(_calMonth+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
  _renderRentalCalendar();
}

// ── Jump to rental detail from calendar chip ──────────────────
function _calSelRental(rentalId){
  closeModal();
  setTimeout(()=>mRentalDetail(rentalId), 60);
}
function _calNewRental(dateStr){
  _mStack.length=0;
  $('mc').innerHTML='';
  setTimeout(function(){ mCreateRental(dateStr||null); },60);
}

