async function mEditExp(id){
  await _syncCatsFromDB();
  if(!can('edit_expenses')){ toast('\u26d4 Edit Expenses — permission denied for your role','error'); return; }
  const e=D.exp.find(x=>x.id===id);if(!e)return;
  // Use dynamic D.expCats so custom categories are always available
  const typeOpts = ['Recurring','Operating','One-time','Asset Purchase']
    .map(t=>`<option${t===e.type?' selected':''}>${t}</option>`).join('');
  const methodOpts = ['Cash','Bank Transfer','Credit Card','Mobile Money (MTN)','Orange Money','Direct Debit']
    .map(m=>`<option${m===e.method?' selected':''}>${m}</option>`).join('');
  modal(`✏️ Edit Expense — ${e.id}`,`
  <div class="fg-2">
    <div class="fg"><label class="fl">Date</label><input class="fi" type="date" id="edit-exp-dt" value="${e.dt}"/></div>
    <div class="fg"><label class="fl">Category</label>
      <div style="display:flex;gap:6px;align-items:center">
        <div id="edit-exp-cat-wrap" style="position:relative;flex:1"></div>
        <input type="hidden" id="edit-exp-cat" value="${_esc(e.cat||D.expCats[0]||'')}"/>
      </div>
    </div>
    <div class="fg"><label class="fl">Payee *</label><input class="fi" id="edit-exp-payee" value="${_esc(e.payee)}"/></div>
    <div class="fg"><label class="fl">Amount * <span style="font-size:10px;color:var(--text2)">(${CUR.symbol})</span></label><input class="fi" type="number" id="edit-exp-amt" value="${Math.round(e.amt*(CUR.rate||1)*100)/100}" step="any"/></div>
    <div class="fg"><label class="fl">Type</label><select class="fs" id="edit-exp-type">${typeOpts}</select></div>
    <div class="fg"><label class="fl">Payment Method</label><select class="fs" id="edit-exp-method">${methodOpts}</select></div>
  </div>
  <div class="fg"><label class="fl">Notes</label><textarea class="ft" id="edit-exp-notes" placeholder="Additional notes…" style="min-height:52px">${_esc(e.notes||'')}</textarea></div>`,
  `<button class="btn btn-d btn-sm" onclick="confirmDo('Delete this expense?',function(){D.exp=D.exp.filter(function(x){return x.id!==id;});_dbDelExp(id);
    refreshLiveKpis();addAudit('Expense deleted',id);closeModal();toast('Expense deleted','success');nav('expenses');})">🗑 Delete</button>
   <button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="saveExpEdit('${id}')">💾 Save Changes</button>`);
  // Init category searchable select with live D.expCats
  setTimeout(function(){
    var expCats = D.expCats.length ? D.expCats : ['Rent & Lease','Salaries & Wages','Utilities','Internet & Phone','Marketing & Advertising','Transport & Fuel','Packaging & Supplies','Repairs & Maintenance','Insurance','Staff Bonus','Cleaning','Photography','Bank Charges','Taxes & Duties','Miscellaneous','Other'];
    var catOpts = expCats.map(function(c){ return {val:c, label:c}; });
    _mkSearchSelect('edit-exp-cat-wrap', catOpts, e.cat||expCats[0]||'', function(val){
      var h = document.getElementById('edit-exp-cat'); if(h) h.value = val;
    }, 'Expense category…');
  }, 80);
}

function saveExpEdit(id){
  if(_trialWriteBlocked('Editing an expense')) return;
  const e=D.exp.find(x=>x.id===id);if(!e)return;
  const _er=CUR.rate||1;
  const newDt    = document.getElementById('edit-exp-dt')?.value;
  const newCat   = document.getElementById('edit-exp-cat')?.value;
  const newPayee = document.getElementById('edit-exp-payee')?.value?.trim();
  const newAmt   = parseFloat(document.getElementById('edit-exp-amt')?.value);
  const newType  = document.getElementById('edit-exp-type')?.value;
  const newMethod= document.getElementById('edit-exp-method')?.value;
  const newNotes = document.getElementById('edit-exp-notes')?.value??'';
  if(!newPayee){ toast('Payee is required','error'); return; }
  if(isNaN(newAmt)||newAmt<=0){ toast('Please enter a valid amount','error'); return; }
  e.dt    = newDt    || e.dt;
  e.cat   = newCat   || e.cat;
  e.payee = newPayee;
  e.amt   = newAmt / _er;
  e.type  = newType  || e.type;
  e.method= newMethod|| e.method;
  e.notes = newNotes;
  _dbSaveExp(e); // ← was missing — edits now persist to Supabase
  refreshLiveKpis();
  closeModal();
  addAudit('Expense updated', id+' — '+e.cat+' | '+e.payee+' | '+fmt(e.amt));
  toast('Expense updated ✓','success');
  nav('expenses');
}

// ============================================================
// EXPORT FUNCTIONS
// ============================================================
// ============================================================
// EXPORT UTILITIES
// ============================================================
function downloadCSV(filename, rows, headers){
  const BOM='\uFEFF'; // UTF-8 BOM for Excel compatibility
  const csvContent=BOM+[headers.join(','),...rows.map(r=>r.map(v=>{
    const s=String(v==null?'':v).replace(/"/g,'""');
    return /[,\n\r"]/.test(s)?'"'+s+'"':s;
  }).join(','))].join('\r\n');
  const blob=new Blob([csvContent],{type:'text/csv;charset=utf-8;'});
  const a=document.createElement('a');
  a.href=URL.createObjectURL(blob);
  a.download=filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(a.href);
  toast('✅ '+filename+' downloaded','success');
}

function _fmtRaw(v){ return v!=null?Math.round(v*CUR.rate*100)/100:''; }

function exportSalesCSV(){
  const headers=['Sale #','Date','Customer','Description','Selling Price','Freight','Taxes','Other','Total','Paid','Balance','COGS','Profit','Status','Method'];
  const rows=D.sales.map(s=>[
    s.id, s.dt, s.cust, s.items,
    _fmtRaw(s.amt), _fmtRaw(s.freight||0), _fmtRaw(s.taxes||0), _fmtRaw(s.other||0),
    _fmtRaw(s.total||s.amt), _fmtRaw(s.paid),
    _fmtRaw((s.total||s.amt)-s.paid), _fmtRaw(s.cost), _fmtRaw(s.profit),
    s.st, s.method||''
  ]);
  downloadCSV('sales_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportRentalsCSV(){
  const headers=['Rental #','Customer','Item','Start Date','Due Date','Returned','Daily Fee','Deposit','Total Fees','Late Fee','Status','Method','Notes'];
  const rows=D.rentals.map(r=>[
    r.id, r.cust, r.item, r.start, r.due, r.ret||'',
    _fmtRaw(r.fee), _fmtRaw(r.dep||0), _fmtRaw(r.total||r.fee),
    _fmtRaw(r.lateFee||0), r.st, r.method||'', r.notes||''
  ]);
  downloadCSV('rentals_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportInventoryCSV(){
  const headers=['ID','SKU','Name','Category','Brand','Status','Condition','Cost Price','Selling Price','Rental/Day','Min Sell','Deposit','Qty','Rented','Available','Color','Size'];
  const rows=D.inv.map(i=>[
    i.id, i.sku, i.name, i.cat, i.brand||'', i.st, i.cond||'',
    _fmtRaw(i.cost), _fmtRaw(i.sp), _fmtRaw(i.rp||0),
    _fmtRaw(i.minSp||0), _fmtRaw(i.dep||0),
    i.qty||0, i.rented||0, (i.qty||0)-(i.rented||0),
    i.color||'', i.sz||''
  ]);
  downloadCSV('inventory_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportPurchasesCSV(){
  const headers=['PO #','Date','Vendor','Items','Qty','Unit Cost×Qty','Freight','Duties','Taxes','Other','Total Cost','Status','Payment Method','Delivery','Notes'];
  const rows=D.purchases.map(p=>[
    p.id, p.dt, p.vendor, p.items, p.qty||'',
    _fmtRaw(p.sub), _fmtRaw(p.freight||0), _fmtRaw(p.duties||0),
    _fmtRaw(p.taxes||0), _fmtRaw(p.other||0), _fmtRaw(p.total),
    p.st, p.method||'', p.delivery||'', p.notes||''
  ]);
  downloadCSV('purchases_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportCustomersCSV(){
  const headers=['ID','Name','Type','Email','Phone','WhatsApp','City','Total Spend','Balance','Visits','Last Activity','Status','Notes'];
  const rows=D.cust.map(c=>[
    c.id, c.name, c.type||(c.vip?'VIP':'Regular'),
    c.email||'', c.ph||c.phone||'', c.whatsapp||'',
    c.addr||c.city||'',
    _fmtRaw(c.spend||c.spent||0), _fmtRaw(c.bal||0),
    c.visits||0, c.last||'', c.st||'Active', c.notes||''
  ]);
  downloadCSV('customers_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportVendorsCSV(){
  const headers=['ID','Name','Category','Country','Contact','Email','Phone','Payment Terms','Payment Method','Total Purchases','Outstanding','Orders','Status'];
  const rows=D.vendors.map(v=>[
    v.id, v.name, v.cat||'', v.country||'',
    v.contact||'', v.email||'', v.phone||'',
    v.terms||'', v.method||v.payment||'',
    _fmtRaw(v.total||0), _fmtRaw(v.bal||0),
    v.orders||0, v.st||'Active'
  ]);
  downloadCSV('vendors_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportExpensesCSV(){
  const headers=['Exp #','Date','Category','Payee','Amount','Type','Payment Method','Notes'];
  const rows=D.exp.map(e=>[
    e.id, e.dt, e.cat, e.payee||'',
    _fmtRaw(e.amt), e.type||'', e.method||'', e.notes||''
  ]);
  downloadCSV('expenses_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportAuditCSV(){
  const headers=['Timestamp','User','Role','Action','Record','Old Value','New Value'];
  const rows=D.audit.map(a=>[
    a.ts, a.user||'', a.role||'', a.action||'',
    a.rec||'', a.old||'', a.nw||''
  ]);
  downloadCSV('audit_log_'+new Date().toISOString().slice(0,10)+'.csv', rows, headers);
}

function exportLedgerCSV(){
  // Build ledger from live data: sales (credits), expenses (debits), rentals (credits)
  const lines=[];
  D.sales.forEach(s=>lines.push([s.dt,'Sale',s.id,s.cust+' — '+s.items,'',_fmtRaw(s.paid||s.amt)]));
  D.rentals.forEach(r=>lines.push([r.start,'Rental',r.id,r.cust+' — '+r.item,'',_fmtRaw(r.total||r.fee)]));
  D.exp.forEach(e=>lines.push([e.dt,'Expense',e.id,e.cat+' — '+(e.payee||''),_fmtRaw(e.amt),'']));
  D.purchases.forEach(p=>{if(p.st==='Paid')lines.push([p.dt,'Purchase',p.id,p.vendor+' — '+p.items,_fmtRaw(p.total),'']);});
  lines.sort((a,b)=>b[0].localeCompare(a[0]));
  const headers=['Date','Type','Reference','Description','Debit','Credit'];
  downloadCSV('ledger_'+new Date().toISOString().slice(0,10)+'.csv', lines, headers);
}

// ============================================================
// FULL BUSINESS DATA EXPORT -- multi-sheet Excel workbook
// Reports page: "Export All Data (.xlsx)" button
// ============================================================
function exportAllDataXLSX(){
  if(!canEdit('export_data')){ toast('You do not have permission to export data','error'); return; }
  _loadSheetJS(function(){
    toast('Building Excel export...','info');
    var wb  = XLSX.utils.book_new();
    var r   = CUR.rate||1;
    var cur = CUR.code||'USD';
    var dt  = new Date().toISOString().slice(0,10);
    function safe(v){ return (v===null||v===undefined)?'':v; }
    function money(v){ return Math.round((v||0)*r*100)/100; }

    function makeSheet(headers, rows){
      var aoa = [headers].concat(rows);
      var ws  = XLSX.utils.aoa_to_sheet(aoa);
      ws['!cols'] = headers.map(function(h){ return {wch: Math.max(12,(h||'').length+4)}; });
      return ws;
    }

    // -- 1. Business Summary -----------------------------------------
    var allRange = {start:'2000-01-01',end:'2099-12-31',label:'All Time'};
    var k = computeKPIs(allRange);
    var summaryRows = [
      ['Business Name',       safe(BIZ.name)],
      ['Owner',               safe(BIZ.owner||SESSION.name||'')],
      ['Email',               safe(BIZ.email)],
      ['Phone',               safe(BIZ.phone)],
      ['Country',             safe(BIZ.country)],
      ['Currency',            cur],
      ['Tax Name',            safe(BIZ.taxName)],
      ['Tax Rate (%)',        BIZ.taxRate||0],
      ['Plan',                safe(BIZ.plan)],
      ['Export Date',         dt],
      [''],
      ['--- KEY METRICS (ALL TIME) ---',''],
      ['Total Revenue',       money(k.rev)],
      ['Gross Profit',        money(k.gp)],
      ['Net Profit',          money(k.np)],
      ['Total COGS',          money(k.cogs)],
      ['Total Expenses',      money(k.oh)],
      ['Cash In',             money(k.cashIn)],
      ['Cash Out',            money(k.cashOut)],
      ['Accounts Receivable', money(k.ar)],
      ['Accounts Payable',    money(k.ap)],
      ['Inventory Value',     money(k.invVal)],
      [''],
      ['--- RECORD COUNTS ---',''],
      ['Inventory Items',     D.inv.length],
      ['Sales',               D.sales.length],
      ['Rentals',             D.rentals.length],
      ['Purchase Orders',     D.purchases.length],
      ['Customers',           D.cust.length],
      ['Vendors',             D.vendors.length],
      ['Expenses',            D.exp.length],
      ['Services',            (D.services||[]).length],
      ['Appointments',        (D.appointments||[]).length],
    ];
    var wsSummary = XLSX.utils.aoa_to_sheet(summaryRows);
    wsSummary['!cols'] = [{wch:28},{wch:32}];
    XLSX.utils.book_append_sheet(wb, wsSummary, 'Business Summary');

    // -- 2. Inventory ------------------------------------------------
    var invH = ['ID','SKU','Name','Category','Brand','Status','Condition',
      'Cost ('+cur+')','Sell Price ('+cur+')','Rental/Day ('+cur+')',
      'Min Sell ('+cur+')','Deposit ('+cur+')',
      'Qty Total','Qty Rented','Qty Available','Color','Size','Description'];
    var invR = D.inv.map(function(i){return [
      safe(i.id),safe(i.sku),safe(i.name),safe(i.cat),safe(i.brand),
      safe(i.st),safe(i.cond),
      money(i.cost),money(i.sp),money(i.rp||0),
      money(i.minSp||0),money(i.dep||0),
      i.qty||0,i.rented||0,(i.qty||0)-(i.rented||0),
      safe(i.color),safe(i.sz),safe(i.desc)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(invH, invR), 'Inventory');

    // -- 3. Sales ----------------------------------------------------
    var saleH = ['Sale #','Date','Customer','Description',
      'Subtotal ('+cur+')','Freight ('+cur+')','Tax ('+cur+')','Other ('+cur+')',
      'Total ('+cur+')','Paid ('+cur+')','Balance ('+cur+')',
      'COGS ('+cur+')','Gross Profit ('+cur+')','Status','Payment Method','Notes'];
    var saleR = D.sales.map(function(s){
      var tot=s.total||s.amt||0;
      return [safe(s.id),safe(s.dt),safe(s.cust),safe(s.items),
        money(s.amt),money(s.freight||0),money(s.taxes||0),money(s.other||0),
        money(tot),money(s.paid||0),money(tot-(s.paid||0)),
        money(s.cost||0),money(tot-(s.cost||0)), // always recompute profit = revenue - COGS
        safe(s.st),safe(s.method),safe(s.notes)];
    });
    XLSX.utils.book_append_sheet(wb, makeSheet(saleH, saleR), 'Sales');

    // -- 4. Rentals --------------------------------------------------
    var rentH = ['Rental #','Customer','Item','Start Date','Due Date','Return Date',
      'Rental Fee ('+cur+')','Deposit ('+cur+')','Late Fee ('+cur+')',
      'Total Charged ('+cur+')','Total Paid ('+cur+')',
      'Status','Payment Method','Condition Out','Condition In','Contract Signed','Notes'];
    var rentR = D.rentals.map(function(r){return [
      safe(r.id),safe(r.cust),safe(r.item),
      safe(r.start),safe(r.due),safe(r.ret||r.returnDate||''),
      money(r.fee),money(r.dep||0),money(r.lf||r.lateFee||0),
      money(r.total||r.fee),money(r.paid||0),
      safe(r.st),safe(r.method),safe(r.cb),safe(r.ca),
      r.contractSigned?'Yes':'No',safe(r.notes)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(rentH, rentR), 'Rentals');

    // -- 5. Purchases ------------------------------------------------
    var poH = ['PO #','Date','Vendor','Items','Qty',
      'Subtotal ('+cur+')','Freight ('+cur+')','Duties ('+cur+')','Taxes ('+cur+')','Other ('+cur+')',
      'Total ('+cur+')','Status','Payment Method','Delivery Date','Notes'];
    var poR = D.purchases.map(function(p){return [
      safe(p.id),safe(p.dt),safe(p.vendor),safe(p.items),safe(p.qty),
      money(p.sub),money(p.freight||0),money(p.duties||0),
      money(p.taxes||0),money(p.other||0),money(p.total),
      safe(p.st),safe(p.method),safe(p.delivery),safe(p.notes)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(poH, poR), 'Purchases');

    // -- 6. Customers ------------------------------------------------
    var custH = ['ID','Name','Type','Email','Phone','WhatsApp',
      'Address','Total Spend ('+cur+')','Outstanding ('+cur+')','Visits',
      'Last Activity','Status','Notes'];
    var custR = D.cust.map(function(c){return [
      safe(c.id),safe(c.name),safe(c.type||(c.vip?'VIP':'Regular')),
      safe(c.email),safe(c.ph||c.phone),safe(c.whatsapp),
      safe(c.addr||c.city),
      money(c.spend||c.spent||0),money(c.bal||0),
      c.visits||0,safe(c.last),safe(c.st||'Active'),safe(c.notes)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(custH, custR), 'Customers');

    // -- 7. Vendors --------------------------------------------------
    var vendH = ['ID','Name','Category','Country','Contact',
      'Email','Phone',
      'Total Purchases ('+cur+')','Outstanding ('+cur+')','Orders',
      'Payment Terms','Payment Method','Status','Notes'];
    var vendR = D.vendors.map(function(v){return [
      safe(v.id),safe(v.name),safe(v.cat),safe(v.country),
      safe(v.contact),safe(v.email),safe(v.phone||v.ph),
      money(v.total||0),money(v.bal||0),v.orders||0,
      safe(v.terms),safe(v.method||v.payment),
      safe(v.st||'Active'),safe(v.notes)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(vendH, vendR), 'Vendors');

    // -- 8. Expenses -------------------------------------------------
    var expH = ['Exp #','Date','Category','Payee',
      'Amount ('+cur+')','Type','Payment Method','Notes'];
    var expR = D.exp.map(function(e){return [
      safe(e.id),safe(e.dt),safe(e.cat),safe(e.payee),
      money(e.amt),safe(e.type),safe(e.method),safe(e.notes)
    ];});
    XLSX.utils.book_append_sheet(wb, makeSheet(expH, expR), 'Expenses');

    // -- 9. Services (if any) ----------------------------------------
    if((D.services||[]).length){
      var svcH = ['ID','Name','Category','Duration (min)',
        'Price ('+cur+')','Deposit ('+cur+')','Active','Description'];
      var svcR = (D.services||[]).map(function(s){return [
        safe(s.id),safe(s.name),safe(s.cat),
        s.duration||0,money(s.price||0),money(s.deposit||0),
        s.active!==false?'Yes':'No',safe(s.desc)
      ];});
      XLSX.utils.book_append_sheet(wb, makeSheet(svcH, svcR), 'Services');
    }

    // -- 10. Appointments (if any) -----------------------------------
    if((D.appointments||[]).length){
      var apptH = ['ID','Date','Time','Customer','Customer Phone',
        'Service','Staff',
        'Total ('+cur+')','Paid ('+cur+')','Payment Method','Status','Notes'];
      var apptR = (D.appointments||[]).map(function(a){return [
        safe(a.id),safe(a.date),safe(a.startTime||a.time||''),
        safe(a.custName),safe(a.custPhone),
        safe(a.serviceName),safe(a.staffName),
        money(a.totalAmt||0),money(a.paid||0),safe(a.payMethod),
        safe(a.st),safe(a.notes)
      ];});
      XLSX.utils.book_append_sheet(wb, makeSheet(apptH, apptR), 'Appointments');
    }

    // -- 11. Cash Ledger ---------------------------------------------
    var ledLines = [];
    D.sales.forEach(function(s){ledLines.push([safe(s.dt),'Sale',safe(s.id),safe(s.cust)+' - '+safe(s.items),'',money(s.paid||s.amt)]);});
    D.rentals.forEach(function(r){ledLines.push([safe(r.start),'Rental',safe(r.id),safe(r.cust)+' - '+safe(r.item),'',money(r.total||r.fee)]);});
    D.exp.forEach(function(e){ledLines.push([safe(e.dt),'Expense',safe(e.id),safe(e.cat)+' - '+safe(e.payee||''),money(e.amt),'']);});
    D.purchases.forEach(function(p){if(p.st==='Paid')ledLines.push([safe(p.dt),'Purchase',safe(p.id),safe(p.vendor)+' - '+safe(p.items),money(p.total),'']);});
    (D.appointments||[]).forEach(function(a){if(a.paid>0)ledLines.push([safe(a.date),'Service',safe(a.id),safe(a.custName)+' - '+safe(a.serviceName),'',money(a.paid||0)]);});
    ledLines.sort(function(a,b){return (b[0]||'').localeCompare(a[0]||'');});
    var ledH = ['Date','Type','Reference','Description','Debit ('+cur+')','Credit ('+cur+')'];
    XLSX.utils.book_append_sheet(wb, makeSheet(ledH, ledLines), 'Ledger');

    // -- 12. Audit Log -----------------------------------------------
    if((D.audit||[]).length){
      var auditH = ['Timestamp','User','Role','Action','Record','Old Value','New Value'];
      var auditR = (D.audit||[]).map(function(a){return [
        safe(a.ts),safe(a.user),safe(a.role),
        safe(a.action),safe(a.rec),safe(a.old),safe(a.nw)
      ];});
      XLSX.utils.book_append_sheet(wb, makeSheet(auditH, auditR), 'Audit Log');
    }

    // -- Write file --------------------------------------------------
    var bizSlug = (BIZ.name||'ShopTrack').replace(/[^a-zA-Z0-9]/g,'_').substring(0,20);
    var filename = bizSlug+'_Full_Export_'+dt+'.xlsx';
    XLSX.writeFile(wb, filename);
    toast('Excel export ready: '+filename,'success');
    addAudit('Full data export downloaded','Excel: '+filename);
  });
}


