// ── Password hashing using Web Crypto (SHA-256) ──────────────────────────
async function _hashPwd(password){
  try {
    const msgBuffer = new TextEncoder().encode(password + 'shoptrack_salt_2026');
    const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2,'0')).join('');
  } catch(e) {
    // Fallback if crypto not available
    return password;
  }
}
// Verify password against stored hash
async function _verifyPwd(password, stored){
  if(!stored || stored.length < 32) return password === stored; // plain text fallback
  const hashed = await _hashPwd(password);
  return hashed === stored;
}

// ── Plan expiry check — show warning banner ──────────────────────────────
// ── Trial expiry enforcement — 3 states ──────────────────────
// daysLeft > 7  : nothing shown
// 0 < daysLeft ≤ 7  : warning banner, full access
// -7 ≤ daysLeft ≤ 0 : read-only grace period + paywall modal (dismissible)
// daysLeft < -7 : hard block paywall (not dismissible)
function _checkPlanExpiry(){
  if(SESSION.isSuperAdmin) return;
  if(!SESSION.bizId) return;
  if(SESSION.bizId==='BIZ-001'||SESSION.bizId==='BIZ-107') return;
  var expiryStr = BIZ.subExpires
    || ((D.adminBiz.find(function(b){ return b.id===SESSION.bizId; })||{}).trialEnd)
    || null;
  if(!expiryStr) return;
  var today = new Date(); today.setHours(0,0,0,0);
  var expiry = new Date(expiryStr+'T00:00:00');
  var daysLeft = Math.ceil((expiry - today) / (1000*60*60*24));
  // Auto-create the banner if it doesn't exist in HTML — no HTML file changes needed
  var banner = document.getElementById('plan-expiry-banner');
  if(!banner){
    banner = document.createElement('div');
    banner.id = 'plan-expiry-banner';
    banner.style.cssText = 'display:none;align-items:center;gap:10px;padding:9px 16px;'
      +'background:rgba(245,158,11,.08);border-bottom:1px solid rgba(245,158,11,.25);'
      +'font-size:13px;font-weight:500;color:var(--ink);position:sticky;top:0;z-index:9000;flex-wrap:wrap';
    banner.innerHTML = '<span class="peb-msg" style="flex:1;min-width:200px"></span>'
      +'<button class="peb-upgrade-btn btn btn-p btn-sm" style="display:none;white-space:nowrap;flex-shrink:0">'
        +'\u25b6 Upgrade Now'
      +'</button>'
      +'<button onclick="document.getElementById(\'plan-expiry-banner\').style.display=\'none\'" '
        +'style="background:none;border:none;color:var(--text2);cursor:pointer;font-size:18px;padding:0 4px;line-height:1;flex-shrink:0">'
        +'\u00d7'
      +'</button>';
    var page = document.getElementById('page');
    if(page && page.parentNode) page.parentNode.insertBefore(banner, page);
    else document.body.insertBefore(banner, document.body.firstChild);
  }
  if(daysLeft > 7){ banner.style.display='none'; return; }
  if(daysLeft > 0){
    banner.style.display='flex'; banner.style.background=''; banner.style.borderColor='';
    var msgEl=banner.querySelector('.peb-msg');
    if(msgEl) msgEl.textContent='\u23f0 Your trial expires in '+daysLeft+' day'+(daysLeft!==1?'s':'')+'. Upgrade now to keep all your data.';
    var btnEl=banner.querySelector('.peb-upgrade-btn');
    if(btnEl){ btnEl.style.display=''; btnEl.onclick=function(){ _showTrialPaywall(daysLeft,false); }; }
    return;
  }
  // EXPIRED
  banner.style.display='flex';
  banner.style.background='rgba(220,38,38,.08)'; banner.style.borderColor='rgba(220,38,38,.25)';
  var msgEl2=banner.querySelector('.peb-msg');
  var ago = daysLeft===0?'today':Math.abs(daysLeft)+' day'+(Math.abs(daysLeft)!==1?'s':'')+' ago';
  if(msgEl2) msgEl2.textContent='\u26a0\ufe0f Your trial ended '+ago+'. Your data is safe \u2014 upgrade to continue.';
  var btnEl2=banner.querySelector('.peb-upgrade-btn');
  if(btnEl2){ btnEl2.style.display=''; btnEl2.onclick=function(){ _showTrialPaywall(daysLeft,true); }; }
  window._trialReadOnly  = (daysLeft >= -7);
  window._trialHardBlock = (daysLeft < -7);
  _showTrialPaywall(daysLeft, window._trialHardBlock);
}

// ── Full-screen paywall modal ──────────────────────────────────
function _showTrialPaywall(daysLeft, hardBlock){
  if(document.getElementById('trial-paywall-overlay')) return;
  var salesCount = D.sales.length;
  var custCount  = D.cust.length;
  var invCount   = D.inv.length;
  var totalRev   = D.sales.reduce(function(a,s){ return a+(s.total||s.amt||0); },0)
    + D.rentals.filter(function(r){ return r.st==='Returned'||r.st==='Checked Out'||r.st==='Overdue'; })
               .reduce(function(a,r){ return a+(r.fee||0); },0);
  var statusLine = daysLeft===0 ? 'Your trial ended today.'
    : daysLeft<0  ? 'Your trial ended '+Math.abs(daysLeft)+' day'+(Math.abs(daysLeft)!==1?'s':'')+' ago.'
    : 'Your trial expires in '+daysLeft+' day'+(daysLeft!==1?'s':'')+'.';
  var accessMsg = hardBlock
    ? 'Your account is in read-only mode. You can view your data but cannot record new sales, add products, or make any changes until you upgrade.'
    : 'You have a 7-day grace period. You can view all your data but cannot record new transactions until you upgrade.';
  var ov = document.createElement('div');
  ov.id = 'trial-paywall-overlay';
  ov.style.cssText = 'position:fixed;inset:0;z-index:99999;display:flex;align-items:center;justify-content:center;background:rgba(15,17,30,.82);backdrop-filter:blur(4px);padding:16px;box-sizing:border-box';
  ov.innerHTML =
    '<div style="background:var(--bg2);border:1px solid var(--border2);border-radius:16px;max-width:520px;width:100%;overflow:hidden;box-shadow:0 24px 60px rgba(0,0,0,.5)">'
    +'<div style="background:linear-gradient(135deg,#dc2626,#991b1b);padding:20px 24px;text-align:center">'
      +'<div style="font-size:28px;margin-bottom:8px">\uD83D\uDD12</div>'
      +'<div style="font-size:18px;font-weight:800;color:#fff;font-family:var(--display)">Trial Ended</div>'
      +'<div style="font-size:13px;color:rgba(255,255,255,.75);margin-top:4px">'+statusLine+'</div>'
    +'</div>'
    +'<div style="padding:20px 24px 0">'
      +'<div style="font-size:11px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;margin-bottom:10px">Your data is safe \u2014 waiting for you</div>'
      +'<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:14px">'
        +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:10px;padding:11px;text-align:center"><div style="font-size:19px;font-weight:800;color:var(--a);font-family:var(--mono)">'+salesCount+'</div><div style="font-size:10px;color:var(--text2);margin-top:2px">Sales</div></div>'
        +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:10px;padding:11px;text-align:center"><div style="font-size:19px;font-weight:800;color:var(--g);font-family:var(--mono)">'+custCount+'</div><div style="font-size:10px;color:var(--text2);margin-top:2px">Customers</div></div>'
        +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:10px;padding:11px;text-align:center"><div style="font-size:19px;font-weight:800;color:var(--p);font-family:var(--mono)">'+invCount+'</div><div style="font-size:10px;color:var(--text2);margin-top:2px">Products</div></div>'
        +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:10px;padding:11px;text-align:center"><div style="font-size:15px;font-weight:800;color:var(--g);font-family:var(--mono)">'+fmtKpi(totalRev)+'</div><div style="font-size:10px;color:var(--text2);margin-top:2px">Revenue</div></div>'
      +'</div>'
      +'<div style="background:rgba(220,38,38,.08);border:1px solid rgba(220,38,38,.2);border-radius:8px;padding:10px 12px;font-size:12px;color:#dc2626;margin-bottom:14px">\u26a0\ufe0f '+accessMsg+'</div>'
      +'<div style="font-size:11px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;margin-bottom:8px">Choose your plan to continue</div>'
      +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">'
        +'<div style="border:1.5px solid var(--border2);border-radius:10px;padding:13px;cursor:pointer" id="pw-starter-card" onclick="_pwSelectPlan(\'Starter\')">'
          +'<div style="font-size:10px;font-weight:700;color:var(--text2);margin-bottom:4px">\uD83C\uDF31 STARTER</div>'
          +'<div style="font-size:18px;font-weight:800;color:var(--ink)">4,900 <span style="font-size:11px;font-weight:400;color:var(--text2)">XAF/mo</span></div>'
          +'<div style="font-size:11px;color:var(--text2);margin-top:3px">1 user \u00b7 All core features</div>'
        +'</div>'
        +'<div style="border:2px solid var(--a);border-radius:10px;padding:13px;cursor:pointer;position:relative;background:var(--a-dim)" id="pw-pro-card" onclick="_pwSelectPlan(\'Pro\')">'
          +'<div style="position:absolute;top:-9px;left:50%;transform:translateX(-50%);background:var(--a);color:#fff;font-size:9px;font-weight:800;padding:2px 10px;border-radius:20px;white-space:nowrap">\u2b50 MOST POPULAR</div>'
          +'<div style="font-size:10px;font-weight:700;color:var(--a);margin-bottom:4px">\uD83D\uDE80 PRO</div>'
          +'<div style="font-size:18px;font-weight:800;color:var(--ink)">11,900 <span style="font-size:11px;font-weight:400;color:var(--text2)">XAF/mo</span></div>'
          +'<div style="font-size:11px;color:var(--text2);margin-top:3px">5 users \u00b7 AI Studio \u00b7 Rentals</div>'
        +'</div>'
      +'</div>'
    +'</div>'
    +'<div style="padding:0 24px 20px">'
      +'<button id="pw-upgrade-btn" onclick="_pwProceed()" style="width:100%;padding:13px;background:var(--a);color:#fff;border:none;border-radius:10px;font-size:14px;font-weight:800;cursor:pointer;font-family:inherit">\u25b6 Upgrade Now \u2014 Keep My Data</button>'
      +(hardBlock ? '' : '<button onclick="_pwDismiss()" style="width:100%;margin-top:8px;padding:9px;background:none;border:none;color:var(--text2);font-size:12px;cursor:pointer;font-family:inherit">Continue in read-only mode \u2192</button>')
      +'<div style="text-align:center;font-size:11px;color:var(--text3);margin-top:10px">Data preserved for 60 days after trial \u00b7 Cancel anytime \u00b7 No credit card required during trial</div>'
    +'</div>'
  +'</div>';
  document.body.appendChild(ov);
  window._pwSelectedPlan = 'Pro';
  _pwSelectPlan('Pro');
}

function _pwSelectPlan(plan){
  window._pwSelectedPlan = plan;
  var sc=document.getElementById('pw-starter-card'), pc=document.getElementById('pw-pro-card');
  if(!sc||!pc) return;
  if(plan==='Starter'){
    sc.style.borderColor='var(--a)'; sc.style.background='var(--a-dim)';
    pc.style.borderColor='var(--border2)'; pc.style.background='';
  } else {
    pc.style.borderColor='var(--a)'; pc.style.background='var(--a-dim)';
    sc.style.borderColor='var(--border2)'; sc.style.background='';
  }
  var btn=document.getElementById('pw-upgrade-btn');
  if(btn) btn.textContent='\u25b6 Upgrade to '+plan+' \u2014 '+(plan==='Pro'?'11,900':'4,900')+' XAF/mo';
}

function _pwDismiss(){
  var ov=document.getElementById('trial-paywall-overlay'); if(ov) ov.remove();
  toast('\uD83D\uDC40 Read-only mode \u2014 you can view your data but not record new transactions','info');
}

function _pwProceed(){
  var ov=document.getElementById('trial-paywall-overlay'); if(ov) ov.remove();
  var selectedPlan = window._pwSelectedPlan || 'Starter';
  var planId = (selectedPlan==='Pro'||selectedPlan==='Professional') ? 'Professional' : 'Starter';
  if(_sb && SESSION.bizId){
    _sb.from('businesses').update({plan:planId}).eq('id',SESSION.bizId).then(function(r){
      if(r&&r.error){toast('Could not set plan: '+r.error.message,'error');return;}
      BIZ.plan=planId;
      BIZ.subExpires=BIZ.subExpires||BIZ.trialEnd||'';
      addAudit('Trial converted via paywall',SESSION.bizId+' to '+planId);
    });
  } else { BIZ.plan=planId; }
  setTimeout(function(){ mSubPayNow(); }, 200);
}

// ── Write-guard — call at top of any save function ─────────────
// Returns true if the write is blocked (caller should return immediately)
function _trialWriteBlocked(actionLabel){
  if(SESSION.isSuperAdmin) return false;
  if(SESSION.bizId==='BIZ-001'||SESSION.bizId==='BIZ-107') return false;
  if(window._trialHardBlock || window._trialReadOnly){
    _showTrialPaywall(-8, !!window._trialHardBlock);
    toast((actionLabel||'This action')+' is paused \u2014 please upgrade to continue recording','error');
    return true;
  }
  return false;
}

// ── Record vendor payment (AP) ───────────────────────────────────────────
function mPayVendor(vendorId){
  const v = D.vendors.find(x=>x.id===vendorId);
  if(!v) return;
  const today = localDateStr();
  modal(`💰 Pay ${v.name}`,`
  <div class="alrt alrt-r" style="margin-bottom:14px">
    <strong>Outstanding Balance: ${fmt(v.bal)}</strong><br>
    <span style="font-size:12px">This payment will reduce the vendor balance.</span>
  </div>
  <div class="fg-2">
    <div class="fg"><label class="fl">Payment Amount</label>
      <input class="fi" id="vp-amt" type="number" value="${(v.bal*CUR.rate).toFixed(2)}" min="0" step="0.01" placeholder="Amount in ${CUR.code}"/></div>
    <div class="fg"><label class="fl">Payment Date</label>
      <input class="fi" id="vp-dt" type="date" value="${today}"/></div>
  </div>
  <div class="fg-2">
    <div class="fg"><label class="fl">Payment Method</label>
      <select class="fs" id="vp-method">
        <option>Bank Transfer</option><option>Cash</option>
        <option>Mobile Money</option><option>Cheque</option><option>Card</option>
      </select></div>
    <div class="fg"><label class="fl">Reference / Note</label>
      <input class="fi" id="vp-ref" placeholder="e.g. Bank ref, receipt no…"/></div>
  </div>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button>
   <button class="btn btn-p" onclick="
     const amtDisplay = parseFloat(document.getElementById('vp-amt').value)||0;
     if(!amtDisplay){ toast('Enter a payment amount','error'); return; }
     const amtUSD = amtDisplay / CUR.rate;
     const dt  = document.getElementById('vp-dt').value||localDateStr();
     const mth = document.getElementById('vp-method').value;
     const ref = document.getElementById('vp-ref').value.trim();
     const vnd = D.vendors.find(x=>x.id==='${vendorId}');
     if(!vnd){ toast('Vendor not found','error'); return; }
     const prev = vnd.bal||0;
     vnd.bal = Math.max(0, prev - amtUSD);
     // Record as an expense entry
     var _mxEN=D.exp.reduce(function(m,e){var n=parseInt((e.id||'').replace(/\D/g,''),10)||0;return n>m?n:m;},0);
     const expId = 'EX-' + String(_mxEN+1).padStart(3,'0');
     const newExp = {
       id:expId, dt, cat:'Vendor Payment',
       payee:vnd.name,
       amt:amtUSD, type:'One-time', method:mth,
       notes:'Payment to ' + vnd.name + (ref?' — Ref: '+ref:''),
       st:'Paid', docs:[]
     };
     D.exp.unshift(newExp);
     _dbSaveExp(newExp);
     _dbSaveVendor(vnd);
     refreshLiveKpis();
     addAudit('Vendor payment recorded', vnd.name + ' — ' + fmt(amtUSD) + ' via ' + mth);
     closeModal();
     toast('Payment of ' + fmt(amtUSD) + ' recorded for ' + vnd.name, 'success');
     // Refresh current page if on vendors or accounting
     if(curPage==='vendors'||curPage==='accounting'||curPage==='purchases') nav(curPage);
   ">💰 Record Payment</button>`,'sm');
}

// ── Keyboard shortcuts ───────────────────────────────────────────────────
document.addEventListener('keydown', function(e){
  if(!SESSION.userId) return; // not logged in
  // Ignore when typing in inputs
  if(['INPUT','TEXTAREA','SELECT'].includes(e.target.tagName)) return;
  // Ctrl/Cmd + shortcuts
  if((e.ctrlKey||e.metaKey) && !e.shiftKey){
    switch(e.key){
      case 'i': e.preventDefault(); nav('inventory'); break;
      case 's': e.preventDefault(); nav('sales'); break;
      case 'r': e.preventDefault(); nav('rentals'); break;
      case 'e': e.preventDefault(); nav('expenses'); break;
      case 'c': e.preventDefault(); nav('customers'); break;
      case 'k': e.preventDefault(); document.getElementById('global-search')?.focus(); break;
      case 'a': e.preventDefault(); nav('appointments'); break;
    }
  }
  // Escape closes top modal
  if(e.key==='Escape' && _mStack.length>0){ closeModal(); }
});

// ── Save indicator (subtle flash after DB write) ─────────────────────────
let _saveTimer;
function _syncDataFromCloud(){
  if(!SESSION.bizId||SESSION.isSuperAdmin||!_sb){ toast('Not connected to cloud','info'); return; }
  var syncBtn = document.getElementById('topbar-sync-btn');
  if(syncBtn){ syncBtn.textContent='↻'; syncBtn.style.animation='spin .8s linear infinite'; }
  Promise.all([_dbLoadBizProfile(SESSION.bizId), _dbLoadBizData(SESSION.bizId)])
    .then(function(){
      refreshLiveKpis();
      if(syncBtn){ syncBtn.textContent='↻'; syncBtn.style.animation=''; }
      toast('Data synced from cloud ✓','success');
      nav(curPage||'dashboard');
    })
    .catch(function(err){
      if(syncBtn){ syncBtn.textContent='↻'; syncBtn.style.animation=''; }
      toast('Sync failed — check connection','error');
    });
}

function _showSaved(){
  const el = document.getElementById('save-indicator');
  if(!el) return;
  el.style.opacity='1';
  clearTimeout(_saveTimer);
  _saveTimer = setTimeout(()=>{ el.style.opacity='0'; }, 1500);
}

// ── Auto-shrink long KPI values ──────────────────────────────────────────
function _autoSizeKpis(){
  document.querySelectorAll('.kpi-val').forEach(el=>{
    // Use innerText to get visible text only (excludes hidden elements), strip currency suffix
    const txt = (el.innerText||el.textContent||'').replace(/Frs|USD|NGN|GBP|EUR/g,'').trim();
    el.classList.remove('sm','xs');
    if(txt.length > 12) el.classList.add('xs');
    else if(txt.length > 8) el.classList.add('sm');
  });
}

// ── Accounting ledger type filter ────────────────────────────────────────
function filterLedger(el, type){
  if(el && el.parentElement){
    el.parentElement.querySelectorAll('.stab').forEach(b=>b.classList.remove('on'));
    el.classList.add('on');
  }
  const rows = document.querySelectorAll('#ledger-body tr');
  rows.forEach(function(row){
    const rowType = row.dataset.type||'';
    row.style.display = (!type || rowType===type) ? '' : 'none';
  });
}


