// ── DB helpers ──────────────────────────────────────────────
async function _dbToService(r){ return {id:r.id,name:r.name,duration:r.duration_mins!=null?r.duration_mins:60,price:r.price||0,color:r.color||'#4361ee',staffIds:r.staff_ids||[],active:r.active!==false,desc:r.description||'',imgDataUrl:r.img_data_url||null}; }
function _dbToAppt(r){ return {id:r.id,serviceId:r.service_id||'',serviceName:r.service_name||'',custId:r.customer_id||'',custName:r.customer_name||'',custPhone:r.customer_phone||'',staffId:r.staff_id||'',staffName:r.staff_name||'',date:r.date||'',startTime:r.start_time||'',endTime:r.end_time||'',st:r.status||'Reserved',notes:r.notes||'',walkIn:r.walk_in||false,totalAmt:r.total_amount||0,payMethod:r.pay_method||'Cash',saleId:r.sale_id||'',createdAt:r.created_at||''}; }
function _serviceDB(s,bizId){ return {id:s.id,biz_id:bizId,name:s.name,duration_mins:s.duration,price:s.price||0,price_type:s.priceType||'flat',category:s.cat||'',color:s.color||'#4361ee',staff_ids:s.staffIds||[],active:s.active!==false,description:s.desc||'',img_data_url:s.imgDataUrl||null}; }
function _apptDB(a,bizId){ return {id:a.id,biz_id:bizId,service_id:a.serviceId,service_name:a.serviceName,customer_id:a.custId,customer_name:a.custName,customer_phone:a.custPhone,staff_id:a.staffId,staff_name:a.staffName,date:a.date,start_time:a.startTime,end_time:a.endTime,status:a.st,notes:a.notes,walk_in:a.walkIn,total_amount:a.totalAmt,pay_method:a.payMethod||'',sale_id:a.saleId||''}; }
async function _dbSaveService(s){
  if(!_sb) return;
  if(!SESSION.bizId){
    for(var _w=0; _w<10; _w++){
      await new Promise(function(r){ setTimeout(r, 500); });
      if(SESSION.bizId) break;
    }
  }
  if(!SESSION.bizId){
    toast('Cannot save service — please sign out and sign in again','error');
    console.error('_dbSaveService: SESSION.bizId still null after waiting');
    return;
  }
  try{
    // Try full payload (includes price_type and category if columns exist)
    var payload = _serviceDB(s, SESSION.bizId);
    var {error} = await _sb.from('services').upsert(payload);
    if(error){
      // If error is about missing columns, retry with base columns only
      if(error.message && (error.message.includes('price_type')||error.message.includes('category')||error.message.includes('column'))){
        console.warn('[ShopTrack] New service columns not yet in DB, falling back to base payload:', error.message);
        var base = {id:s.id,biz_id:SESSION.bizId,name:s.name,duration_mins:s.duration,price:s.price||0,color:s.color||'#4361ee',staff_ids:s.staffIds||[],active:s.active!==false,description:s.desc||'',img_data_url:s.imgDataUrl||null};
        var {error:e2} = await _sb.from('services').upsert(base);
        if(e2){
          console.error('_dbSaveService fallback error:', e2.message);
          toast('Service saved locally but cloud sync failed: '+e2.message,'error');
        } else {
          _showSaved();
          console.log('[ShopTrack] Service saved (base columns) to Supabase:', s.name);
        }
      } else {
        console.error('_dbSaveService error:', error.message);
        toast('Service saved locally but cloud sync failed: '+error.message,'error');
      }
    } else {
      _showSaved();
      console.log('[ShopTrack] Service saved to Supabase:', s.name, 'biz:', SESSION.bizId);
    }
  }catch(e){ _dbErr('saveService',e); }
}
async function _dbSaveAppt(a){ if(!_sb||!SESSION.bizId) return; try{ await _sb.from('appointments').upsert(_apptDB(a,SESSION.bizId)); _showSaved(); }catch(e){ _dbErr('saveAppt',e); } }
async function _dbDelService(id){ if(!_sb||!SESSION.bizId) return; try{ await _sb.from('services').delete().eq('id',id).eq('biz_id',SESSION.bizId); }catch(e){ _dbErr('delService',e); } }
async function _dbDelAppt(id){ if(!_sb||!SESSION.bizId) return; try{ await _sb.from('appointments').delete().eq('id',id).eq('biz_id',SESSION.bizId); }catch(e){ _dbErr('delAppt',e); } }

// ── Helpers ──────────────────────────────────────────────────
function _newSvcId(){ var mx=(D.services||[]).reduce(function(m,s){var n=parseInt((s.id||'').replace(/[^0-9]/g,''),10)||0;return n>m?n:m;},0); return 'SVC-'+String(mx+1).padStart(3,'0'); }
function _newApptId(){ var mx=(D.appointments||[]).reduce(function(m,a){var n=parseInt((a.id||'').replace(/[^0-9]/g,''),10)||0;return n>m?n:m;},0); return 'APT-'+String(mx+1).padStart(4,'0'); }

// ── Pricing type helpers ──────────────────────────────────────
// Supported price types:
//  flat      – one fixed price, no duration multiplier
//  per_hour  – price × (duration_mins / 60)
//  per_min   – price × duration_mins
//  per_day   – price × (duration_mins / 1440)
//  per_week  – price × (duration_mins / 10080)
//  per_session – price per session/visit (same as flat, labelled differently for clarity)
//  starting  – minimum / "from" price; staff quotes final after assessment
var _PRICE_TYPES = [
  {value:'flat',       label:'Flat Rate',     hint:'Fixed price — same for every booking'},
  {value:'per_session',label:'Per Session',   hint:'Per visit / session — for packages and classes'},
  {value:'per_hour',   label:'Per Hour',      hint:'Price × hours of service (duration drives total)'},
  {value:'per_day',    label:'Per Day',       hint:'Day rate — for contractors, events, or long sessions'},
  {value:'per_week',   label:'Per Week',      hint:'Weekly rate — for ongoing engagements'},
  {value:'per_min',    label:'Per Minute',    hint:'Minute billing — for very short precision services'},
  {value:'starting',   label:'Starting From', hint:'Minimum price shown — final price quoted on-site'},
];
function _ptLabel(pt){ var t=_PRICE_TYPES.find(function(x){return x.value===pt;}); return t?t.label:'Flat Rate'; }
function _ptHint(pt){  var t=_PRICE_TYPES.find(function(x){return x.value===pt;}); return t?t.hint:''; }

// Compute the appointment total given a service's price, priceType, and duration in minutes
function _computeSvcTotal(price, priceType, durationMins){
  var p = price || 0;
  var d = durationMins || 60;
  switch(priceType){
    case 'per_hour':    return Math.round(p * (d / 60) * 100) / 100;
    case 'per_min':     return Math.round(p * d * 100) / 100;
    case 'per_day':     return Math.round(p * (d / 1440) * 100) / 100;
    case 'per_week':    return Math.round(p * (d / 10080) * 100) / 100;
    case 'flat':
    case 'per_session':
    case 'starting':
    default:            return p;
  }
}

// Format price label for display (e.g. "5,000 Frs/hr", "Starting from 10,000 Frs")
function _fmtSvcPrice(s){
  var base = fmt(s.price);
  switch(s.priceType){
    case 'per_hour':    return base + '<span style="font-size:10px;font-weight:500;opacity:.7">/hr</span>';
    case 'per_min':     return base + '<span style="font-size:10px;font-weight:500;opacity:.7">/min</span>';
    case 'per_day':     return base + '<span style="font-size:10px;font-weight:500;opacity:.7">/day</span>';
    case 'per_week':    return base + '<span style="font-size:10px;font-weight:500;opacity:.7">/wk</span>';
    case 'per_session': return base + '<span style="font-size:10px;font-weight:500;opacity:.7">/session</span>';
    case 'starting':    return '<span style="font-size:10px;font-weight:500;opacity:.7">from </span>' + base;
    default:            return base;
  }
}
function _addMins(time,mins){ const [h,m]=time.split(':').map(Number); const t=h*60+m+mins; return String(Math.floor(t/60)%24).padStart(2,'0')+':'+String(t%60).padStart(2,'0'); }
function _timeLabel(t){ if(!t) return ''; const [h,m]=t.split(':').map(Number); const ap=h>=12?'PM':'AM'; return ((h%12)||12)+':'+(m<10?'0':'')+m+' '+ap; }
function _apptCol(st){ return {Reserved:'#6366f1',Confirmed:'#0ea5e9','In Progress':'#f59e0b',Completed:'#059669','No-Show':'#ef4444',Cancelled:'#94a3b8'}[st]||'#6366f1'; }
function _apptBg(st){ return {Reserved:'rgba(99,102,241,.12)',Confirmed:'rgba(14,165,233,.12)','In Progress':'rgba(245,158,11,.12)',Completed:'rgba(5,150,105,.12)','No-Show':'rgba(239,68,68,.12)',Cancelled:'rgba(148,163,184,.12)'}[st]||'rgba(99,102,241,.12)'; }

// ── Badge updater ────────────────────────────────────────────
function _updateApptBadge(){
  const n=(D.appointments||[]).filter(a=>a.date===localDateStr()&&!['Completed','Cancelled','No-Show'].includes(a.st)).length;
  const b=document.getElementById('appt-badge');
  if(b){ b.style.display=n>0?'':'none'; b.textContent=n; }
}

