function _apptCalHTML(){
  const Y=_apptCalY, M=_apptCalM, today=localDateStr();
  const tY=+today.slice(0,4), tMo=+today.slice(5,7)-1, tD=+today.slice(8);
  const MN=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const DN=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const fd=new Date(Y,M,1).getDay(), dim=new Date(Y,M+1,0).getDate();
  const ms=`${Y}-${String(M+1).padStart(2,'0')}`;
  const pY=M===0?Y-1:Y, pM=M===0?11:M-1, nY=M===11?Y+1:Y, nM=M===11?0:M+1;
  const amap={};
  (D.appointments||[]).filter(a=>a.date&&a.date.startsWith(ms)&&a.st!=='Cancelled').forEach(a=>{ (amap[a.date]=amap[a.date]||[]).push(a); });
  const mA=(D.appointments||[]).filter(a=>a.date&&a.date.startsWith(ms));
  const mR=mA.filter(a=>a.st==='Completed').reduce((s,a)=>s+a.totalAmt,0);
  let cells='';
  for(let i=0;i<fd;i++) cells+=`<div style="min-height:78px"></div>`;
  for(let d=1;d<=dim;d++){
    const ds=`${Y}-${String(M+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const da=amap[ds]||[];
    const isTd=(Y===tY&&M===tMo&&d===tD), isSel=_apptCalSel===ds, isWe=new Date(Y,M,d).getDay()%6===0;
    const chips=da.slice(0,3).map(a=>`<div onclick="event.stopPropagation();mViewAppt('${a.id}')" title="${a.custName} ${_timeLabel(a.startTime)}" style="font-size:9px;font-weight:600;background:${_apptBg(a.st)};color:${_apptCol(a.st)};border-left:2px solid ${_apptCol(a.st)};padding:1px 3px;border-radius:2px;margin-bottom:1px;cursor:pointer;overflow:hidden;white-space:nowrap;text-overflow:ellipsis">${_timeLabel(a.startTime)} ${a.custName.split(' ')[0]}</div>`).join('');
    const more=da.length>3?`<div style="font-size:9px;color:var(--text2);padding:0 3px">+${da.length-3}</div>`:'';
    cells+=`<div onclick="_apptDay('${ds}')" style="min-height:78px;border:1px solid ${isSel||isTd?'var(--a)':'var(--border)'};border-radius:var(--r8);padding:4px 5px;background:${isSel?'rgba(67,97,238,.07)':isWe?'var(--bg3)':'var(--bg2)'};cursor:pointer;position:relative" onmouseover="this.style.borderColor='var(--a)'" onmouseout="this.style.borderColor='${isSel||isTd?'var(--a)':'var(--border)'}'" >
      <div style="font-size:11px;font-weight:${isTd?'800':'500'};color:${isTd?'#fff':isWe?'var(--text2)':'var(--text)'};margin-bottom:2px;display:flex;justify-content:space-between">
        <span${isTd?' style="background:var(--a);border-radius:50%;width:18px;height:18px;display:flex;align-items:center;justify-content:center;font-size:10px"':''}>${d}</span>
        ${da.length?`<span style="font-size:9px;background:var(--a-dim);color:var(--a);border-radius:8px;padding:0 4px;font-weight:700">${da.length}</span>`:''}
      </div>${chips}${more}
      <button onclick="event.stopPropagation();mNewAppt('${ds}')" title="Book" style="position:absolute;bottom:2px;right:2px;background:var(--a-dim);border:none;color:var(--a);cursor:pointer;border-radius:3px;width:16px;height:16px;font-size:12px;font-weight:700;opacity:0;transition:opacity .13s;display:flex;align-items:center;justify-content:center" onmouseover="this.style.opacity=1" onmouseout="this.style.opacity=0">+</button>
    </div>`;
  }
  const sd=_apptCalSel, sa=sd?(amap[sd]||[]):[];
  const sdFmt=sd?new Date(sd+'T12:00:00').toLocaleDateString('en-GB',{weekday:'long',day:'numeric',month:'long'}):'';
  return `
<div style="display:flex;gap:12px;align-items:flex-start">
  <div style="flex:1;min-width:0"><div class="card" style="padding:14px">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
      <button class="btn btn-g btn-sm" onclick="_apptNav(${pY},${pM})">‹</button>
      <div style="text-align:center"><div style="font-size:15px;font-weight:800;color:var(--ink);font-family:var(--display)">${MN[M]} ${Y}</div><div style="font-size:11px;color:var(--text2)">${mA.length} appt${mA.length!==1?'s':''} · ${fmt(mR)} revenue</div></div>
      <button class="btn btn-g btn-sm" onclick="_apptNav(${nY},${nM})">›</button>
    </div>
    <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:2px;margin-bottom:4px">${DN.map(d=>`<div style="text-align:center;font-size:9.5px;font-weight:700;color:var(--text2);text-transform:uppercase;padding:3px 0">${d}</div>`).join('')}</div>
    <div style="display:grid;grid-template-columns:repeat(7,1fr);gap:3px">${cells}</div>
    <div style="display:flex;gap:6px;margin-top:10px;flex-wrap:wrap;align-items:center">
      ${[['Reserved','#6366f1'],['Confirmed','#0ea5e9'],['In Progress','#f59e0b'],['Completed','#059669'],['No-Show','#ef4444'],['Cancelled','#94a3b8']].map(([s,c])=>`<span style="display:flex;align-items:center;gap:5px;background:var(--bg3);border-radius:20px;padding:4px 10px;border:1px solid var(--border)"><span style="width:11px;height:11px;background:${c};border-radius:3px;display:inline-block;flex-shrink:0"></span><span style="color:var(--ink);font-size:12px;font-weight:600">${s}</span></span>`).join('')}
    </div>
  </div></div>
  <div style="width:210px;flex-shrink:0"><div class="card" style="padding:12px;min-height:180px">
    ${sd?`<div style="font-size:11px;font-weight:700;color:var(--a);text-transform:uppercase;letter-spacing:.4px;margin-bottom:8px">${sdFmt}</div>
    ${sa.length===0?`<div style="text-align:center;padding:16px 0;color:var(--text2);font-size:12px">No appointments</div>
    <button class="btn btn-p btn-sm" style="width:100%;margin-top:4px" onclick="mNewAppt('${sd}')">+ Book</button>`:
    sa.map(a=>`<div style="border:1px solid var(--border);border-left:3px solid ${_apptCol(a.st)};border-radius:var(--r8);padding:8px 9px;margin-bottom:7px;cursor:pointer" onclick="mViewAppt('${a.id}')">
      <div style="font-size:12px;font-weight:700;color:var(--ink)">${a.custName}</div>
      <div style="font-size:11px;color:var(--text2)">${a.serviceName} · ${_timeLabel(a.startTime)}</div>
      ${a.staffName?`<div style="font-size:10px;color:var(--text2)">👤 ${a.staffName}</div>`:''}
      <div style="display:flex;gap:4px;margin-top:5px">
        <button class="btn btn-g btn-xs" onclick="event.stopPropagation();mViewAppt('${a.id}')">View</button>
        ${a.st==='Completed'?`<button class="btn btn-p btn-xs" onclick="event.stopPropagation();_apptCheckout('${a.id}')">Checkout</button>`:''}
      </div>
    </div>`).join('')}
    <button class="btn btn-s btn-sm" style="width:100%;margin-top:2px" onclick="mNewAppt('${sd}')">+ Add</button>`
    :`<div style="text-align:center;padding:30px 8px;color:var(--text2)"><div style="font-size:26px;margin-bottom:8px">📅</div><div style="font-size:12px">Click a day to view appointments</div></div>`}
  </div></div>
</div>`;
}
