function _naSync(){
  // Works for both plain <select> and searchable hidden input
  var svcId = (document.getElementById('na-s')||{}).value || _ssGetVal('na-s-wrap');
  var svc = (D.services||[]).find(function(s){ return s.id===svcId; });
  var dur = svc ? (svc.duration||60) : 60;
  var pr  = svc ? (svc.price||0) : 0;
  var pt  = svc ? (svc.priceType||'flat') : 'flat';
  var t   = (document.getElementById('na-t')||{value:'09:00'}).value||'09:00';
  var eEl = document.getElementById('na-e'); if(eEl) eEl.value=_addMins(t,dur);
  var aEl = document.getElementById('na-amt');
  if(aEl&&!aEl._t){
    var total=_computeSvcTotal(pr,pt,dur)*CUR.rate;
    aEl.value=total.toFixed(2);
  }
}
function _naCust(){
  // Works for both plain <select> and the searchable hidden input
  var custId = (document.getElementById('na-c')||{}).value || _ssGetVal('na-c-wrap');
  var cust = D.cust.find(function(c){ return c.id===custId; });
  var ph = cust ? (cust.phone||cust.whatsapp||'') : '';
  var phEl = document.getElementById('na-ph'); if(phEl) phEl.value = ph;
  var form = document.getElementById('na-new-cust-form');
  if(form && custId) form.style.display='none';
}

// ── Inline new customer inside appointment modal ─────────────
function _apptCheckout(id){
  const a=D.appointments.find(x=>x.id===id); if(!a){ toast('Not found','error'); return; }
  var _mxSN=D.sales.reduce(function(m,s){var n=parseInt((s.id||'').replace(/\D/g,''),10)||0;return n>m?n:m;},0);
  const sid='S-'+String(_mxSN+1).padStart(4,'0');
  const sale={id:sid,dt:a.date||localDateStr(),cust:a.custName,custId:a.custId||'',invId:'__custom__',
    items:a.serviceName+(a.staffName?' ('+a.staffName+')':''),
    amt:a.totalAmt,total:a.totalAmt,paid:a.totalAmt,cost:0,
    profit:a.totalAmt,st:'Paid',method:a.payMethod||'Cash',
    notes:'Appointment '+a.id};
  D.sales.unshift(sale);
  _dbSaveSale(sale);
  a.saleId=sid; _dbSaveAppt(a);
  // Update customer stats
  if(a.custId){
    const cust=D.cust.find(c=>c.id===a.custId);
    if(cust){
      cust.spent=(cust.spent||0)+a.totalAmt;
      cust.orders=(cust.orders||0)+1;
      cust.last=localDateStr();
      _dbSaveCust(cust);
    }
  }
  refreshLiveKpis();
  addAudit('Appointment checkout',a.id+' → Sale '+sid+' '+fmt(a.totalAmt));
  toast('Sale '+sid+' created for '+a.custName,'success');
  setTimeout(()=>{ if(confirm('Generate receipt for '+a.custName+'?')) genReceiptDoc(sid); },300);
}

function _apptWA(id){
  const a=D.appointments.find(x=>x.id===id); if(!a) return;
  const ph=(a.custPhone||'').replace(/[^0-9]/g,'');
  if(!ph){ toast('No phone number on record','error'); return; }
  const msg=encodeURIComponent('Hi '+a.custName.split(' ')[0]+'! 👋\n\nReminder: appointment at *'+BIZ.name+'*\n\n📋 *'+a.serviceName+'*\n📅 '+a.date+' at '+_timeLabel(a.startTime)+(a.staffName?'\n👤 with '+a.staffName:'')+'\n\nSee you soon! 😊\n\n_'+BIZ.name+'_');
  _sendWA(ph, decodeURIComponent(msg));
}

