function pgServices(){
  var activeCats=[...new Set((D.services||[]).filter(function(s){return s.cat;}).map(function(s){return s.cat;}))].sort();
  var out = '';

  // ── Page header ───────────────────────────────────────────
  out += '<div class="ph">';
  out += '<div class="bc">'+_esc(BIZ.name||'ShopTrack')+' / <span>${_ui.nav_services}</span></div>';
  out += '<div class="ph-row"><h1>Services</h1><div class="btn-row">';
  out += '<button class="btn btn-s btn-sm" onclick="_syncServicesToCloud()" title="Save all services to cloud so they appear on your booking page">\u2601 Sync to Cloud</button>';
  out += '<button class="btn btn-g btn-sm" onclick="_fixServicePrices()" title="Detect and fix prices that appear wrong on the booking page">🔧 Fix Prices</button>';
  out += '<button class="btn btn-g btn-sm" onclick="mDuplicateCategory(\'svc\')">⧉ Duplicate Category</button>';
  out += '<button class="btn btn-p btn-sm" onclick="mNewService()">+ Add Service</button>';
  out += '</div></div>';
  out += '<p>Your service catalog \u2014 manage pricing, duration, categories, and your booking page</p>';
  if(activeCats.length>1){
    out += '<div style="display:flex;flex-wrap:wrap;gap:6px;margin-top:10px">';
    out += '<button class="btn btn-s btn-sm" id="svc-cat-all" onclick="_filterSvcs(\'\')" style="border-color:var(--a);color:var(--a)">All</button>';
    activeCats.forEach(function(c){
      out += '<button class="btn btn-s btn-sm svc-cat-btn" onclick="_filterSvcs(\''+c.replace(/\\/g,'\\\\').replace(/'/g,"\\'")+'\')" >'+_esc(c)+'</button>';
    });
    out += '</div>';
  }
  out += '</div>';

  // ── Empty state ───────────────────────────────────────────
  if(!D.services.length){
    out += '<div class="card" style="text-align:center;padding:56px 24px">';
    out += '<div style="font-size:52px;margin-bottom:14px">\u2702\ufe0f</div>';
    out += '<div style="font-size:18px;font-weight:700;color:var(--ink);margin-bottom:6px">No services yet</div>';
    out += '<div style="color:var(--text2);margin-bottom:20px">Add your services so clients can book appointments online</div>';
    out += '<button class="btn btn-p" onclick="mNewService()">+ Add Your First Service</button>';
    out += '</div>';
    return out;
  }

  // ── Card grid ─────────────────────────────────────────────
  out += '<div id="svc-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:16px">';

  var ptColorMap = {flat:'var(--a)',per_session:'#7c3aed',per_hour:'#0284c7',per_day:'#0891b2',per_week:'#0f766e',per_min:'#dc2626',starting:'#d97706'};
  var ptSuffix   = {per_hour:'/hr',per_min:'/min',per_day:'/day',per_week:'/wk',per_session:'/session'};
  var ptPrefix   = {starting:'From '};

  D.services.forEach(function(s){
    var pt       = s.priceType||'flat';
    var ptL      = _ptLabel(pt);
    var ptColor  = ptColorMap[pt]||'var(--a)';
    var sColor   = s.color||'#4361ee';
    var inactive = s.active===false;

    // Duration label — "TBD" if 0 or not set
    var durLabel = (!s.duration || s.duration<=0) ? 'Duration TBD' : (s.duration+' min');

    // Price display
    var priceStr = '';
    if(ptPrefix[pt]) priceStr += '<span style="font-size:11px;font-weight:600;vertical-align:middle;letter-spacing:.2px;opacity:.75">'+ptPrefix[pt]+'</span>';
    priceStr += '<span style="font-size:20px;font-weight:900;letter-spacing:-.5px">'+fmt(s.price)+'</span>';
    if(ptSuffix[pt]) priceStr += '<span style="font-size:11px;font-weight:600;vertical-align:middle;opacity:.75">'+ptSuffix[pt]+'</span>';

    // Card wrapper — tall image area if photo exists
    var card = '';
    card += '<div class="card svc-card-item" data-svc-cat="'+_esc(s.cat||'')+'" style="'
      +'padding:0;overflow:hidden;border-left:4px solid '+sColor+';'
      +'display:flex;flex-direction:column;'
      +(inactive?'opacity:.55;':'')
      +'">';

    // ── Photo banner (full width, 160px tall if photo) ──
    if(s.imgDataUrl){
      card += '<div style="width:100%;height:160px;overflow:hidden;flex-shrink:0;position:relative;">';
      card += '<img src="'+s.imgDataUrl+'" style="width:100%;height:100%;object-fit:cover;display:block;"/>';
      // Inactive overlay
      if(inactive) card += '<div style="position:absolute;inset:0;background:rgba(0,0,0,.35);display:flex;align-items:center;justify-content:center"><span style="color:#fff;font-size:11px;font-weight:700;letter-spacing:1px;text-transform:uppercase;background:rgba(0,0,0,.5);padding:4px 10px;border-radius:20px">Inactive</span></div>';
      card += '</div>';
    } else {
      // Decorative coloured band
      card += '<div style="width:100%;height:6px;background:'+sColor+';flex-shrink:0;"></div>';
    }

    // ── Card body ──
    card += '<div style="padding:16px 16px 14px;flex:1;display:flex;flex-direction:column;gap:0">';

    // Row 1: name + status badge
    card += '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:8px">';
    card += '<div style="font-size:15px;font-weight:800;color:var(--ink);line-height:1.3;flex:1;min-width:0">'+_esc(s.name)+'</div>';
    var statusBadge = inactive
      ? '<span style="flex-shrink:0;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.6px;background:var(--r-dim);color:var(--r);padding:3px 7px;border-radius:10px">Inactive</span>'
      : '<span style="flex-shrink:0;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.6px;background:#dcfce7;color:#166534;padding:3px 7px;border-radius:10px">Active</span>';
    card += statusBadge;
    card += '</div>';

    // Row 2: category + pricing model pills
    card += '<div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:12px">';
    if(s.cat) card += '<span style="font-size:10px;font-weight:600;background:var(--bg3);color:var(--text2);padding:2px 8px;border-radius:10px;border:1px solid var(--border2)">'+_esc(s.cat)+'</span>';
    if(pt!=='flat') card += '<span style="font-size:10px;font-weight:700;background:'+ptColor+'18;color:'+ptColor+';padding:2px 8px;border-radius:10px;border:1px solid '+ptColor+'33">'+ptL+'</span>';
    card += '</div>';

    // Row 3: price + duration side by side — fully separated, no overlap
    card += '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;padding:10px 12px;background:var(--bg3);border-radius:8px;margin-bottom:12px;border:1px solid var(--border2)">';
    card += '<div style="color:'+sColor+'">'+priceStr+'</div>';
    card += '<div style="display:flex;align-items:center;gap:5px;flex-shrink:0">';
    card += '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" style="width:13px;height:13px;color:var(--text3);stroke-width:2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>';
    card += '<span style="font-size:12px;font-weight:600;color:var(--text2)">'+durLabel+'</span>';
    card += '</div>';
    card += '</div>';

    // Est. total for time-based pricing
    if(['per_hour','per_min','per_day','per_week'].indexOf(pt)>=0 && s.duration>0){
      card += '<div style="font-size:11px;color:var(--text3);margin-bottom:10px;padding:5px 10px;background:'+ptColor+'0c;border-radius:6px;border-left:3px solid '+ptColor+'">Est. booking total: <strong style="color:var(--ink)">'+fmt(_computeSvcTotal(s.price,pt,s.duration))+'</strong></div>';
    }

    // Description
    if(s.desc){
      card += '<div style="font-size:12px;color:var(--text2);line-height:1.55;margin-bottom:12px;flex:1">'+_esc(s.desc)+'</div>';
    } else {
      card += '<div style="flex:1"></div>';
    }

    // Staff
    var staffLabel = (s.staffIds&&s.staffIds.length)
      ? s.staffIds.map(function(sid){var u=BIZ_USERS.find(function(u){return u.id===sid;});return u?u.name:sid;}).join(', ')
      : 'Any staff';
    card += '<div style="font-size:11px;color:var(--text3);margin-bottom:12px;display:flex;align-items:center;gap:5px">';
    card += '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" style="width:12px;height:12px;stroke-width:2;flex-shrink:0"><path d="M20 21v-2a4 4 0 00-4-4H8a4 4 0 00-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>';
    card += '<span>'+_esc(staffLabel)+'</span>';
    card += '</div>';

    // Action buttons
    card += '<div style="display:flex;gap:8px;padding-top:10px;border-top:1px solid var(--border)">';
    card += '<button class="btn btn-p btn-sm" style="flex:1" onclick="mNewAppt();setTimeout(function(){var el=document.getElementById(\'na-s\');if(el){el.value=\''+s.id+'\';_naSync();}},100)">\ud83d\udcc5 Book</button>';
    card += '<button class="btn btn-g btn-sm" onclick="mEditSvc(\''+s.id+'\')">\u270f Edit</button>';
    card += '<button class="btn btn-sm" style="background:var(--r-dim);color:var(--r)" onclick="_delSvc(\''+s.id+'\')">\ud83d\uddd1</button>';
    card += '</div>';

    card += '</div>'; // end card body
    card += '</div>'; // end card
    out += card;
  });

  out += '</div>';
  return out;
}
// ── Service category filter ──────────────────────────────────
function _filterSvcs(cat){
  document.querySelectorAll('.svc-card-item').forEach(function(el){
    el.style.display=(!cat||el.dataset.svcCat===cat)?'':'none';
  });
  document.querySelectorAll('.svc-cat-btn').forEach(function(btn){
    btn.style.borderColor=btn.textContent.trim()===cat?'var(--a)':'';
    btn.style.color=btn.textContent.trim()===cat?'var(--a)':'';
  });
  var allBtn=document.getElementById('svc-cat-all');
  if(allBtn){allBtn.style.borderColor=cat?'':'var(--a)';allBtn.style.color=cat?'':'var(--a)';}
}
function _apptQuickStatus(id, newSt){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  a.st=newSt; _dbSaveAppt(a);
  addAudit('Appt status',id+' \u2192 '+newSt);
  toast(a.custName+' \u2014 '+newSt,'success');
  if(newSt==='Completed'&&(a.totalAmt||0)>0&&!a.saleId)
    setTimeout(function(){if(confirm('Checkout & create sale for '+a.custName+'?'))_apptCheckout(id);},300);
  nav('appointments');
}

// ── EDIT APPOINTMENT ─────────────────────────────────────────
function mEditAppt(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a){toast('Not found','error');return;}
  var svcOpts=D.services.filter(function(s){return s.active;}).map(function(s){var pt=s.priceType||'flat';var totalDisp=_computeSvcTotal(s.price,pt,s.duration)*CUR.rate;return '<option value="'+s.id+'" data-dur="'+s.duration+'" data-p="'+s.price+'" data-pt="'+pt+'"'+(s.id===a.serviceId?' selected':'')+'>'+s.name+' ('+s.duration+'min · '+fmt(s.price)+'/'+_ptLabel(pt)+')</option>';}).join('');
  var custOpts=D.cust.map(function(c){return '<option value="'+c.id+'" data-ph="'+(c.phone||c.whatsapp||'')+'"'+(c.id===a.custId?' selected':'')+'>'+c.name+'</option>';}).join('');
  var stfOpts=BIZ_USERS.filter(function(u){return u.bizId===SESSION.bizId;}).map(function(u){return '<option value="'+u.id+'"'+(u.id===a.staffId?' selected':'')+'>'+u.name+'</option>';}).join('');
  var stList=['Reserved','Confirmed','In Progress','Completed','No-Show','Cancelled'].map(function(s){return '<option'+(s===a.st?' selected':'')+'>'+s+'</option>';}).join('');
  modal('\u270F Edit \u2014 '+a.id,
    '<div class="fg-2">'
    +'<div class="fg"><label class="fl">Service</label><select class="fs" id="ea-svc" onchange="_eaSync()">'+svcOpts+'</select></div>'
    +'<div class="fg"><label class="fl">Date</label><input class="fi" id="ea-date" type="date" value="'+a.date+'"/></div>'
    +'<div class="fg"><label class="fl">Start</label><input class="fi" id="ea-st" type="time" value="'+(a.startTime||'09:00')+'" oninput="_eaSync()"/></div>'
    +'<div class="fg"><label class="fl">End</label><input class="fi" id="ea-et" type="time" value="'+(a.endTime||'')+'" readonly style="background:var(--bg3);color:var(--text2)"/></div>'
    +'</div>'
    +'<div class="fg">'+_newCustBtnHTML('ea')+'<select class="fs" id="ea-cust"><option value="">Walk-in</option>'+custOpts+'</select>'+_inlineCustFormHTML('ea')+'</div>'
    +'<div class="fg-2">'
    +'<div class="fg"><label class="fl">Phone</label><input class="fi" id="ea-phone" value="'+(a.custPhone||'')+'"/></div>'
    +'<div class="fg"><label class="fl">Staff</label><select class="fs" id="ea-staff"><option value="">Any</option>'+stfOpts+'</select></div>'
    +'<div class="fg"><label class="fl">Amount ('+CUR.symbol+')</label><input class="fi" id="ea-amt" type="number" value="'+Math.round((a.totalAmt||0)*CUR.rate*100)/100+'" step="0.01" oninput="this._t=true"/></div>'
    +'<div class="fg"><label class="fl">Status</label><select class="fs" id="ea-status">'+stList+'</select></div>'
    +'</div>'
    +'<div class="fg"><label class="fl">Notes</label><textarea class="ft" id="ea-notes" rows="2">'+(a.notes||'')+'</textarea></div>',
    '<button class="btn btn-d btn-sm" onclick="confirmDo(\'Delete this appointment?\',function(){_delAppt(\''+id+'\');})">&#128465;</button>'
    +' <button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +' <button class="btn btn-p" onclick="_saveEditAppt(\''+id+'\')">&#128190; Save</button>');
  setTimeout(_eaSync,60);
}
function _eaSync(){
  var sel=document.getElementById('ea-svc');
  var opt=sel&&sel.options[sel.selectedIndex];
  var dur=parseInt(opt&&opt.dataset&&opt.dataset.dur)||60;
  var pr=parseFloat(opt&&opt.dataset&&opt.dataset.p)||0;
  var pt=(opt&&opt.dataset&&opt.dataset.pt)||'flat';
  var st=document.getElementById('ea-st')?document.getElementById('ea-st').value:'09:00';
  var et=document.getElementById('ea-et'); if(et) et.value=_addMins(st,dur);
  var amtEl=document.getElementById('ea-amt');
  if(amtEl&&!amtEl._t){ var total=_computeSvcTotal(pr,pt,dur)*CUR.rate; amtEl.value=total.toFixed(2); }
}
function _saveEditAppt(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  var svcId=document.getElementById('ea-svc')?document.getElementById('ea-svc').value:a.serviceId;
  var svc=D.services.find(function(s){return s.id===svcId;});
  var custId=(document.getElementById('ea-cust')||{}).value||a.custId;
  var custObj=D.cust.find(function(c){return c.id===custId;});
  var csel=document.getElementById('ea-cust');
  a.serviceId=svcId; a.serviceName=svc?svc.name:a.serviceName;
  a.date=(document.getElementById('ea-date')||{}).value||a.date;
  a.startTime=(document.getElementById('ea-st')||{}).value||a.startTime;
  a.endTime=(document.getElementById('ea-et')||{}).value||a.endTime;
  a.custId=custId||a.custId;
  a.custName=custObj?custObj.name:(csel&&csel.options[csel.selectedIndex]?csel.options[csel.selectedIndex].text:a.custName);
  a.custPhone=(document.getElementById('ea-phone')||{}).value||a.custPhone;
  var stfSel=document.getElementById('ea-staff');
  a.staffId=stfSel?stfSel.value:a.staffId;
  a.staffName=(stfSel&&stfSel.value&&stfSel.options[stfSel.selectedIndex])?stfSel.options[stfSel.selectedIndex].text:a.staffName;
  a.totalAmt=(parseFloat((document.getElementById('ea-amt')||{}).value)||0)/CUR.rate;
  a.st=(document.getElementById('ea-status')||{}).value||a.st;
  a.notes=(document.getElementById('ea-notes')||{}).value||'';
  _dbSaveAppt(a);
  addAudit('Appt edited',id+' \u2014 '+a.custName+' '+a.date);
  toast('Appointment updated \u2713','success'); closeModal(); nav('appointments');
}

// ── CANCEL / NO-SHOW ─────────────────────────────────────────
function mCancelAppt(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  modal('\u274C Cancel \u2014 '+a.custName,
    '<div class="alrt alrt-r" style="margin-bottom:12px">Cancel <strong>'+a.serviceName+'</strong> for <strong>'+a.custName+'</strong> on '+a.date+' at '+_timeLabel(a.startTime)+'?</div>'
    +'<div class="fg"><label class="fl">Reason</label>'
    +'<select class="fs" id="ca-reason"><option value="">No reason</option>'
    +'<option>Client requested</option><option>No-show</option><option>Staff unavailable</option>'
    +'<option>Rescheduled</option><option>Other</option></select></div>'
    +'<label style="display:flex;align-items:center;gap:8px;font-size:13px;cursor:pointer;margin-top:8px">'
    +'<input type="checkbox" id="ca-noshow" style="accent-color:var(--r)"/> Mark as No-Show</label>',
    '<button class="btn btn-s" onclick="closeModal()">Keep</button>'
    +' <button class="btn btn-d" onclick="(function(){'
    +'var ns=document.getElementById(\'ca-noshow\')&&document.getElementById(\'ca-noshow\').checked;'
    +'var rs=(document.getElementById(\'ca-reason\')||{}).value||\'\';'
    +'var a2=D.appointments.find(function(x){return x.id===\''+id+'\';});'
    +'if(a2){a2.st=ns?\'No-Show\':\'Cancelled\';a2.notes=(a2.notes?a2.notes+\' | \':\'\')+(rs||\'Cancelled\');'
    +'_dbSaveAppt(a2);addAudit(\'Appt \'+(ns?\'no-show\':\'cancelled\'),\''+id+'\');'
    +'toast(a2.custName+\' \u2014 \'+(ns?\'No-Show\':\'Cancelled\'),\'success\');}'
    +'closeModal();nav(\'appointments\');'
    +'})()">&#10060; Confirm</button>','sm');
}

// ── RESCHEDULE ───────────────────────────────────────────────
function mRescheduleAppt(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  var stfOpts=BIZ_USERS.filter(function(u){return u.bizId===SESSION.bizId;}).map(function(u){return '<option value="'+u.id+'"'+(u.id===a.staffId?' selected':'')+'>'+u.name+'</option>';}).join('');
  modal('\uD83D\uDD04 Reschedule \u2014 '+a.custName,
    '<div class="alrt alrt-b" style="margin-bottom:12px">Currently: <strong>'+a.date+'</strong> at <strong>'+_timeLabel(a.startTime)+'</strong></div>'
    +'<div class="fg-2">'
    +'<div class="fg"><label class="fl">New Date</label><input class="fi" id="rs-date" type="date" value="'+a.date+'"/></div>'
    +'<div class="fg"><label class="fl">New Start</label><input class="fi" id="rs-st" type="time" value="'+(a.startTime||'09:00')+'" oninput="_rsSync(\''+id+'\')"/></div>'
    +'<div class="fg"><label class="fl">New End</label><input class="fi" id="rs-et" type="time" value="'+(a.endTime||'')+'" readonly style="background:var(--bg3);color:var(--text2)"/></div>'
    +'<div class="fg"><label class="fl">Staff</label><select class="fs" id="rs-staff" onchange="_rsSync(\''+id+'\')"><option value="">Any</option>'+stfOpts+'</select></div>'
    +'</div>'
    +'<div class="fg"><label class="fl">Reason</label><input class="fi" id="rs-reason" placeholder="e.g. Client request\u2026"/></div>'
    +'<div id="rs-conflict" style="display:none;margin-top:8px" class="alrt alrt-y"></div>',
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +' <button class="btn btn-p" onclick="_saveReschedule(\''+id+'\')">&#128197; Reschedule</button>','sm');
  setTimeout(function(){_rsSync(id);},60);
}
function _rsSync(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  var svc=D.services.find(function(s){return s.id===a.serviceId;});
  var dur=svc?svc.duration:60;
  var t=(document.getElementById('rs-st')||{}).value||'09:00';
  var et=document.getElementById('rs-et'); if(et) et.value=_addMins(t,dur);
  var date=(document.getElementById('rs-date')||{}).value||a.date;
  var stfSel=document.getElementById('rs-staff');
  var staff=stfSel?stfSel.value:a.staffId;
  var endT=_addMins(t,dur);
  var conflicts=(D.appointments||[]).filter(function(x){
    return x.id!==id&&x.date===date&&(staff?x.staffId===staff:false)
      &&x.st!=='Cancelled'&&x.st!=='No-Show'
      &&x.startTime<endT&&(x.endTime||_addMins(x.startTime,30))>t;
  });
  var el=document.getElementById('rs-conflict');
  if(el){if(conflicts.length){el.style.display='block';el.textContent='\u26A0 Conflict: '+conflicts.map(function(c){return c.custName+' at '+_timeLabel(c.startTime);}).join(', ');}else el.style.display='none';}
}
function _saveReschedule(id){
  var a=D.appointments.find(function(x){return x.id===id;}); if(!a) return;
  var oldDate=a.date, oldTime=a.startTime;
  a.date=(document.getElementById('rs-date')||{}).value||a.date;
  a.startTime=(document.getElementById('rs-st')||{}).value||a.startTime;
  a.endTime=(document.getElementById('rs-et')||{}).value||a.endTime;
  var stfSel=document.getElementById('rs-staff');
  if(stfSel&&stfSel.value){a.staffId=stfSel.value;a.staffName=stfSel.options[stfSel.selectedIndex]?stfSel.options[stfSel.selectedIndex].text:a.staffName;}
  var reason=(document.getElementById('rs-reason')||{}).value||'Rescheduled';
  a.notes=(a.notes?a.notes+' | ':'')+('Rescheduled from '+oldDate+' '+_timeLabel(oldTime)+': '+reason);
  a.st='Confirmed'; _dbSaveAppt(a);
  addAudit('Appt rescheduled',id+' \u2192 '+a.date+' '+a.startTime);
  if(a.custPhone){
    var ph=a.custPhone.replace(/[^0-9]/g,'');
    var msg=encodeURIComponent('Hi '+a.custName.split(' ')[0]+'! \uD83D\uDC4B\n\nYour appointment at *'+BIZ.name+'* has been rescheduled:\n\n\uD83D\uDCCB *'+a.serviceName+'*\n\uD83D\uDCC5 '+a.date+'\n\uD83D\uDD50 '+_timeLabel(a.startTime)+(a.staffName?' with '+a.staffName:'')+'\n\nApologies for any inconvenience!\n_'+BIZ.name+'_');
    setTimeout(function(){if(confirm('Send reschedule notification to '+a.custName+'?'))_sendWA(ph, decodeURIComponent(msg));},300);
  }
  toast('Rescheduled to '+a.date+' at '+_timeLabel(a.startTime)+' \u2713','success');
  closeModal(); nav('appointments');
}

// ── BULK ACTIONS ─────────────────────────────────────────────
function _apptBulkConfirm(){
  var today=localDateStr();
  var reserved=(D.appointments||[]).filter(function(a){return a.st==='Reserved'&&a.date>=today;});
  if(!reserved.length){toast('No pending appointments to confirm','info');return;}
  confirmDo('Confirm all <strong>'+reserved.length+'</strong> pending appointments?',function(){
    reserved.forEach(function(a){a.st='Confirmed';_dbSaveAppt(a);});
    toast(reserved.length+' appointments confirmed ✓','success'); nav('appointments');
  }, 'Confirm All', 'btn-p');
}
function _apptSendReminders(){
  var tomorrow=new Date(); tomorrow.setDate(tomorrow.getDate()+1);
  var tStr=tomorrow.toISOString().slice(0,10);
  var tmr=(D.appointments||[]).filter(function(a){return a.date===tStr&&a.st!=='Cancelled'&&a.st!=='No-Show'&&a.st!=='Completed'&&a.custPhone;});
  if(!tmr.length){toast('No appointments tomorrow with phone numbers','info');return;}
  _bulkWAReminders('appt-tomorrow');
}
function mAddService(){ mNewService(); }
function mEditService(id){ mEditSvc(id); }


