// Preview selected service photo
function _svcImgPreview(input){
  var file = input.files[0]; if(!file) return;
  if(file.size > 2*1024*1024){ toast('Photo too large — max 2MB','error'); input.value=''; return; }
  var reader = new FileReader();
  reader.onload = function(e){
    window._svcImgData = e.target.result;
    var prev = document.getElementById('sv-img-preview');
    if(prev) prev.innerHTML = '<img src="'+e.target.result+'" style="width:100%;height:100%;object-fit:cover"/>';
  };
  reader.readAsDataURL(file);
}
// Pricing model UI helpers (modal)
function _svPtChange(){
  var pt = document.getElementById('sv-pt')?.value || 'flat';
  var hint = document.getElementById('sv-pt-hint');
  var lbl  = document.getElementById('sv-pr-lbl');
  if(hint) hint.textContent = _ptHint(pt);
  var lmap = {flat:'Price ('+CUR.symbol+')', per_session:'Price per Session ('+CUR.symbol+')', per_hour:'Rate per Hour ('+CUR.symbol+')', per_min:'Rate per Minute ('+CUR.symbol+')', per_day:'Day Rate ('+CUR.symbol+')', per_week:'Weekly Rate ('+CUR.symbol+')', starting:'Starting From ('+CUR.symbol+')'};
  if(lbl) lbl.textContent = lmap[pt] || ('Price ('+CUR.symbol+')');
  _svSyncTotal();
}
function _svSyncTotal(){
  var pt   = document.getElementById('sv-pt')?.value || 'flat';
  var pr   = parseFloat(document.getElementById('sv-pr')?.value) || 0;
  var dur  = parseInt(document.getElementById('sv-du')?.value) || 0;
  var prev = document.getElementById('sv-total-preview');
  if(!prev) return;
  if(['per_hour','per_min','per_day','per_week'].includes(pt) && pr > 0 && dur > 0){
    var total = _computeSvcTotal(pr / CUR.rate, pt, dur) * CUR.rate;
    var labels = {per_hour:'for '+dur+' min', per_min:'for '+dur+' min', per_day:'for '+dur+' min', per_week:'for '+dur+' min'};
    prev.style.display = 'block';
    prev.textContent = 'Est. booking total: ' + CUR.symbol + total.toLocaleString(undefined,{maximumFractionDigits:0}) + ' ' + (labels[pt]||'');
  } else if(['per_hour','per_min','per_day','per_week'].includes(pt) && pr > 0 && dur <= 0){
    prev.style.display = 'block';
    prev.style.color = 'var(--text3)';
    prev.textContent = 'Est. total depends on actual duration — set duration to calculate';
  } else if(pt === 'starting'){
    prev.style.display = pr > 0 ? 'block' : 'none';
    prev.textContent = 'Clients see: "From ' + CUR.symbol + (pr).toLocaleString(undefined,{maximumFractionDigits:0}) + '" — final price confirmed on-site';
    prev.style.color = 'var(--text2)';
  } else {
    prev.style.display = 'none';
  }
}

function _getSvcData(){
  const nm=(document.getElementById('sv-nm')?.value||'').trim();
  if(!nm){ toast('Name required','error'); return null; }
  const priceType = document.getElementById('sv-pt')?.value || 'flat';
  const cat = document.getElementById('sv-cat')?.value || '';
  // Use newly uploaded image, or preserve existing (set by edit modal)
  const imgDataUrl = window._svcImgData !== undefined ? window._svcImgData : (window._svcImgData || null);
  const result = {name:nm,cat,duration:parseInt(document.getElementById('sv-du')?.value)||0,price:(parseFloat(document.getElementById('sv-pr')?.value)||0)/CUR.rate,priceType,color:document.getElementById('sv-cl')?.value||'#4361ee',desc:document.getElementById('sv-ds')?.value||'',active:document.getElementById('sv-ac')?.checked!==false,staffIds:[...document.querySelectorAll('#sv-stl input:checked')].map(e=>e.value),costLines:_cbReadLines('cs')};
  if(window._svcImgData !== undefined) result.imgDataUrl = window._svcImgData;
  window._svcImgData = undefined; // reset after use
  return result;
}
async function _saveSvc(){
  const d=_getSvcData(); if(!d) return;
  const s={id:_newSvcId(),...d};
  D.services.push(s);
  closeModal();
  toast(s.name+' saving to cloud…','info');
  await _dbSaveService(s);
  addAudit('Service added',s.id+' '+s.name);
  toast(s.name+' added & synced to booking page ✓','success');
  nav('services');
}
async function _saveSvcEdit(id){
  const d=_getSvcData(); if(!d) return;
  const s=D.services.find(x=>x.id===id); if(!s) return;
  Object.assign(s,d);
  closeModal();
  toast(s.name+' saving to cloud…','info');
  await _dbSaveService(s);
  addAudit('Service updated',id+' '+s.name);
  toast(s.name+' updated & synced ✓','success');
  nav('services');
}
function _delSvc(id){
  var svc=D.services.find(function(x){return x.id===id;}); if(!svc) return;
  var futureAppts=(D.appointments||[]).filter(function(a){return a.serviceId===id&&!['Completed','Cancelled'].includes(a.st);});
  var allAppts=(D.appointments||[]).filter(function(a){return a.serviceId===id;});
  if(futureAppts.length){
    var apptRows=futureAppts.slice(0,4).map(function(a){
      return '<div style="padding:6px 0;border-bottom:1px solid var(--border);font-size:12px"><strong>'+a.id+'</strong> — '+_esc(a.custName)+' · '+a.date+'</div>';
    }).join('');
    modal('Cannot Delete Service',
      '<div class="alrt alrt-r" style="margin-bottom:10px"><strong>'+_esc(svc.name)+'</strong> has '+futureAppts.length+' upcoming appointment'+(futureAppts.length!==1?'s':'')+'.</div>'+
      '<p style="font-size:13px;color:var(--text2);margin-bottom:8px">Cancel or reschedule all upcoming appointments first.</p>'+
      '<div>'+apptRows+'</div>',
      '<button class="btn btn-s" onclick="closeModal()">OK</button>'+
      '<button class="btn btn-p btn-sm" id="go-appts-btn">View Appointments</button>');
    setTimeout(function(){ var b=document.getElementById('go-appts-btn'); if(b) b.onclick=function(){closeModal();nav('appointments');}; },30);
    return;
  }
  var historyNote=allAppts.length?'<p style="font-size:12px;color:var(--text3);margin-top:8px">'+allAppts.length+' completed appointment record'+(allAppts.length!==1?'s':'')+' will keep the service name for history.</p>':'';
  var mid=id, mname=svc.name;
  modal('Delete Service — '+_esc(svc.name),
    '<p style="font-size:13px;color:var(--text2);margin-bottom:8px">Delete <strong>'+_esc(svc.name)+'</strong>? This cannot be undone.</p>'+historyNote,
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'+
    '<button class="btn btn-d" id="confirm-del-svc-btn">Delete</button>');
  setTimeout(function(){
    var btn=document.getElementById('confirm-del-svc-btn');
    if(btn) btn.onclick=function(){
      D.services=D.services.filter(function(x){return x.id!==mid;});
      _dbDelService(mid);
      addAudit('Service deleted',mid+' — '+mname);
      closeModal();
      toast(mname+' deleted','success');
      nav('services');
    };
  },30);
}

// ── BOOKING SETTINGS PAGE ────────────────────────────────────



// ── Country change handler — auto-sets currency + tax in Financial tab ────────
function _bizCountryChanged(country){
  var autoCur = COUNTRY_CURRENCY[country];
  if(autoCur && autoCur !== CUR.code){
    var flagMap4 = {XAF:'🇨🇲',NGN:'🇳🇬',GHS:'🇬🇭',USD:'🇺🇸',GBP:'🇬🇧',EUR:'🇪🇺'};
    setCurrency(autoCur, flagMap4[autoCur]||'');
    // Update the currency dropdown in Financial tab if open
    var curSel = document.getElementById('cur-settings-sel');
    if(curSel) curSel.value = autoCur;
    toast(country+' selected — currency auto-set to '+autoCur,'info');
  }
  // Apply tax defaults — update Financial tab fields if visible
  var taxDef = COUNTRY_TAX_DEFAULTS[country];
  if(taxDef){
    var trEl  = document.getElementById('fin-tax-rate');
    var tnEl  = document.getElementById('fin-tax-name');
    var rlEl  = document.getElementById('fin-tax-reg-lbl');
    var prevEl= document.getElementById('fin-tax-preview');
    if(trEl)  trEl.value = taxDef.rate;
    if(tnEl)  tnEl.value = taxDef.name;
    if(rlEl)  rlEl.childNodes[0].textContent = (taxDef.reg||'Tax Registration Number')+' ';
    if(prevEl) prevEl.textContent = taxDef.rate>0 ? taxDef.name+' ('+taxDef.rate+'%)' : 'No tax applied';
    BIZ.taxRate = taxDef.rate;
    BIZ.taxName = taxDef.name;
  }
  BIZ.country = country;
  _applyLocaleToForms(CUR.code);
  _updateCurPreview(CUR.code);
}

