// Legacy alias — kept for backward compat
function _docLbl(enLabel, frLabel){
  return (BIZ.language||'en')==='fr' ? frLabel : enLabel;
}

// ── Apply language to entire UI ────────────────────────────────
// Called: on login, and when language setting changes.
// Patches DOM text for sidebar/drawer/nav (static HTML).
// Page bodies re-render through nav() which calls pg*() which uses _L().
function _applyLanguage(lang){
  BIZ.language = lang;
  try{ localStorage.setItem('st_lang_'+SESSION.bizId, lang); }catch(e){}

  const L = _L();

  // ── Sidebar (desktop) — target by data-p attribute ────────────
  const sbMap = {
    'dashboard':       L.nav_dashboard,
    'inventory':       L.nav_inventory,
    'sales':           L.nav_sales,
    'rentals':         L.nav_rentals,
    'purchases':       L.nav_purchases,
    'customers':       L.nav_customers,
    'vendors':         L.nav_vendors,
    'expenses':        L.nav_expenses,
    'accounting':      L.nav_accounting,
    'reports':         L.nav_reports,
    'appointments':    L.nav_appointments,
    'services':        L.nav_services,
    'booking-settings':L.nav_booking,
    'catalog':         L.nav_catalog,
    'ai-studio':       L.nav_ai,
    'auditlog':        L.nav_audit,
    'settings':        L.nav_settings,
    'admin-biz':       L.nav_businesses,
    'admin-users':     L.nav_users,
    'admin-analytics': L.nav_analytics,
      'admin-affiliates': 'Affiliates',
  };
  document.querySelectorAll('.sb-item[data-p]').forEach(function(el){
    const lbl = el.querySelector('.sb-lbl-txt');
    if(lbl && sbMap[el.dataset.p]) lbl.textContent = sbMap[el.dataset.p];
  });

  // ── Drawer (mobile slide-out) — target by id ──────────────────
  const drMap = {
    'dr-appointments':   L.nav_appointments,
    'dr-services':       L.nav_services,
    'dr-biz-purchases':  L.nav_purchases,
    'dr-customers':      L.nav_customers,
    'dr-vendors':        L.nav_vendors,
    'dr-expenses':       L.nav_expenses,
    'dr-accounting':     L.nav_accounting,
    'dr-reports':        L.nav_reports,
    'dr-catalog':        L.nav_catalog,
    'dr-ai-studio':      L.nav_ai,
    'dr-auditlog':       L.nav_audit,
    'dr-admin-biz':      L.nav_businesses,
    'dr-admin-users':    L.nav_users,
    'dr-admin-analytics':L.nav_analytics,
    'dr-admin-affiliates':'Affiliates',
    'dr-admin-biz':      L.nav_businesses,
    'dr-admin-users':    L.nav_users,
    'dr-settings':       L.nav_settings,
    'dr-signout':        L.nav_signout,
  };
  Object.entries(drMap).forEach(function(_ref){
    var id=_ref[0], txt=_ref[1];
    var el=document.getElementById(id);
    if(el){ var span=el.querySelector('span'); if(span) span.textContent=txt; }
  });

  // ── Bottom mobile nav (bni) ───────────────────────────────────
  var bnMap = {
    'bn-dashboard': L.nav_home,
    'bn-inventory': L.nav_inventory,
    'bn-sales':     L.nav_sales,
    'bn-rentals':   L.nav_rentals,
  };
  Object.entries(bnMap).forEach(function(_ref){
    var id=_ref[0], txt=_ref[1];
    var el=document.getElementById(id);
    if(el){ var span=el.querySelector('.bni-lbl'); if(span) span.textContent=txt; }
  });

  // ── "More" drawer label (bottom nav) ─────────────────────────
  var moreEl = document.querySelector('#bn-more .bni-lbl');
  if(moreEl) moreEl.textContent = L.nav_more;
  // SA bottom nav labels
  ['bn-sa-biz','bn-sa-users','bn-sa-aff'].forEach(function(bid){
    var bMap={'bn-sa-biz':L.nav_businesses,'bn-sa-users':L.nav_users,'bn-sa-aff':'Affiliates'};
    var bel=document.getElementById(bid);
    if(bel){var sp=bel.querySelector('.bni-lbl');if(sp)sp.textContent=bMap[bid];}
  });
  // Drawer title + lang toggle label
  var drawerTtl=document.getElementById('drawer-ttl');
  if(drawerTtl) drawerTtl.textContent=lang==='fr'?'Toutes les sections':'All Sections';
  var langLbl=document.getElementById('dr-lang-label');
  if(langLbl) langLbl.textContent=lang==='fr'?'Switch to English':'Passer en Français';

  // ── Re-render current page so pg*() picks up the new language ─
  if(typeof curPage !== 'undefined' && curPage) nav(curPage);

  if(lang==='fr'){
    toast('Langue réglée sur Français — l\'interface et les documents sont en français ✓','success');
  } else {
    toast('Language set to English ✓','info');
  }
}
function _onCurSettingsChange(code){
  const flagMap = {XAF:'🇨🇲',NGN:'🇳🇬',GHS:'🇬🇭',USD:'🇺🇸',GBP:'🇬🇧',EUR:'🇪🇺'};
  setCurrency(code, flagMap[code]||'');
  // Auto-fill tax defaults for this currency/country
  const country = BIZ.country || '';
  const taxKey = country || Object.values(CUR_LOCALE).find(l=>l.country && CUR_LOCALE[code] && l === CUR_LOCALE[code])?.country || '';
  const taxDef = COUNTRY_TAX_DEFAULTS[country] || null;
  if(taxDef){
    const trEl  = document.getElementById('fin-tax-rate');
    const tnEl  = document.getElementById('fin-tax-name');
    const rlEl  = document.getElementById('fin-tax-reg-lbl');
    const prevEl= document.getElementById('fin-tax-preview');
    if(trEl && !parseFloat(trEl.value)) trEl.value = taxDef.rate;
    if(tnEl && !tnEl.value)             tnEl.value = taxDef.name;
    if(rlEl)  rlEl.childNodes[0].textContent = (taxDef.reg||'Tax Registration Number')+' ';
    if(prevEl) prevEl.textContent = taxDef.rate>0 ? taxDef.name+' ('+taxDef.rate+'%)' : 'No tax applied';
  }
  _updateCurPreview(code);
}
function _updateCurPreview(code){
  const loc = _getLocale();
  const el = document.getElementById('cur-locale-preview');
  if(el) el.textContent = (loc.flag||'')+(loc.flag?' ':'')+(loc.country||code)+' · Phone: '+(loc.phonePfx||'+?')+' · City example: '+(loc.city||'—')+' · Bank example: '+(loc.bankEx||'—');
}

// ── Save financial settings properly ─────────────────────────────────────────
function _saveFinancialSettings(){
  const taxRate = parseFloat(document.getElementById('fin-tax-rate')?.value)||0;
  const taxName = (document.getElementById('fin-tax-name')?.value||'VAT').trim();
  const taxNum  = (document.getElementById('fin-tax-num')?.value||'').trim();
  BIZ.taxRate      = taxRate;
  BIZ.taxName      = taxName;
  BIZ.taxRegNumber = taxNum;
  BIZ.currency     = CUR.code;
  _dbSaveBizProfile(SESSION.bizId);
  // Update live preview label
  const prev = document.getElementById('fin-tax-preview');
  if(prev) prev.textContent = taxRate>0 ? taxName+' ('+taxRate+'%)' : 'No tax applied';
  addAudit('Financial settings saved','Currency: '+CUR.code+', Tax: '+taxRate+'% '+taxName+(taxNum?' | Reg: '+taxNum:''));
  toast('Financial settings saved ✓','success');
}


