// ── EXPENSES PDF ─────────────────────────────────────────────
function exportExpensesPDF(){
  const exps = D.exp;
  const total = exps.reduce((a,e)=>a+e.amt,0);
  const recurring = exps.filter(e=>e.type==='Recurring').reduce((a,e)=>a+e.amt,0);
  // Group by category
  const byCat = {};
  exps.forEach(e=>{ byCat[e.cat]=(byCat[e.cat]||0)+e.amt; });
  const topCat = Object.entries(byCat).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([c,v])=>`${c}: ${fmt(v)}`).join(' · ');
  const body = `
    <div class="doc-title">Expense Report</div>
    <div class="summary">
      <div class="sum-box"><div class="sum-lbl">Total Expenses</div><div class="sum-val red">${fmt(total)}</div></div>
      <div class="sum-box"><div class="sum-lbl">Recurring</div><div class="sum-val" style="color:#d97706">${fmt(recurring)}</div></div>
      <div class="sum-box"><div class="sum-lbl">Entries</div><div class="sum-val blue">${exps.length}</div></div>
    </div>
    ${topCat?`<p style="font-size:11px;color:#64748b;margin-bottom:14px">Top categories: ${topCat}</p>`:''}
    <table>
      <thead><tr><th>Exp #</th><th>Date</th><th>Category</th><th>Payee</th><th class="num">Amount</th><th>Type</th><th>Method</th><th>Status</th></tr></thead>
      <tbody>${exps.map(e=>`<tr>
        <td style="font-family:monospace;font-size:11px">${e.id}</td>
        <td>${e.dt}</td>
        <td>${e.cat}</td>
        <td>${e.payee||'—'}</td>
        <td class="num red">${fmt(e.amt)}</td>
        <td>${e.type||'—'}</td>
        <td>${e.method||'—'}</td>
        <td><span class="badge ${e.st==='Paid'?'badge-g':'badge-y'}">${e.st||'Paid'}</span></td>
      </tr>`).join('')}</tbody>
    </table>`;
  _pdfOpen('Expense Report', body);
}

