// ============================================================
// NOTIFICATION ENGINE — ShopTrack
// Covers: Browser Push, WhatsApp, In-App Panel
// ============================================================

// ── Browser Push Notification helper ────────────────────────

// ============================================================
// WHATSAPP NOTIFICATIONS TO OWNER
// Sends alerts to the business owner's own WhatsApp number.
// All functions use window.open (wa.me) — no API key needed.
// ============================================================

// Core helper: open WhatsApp to owner's number with pre-drafted message
function _waOwner(msg) {
  if (!msg) return;
  var raw = (BIZ.whatsapp || BIZ.phone || '').replace(/[^0-9]/g, '');
  if (!raw || raw.length < 7) {
    console.warn('[ShopTrack] WA-to-owner skipped: no WhatsApp number in Business Profile');
    return;
  }
  try {
    _sendWA(raw, msg);
  } catch(e) { console.warn('[ShopTrack] WA open failed:', e); }
}

// Check if owner WA is configured; if not, show a setup nudge
function _waOwnerCheck() {
  var raw = (BIZ.whatsapp || '').replace(/[^0-9]/g, '');
  if (!raw || raw.length < 7) {
    toast('Add your WhatsApp number in Settings -> Business Profile to receive owner alerts', 'info');
    return false;
  }
  return true;
}

// 1. New sale alert to owner
function _waOwnerNewSale(sale, staffName) {
  var total = sale.total || sale.amt || 0;
  var isLarge = NOTIF_PREFS.waOwnerLargeOrder &&
    total >= (NOTIF_PREFS.waOwnerLargeOrderThreshold || 500);
  if (!NOTIF_PREFS.waOwnerNewSale && !isLarge) return;
  if(!window._waNewSaleSent) window._waNewSaleSent = new Set();
  if(sale && sale.id !== 'TEST' && window._waNewSaleSent.has(sale.id)) return;
  if(sale && sale.id && sale.id !== 'TEST') window._waNewSaleSent.add(sale.id);
  var biz  = BIZ.name || 'your shop';
  var bal  = total - (sale.paid || 0);
  var paidLine = (sale.paid || 0) >= total
    ? 'Paid: ' + fmt(sale.paid || 0) + ' OK Fully paid'
    : 'Paid: ' + fmt(sale.paid || 0) + ' Balance due: ' + fmt(bal);
  var raw = (BIZ.whatsapp || BIZ.phone || '').replace(/[^0-9]/g, '');
  if (!raw || raw.length < 7) {
    console.warn('[ShopTrack] WA-to-owner skipped: no WhatsApp number in Business Profile');
    return;
  }
  // Use approved template for business-initiated message
  fetch('/.netlify/functions/whatsapp-notify', {
    method: 'POST', headers: {'Content-Type':'application/json'},
    body: JSON.stringify({
      to: raw,
      template: 'new_sale_alert',
      variables: {
        '1': biz,
        '2': sale.id || '',
        '3': sale.cust || 'Customer',
        '4': sale.items || '',
        '5': fmt(total),
        '6': paidLine,
        '7': staffName || 'Staff',
        '8': sale.method || 'Cash',
        '9': localDateStr(),
      }
    })
  }).then(function(r){ return r.json(); }).then(function(data){
    if(data.success){
      toast('✅ WhatsApp alert sent!','success');
      var _waKey='st_wa1_'+(SESSION.bizId||'');
      try{
        if(!localStorage.getItem(_waKey)){
          localStorage.setItem(_waKey,'1');
          setTimeout(function(){
            var refLink='https://shoptrack.org/?ref='+(SESSION.bizId||'');
            modal('🎉 Your first live alert!',
              '<p style="font-size:14px;color:var(--text2);line-height:1.7;margin:0 0 14px">That alert just arrived on your phone the moment the sale was recorded. <strong>This is ShopTrack.</strong></p>'
              +'<p style="font-size:13px;color:var(--text2);margin:0 0 12px">Know another business owner? Share ShopTrack — you get 1 free month when they subscribe.</p>'
              +'<div style="background:var(--bg3);border-radius:var(--r8);padding:10px 14px;display:flex;align-items:center;gap:8px;margin-bottom:4px">'
              +'<span style="flex:1;font-family:var(--mono);font-size:11px;color:var(--a)">'+refLink+'</span>'
              +'<button class="btn btn-p btn-xs" onclick="navigator.clipboard.writeText(\''+refLink+'\').then(function(){toast(\'Copied!\',\'success\');}).catch(function(){toast(refLink,\'info\')})">Copy</button>'
              +'</div>',
              '<button class="btn btn-s btn-sm" onclick="closeModal()">Later</button>'
              +'<button class="btn btn-g btn-sm" onclick="var m=\'Hi! I use ShopTrack \xe2\x80\x94 try free: \'+refLink;window.open(\'https://wa.me/?text=\'+encodeURIComponent(m),\'_blank\');closeModal()">'
              +'💬 Share on WhatsApp</button>','sm');
          },1500);
        }
      }catch(e){}
    } else {
      console.warn('[WA] new sale alert failed:', data.error, data.code);
      // Fallback to freeform if template not yet approved
      var msg = (isLarge ? 'LARGE ORDER at ' : 'New Sale at ') + biz + '\n\n'
        + (sale.id||'') + ' - ' + (sale.cust||'Customer') + '\n'
        + 'Items: ' + (sale.items||'') + '\n'
        + 'Total: ' + fmt(total) + '\n'
        + paidLine + '\n'
        + (staffName ? 'Recorded by: ' + staffName + '\n' : '')
        + (sale.method ? 'Method: ' + sale.method + '\n' : '')
        + localDateStr() + '\n\n'
        + '_ShopTrack - ' + biz + '_';
      _openWA(raw, msg);
    }
  }).catch(function(e){ console.warn('[WA] fetch error:', e.message); });
}

// 2. Below-minimum price block alert to owner
function _waOwnerMinBlock(itemName, attemptedPriceDisplay, minPriceUsd, staffName) {
  if (!NOTIF_PREFS.waOwnerMinBlock) return;
  var biz = BIZ.name || 'your shop';
  var msg = 'PRICE BLOCKED at ' + biz + '\n\n'
    + 'Item: ' + itemName + '\n'
    + 'Attempted price: ' + fmt(attemptedPriceDisplay / CUR.rate) + '\n'
    + 'Your minimum:    ' + fmt(minPriceUsd) + '\n'
    + (staffName ? 'Staff: ' + staffName + '\n' : '')
    + localDateStr() + ' at ' + new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) + '\n\n'
    + 'Sale was blocked. No action needed.\n'
    + '_ShopTrack - ' + biz + '_';
  _waOwner(msg);
}

// 3. Payment received alert to owner
function _waOwnerPayment(amount, custName, refId, method) {
  if (!NOTIF_PREFS.waOwnerPayment) return;
  var biz = BIZ.name || 'your shop';
  var msg = 'Payment Received at ' + biz + '\n\n'
    + 'Amount: ' + fmt(amount) + '\n'
    + 'From: ' + (custName || 'Customer') + '\n'
    + 'Ref: ' + (refId || 'N/A') + '\n'
    + 'Method: ' + (method || 'Cash') + '\n'
    + localDateStr() + '\n\n'
    + '_ShopTrack - ' + biz + '_';
  _waOwner(msg);
}

// 4. Low stock / out of stock alert to owner
function _waOwnerLowStock(itemName, available, threshold) {
  if (!NOTIF_PREFS.waOwnerLowStock) return;
  if(!window._waLowStockSent) window._waLowStockSent = new Set();
  var _lsKey = itemName + ':' + localDateStr();
  if(itemName !== 'Test Item' && window._waLowStockSent.has(_lsKey)) return;
  if(itemName !== 'Test Item') window._waLowStockSent.add(_lsKey);
  var oos = available <= 0;
  var biz = BIZ.name || 'your shop';
  var msg = (oos ? 'OUT OF STOCK' : 'Low Stock Alert') + ' at ' + biz + '\n\n'
    + 'Item: ' + itemName + '\n'
    + 'Available: ' + available + ' units' + (threshold > 0 ? ' (min: ' + threshold + ')' : '') + '\n'
    + (oos ? 'Item is completely out of stock.\n' : '')
    + localDateStr() + '\n\n'
    + 'Go to Inventory to reorder.\n'
    + '_ShopTrack - ' + biz + '_';
  _waOwner(msg);
}

// 5. New booking alert to owner
function _waOwnerNewBooking(appt) {
  if (!NOTIF_PREFS.waOwnerNewBooking) return;
  var biz = BIZ.name || 'your shop';
  var timeLabel = typeof _timeLabel === 'function' ? _timeLabel(appt.startTime) : (appt.startTime || '');
  var msg = 'New Booking at ' + biz + '\n\n'
    + 'Client: ' + (appt.custName || 'Guest') + '\n'
    + (appt.custPhone ? 'Phone: ' + appt.custPhone + '\n' : '')
    + 'Service: ' + (appt.serviceName || 'Appointment') + '\n'
    + 'Date: ' + (appt.date || '') + '\n'
    + 'Time: ' + timeLabel + '\n'
    + (appt.staffName ? 'Staff: ' + appt.staffName + '\n' : '')
    + (appt.totalAmt > 0 ? 'Amount: ' + fmt(appt.totalAmt) + '\n' : '')
    + '\n_ShopTrack - ' + biz + '_';
  _waOwner(msg);
}

// 6. Weekly summary — runs automatically every Monday at 09:00
function _waOwnerWeeklySummary() {
  var today = localDateStr();
  var d7ago = new Date(); d7ago.setDate(d7ago.getDate()-7);
  var weekStart = d7ago.toISOString().slice(0,10);
  var weekSales = D.sales.filter(function(s){ return s.dt >= weekStart && s.dt <= today; });
  var totalRev  = weekSales.reduce(function(a,s){ return a+(s.total||s.amt||0); },0);
  var totalPaid = weekSales.reduce(function(a,s){ return a+(s.paid||0); },0);
  var unpaid    = D.sales.filter(function(s){ return s.st==='Unpaid'||s.st==='Partial'; });
  var arTotal   = unpaid.reduce(function(a,s){ return a+((s.total||s.amt||0)-(s.paid||0)); },0);
  var overdueR  = D.rentals.filter(function(r){ return r.st==='Overdue'; });
  var lowStockI = D.inv.filter(function(i){
    var av=(i.qty||0)-(i.rented||0); var mn=i.minStock||i.minQty||0;
    return mn>0 && av<=mn;
  });
  var weekAppts  = (D.appointments||[]).filter(function(a){ return a.date>=weekStart && a.date<=today; });
  var completedA = weekAppts.filter(function(a){ return a.st==='Completed'; });
  var apptRev    = completedA.reduce(function(a,ap){ return a+(ap.totalAmt||0); },0);
  var grossProfit= weekSales.reduce(function(a,s){ return a+(s.profit||0); },0);
  var biz = BIZ.name || 'ShopTrack';
  var msg = 'Weekly Summary - ' + biz + '\n'
    + weekStart + ' to ' + today + '\n\n'
    + 'SALES THIS WEEK\n'
    + 'Transactions: ' + weekSales.length + '\n'
    + 'Revenue: ' + fmt(totalRev) + '\n'
    + 'Collected: ' + fmt(totalPaid) + '\n'
    + 'Gross Profit: ' + fmt(grossProfit) + '\n'
    + (apptRev>0 ? 'Service revenue: ' + fmt(apptRev) + '\n' : '')
    + (completedA.length>0 ? 'Appointments: ' + completedA.length + ' completed\n' : '')
    + '\nOUTSTANDING\n'
    + (arTotal>0 ? 'Unpaid invoices: ' + fmt(arTotal) + ' (' + unpaid.length + ' customers)\n' : 'No unpaid invoices ✓\n')
    + (overdueR.length>0 ? 'Overdue rentals: ' + overdueR.length + '\n' : '')
    + '\nINVENTORY\n'
    + (lowStockI.length>0 ? 'Low/out of stock: ' + lowStockI.map(function(i){return i.name;}).slice(0,3).join(', ') + (lowStockI.length>3?' + '+(lowStockI.length-3)+' more':'') + '\n' : 'Stock levels OK ✓\n')
    + '\n_ShopTrack - shoptrack.org_';
  _waOwner(msg);
}


function _pushNotif(title, body, opts){
  if(typeof Notification === 'undefined') return;
  if(Notification.permission !== 'granted') return;
  try{
    const n = new Notification(title, {
      body:    body || '',
      icon:    BIZ.logoDataUrl || '/favicon.ico',
      badge:   '/favicon.ico',
      tag:     opts?.tag || 'shoptrack',
      requireInteraction: opts?.sticky || false,
      silent:  opts?.silent || false,
      ...opts
    });
    // Click opens the app and navigates to relevant page
    if(opts?.page) n.onclick = ()=>{ window.focus(); nav(opts.page); n.close(); };
  }catch(e){ console.warn('Push notification failed:', e); }
}

// ── Request push permission ───────────────────────────────────
async function _requestPushPermission(){
  if(typeof Notification === 'undefined'){
    toast('Push notifications are not supported in this browser','error');
    return;
  }
  if(Notification.permission === 'granted'){
    toast('Push notifications are already enabled ✓','success');
    _testPushNotif();
    return;
  }
  if(Notification.permission === 'denied'){
    toast('Notifications are blocked. Go to browser settings → Site Settings → Notifications to allow shoptrack.org','error');
    return;
  }
  try{
    const result = await Notification.requestPermission();
    if(result === 'granted'){
      toast('Push notifications enabled! ✓','success');
      _testPushNotif();
      // Re-render settings to show updated state
      if(curPage === 'settings') nav('settings');
    } else {
      toast('Permission denied — you can enable this later in browser settings','error');
    }
  }catch(e){
    console.error('Permission request failed:', e);
  }
}

function _testPushNotif(){
  setTimeout(()=>{
    _pushNotif(
      '🎉 Notifications active!',
      'You will now receive alerts for sales, appointments, overdue rentals and more.',
      {tag:'test', page:'dashboard'}
    );
  }, 800);
}

// ── Save notification preferences to DB ──────────────────────
// Reset all notification preferences to defaults
function _resetNotifPrefs(){
  var defaults = {
    newSale:false, rentalDue:true, rentalOverdue:true, lowStock:true,
    newAppointment:true, apptReminder:true, arOutstanding:false,
    apPaymentDue:false, newExpense:false, monthlySummary:false,
    waApptConfirm:true, waApptReminder:true, waOverdueAlert:false, waArReminder:false,
    waOwnerNewSale:false, waOwnerLargeOrder:false, waOwnerMinBlock:true,
    waOwnerPayment:true, waOwnerLowStock:true, waOwnerNewBooking:false,
  };
  Object.assign(NOTIF_PREFS, defaults);
  if(confirm('Reset all notifications to default settings?')){
    _saveNotifPrefs();
    if(typeof pgSettings === 'function' && curPage === 'settings') nav('settings');
  }
}

function _saveNotifPrefs(){
  // Persist to per-business localStorage key (avoids cross-session bleed)
  const _lsKey = 'shoptrack_notif_prefs_' + (SESSION.bizId||'default');
  try{ localStorage.setItem(_lsKey, JSON.stringify(NOTIF_PREFS)); }catch(e){}
  // Also save to businesses table so prefs survive on new devices/browsers
  if(_sb && SESSION.bizId && !SESSION.isSuperAdmin){
    _sb.from('businesses').update({ notif_prefs: JSON.stringify(NOTIF_PREFS) })
      .eq('id', SESSION.bizId).then(function(r){
        if(r.error) console.warn('[notif] Could not save prefs to DB:', r.error.message);
      });
  }
  addAudit('Notification preferences saved', Object.entries(NOTIF_PREFS).filter(([,v])=>v).map(([k])=>k).join(', '));
  toast('Notification preferences saved ✓','success');
}

// ── Restore notification preferences ─────────────────────────
function _restoreNotifPrefs(){
  // Try per-biz key first, fall back to legacy global key
  const _lsKey = 'shoptrack_notif_prefs_' + (SESSION.bizId||'default');
  try{
    const saved = localStorage.getItem(_lsKey) || localStorage.getItem('shoptrack_notif_prefs');
    if(saved){
      const parsed = JSON.parse(saved);
      Object.assign(NOTIF_PREFS, parsed);
      console.log('[notif] Restored from localStorage:', Object.keys(parsed).length, 'prefs');
    }
  }catch(e){ console.warn('[notif] localStorage restore failed:', e.message); }
}

// Restore notif prefs from DB (called after BIZ profile loads from Supabase)
// DB is the source of truth and always wins over hardcoded defaults
function _restoreNotifPrefsFromDB(notifPrefsJson){
  if(!notifPrefsJson) return;
  try{
    const dbPrefs = JSON.parse(notifPrefsJson);
    if(!dbPrefs || typeof dbPrefs !== 'object') return;
    Object.assign(NOTIF_PREFS, dbPrefs);
    // Sync back to localStorage so next refresh before DB loads is instant
    const _lsKey = 'shoptrack_notif_prefs_' + (SESSION.bizId||'default');
    try{ localStorage.setItem(_lsKey, JSON.stringify(dbPrefs)); }catch(e){}
    console.log('[notif] Restored from DB:', Object.keys(dbPrefs).length, 'prefs');
  }catch(e){ console.warn('[notif] DB restore failed:', e.message); }
}

// ── Fire a push notification for a specific event ────────────
function _notifEvent(type, payload){
  if(!NOTIF_PREFS[type]) return;
  const biz = BIZ.name || 'ShopTrack';
  const msgs = {
    newSale:        {title:`💳 New Sale — ${biz}`, body:`${payload?.cust||'Customer'} · ${payload?.amt||''}`, tag:'sale', page:'sales'},
    rentalDue:      {title:`🕐 Rental Due Today — ${biz}`, body:`${payload?.cust||''} — ${payload?.item||''}`, tag:'rental-due', page:'rentals'},
    rentalOverdue:  {title:`⚠ Overdue Rental — ${biz}`, body:`${payload?.cust||''} — ${payload?.item||''} is overdue`, tag:'overdue', page:'rentals', sticky:true},
    newAppointment: {title:`📅 New Appointment — ${biz}`, body:`${payload?.cust||''} booked ${payload?.svc||''} on ${payload?.date||''}`, tag:'appt', page:'appointments'},
    apptReminder:   {title:`🔔 Appointment in 1 hour — ${biz}`, body:`${payload?.cust||''} · ${payload?.svc||''} at ${payload?.time||''}`, tag:'appt-remind', page:'appointments', sticky:true},
    lowStock:       {title:`📦 Low Stock Alert — ${biz}`, body:`${payload?.name||'Item'} has only ${payload?.qty||0} units left`, tag:'stock', page:'inventory'},
    arOutstanding:  {title:`💰 Unpaid Invoice — ${biz}`, body:`${payload?.cust||''} owes ${payload?.amt||''} (${payload?.days||0} days)`, tag:'ar', page:'sales'},
    apPaymentDue:   {title:`🏭 Vendor Payment Due — ${biz}`, body:`${payload?.vendor||''} balance: ${payload?.amt||''}`, tag:'ap', page:'vendors'},
    newExpense:     {title:`💸 Expense Recorded — ${biz}`, body:`${payload?.cat||''} · ${payload?.amt||''}`, tag:'expense', page:'expenses'},
  };
  const cfg = msgs[type];
  if(cfg) _pushNotif(cfg.title, cfg.body, {tag:cfg.tag, page:cfg.page, sticky:cfg.sticky||false});
}

// ── Proactive monitoring — runs every 60 seconds ──────────────
function _startNotifMonitor(){
  if(_notifCheckInterval) return; // already running
  _notifCheckInterval = setInterval(_checkAllNotifConditions, 60000);
  // Also run once after 5 seconds on login
  setTimeout(_checkAllNotifConditions, 5000);
}

function _stopNotifMonitor(){
  if(_notifCheckInterval){ clearInterval(_notifCheckInterval); _notifCheckInterval=null; }
}

function _checkAllNotifConditions(){
  if(!SESSION.userId || SESSION.isSuperAdmin) return;
  const today = localDateStr();
  const now   = new Date();
  const nowH  = now.getHours();
  const nowM  = now.getMinutes();

  // 1. Overdue rentals
  if(NOTIF_PREFS.rentalOverdue){
    D.rentals.filter(r=>r.st==='Overdue').forEach(r=>{
      const key = 'overdue:'+r.id;
      if(!_notifSeen.has(key)){
        _notifSeen.add(key);
        _notifEvent('rentalOverdue', {cust:r.cust, item:r.item});
        // WhatsApp prompt if enabled
        if(NOTIF_PREFS.waOverdueAlert && r.cust){
        var _oc=D.cust.find(function(c){return c.id===r.custId||c.name===r.cust;});
        var _oph=(_oc&&(_oc.whatsapp||_oc.phone||_oc.ph)||'').replace(/[^0-9]/g,'');
        if(_oph) _rentalWARemind(r.id);
      }
      }
    });
  }

  // 2. Rentals due today
  if(NOTIF_PREFS.rentalDue){
    D.rentals.filter(r=>r.due===today && (r.st==='Checked Out'||r.st==='Reserved')).forEach(r=>{
      const key = 'due:'+r.id+':'+today;
      if(!_notifSeen.has(key)){
        _notifSeen.add(key);
        _notifEvent('rentalDue', {cust:r.cust, item:r.item});
      }
    });
  }

  // 3. Today's appointment reminders — fire 1hr before
  if(NOTIF_PREFS.apptReminder){
    const todayAppts = (D.appointments||[]).filter(a=>a.date===today && !['Completed','Cancelled','No-Show'].includes(a.st));
    todayAppts.forEach(a=>{
      if(!a.startTime) return;
      const [aH, aM] = a.startTime.split(':').map(Number);
      const minsTill = (aH*60+aM) - (nowH*60+nowM);
      if(minsTill >= 55 && minsTill <= 65){ // 55–65 min window
        const key = 'appt-remind:'+a.id;
        if(!_notifSeen.has(key)){
          _notifSeen.add(key);
          _notifEvent('apptReminder', {cust:a.custName, svc:a.serviceName, time:_timeLabel(a.startTime)});
          if(NOTIF_PREFS.waApptReminder && a.custPhone) _sendWAApptReminder(a);
        }
      }
    });
  }

  // 4. Low stock — only fire for items that have a threshold set (minStock > 0)
  if(NOTIF_PREFS.lowStock){
    D.inv.filter(i=>{
      const avail=(i.qty||0)-(i.rented||0);
      const min=i.minStock||i.minQty||0;
      return min>0 && avail<=min && avail>0; // threshold enabled AND not fully out (separate alert)
    }).forEach(i=>{
      const key = 'stock:'+i.id+':'+today;
      if(!_notifSeen.has(key)){
        _notifSeen.add(key);
        _notifEvent('lowStock', {name:i.name, qty:i.qty-i.rented});
      }
    });
  }

  // 5. AR outstanding > 7 days
  if(NOTIF_PREFS.arOutstanding){
    const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate()-7);
    D.sales.filter(s=>s.st==='Unpaid' && new Date(s.dt) < weekAgo).forEach(s=>{
      const key = 'ar:'+s.id+':'+today;
      if(!_notifSeen.has(key)){
        _notifSeen.add(key);
        const days = Math.floor((now - new Date(s.dt))/86400000);
        _notifEvent('arOutstanding', {cust:s.cust, amt:fmt(s.total||s.amt), days});
        if(NOTIF_PREFS.waArReminder) _queueWAReminder('ar', s);
      }
    });
  }

  // 6. AP outstanding
  if(NOTIF_PREFS.apPaymentDue){
    D.vendors.filter(v=>v.bal>0).forEach(v=>{
      const key = 'ap:'+v.id+':'+today;
      if(!_notifSeen.has(key)){
        _notifSeen.add(key);
        _notifEvent('apPaymentDue', {vendor:v.name, amt:fmt(v.bal)});
      }
    });
  }

  // 7. Weekly summary — every Monday at 09:00
  if(NOTIF_PREFS.waOwnerWeeklySummary){
    if(now.getDay()===1 && now.getHours()===9 && now.getMinutes()<2){
      var _wsKey = 'weekly-summary:'+today;
      if(!_notifSeen.has(_wsKey)){
        _notifSeen.add(_wsKey);
        _waOwnerWeeklySummary();
      }
    }
  }

  // Reset seen set daily
  const todayKey = 'notif-seen-date';
  const lastDay = sessionStorage.getItem(todayKey);
  if(lastDay !== today){ _notifSeen.clear(); sessionStorage.setItem(todayKey, today); }
}

// ── WhatsApp notification functions ──────────────────────────
const _waPendingQueue = []; // store items needing WA action

function _queueWAReminder(type, data){
  // Don't add duplicates
  if(_waPendingQueue.find(q=>q.type===type && q.id===data.id)) return;
  _waPendingQueue.push({type, ...data, ts: Date.now()});
  refreshNotifPanel(); // update the notification panel badge
}

// Appointment confirmation WA — called immediately on booking
function _sendWAApptConfirm(appt){
  if(!NOTIF_PREFS.waApptConfirm || !appt.custPhone) return;
  const ph = appt.custPhone.replace(/[^0-9]/g,'');
  if(!ph) return;
  const msg = encodeURIComponent(
    `Hi ${appt.custName.split(' ')[0]}! 👋\n\n`+
    `Your appointment at *${BIZ.name}* is confirmed ✅\n\n`+
    `📋 *${appt.serviceName}*\n`+
    `📅 ${appt.date}\n`+
    `🕐 ${_timeLabel(appt.startTime)}`+
    `${appt.staffName?' with '+appt.staffName:''}\n\n`+
    `${BIZ.bookingNote||'We look forward to seeing you!'}`
  );
  // Show as in-app prompt rather than auto-opening (avoid spamming)
  setTimeout(()=>{
    if(confirm('Send WhatsApp confirmation to '+appt.custName+'?')){
      _sendWA(ph, decodeURIComponent(msg));
    }
  }, 500);
}

// Appointment reminder WA — called by proactive monitor
function _sendWAApptReminder(appt){
  if(!appt.custPhone) return;
  const ph = appt.custPhone.replace(/[^0-9]/g,'');
  if(!ph) return;
  const msg = encodeURIComponent(
    `Hi ${appt.custName.split(' ')[0]}! 👋\n\n`+
    `Reminder: You have an appointment at *${BIZ.name}* in 1 hour!\n\n`+
    `📋 *${appt.serviceName}*\n`+
    `🕐 ${_timeLabel(appt.startTime)}`+
    `${appt.staffName?' with '+appt.staffName:''}\n\n`+
    `See you soon! 😊\n_${BIZ.name}_`
  );
  _sendWA(ph, decodeURIComponent(msg));
}

// ── Bulk WA reminder helper ───────────────────────────────────
// Sends reminders to all customers with a specific condition
function _bulkWAReminders(type){
  const today = localDateStr();
  let items = [];
  let getMsgFn;

  if(type === 'overdue'){
    items = D.rentals.filter(r=>r.st==='Overdue');
    getMsgFn = r => {
      const c = D.cust.find(x=>x.name===r.cust);
      const ph = (c?.whatsapp||c?.phone||r.phone||'').replace(/[^0-9]/g,'');
      if(!ph) return null;
      const msg = encodeURIComponent(
        `Hi ${r.cust.split(' ')[0]}! 👋\n\n`+
        `Friendly reminder from *${BIZ.name}* — your rental of *${r.item}* was due on ${r.due} and is now overdue.\n\n`+
        `⚠ Late fee: ${fmt(r.lf||0)}\n\n`+
        `Please return the item or contact us to arrange an extension.\n\n`+
        `📞 ${BIZ.phone||BIZ.whatsapp||''}\n_${BIZ.name}_`
      );
      return {ph, msg, label: r.cust+' — '+r.item};
    };
  } else if(type === 'appt-tomorrow'){
    const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate()+1);
    const tomorrowStr = tomorrow.toISOString().slice(0,10);
    items = (D.appointments||[]).filter(a=>a.date===tomorrowStr && !['Cancelled','No-Show','Completed'].includes(a.st) && a.custPhone);
    getMsgFn = a => {
      const ph = (a.custPhone||'').replace(/[^0-9]/g,'');
      if(!ph) return null;
      const msg = encodeURIComponent(
        `Hi ${a.custName.split(' ')[0]}! 👋\n\n`+
        `Reminder: You have an appointment tomorrow at *${BIZ.name}*\n\n`+
        `📋 *${a.serviceName}*\n`+
        `📅 ${a.date} at ${_timeLabel(a.startTime)}`+
        `${a.staffName?' with '+a.staffName:''}\n\n`+
        `We look forward to seeing you! 😊\n_${BIZ.name}_`
      );
      return {ph, msg, label: a.custName+' — '+a.serviceName};
    };
  } else if(type === 'ar'){
    items = D.sales.filter(s=>s.st==='Unpaid');
    getMsgFn = s => {
      const c = D.cust.find(x=>x.name===s.cust);
      const ph = (c?.whatsapp||c?.phone||'').replace(/[^0-9]/g,'');
      if(!ph) return null;
      const msg = encodeURIComponent(
        `Hi ${s.cust.split(' ')[0]}! 👋\n\n`+
        `Friendly payment reminder from *${BIZ.name}*.\n\n`+
        `💰 Outstanding balance: *${fmt(s.total||s.amt)}*\n`+
        `📋 Ref: ${s.id} · ${s.dt}\n\n`+
        `Please arrange payment at your earliest convenience. Thank you! 🙏\n\n`+
        `📞 ${BIZ.phone||BIZ.whatsapp||''}\n_${BIZ.name}_`
      );
      return {ph, msg, label: s.cust+' — '+fmt(s.total||s.amt)};
    };
  }

  if(!items.length){ toast('No items to send reminders for','info'); return; }

  // Build modal showing who will receive reminders
  const recipients = items.map(getMsgFn).filter(Boolean);
  if(!recipients.length){ toast('No phone numbers found for these contacts','error'); return; }

  modal('💬 Send WhatsApp Reminders',`
    <div class="alrt alrt-b" style="margin-bottom:12px">
      <strong>${recipients.length} reminder${recipients.length>1?'s':''} will be sent via WhatsApp</strong><br>
      <span style="font-size:12px">Each message opens in WhatsApp — you send it manually.</span>
    </div>
    <div style="max-height:240px;overflow-y:auto">
      ${recipients.map((r,i)=>`
        <div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;background:var(--bg3);border-radius:var(--r6);margin-bottom:6px">
          <div>
            <div style="font-size:13px;font-weight:600;color:var(--ink)">${r.label}</div>
            <div style="font-size:11px;color:var(--text2)">+${r.ph}</div>
          </div>
          <button class="btn btn-g btn-xs" onclick="window.open('https://wa.me/${r.ph}?text=${r.msg}','_blank')">Send</button>
        </div>`).join('')}
    </div>`,
    `<button class="btn btn-s" onclick="closeModal()">Close</button>
     <button class="btn btn-p" onclick="(function(){
       ${recipients.map((r,i)=>`setTimeout(()=>window.open('https://wa.me/${r.ph}?text=${r.msg}','_blank'),${i*1200})`).join(';')};
       closeModal();
       toast('Opening ${recipients.length} WhatsApp messages…','success');
     }())">💬 Open All (${recipients.length})</button>`
  , 'sm');
}

// ── Upgraded refreshNotifPanel with actionable items ─────────
function refreshNotifPanel(){
  _updateApptBadge();
  const today = localDateStr();

  // ── Live overdue detection: mark any past-due active rental as Overdue ──
  D.rentals.forEach(function(r){
    if((r.st==='Checked Out'||r.st==='Reserved') && r.due && r.due < today){
      r.st = 'Overdue';
    }
  });

  const body  = document.getElementById('np-body');
  const badge = document.getElementById('np-count');
  const dot   = document.querySelector('.notif-dot');
  if(!body) return;

  // helper: close panel
  const _close = "document.getElementById('np').classList.remove('open');";

  let html  = '';
  let count = 0;

  // ── Access requests ───────────────────────────────────────────
  const pendingReqs = !SESSION.isSuperAdmin
    ? ACCESS_REQUESTS.filter(function(r){ return r.bizId===SESSION.bizId&&r.status==='pending'; })
    : [];
  if(pendingReqs.length){
    count += pendingReqs.length;
    html += `<div class="np-item np-item-y" onclick="${_close}mViewAccessRequests()">
      <div class="np-item-icon">🔔</div>
      <div class="np-item-body">
        <div class="np-item-title">${pendingReqs.length} pending access request${pendingReqs.length>1?'s':''}</div>
        <div class="np-item-desc">${pendingReqs.map(function(r){return _esc(r.userName);}).slice(0,2).join(', ')}${pendingReqs.length>2?' +more':''} — <strong>Tap to review</strong></div>
      </div>
      <button class="np-act-btn" onclick="event.stopPropagation();${_close}mViewAccessRequests()">Review →</button>
    </div>`;
  }

  if(!SESSION.isSuperAdmin){

    // ── Today's appointments ──────────────────────────────────
    const todayAppts = (D.appointments||[]).filter(function(a){
      return a.date===today && !['Completed','Cancelled','No-Show'].includes(a.st);
    });
    if(todayAppts.length){
      count += todayAppts.length;
      const apptLines = todayAppts.slice(0,4).map(function(a){
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}mViewAppt('${a.id}')">`
          +`<span class="np-sub-time">${_timeLabel(a.startTime)}</span>`
          +`<span class="np-sub-name">${_esc(a.custName)}</span>`
          +`<span class="np-sub-svc">${_esc(a.serviceName||'')}</span>`
          +`</div>`;
      }).join('');
      html += `<div class="np-item np-item-b np-expandable" onclick="${_close}nav('appointments')">
        <div class="np-item-icon">📅</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${todayAppts.length} appointment${todayAppts.length>1?'s':''} today</div>
          <div class="np-sub-list">${apptLines}${todayAppts.length>4?`<div class="np-sub-more">+${todayAppts.length-4} more →</div>`:''}</div>
        </div>
        <button class="np-act-btn" onclick="event.stopPropagation();${_close}nav('appointments')">All →</button>
      </div>`;
    }

    // ── Tomorrow's appointments ───────────────────────────────
    const tmrDate = localDateStr(1);
    const tmrAppts = (D.appointments||[]).filter(function(a){
      return a.date===tmrDate && !['Cancelled','No-Show','Completed'].includes(a.st);
    });
    if(tmrAppts.length){
      // tomorrow is informational — don't add to badge count
      html += `<div class="np-item np-item-b" style="opacity:.82" onclick="${_close}nav('appointments')">
        <div class="np-item-icon">🗓</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${tmrAppts.length} appointment${tmrAppts.length>1?'s':''} tomorrow</div>
          <div class="np-item-desc">${tmrAppts.slice(0,3).map(function(a){return _esc(a.custName);}).join(', ')}${tmrAppts.length>3?' +more':''}</div>
        </div>
        <button class="np-act-btn" onclick="event.stopPropagation();_apptSendReminders()">Remind 💬</button>
      </div>`;
    }

    // ── Overdue rentals ──────────────────────────────────────
    const overdueList = D.rentals.filter(function(r){ return r.st==='Overdue'; });
    if(overdueList.length){
      count += overdueList.length;
      // Calculate days overdue and late fees dynamically
      const rentalRows = overdueList.slice(0,4).map(function(r){
        const daysLate = Math.max(0, Math.floor((new Date(today)-new Date(r.due))/(1000*60*60*24)));
        const dynamicLf = r.lf > 0 ? r.lf : (r.rp||0)*daysLate; // estimate if not set
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}mRentalDetail('${r.id}')">`
          +`<span class="np-sub-name">${_esc(r.cust)}</span>`
          +`<span class="np-sub-svc" style="color:var(--r)">${_esc(r.item.split(' ').slice(0,3).join(' '))}${r.item.split(' ').length>3?'…':''}</span>`
          +`<span class="np-sub-time" style="color:var(--r)">${daysLate}d late</span>`
          +`</div>`;
      }).join('');
      const totalLf = overdueList.reduce(function(a,r){
        const daysLate = Math.max(0, Math.floor((new Date(today)-new Date(r.due))/(1000*60*60*24)));
        return a + (r.lf > 0 ? r.lf : (r.rp||0)*daysLate);
      }, 0);
      html += `<div class="np-item np-item-r np-expandable" onclick="${_close}nav('rentals');setTimeout(filterRentalsOverdue,120)">
        <div class="np-item-icon">⏰</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${overdueList.length} overdue rental${overdueList.length>1?'s':''}</div>
          <div class="np-sub-list">${rentalRows}${overdueList.length>4?`<div class="np-sub-more">+${overdueList.length-4} more →</div>`:''}</div>
          ${totalLf>0?`<div style="font-size:10px;color:var(--r);margin-top:3px;font-weight:600">Est. late fees: ${fmt(totalLf)}</div>`:''}
        </div>
        <button class="np-act-btn np-act-r" onclick="event.stopPropagation();${_close}nav('rentals')">View all →</button>
      </div>`;
    }

    // ── Rentals due soon (next 2 days, not yet overdue) ───────
    const tmrStr = localDateStr(1);
    const dayAfterStr = localDateStr(2);
    const dueSoon = D.rentals.filter(function(r){
      return (r.st==='Checked Out'||r.st==='Reserved') && r.due >= today && r.due <= dayAfterStr;
    });
    if(dueSoon.length){
      count += dueSoon.length;
      const dueRows = dueSoon.slice(0,3).map(function(r){
        const label = r.due===today?'due today':r.due===tmrStr?'due tomorrow':'due '+r.due;
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}mRentalDetail('${r.id}')">`
          +`<span class="np-sub-name">${_esc(r.cust)}</span>`
          +`<span class="np-sub-svc">${_esc(r.item.split(' ').slice(0,3).join(' '))}${r.item.split(' ').length>3?'…':''}</span>`
          +`<span class="np-sub-time" style="color:var(--y)">${label}</span>`
          +`</div>`;
      }).join('');
      html += `<div class="np-item np-item-y np-expandable" onclick="${_close}nav('rentals')">
        <div class="np-item-icon">📋</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${dueSoon.length} rental${dueSoon.length>1?'s':''} due soon</div>
          <div class="np-sub-list">${dueRows}</div>
        </div>
        <button class="np-act-btn" onclick="event.stopPropagation();${_close}nav('rentals')">View →</button>
      </div>`;
    }

    // ── AR: unpaid + partial sales ────────────────────────────
    const unpaidSales = D.sales.filter(function(s){ return s.st==='Unpaid'||s.st==='Partial'; });
    if(unpaidSales.length){
      count += unpaidSales.length;
      const arTotal = unpaidSales.reduce(function(a,s){ return a+((s.total||s.amt||0)-s.paid); }, 0);
      const arRows = unpaidSales.slice(0,4).map(function(s){
        const bal = (s.total||s.amt||0)-s.paid;
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}genInvoiceDoc('${s.id}')">`
          +`<span class="np-sub-name">${_esc(s.cust)}</span>`
          +`<span class="np-sub-svc">${s.id}</span>`
          +`<span class="np-sub-time" style="color:var(--y);font-weight:600">${fmt(bal)}</span>`
          +`</div>`;
      }).join('');
      html += `<div class="np-item np-item-y np-expandable" onclick="${_close}mARDetail()">
        <div class="np-item-icon">💰</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${unpaidSales.length} unpaid invoice${unpaidSales.length>1?'s':''} — ${fmt(arTotal)} AR</div>
          <div class="np-sub-list">${arRows}${unpaidSales.length>4?`<div class="np-sub-more">+${unpaidSales.length-4} more →</div>`:''}</div>
        </div>
        <button class="np-act-btn" onclick="event.stopPropagation();${_close}mARDetail()">AR Report →</button>
      </div>`;
    }

    // ── Low stock ─────────────────────────────────────────────
    const lowStock = D.inv.filter(function(i){
      const avail = (i.qty||0)-(i.rented||0);
      const threshold = i.minStock||i.minQty||0;
      // Only alert when: threshold explicitly set AND available is at or below it but NOT zero
      // (out-of-stock items are a separate category shown below)
      return threshold>0 && avail>0 && avail<=threshold;
    });
    const outOfStockItems = D.inv.filter(function(i){
      return (i.qty||0)-(i.rented||0)<=0 && (i.st==='For Sale'||i.st==='Both'||i.st==='For Rent');
    });
    const allStockAlerts = [].concat(outOfStockItems.map(function(i){return Object.assign({},i,{_oos:true});}), lowStock);
    if(allStockAlerts.length){
      count++;
      const stockRows = allStockAlerts.slice(0,4).map(function(i){
        const avail = (i.qty||0)-(i.rented||0);
        const isOOS = i._oos||avail<=0;
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}mItem('${i.id}')">`
          +`<span class="np-sub-name">${_esc(i.name)}</span>`
          +`<span class="np-sub-svc">${_esc(i.sku||i.cat||'')}</span>`
          +`<span class="np-sub-time" style="color:${isOOS?'var(--r)':'var(--y)'};font-weight:600">${isOOS?'Out of stock':avail+' left'}</span>`
          +`</div>`;
      }).join('');
      const alertTitle = outOfStockItems.length>0 && lowStock.length>0
        ? `${outOfStockItems.length} out of stock, ${lowStock.length} low`
        : outOfStockItems.length>0
          ? `${outOfStockItems.length} item${outOfStockItems.length>1?'s':''} out of stock`
          : `${lowStock.length} item${lowStock.length>1?'s':''} low on stock`;
      html += `<div class="np-item np-item-y np-expandable" onclick="${_close}nav('inventory')">
        <div class="np-item-icon">📦</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">${alertTitle}</div>
          <div class="np-sub-list">${stockRows}${allStockAlerts.length>4?`<div class="np-sub-more">+${allStockAlerts.length-4} more →</div>`:''}</div>
        </div>
        <button class="np-act-btn" onclick="event.stopPropagation();${_close}nav('inventory')">View →</button>
      </div>`;
    }

    // ── AP: vendor balances due ───────────────────────────────
    const apDue = D.vendors.filter(function(v){ return v.bal>0; });
    if(apDue.length){
      count++;
      const apTotal = apDue.reduce(function(a,v){ return a+v.bal; }, 0);
      const apRows = apDue.slice(0,3).map(function(v){
        return `<div class="np-sub-row" onclick="event.stopPropagation();${_close}mAPDetail()">`
          +`<span class="np-sub-name">${_esc(v.name)}</span>`
          +`<span class="np-sub-svc">${_esc(v.terms||v.cat||'')}</span>`
          +`<span class="np-sub-time" style="color:var(--r);font-weight:600">${fmt(v.bal)}</span>`
          +`</div>`;
      }).join('');
      html += `<div class="np-item np-item-r" style="opacity:.9" onclick="${_close}mAPDetail()">
        <div class="np-item-icon">🏭</div>
        <div class="np-item-body" style="flex:1">
          <div class="np-item-title">AP: ${fmt(apTotal)} due to ${apDue.length} vendor${apDue.length>1?'s':''}</div>
          <div class="np-sub-list">${apRows}</div>
        </div>
        <button class="np-act-btn np-act-r" onclick="event.stopPropagation();${_close}mAPDetail()">AP Report →</button>
      </div>`;
    }
  }

  if(!html){
    html = `<div style="text-align:center;padding:28px 16px">
      <div style="font-size:32px;margin-bottom:10px">✅</div>
      <div style="font-size:13px;font-weight:600;color:var(--ink);margin-bottom:4px">All clear!</div>
      <div style="font-size:12px;color:var(--text2)">No outstanding alerts right now.</div>
    </div>`;
  }
  // Append WA quick-action footer to notification panel
  html += '<div style="border-top:1px solid var(--border);margin-top:10px;padding:10px 14px;display:flex;flex-direction:column;gap:7px">'
    + '<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:var(--text2);margin-bottom:2px">Quick Actions</div>'
    + '<button class="btn btn-g btn-sm" style="justify-content:flex-start;gap:8px" onclick="nav(\'settings\');setTimeout(function(){var t=document.querySelector(\'.stab[onclick*=tab-notif]\');if(t){t.click();}},300)">'
    + '⚙️ Notification Settings</button>'
    + '</div>';

  body.innerHTML = html;
  const displayCount = Math.min(count, 99);
  if(badge){
    badge.textContent = displayCount > 9 ? '9+' : displayCount;
    badge.style.display = count > 0 ? '' : 'none';
  }
  if(dot) dot.style.background = count > 0 ? 'var(--r)' : 'var(--g)';
}

function _saveAppt(){
  if(_trialWriteBlocked('Booking an appointment')) return;
  const date=document.getElementById('na-d')?.value;
  if(!date){ toast('Select a date','error'); return; }
  const svcId=_ssGetVal('na-s-wrap')||(document.getElementById('na-s')||{}).value||'';
  const svc=D.services.find(s=>s.id===svcId);
  const st=document.getElementById('na-t')?.value||'09:00';
  const et=document.getElementById('na-e')?.value||'';
  const cId=_ssGetVal('na-c-wrap')||(document.getElementById('na-c')||{}).value||'';
  // Resolve customer from D.cust for accurate name/phone
  const custObj = cId ? D.cust.find(c=>c.id===cId) : null;
  const cName = custObj ? custObj.name : (cId ? (cSel?.options[cSel.selectedIndex]?.text||'Guest') : 'Walk-in');
  const ph=document.getElementById('na-ph')?.value || custObj?.phone || custObj?.whatsapp || '';
  const stfSel=document.getElementById('na-st');
  const stfOpt=stfSel?.options[stfSel.selectedIndex];
  const stfId=stfSel?.value||'';
  const stfName=stfId?stfOpt?.text:'';
  const amt=parseFloat(document.getElementById('na-amt')?.value)||0;
  const notes=document.getElementById('na-n')?.value||'';
  const wi=document.getElementById('na-wi')?.checked||false;
  // Validate — if new-cust form is open, prompt to save first
  const ncForm=document.getElementById('na-new-cust-form');
  if(ncForm && ncForm.style.display!=='none'){
    const ncName=document.getElementById('na-nc-name')?.value?.trim();
    if(ncName){ toast('Please click "Save & Select" to add the new customer first','error'); return; }
  }
  // ── Double-booking conflict check ─────────────────────────────────
  if(st && et){
    var _conflicts=(D.appointments||[]).filter(function(ex){
      if(ex.date!==date||ex.st==='Cancelled') return false;
      var sameStaff=stfId&&ex.staffId&&ex.staffId===stfId;
      var overlapTime=st<(ex.endTime||'23:59')&&(et||'23:59')>(ex.startTime||'00:00');
      return overlapTime&&(sameStaff||(!stfId&&!ex.staffId));
    });
    if(_conflicts.length>0){
      var _cMsg='⚠️ Time conflict detected:\n'+_conflicts.map(function(ex){
        return '  '+ex.startTime+'-'+(ex.endTime||'?')+' — '+_esc(ex.custName)+' ('+_esc(ex.serviceName)+')';
      }).join('\n')+'\n\nBook anyway?';
      if(!confirm(_cMsg)) return;
    }
  }
  const a={id:_newApptId(),serviceId:svc?.id||'',serviceName:svc?.name||'Custom',custId:cId,custName:cName,custPhone:ph,staffId:stfId,staffName:stfName,date,startTime:st,endTime:et,st:'Reserved',notes,walkIn:wi,totalAmt:amt/CUR.rate,createdAt:localDateStr()};
  D.appointments.unshift(a);
  _dbSaveAppt(a);
  _updateApptBadge();
  addAudit('Appointment booked',a.id+' — '+cName+' — '+a.serviceName+' '+date);
  _notifEvent('newAppointment',{cust:a.custName,svc:a.serviceName,date:a.date});
  _sendWAApptConfirm(a);
  // Alert owner about new booking
  _waOwnerNewBooking(a);
  closeModal();
  toast(a.serviceName+' booked for '+cName,'success');
  nav('appointments');
}

function _deleteAppt(id){
  var a=D.appointments.find(function(x){return x.id===id;});
  if(!a){ toast('Not found','error'); return; }
  var linkedSale=a.saleId?D.sales.find(function(s){return s.id===a.saleId;}):null;
  var isActive=a.st!=='Completed'&&a.st!=='Cancelled';
  var warnHtml='<p style="font-size:13px;color:var(--text2);margin-bottom:8px">Delete <strong>'+_esc(a.id)+'</strong> — '+_esc(a.custName)+' / '+_esc(a.serviceName)+' on '+a.date+'?</p>';
  if(isActive) warnHtml+='<div class="alrt alrt-y" style="margin-bottom:8px">This appointment is <strong>'+a.st+'</strong>. Consider cancelling instead.</div>';
  if(linkedSale) warnHtml+='<div class="alrt alrt-r" style="margin-bottom:8px">Linked sale <strong>'+linkedSale.id+'</strong> ('+fmt(linkedSale.amt)+') will NOT be deleted.</div>';
  if(a.totalAmt>0&&!linkedSale) warnHtml+='<p style="font-size:12px;color:var(--text3)">Revenue of '+fmt(a.totalAmt)+' will be removed from KPIs.</p>';
  var mid=id;
  modal('Delete Appointment', warnHtml,
    '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'+
    '<button class="btn btn-d" id="confirm-del-appt-btn">Delete</button>');
  setTimeout(function(){
    var btn=document.getElementById('confirm-del-appt-btn');
    if(btn) btn.onclick=function(){
      D.appointments=(D.appointments||[]).filter(function(x){return x.id!==mid;});
      _dbDelAppt(mid); refreshLiveKpis();
      addAudit('Appointment deleted',mid);
      closeModal(); toast('Appointment deleted','success'); nav('appointments');
    };
  },30);
}

function mEditApptCompleted(id){
  var a = D.appointments.find(function(x){return x.id===id;});
  if(!a){ toast('Not found','error'); return; }
  var rate = CUR.rate||1;
  var sym  = CUR.symbol;
  var body = '<div class="fg-2">'
    +'<div class="fg"><label class="fl">Date</label>'
    +'<input class="fi" type="date" id="eac-date" value="'+a.date+'"/></div>'
    +'<div class="fg"><label class="fl">Amount ('+sym+')</label>'
    +'<input class="fi" type="number" id="eac-amt" value="'+Math.round((a.totalAmt||0)*rate)+'" step="any"/></div>'
    +'</div>'
    +'<div class="fg"><label class="fl">Payment Method</label>'
    +'<select class="fs" id="eac-method">'
    +'<option'+(a.payMethod==='Cash'?' selected':'')+'>Cash</option>'
    +'<option'+(a.payMethod==='Mobile Money (MTN)'?' selected':'')+'>Mobile Money (MTN)</option>'
    +'<option'+(a.payMethod==='Orange Money'?' selected':'')+'>Orange Money</option>'
    +'<option'+(a.payMethod==='Bank Transfer'?' selected':'')+'>Bank Transfer</option>'
    +'<option'+(a.payMethod==='Card'?' selected':'')+'>Card</option>'
    +'</select></div>'
    +'<div class="fg"><label class="fl">Notes</label>'
    +'<textarea class="ft" id="eac-notes" style="min-height:60px">'+(a.notes||'')+'</textarea></div>';
  var footer = '<button class="btn btn-s" onclick="closeModal()">Cancel</button>'
    +' <button class="btn btn-p" id="eac-save-btn">Save Changes</button>';
  modal('Edit Completed Appointment', body, footer, 'sm');
  // Wire save button after modal renders (avoids all quote-nesting)
  setTimeout(function(){
    var btn = document.getElementById('eac-save-btn');
    if(btn) btn.onclick = function(){ _saveApptEdit(id); };
  }, 30);
}


function _saveApptEdit(id){
  var a = D.appointments.find(function(x){return x.id===id;});
  if(!a){ toast('Not found','error'); return; }
  var rate    = CUR.rate||1;
  var newAmt  = (parseFloat((document.getElementById('eac-amt')||{}).value)||0)/rate;
  var newDate = (document.getElementById('eac-date')||{}).value||a.date;
  var newNotes= (document.getElementById('eac-notes')||{}).value||'';
  var newMeth = (document.getElementById('eac-method')||{}).value||'Cash';
  a.totalAmt  = newAmt;
  a.date      = newDate;
  a.notes     = newNotes;
  a.payMethod = newMeth;
  _dbSaveAppt(a);
  // Sync linked sale if present
  if(a.saleId){
    var sale = D.sales.find(function(s){return s.id===a.saleId;});
    if(sale){
      sale.amt=newAmt; sale.total=newAmt; sale.paid=newAmt;
      sale.dt=newDate; sale.notes=newNotes; sale.method=newMeth;
      _dbSaveSale(sale);
    }
  }
  refreshLiveKpis();
  addAudit('Appointment edited', id+' '+fmt(newAmt));
  closeModal();
  toast('Appointment updated','success');
  nav('appointments');
}

function genApptInvoice(id){
  var a = D.appointments.find(function(x){return x.id===id;});
  if(!a){ toast('Appointment not found','error'); return; }
  var primary  = BIZ.primaryColor||'#4361EE';
  var accent   = BIZ.accentColor||'#059669';
  var rate     = CUR.rate||1;
  var total    = Math.round((a.totalAmt||0)*rate);
  var invNo    = 'SVC-'+a.id;
  var taxRate  = BIZ.taxRate||0;
  var subtotal = taxRate>0 ? Math.round(total/(1+taxRate/100)) : total;
  var taxAmt   = total - subtotal;
  var method   = a.payMethod||'Cash';
  var svc      = D.services.find(function(s){return s.id===a.serviceId;});
  var duration = svc ? svc.duration+' min' : '';
  var stBadge  = a.st==='Completed' ? 'paid' : 'partial';
  var L        = _L();
  var stLabel  = a.st==='Completed' ? L.stCompleted : a.st||'Pending';

  var docHtml = docStyles(primary, accent)
    +'<div style="background:'+primary+';padding:24px 28px 20px;display:flex;justify-content:space-between;align-items:flex-start">'
      +'<div>'
        +(BIZ.logoDataUrl?'<img src="'+BIZ.logoDataUrl+'" style="height:52px;object-fit:contain;display:block"/>':'<div style="width:52px;height:52px;background:rgba(255,255,255,.2);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:20px;font-weight:800;color:#fff">'+_esc(BIZ.name.substring(0,2).toUpperCase())+'</div>')
        +'<div style="font-size:20px;font-weight:800;color:#fff;margin-top:8px;letter-spacing:-.3px">'+_esc(BIZ.name)+'</div>'
        +(BIZ.tagline?'<div style="font-size:11px;color:rgba(255,255,255,.7);margin-top:2px">'+_esc(BIZ.tagline)+'</div>':'')
      +'</div>'
      +'<div style="text-align:right">'
        +'<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,.65)">'+L.serviceInvoice+'</div>'
        +'<div style="font-size:28px;font-weight:900;color:#fff;letter-spacing:-1px;line-height:1.1;margin-top:4px">'+invNo+'</div>'
        +'<div style="margin-top:8px"><span class="doc-badge doc-badge-'+stBadge+'">'+stLabel+'</span></div>'
        +'<div style="font-size:11px;color:rgba(255,255,255,.65);margin-top:6px">'+L.date+': '+a.date+'</div>'
      +'</div>'
    +'</div>'
    +'<div class="doc-body">'
      +'<div class="doc-meta">'
        +'<div>'
          +'<div class="doc-label">'+L.customer+'</div>'
          +'<div class="doc-value" style="font-size:15px">'+_esc(a.custName)+'</div>'
          +(a.custPhone?'<div class="doc-value-sub">'+_esc(a.custPhone)+'</div>':'')
        +'</div>'
        +'<div>'
          +'<div class="doc-label">'+L.apptDetails+'</div>'
          +'<div class="doc-value">'+a.date+(a.startTime?' &middot; '+_timeLabel(a.startTime):'')+'</div>'
          +(a.staffName?'<div class="doc-value-sub">'+L.staff+': '+_esc(a.staffName)+'</div>':'')
          +(duration?'<div class="doc-value-sub">'+L.duration+': '+duration+'</div>':'')
        +'</div>'
      +'</div>'
      +'<table class="doc-items">'
        +'<thead><tr><th style="width:50%">'+L.service+'</th><th>'+L.duration+'</th><th>'+L.staff+'</th><th class="num">'+L.amount+'</th></tr></thead>'
        +'<tbody><tr>'
          +'<td class="desc">'+_esc(a.serviceName||'Service')+'</td>'
          +'<td>'+duration+'</td>'
          +'<td>'+_esc(a.staffName||'—')+'</td>'
          +'<td class="num" style="font-weight:700">'+fmtDoc(subtotal/rate)+'</td>'
        +'</tr></tbody>'
      +'</table>'
      +'<div class="doc-totals">'
        +'<div class="doc-totals-box">'
          +(taxRate>0?'<div class="doc-total-row"><span>'+L.subtotal+'</span><span class="num">'+fmtDoc(subtotal/rate)+'</span></div><div class="doc-total-row"><span>'+L.tax+' ('+taxRate+'%)</span><span class="num">'+fmtDoc(taxAmt/rate)+'</span></div>':'')
          +'<div class="doc-total-final"><span>'+L.total+'</span><span class="num">'+fmtDoc(a.totalAmt||0)+'</span></div>'
        +'</div>'
      +'</div>'
      +'<div class="doc-section-title">'+L.payment+'</div>'
      +'<div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px">'
        +'<div><div class="doc-label">'+L.method+'</div><div class="doc-value">'+_esc(method)+'</div></div>'
        +'<div><div class="doc-label">'+L.status+'</div><div class="doc-value">'+stLabel+'</div></div>'
      +'</div>'
      +(a.notes?'<div class="doc-section-title">'+L.notes+'</div><p style="font-size:12px;color:#475569;line-height:1.6;margin-bottom:16px">'+_esc(a.notes)+'</p>':'')
      +(BIZ.signDataUrl||BIZ.stampDataUrl?docSignStamp():'')
    +'</div>'
    +'<div class="doc-footer">'
      +'<div class="doc-footer-note">'
        +(BIZ.invoiceNote?'<strong style="display:block;margin-bottom:4px;font-size:12px">'+_esc(BIZ.invoiceNote)+'</strong>':'')
        +(BIZ.email?'<div>📧 '+_esc(BIZ.email)+'</div>':'')
        +(BIZ.phone?'<div>📞 '+_esc(BIZ.phone)+'</div>':'')
      +'</div>'
      +'<div class="doc-footer-biz">'
        +'<strong>'+_esc(BIZ.name)+'</strong>'
        +(BIZ.address?'<div>'+_esc(BIZ.address)+'</div>':'')
        +(BIZ.website?'<div style="color:'+primary+'">'+_esc(BIZ.website)+'</div>':'')
      +'</div>'
    +'</div>'
    +'<div class="doc-watermark">ShopTrack</div>';

  openDoc(L.serviceInvoice+' — '+invNo, docHtml);
}


function mViewAppt(id){
  var a = D.appointments.find(function(x){return x.id===id;});
  if(!a){ toast('Appointment not found','error'); return; }
  var svc        = D.services.find(function(s){return s.id===a.serviceId;});
  var canEdit    = a.st!=='Completed' && a.st!=='Cancelled';
  var canEditAmt = a.st==='Completed';
  var canCheckout= a.st==='Completed' && !a.saleId && (a.totalAmt||0)>0;
  var col        = _apptCol(a.st);

  var statusHtml = '<div style="background:'+col+'18;border:1px solid '+col+'40;border-radius:var(--r8);padding:10px 14px;margin-bottom:14px;display:flex;align-items:center;justify-content:space-between">'
    +'<span style="font-weight:700;color:'+col+';font-size:14px">'+a.st
    +(a.walkIn?'&nbsp;<span style="font-size:10px;background:var(--o-dim);color:var(--o);padding:2px 6px;border-radius:10px">Walk-in</span>':'')
    +'</span><span style="font-size:11px;color:var(--text2)">'+a.id+'</span></div>';

  var grid = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px">'
    +'<div style="background:var(--bg3);border-radius:var(--r8);padding:11px">'
      +'<div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text2);margin-bottom:4px">Date &amp; Time</div>'
      +'<div style="font-weight:700;color:var(--ink)">'+a.date+'</div>'
      +'<div style="font-size:11px;color:var(--text2)">'+_timeLabel(a.startTime)+(a.endTime?' \u2013 '+_timeLabel(a.endTime):'')+'</div></div>'
    +'<div style="background:var(--bg3);border-radius:var(--r8);padding:11px">'
      +'<div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text2);margin-bottom:4px">Customer</div>'
      +'<div style="font-weight:700;color:var(--ink)">'+a.custName+'</div>'
      +(a.custPhone?'<div style="font-size:11px;color:var(--a)">'+a.custPhone+'</div>':'')+'</div>'
    +'<div style="background:var(--bg3);border-radius:var(--r8);padding:11px">'
      +'<div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text2);margin-bottom:4px">Service</div>'
      +'<div style="font-weight:700;color:var(--ink)">'+a.serviceName+'</div>'
      +(svc?'<div style="font-size:11px;color:var(--text2)">'+svc.duration+' min</div>':'')+'</div>'
    +'<div style="background:var(--bg3);border-radius:var(--r8);padding:11px">'
      +'<div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text2);margin-bottom:4px">Amount</div>'
      +'<div style="font-weight:700;color:var(--ink)">'+(a.totalAmt>0?fmt(a.totalAmt):'\u2014')+'</div>'
      +(a.saleId?'<div style="font-size:11px;color:var(--g)">\u2713 Sale '+a.saleId+'</div>':canCheckout?'<div style="font-size:11px;color:var(--y)">Pending checkout</div>':'')+'</div>'
    +(a.staffName?'<div style="background:var(--bg3);border-radius:var(--r8);padding:11px"><div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text2);margin-bottom:4px">Staff</div><div style="font-weight:700;color:var(--ink)">'+a.staffName+'</div></div>':'')
    +'</div>';

  var notesHtml = a.notes ? '<div style="background:var(--bg3);border-radius:var(--r8);padding:10px 12px;margin-bottom:12px;font-size:12px">\uD83D\uDCDD '+a.notes+'</div>' : '';

  var statusRow = canEdit
    ? '<div class="fg-2"><div class="fg"><label class="fl">Update Status</label>'
      +'<select class="fs" id="va-st">'
      +['Reserved','Confirmed','In Progress','Completed','No-Show','Cancelled'].map(function(s){return '<option'+(s===a.st?' selected':'')+'>'+s+'</option>';}).join('')
      +'</select></div>'
      +'<div class="fg"><label class="fl">Note (append)</label><input class="fi" id="va-n" placeholder="Add a note\u2026"/></div></div>'
    : '';

  var waBtn       = a.custPhone ? '<button class="btn btn-g btn-sm" onclick="_apptWA(\''+id+'\')">💬 WA</button>' : '';
  var reschedBtn  = canEdit ? '<button class="btn btn-s btn-sm" onclick="closeModal();mRescheduleAppt(\''+id+'\')">🔄 Reschedule</button>' : '';
  var cancelBtn   = canEdit ? '<button class="btn btn-sm" style="background:var(--y-dim);color:var(--y)" onclick="closeModal();mCancelAppt(\''+id+'\')">✕ Cancel</button>' : '';
  var checkoutBtn = canCheckout ? '<button class="btn btn-p btn-sm" onclick="closeModal();_apptCheckout(\''+id+'\')">💳 Checkout</button>' : '';
  var editBtn    = canEdit    ? '<button class="btn btn-s btn-sm" onclick="closeModal();mEditAppt(\''+id+'\')">Edit</button>' : '';
  var editAmtBtn = canEditAmt ? '<button class="btn btn-s btn-sm" onclick="closeModal();mEditApptCompleted(\''+id+'\')">✏ Edit Amount</button>' : '';
  var invoiceBtn = (a.st==='Completed'&&(a.totalAmt||0)>0) ? '<button class="btn btn-g btn-sm" onclick="genApptInvoice(\''+id+'\')">🧾 Invoice</button>' : '';
  var deleteBtn  = '<button class="btn btn-sm" style="background:var(--r-dim);color:var(--r)" onclick="_deleteAppt(\''+id+'\')">🗑 Delete</button>';
  var saveBtn     = canEdit ? '<button class="btn btn-p btn-sm" onclick="_updAppt(\''+id+'\')">💾 Save</button>' : '<button class="btn btn-s btn-sm" onclick="closeModal()">Close</button>';

  var footer = '<div style="display:flex;justify-content:space-between;align-items:center;width:100%;gap:6px;flex-wrap:wrap">'
    +'<div style="display:flex;gap:5px;flex-wrap:wrap">'+waBtn+reschedBtn+cancelBtn+checkoutBtn+deleteBtn+'</div>'
    +'<div style="display:flex;gap:5px">'+editBtn+editAmtBtn+invoiceBtn+saveBtn+'</div></div>';

  modal('📅 '+a.serviceName+' \u2014 '+a.custName, statusHtml+grid+notesHtml+statusRow, footer, 'sm');
}


function mNewAppt(date){
  const td=date||localDateStr();
  const so=D.services.filter(s=>s.active).map(s=>{const pt=s.priceType||'flat';return `<option value="${s.id}" data-dur="${s.duration}" data-p="${s.price}" data-pt="${pt}">${s.name} (${s.duration}min · ${fmt(s.price)}/${_ptLabel(pt)})</option>`;}).join('');
  const co=D.cust.map(c=>`<option value="${c.id}" data-ph="${c.phone||c.whatsapp||''}">${c.name}</option>`).join('');
  const stO=BIZ_USERS.filter(u=>u.bizId===SESSION.bizId).map(u=>`<option value="${u.id}">${u.name}</option>`).join('');
  modal('📅 New Appointment',`
  <div class="fg-2">
    <div class="fg"><label class="fl">Service</label>
      <div id="na-s-wrap" style="position:relative"></div><input type="hidden" id="na-s" value=""/>
    </div>
    <div class="fg"><label class="fl">Date</label><input class="fi" id="na-d" type="date" value="${td}"/></div>
  </div>
  <div class="fg-2">
    <div class="fg"><label class="fl">Start Time</label><input class="fi" id="na-t" type="time" value="09:00" oninput="_naSync()"/></div>
    <div class="fg"><label class="fl">End Time</label><input class="fi" id="na-e" type="time" value="10:00" style="background:var(--bg3);color:var(--text2)" readonly/></div>
  </div>
  <div class="fg">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:5px">
      <label class="fl" style="margin:0">Customer</label>
      <button type="button" class="btn btn-g btn-xs" onclick="_apptAddNewCust()" style="font-size:11px">+ New Customer</button>
    </div>
    <div id="na-c-wrap" style="position:relative"></div>
    <input type="hidden" id="na-c" value=""/>
  </div>
  <div id="na-new-cust-form" style="display:none;background:var(--bg3);border:1px solid var(--border2);border-radius:var(--r8);padding:12px;margin-bottom:8px">
    <div style="font-size:11px;font-weight:700;color:var(--a);text-transform:uppercase;letter-spacing:.5px;margin-bottom:10px">New Customer Details</div>
    <div class="fg-2">
      <div class="fg"><label class="fl">Full Name *</label><input class="fi" id="na-nc-name" placeholder="Customer name"/></div>
      <div class="fg"><label class="fl">Phone *</label><input class="fi" id="na-nc-phone" type="tel" placeholder="${_ph('phonePh')}" data-locale="phone"/></div>
    </div>
    <div class="fg-2">
      <div class="fg"><label class="fl">Email</label><input class="fi" id="na-nc-email" type="email" placeholder="email"+'@'+"example.com"/></div>
      <div class="fg"><label class="fl">City</label><input class="fi" id="na-nc-city" placeholder="e.g. ${CUR_LOCALE[CUR.code]?.city||'City'}" data-locale="city"/></div>
    </div>
    <div style="display:flex;gap:8px;margin-top:2px">
      <button type="button" class="btn btn-p btn-sm" onclick="_apptSaveNewCust()" style="flex:1">✓ Save & Select</button>
      <button type="button" class="btn btn-s btn-sm" onclick="_apptCancelNewCust()">Cancel</button>
    </div>
  </div>
  <div class="fg"><label class="fl">Phone</label><input class="fi" id="na-ph" placeholder="Auto-filled from customer"/></div>
  <div class="fg-2">
    <div class="fg"><label class="fl">Staff</label><select class="fs" id="na-st"><option value="">Any Available</option>${stO}</select></div>
    <div class="fg"><label class="fl">Amount</label><input class="fi" id="na-amt" type="number" placeholder="Price" step="0.01" oninput="this._t=true"/></div>
  </div>
  <div class="fg"><label class="fl">Notes</label><textarea class="ft" id="na-n" rows="2" placeholder="Special requests, notes…"></textarea></div>
  <label style="display:flex;align-items:center;gap:8px;font-size:13px;cursor:pointer;margin-top:4px"><input type="checkbox" id="na-wi" style="accent-color:var(--a)"/> Walk-in (no prior booking)</label>`,
  `<button class="btn btn-s" onclick="closeModal()">Cancel</button><button class="btn btn-p" onclick="_saveAppt()">📅 Book</button>`);
  setTimeout(_naSync,60);
}

